code: |
  // HGL HUD Overlay — CanvasTexture overlay ported from HexGL HUD.js

  let game;
  let erth;
  let hudCanvas, hudCtx, hudTexture, hudMesh, hudMat, hudGeo;
  let bgImg = null;
  let speedImg = null;
  let shieldImg = null;

  const SPEED_FONT_RATIO = 24;
  const SPEED_BAR_RATIO = 2.91;
  const SHIELD_FONT_RATIO = 64;
  const SHIELD_BAR_Y_RATIO = 34;
  const SHIELD_BAR_W_RATIO = 18.3;
  const SHIELD_BAR_H_RATIO = 14.3;
  const TIME_MARGIN_RATIO = 18;
  const TIME_FONT_RATIO = 19.2;
  const MESSAGE_FONT_RATIO_START = 6;
  const MESSAGE_FONT_RATIO_END = 10;
  const MESSAGE_FONT_LERP = 0.4;
  const MESSAGE_LERP = 0.4;
  const MESSAGE_FONT_ALPHA = 0.8;
  const MESSAGE_Y_RATIO = 34;
  const MESSAGE_POS_TARGET_RATIO = 12;
  const MESSAGE_DURATION_DEFAULT = 2 * 60;
  const MESSAGE_DURATION_START = 30;
  const LAP_MARGIN_RATIO = 14;
  const TIME_SEPARATORS = ["", "'", "''", ""];

  let visible = true;
  let messageOnly = false;
  let hudTime = "";
  let hudLap = "";
  let currentMessage = "";
  let previousMessage = "";
  let messageTiming = 0;
  let messagePos = 0.0;
  let messagePosTarget = 0.0;
  let messageA = 1.0;
  let messageAS = 1.0;
  let messageDuration = MESSAGE_DURATION_DEFAULT;
  let lastStoreMessage = "";

  function markRuntimeOnly(obj) {
    obj.userData = obj.userData || {};
    obj.userData.isRuntimeOnly = true;
    if (obj.children) {
      for (let i = 0; i < obj.children.length; i++) {
        markRuntimeOnly(obj.children[i]);
      }
    }
    return obj;
  }

  function loadHudImage(assetRef, imgApi) {
    return new Promise(function(resolve) {
      if (!assetRef) { resolve(null); return; }
      imgApi.createTexture(assetRef).then(function(tex) {
        resolve(tex && tex.image ? tex.image : null);
      }).catch(function() { resolve(null); });
    });
  }

  function formatTime(totalMs) {
    let t = totalMs || 0;
    let m = Math.floor(t / 60000);
    let s = Math.floor((t % 60000) / 1000);
    let ms = Math.floor(t % 1000);
    let sStr = s < 10 ? "0" + s : "" + s;
    let msStr = ms < 100 ? (ms < 10 ? "00" + ms : "0" + ms) : "" + ms;
    return TIME_SEPARATORS[0] + m + TIME_SEPARATORS[1] + sStr + TIME_SEPARATORS[2] + msStr + TIME_SEPARATORS[3];
  }

  function displayMessage(msg, duration) {
    messageTiming = 0;
    if (currentMessage !== "") {
      messageA = MESSAGE_FONT_ALPHA;
      messagePos = 0.0;
      messagePosTarget = hudCanvas.width / MESSAGE_POS_TARGET_RATIO;
      previousMessage = currentMessage;
    }
    messageAS = 0.0;
    currentMessage = msg || "";
    messageDuration = duration === undefined ? MESSAGE_DURATION_DEFAULT : duration * 60;
  }

  function drawHud(ctx, w, h, speed, speedRatio, shield, shieldRatio, font) {
    let screenHalfW = w / 2;
    let screenHalfH = h / 2;

    ctx.clearRect(0, 0, w, h);
    if (!visible || !bgImg) return;

    let bgSourceW = bgImg.width || 1;
    let bgSourceH = bgImg.height || 1;
    let bgRatio = bgSourceH / bgSourceW;
    let bgW = w;
    let bgH = bgW * bgRatio;
    let offsetY = h - bgH;
    let baseAlpha = bgH;
    let clampedSpeedRatio = Math.max(0, Math.min(1, speedRatio));
    let clampedShieldRatio = Math.max(0, Math.min(1, shieldRatio));
    let speedBarWidth = (w / SPEED_BAR_RATIO) * clampedSpeedRatio;
    let shieldHalfWidth = w / SHIELD_BAR_W_RATIO;
    let shieldOverlayHeight = w / SHIELD_BAR_H_RATIO;
    let shieldHeight = shieldOverlayHeight * clampedShieldRatio;
    let shieldY = (w / SHIELD_BAR_Y_RATIO) + shieldOverlayHeight - shieldHeight;

    ctx.textAlign = "center";

    if (!messageOnly) {
      ctx.drawImage(bgImg, 0, offsetY, bgW, bgH);

      if (speedImg) {
        ctx.save();
        ctx.beginPath();
        ctx.moveTo(speedBarWidth + baseAlpha + screenHalfW, offsetY);
        ctx.lineTo(-(speedBarWidth + baseAlpha) + screenHalfW, offsetY);
        ctx.lineTo(-speedBarWidth + screenHalfW, h);
        ctx.lineTo(speedBarWidth + screenHalfW, h);
        ctx.lineTo(speedBarWidth + baseAlpha + screenHalfW, offsetY);
        ctx.clip();
        ctx.drawImage(speedImg, 0, offsetY, bgW, bgH);
        ctx.restore();
      }

      if (shieldImg) {
        ctx.save();
        ctx.beginPath();
        ctx.moveTo(-shieldHalfWidth + screenHalfW, offsetY + shieldY);
        ctx.lineTo(shieldHalfWidth + screenHalfW, offsetY + shieldY);
        ctx.lineTo(shieldHalfWidth + screenHalfW, offsetY + shieldHeight + shieldY);
        ctx.lineTo(-shieldHalfWidth + screenHalfW, offsetY + shieldHeight + shieldY);
        ctx.lineTo(-shieldHalfWidth + screenHalfW, offsetY + shieldHeight);
        ctx.clip();
        ctx.drawImage(shieldImg, 0, offsetY, bgW, bgH);
        ctx.restore();
      }

      ctx.font = Math.round(w / SPEED_FONT_RATIO) + "px " + font;
      ctx.fillStyle = "rgba(255, 255, 255, 0.8)";
      ctx.fillText(Math.round(speed), screenHalfW, h - bgH * 0.57);

      ctx.font = Math.round(w / SHIELD_FONT_RATIO) + "px " + font;
      ctx.fillStyle = "rgba(255, 255, 255, 0.4)";
      ctx.fillText(Math.round(shield), screenHalfW, h - bgH * 0.44);
    }

    if (hudTime !== "") {
      ctx.font = Math.round(w / TIME_FONT_RATIO) + "px " + font;
      ctx.fillStyle = "rgba(255, 255, 255, 0.8)";
      ctx.fillText(hudTime, screenHalfW, w / TIME_MARGIN_RATIO);
    }

    if (hudLap !== "") {
      ctx.font = Math.round(w / TIME_FONT_RATIO) + "px " + font;
      ctx.fillStyle = "rgba(255, 255, 255, 0.8)";
      ctx.fillText(hudLap, w - w / LAP_MARGIN_RATIO, w / TIME_MARGIN_RATIO);
    }

    let messageY = screenHalfH - w / MESSAGE_Y_RATIO;
    if (messageTiming > messageDuration + 2000) {
      previousMessage = "";
      currentMessage = "";
      messageA = 0.0;
    } else if (messageTiming > messageDuration && currentMessage !== "") {
      previousMessage = currentMessage;
      currentMessage = "";
      messagePos = 0.0;
      messagePosTarget = w / MESSAGE_POS_TARGET_RATIO;
      messageA = MESSAGE_FONT_ALPHA;
    }

    if (previousMessage !== "") {
      if (messageA < 0.001) {
        messageA = 0.0;
      } else {
        messageA += (0.0 - messageA) * MESSAGE_LERP;
      }
      messagePos += (messagePosTarget - messagePos) * MESSAGE_LERP;
      ctx.font = Math.round(w / MESSAGE_FONT_RATIO_END) + "px " + font;
      ctx.fillStyle = "rgba(255, 255, 255, " + messageA + ")";
      ctx.fillText(previousMessage, screenHalfW, messageY + messagePos);
    }

    if (currentMessage !== "") {
      let messageFontRatio = MESSAGE_FONT_RATIO_START;
      if (messageTiming < MESSAGE_DURATION_START) {
        messageAS += (MESSAGE_FONT_ALPHA - messageAS) * MESSAGE_FONT_LERP;
        messageFontRatio += (MESSAGE_FONT_RATIO_END - messageFontRatio) * MESSAGE_FONT_LERP;
      } else {
        messageAS = MESSAGE_FONT_ALPHA;
        messageFontRatio = MESSAGE_FONT_RATIO_END;
      }
      ctx.font = Math.round(w / messageFontRatio) + "px " + font;
      ctx.fillStyle = "rgba(255, 255, 255, " + messageAS + ")";
      ctx.fillText(currentMessage, screenHalfW, messageY);
    }

    messageTiming++;
  }

  this.init = function(_game) {
    game = _game;
    erth = this.erth;
    hudCanvas = document.createElement("canvas"); // @check-ok
    hudCanvas.width = 1024;
    hudCanvas.height = 512;
    hudCtx = hudCanvas.getContext("2d");

    hudTexture = new THREE.CanvasTexture(hudCanvas);
    hudTexture.minFilter = THREE.LinearFilter;
    hudTexture.magFilter = THREE.LinearFilter;

    hudMat = new THREE.MeshBasicNodeMaterial({
      transparent: true,
      depthTest: false,
      depthWrite: false,
      side: THREE.DoubleSide
    });
    hudMat.colorNode = THREE.TSL.texture(hudTexture);
    hudMat.opacityNode = THREE.TSL.texture(hudTexture).a;

    hudGeo = new THREE.PlaneGeometry(2, 1);
    hudMesh = new THREE.Mesh(hudGeo, hudMat);
    hudMesh.renderOrder = 9999;
    hudMesh.frustumCulled = false;
    markRuntimeOnly(hudMesh);

    if (game.uiCamera) {
      hudMesh.position.set(0, 0, -1);
      game.uiCamera.add(hudMesh);
    } else {
      hudMesh.position.set(0, 0, -1);
      game.camera.add(hudMesh);
    }

    let imgApi = this.erth.asset.image;
    Promise.all([
      loadHudImage(this.getAttribute("hudBgAsset"), imgApi),
      loadHudImage(this.getAttribute("hudSpeedAsset"), imgApi),
      loadHudImage(this.getAttribute("hudShieldAsset"), imgApi)
    ]).then(function(results) {
      bgImg = results[0];
      speedImg = results[1];
      shieldImg = results[2];
    });
  };

  this.update = function(deltaTime) {
    if (!hudCtx) return;

    let w = hudCanvas.width;
    let h = hudCanvas.height;
    let font = this.getAttribute("font") || "BebasNeueRegular, Impact, Arial, sans-serif";
    let speed = erth.store.get("hgl_speed") || 0;
    let speedRatio = erth.store.get("hgl_speedRatio") || 0;
    let shieldRatio = erth.store.get("hgl_shieldRatio");
    if (shieldRatio === undefined || shieldRatio === null) shieldRatio = 1;
    let shield = Math.round(shieldRatio * 100);
    let timeMs = erth.store.get("hgl_time") || 0;
    let lap = erth.store.get("hgl_lap") || "1/3";
    let storeMessage = erth.store.get("hgl_message") || "";

    visible = erth.store.get("hgl_uiHudVisible") !== false;
    hudTime = formatTime(timeMs);
    hudLap = String(lap);

    if (storeMessage && storeMessage !== lastStoreMessage) {
      lastStoreMessage = storeMessage;
      displayMessage(storeMessage);
    } else if (!storeMessage && lastStoreMessage !== "") {
      lastStoreMessage = "";
    }

    drawHud(hudCtx, w, h, speed, speedRatio, shield, shieldRatio, font);
    hudTexture.needsUpdate = true;
  };

  this.onEditorAdded = function() {};
  this.onEditorDispose = function() {};

  this.dispose = function() {
    if (hudMesh && hudMesh.parent) hudMesh.parent.remove(hudMesh);
    if (hudGeo) hudGeo.dispose();
    if (hudMat) hudMat.dispose();
    if (hudTexture) hudTexture.dispose();
    hudCanvas = null;
    hudCtx = null;
    bgImg = null;
    speedImg = null;
    shieldImg = null;
    currentMessage = "";
    previousMessage = "";
  };

