config:
  name: "HGL Ship Controller"
  id: "hgl.shipController"
  author: "HexGL-Port"
  isScript: true
  main: "script.js"
  priority: 0
  version: "1.0.0"
  description: "Faithful port of HexGL ShipControls.js — kinematic ship physics
    with pixel-based collision/height maps, boost pads, shield, and difficulty
    presets."
  tags:
    - gameplay
  inputs:
    hgl_AirBrakeL: { action: true, bindings: [ { keyboard: KeyA }, { keyboard: KeyQ } ] }
    hgl_AirBrakeR: { action: true, bindings: [ { keyboard: KeyD }, { keyboard: KeyE } ] }
  attributes:
    collisionMapAsset:
      name: "Collision Map"
