code: |
  /* HGL Ship Effects — port of ShipEffects.js + Particles.js */

  /* ── Pre-allocated vectors ── */
  let game;
  const _pVel    = new THREE.Vector3(0.5, 0, 0);
  const _pOffset = new THREE.Vector3(-3, -0.3, 0);
  const _pRad    = new THREE.Vector3(0, 0, 1.5);
  const _shipVel = new THREE.Vector3();
  const _tmpV    = new THREE.Vector3();
  const _worldPos = new THREE.Vector3();
  const _lastWorldPos = new THREE.Vector3();
  const _boosterSize = new THREE.Vector3();
  const _boosterBox = new THREE.Box3();

  const pVelS    = _pVel.length();
  const pOffsetS = _pOffset.length();
  const pRadS    = _pRad.length();
  _pVel.normalize();
  _pOffset.normalize();
  _pRad.normalize();

  /* ── Simple particle system (port of bkcore.threejs.Particles) ── */
  function ParticleSystem(opts) {
    this.max = opts.max || 200;
    this.life = opts.life || 60;
    this.size = opts.size || 2;
    this.opacity = opts.opacity !== undefined ? opts.opacity : 1.0;
    this.color1 = new THREE.Color(opts.color || 0xffc000);
    this.color2 = new THREE.Color(opts.color2 || 0xffffff);
    this.randomness = opts.randomness || new THREE.Vector3(0.4, 0.4, 0.4);
    this.friction = opts.friction !== undefined ? opts.friction : 1.0;
    this.blending = opts.blending !== undefined ? opts.blending : THREE.AdditiveBlending;
    this.depthTest = opts.depthTest !== undefined ? opts.depthTest : false;
    this.spawn = (opts.spawn || new THREE.Vector3()).clone();
    this.velocity = (opts.velocity || new THREE.Vector3()).clone();
    this.spawnRadius = (opts.spawnRadius || new THREE.Vector3()).clone();
    this.force = new THREE.Vector3(0, -0.01, 0);

    this.positions = [];
    this.velocities = [];
    this.colors = [];
    this.lives = [];
    this.pool = [];
    this.active = [];
    this.ageing = 1.0 / this.life;

    for (let i = 0; i < this.max; i++) {
      this.positions.push(new THREE.Vector3());
      this.velocities.push(new THREE.Vector3());
      this.colors.push(new THREE.Color());
