code: |
  let game;
  let treeInstances = [];

  const SeededRandom = (seed) => {
    let s = seed;
    return {
      next() { s = (s * 9301 + 49297) % 233280; return s / 233280; },
      nextFloat(min, max) { return min + this.next() * (max - min); },
      nextInt(min, max) { return Math.floor(this.nextFloat(min, max + 1)); }
    };
  }

  this.onEditorAdded = function() {
    // No meaningful preview for scattered trees
  };

  this.onEditorDispose = function() {};

  this.init = async function(_game) {
    game = _game;

    let treeAssets = [
      this.getAttribute("tree1Model"),
      this.getAttribute("tree2Model"),
      this.getAttribute("tree3Model")
    ].filter(Boolean);

    if (treeAssets.length === 0) return;

    let W = this.erth.store.get("vv_W") || 48;
    let D = this.erth.store.get("vv_D") || 48;
    let BS = this.erth.store.get("vv_BS") || 1;
    let count = this.getAttribute("treeCount");
    let rng = SeededRandom(this.getAttribute("treeSeed"));

    let treeData = [];
    for (let i = 0; i < count; i++) {
      let modelIdx = rng.nextInt(0, treeAssets.length - 1);
      let scale = 0.75 + rng.nextFloat(0, 0.5);
      let x = (rng.nextFloat(0, 1) - 0.5) * W * BS * 0.9;
      let z = (rng.nextFloat(0, 1) - 0.5) * D * BS * 0.9;
      treeData.push({ assetRef: treeAssets[modelIdx], scale: scale, x: x, z: z });
    }

    let ctx = this;
    for (let td of treeData) {
      try {
        let instance = await ctx.erth.asset.model.createInstance(td.assetRef);
        if (!instance) continue;
        let threeObj = instance._internal ? instance._internal.three : instance;
        threeObj.traverse(function(n) { if (n.isMesh) n.castShadow = true; });
        instance.scale.setScalar(td.scale);

        ctx.sendEvent("vv_getTerrainHeight", { wx: td.x, wz: td.z });
        let y = ctx.erth.store.get("vv_terrainHeightResult") || 0;

        instance.position.set(td.x, y, td.z);
        if (instance.userData) instance.userData.isRuntimeOnly = true;
        await ctx.erth.scene.addObject(instance, ctx.gameObject);
        treeInstances.push(instance);
      } catch (e) {
        // Tree load failed, skip
      }
    }
  };

  this.dispose = function() {
    for (let tree of treeInstances) {
      let threeObj = tree._internal ? tree._internal.three : tree;
      if (threeObj && threeObj.removeFromParent) threeObj.removeFromParent();
      if (threeObj && threeObj.traverse) {
        threeObj.traverse(function(n) {
          if (n.isMesh) {
            if (n.geometry) n.geometry.dispose();
            if (n.material) {
              if (n.material.map) n.material.map.dispose();
              n.material.dispose();
            }
          }
        });
      }
    }
    treeInstances = [];
  };

