  let game;
  const BLOCK_TYPES = { AIR: 0, GRASS: 1, DIRT: 2, WOOD: 3, ROOF: 4, WATER: 5 };
  const BLOCK_COLORS = { 1: 0x55a630, 2: 0x964b00, 3: 0x654321, 4: 0xdc143c, 5: 0x4682b4 };
  const BLOCK_NAMES = { 1: "Grass", 2: "Dirt", 3: "Wood", 4: "Roof", 5: "Water" };
  const PLACEABLE = [1, 2, 3, 4, 5];

  let W, H, D, BS;
  let data;
  let meshes = {};
  let materials = {};
