  function setBlock(x, y, z, type) {
    if (x < 0 || x >= W || y < 0 || y >= H || z < 0 || z >= D) return;
    data[idx(x, y, z)] = type;
    meshUpdateNeeded = true;
  }

  function getVoxelCoords(wx, wy, wz) {
    return {
      x: Math.floor(wx / BS + W / 2),
      y: Math.floor(wy / BS),
      z: Math.floor(wz / BS + D / 2)
    };
  }

  function getTerrainHeight(wx, wz) {
    let c = getVoxelCoords(wx, 0, wz);
    for (let y = H - 1; y >= 0; y--) {
      if (getBlock(c.x, y, c.z) !== BLOCK_TYPES.AIR) return (y + 1) * BS;
    }
    return 0;
  }

  async function loadGrassTextures(ctx) {
    let colorUrl = await ctx.erth.asset.image.getUrl(ctx.attributes.grassColorTex);
    let roughUrl = await ctx.erth.asset.image.getUrl(ctx.attributes.grassRoughnessTex);
    let aoUrl = await ctx.erth.asset.image.getUrl(ctx.attributes.grassAOTex);
    let normalUrl = await ctx.erth.asset.image.getUrl(ctx.attributes.grassNormalTex);
