    this.erth.store.set("vv_BLOCK_COLORS", JSON.stringify(BLOCK_COLORS));
    this.erth.store.set("vv_BLOCK_NAMES", JSON.stringify(BLOCK_NAMES));
    this.erth.store.set("vv_PLACEABLE", JSON.stringify(PLACEABLE));
    this.erth.store.set("vv_W", W);
    this.erth.store.set("vv_H", H);
    this.erth.store.set("vv_D", D);
    this.erth.store.set("vv_BS", BS);

    makeMaterials();
    makeInstancedMeshes(this);
