    }
  };

  this.update = function(deltaTime) {
    if (meshUpdateNeeded) {
      updateMeshes();
    }
  };

  this.dispose = function() {
    Object.values(meshes).forEach(function(m) {
      m.removeFromParent();
      m.geometry.dispose();
      m.dispose();
    });
    Object.values(materials).forEach(function(m) { m.dispose(); });
    if (grassTextures) {
      Object.values(grassTextures).forEach(function(t) { if (t) t.dispose(); });
    }
    meshes = {};
    materials = {};
  };

