  // Solar System — Planet Orbit Behavior
  // Ported from Planet.tsx / Moon.tsx useFrame loops

  let g;

  let erth;
  let target;
  let game;
  let angle = 0;
  let orbitTargetObj = null;
  let loadedTexture = null;
  let tempVec = null;
  let initialScale = null;
  let targetThree = null;

  this.init = function(_game) {
    game = _game;
    erth = this.erth;
    target = this.gameObject;
    targetThree = this.gameObject._internal.three;
    g = game;
    tempVec = new THREE.Vector3();
    initialScale = targetThree.scale.clone();

    // Random start angle (matches source: Math.random() * Math.PI * 2)
    angle = Math.random() * Math.PI * 2;

    // Set initial position on orbit
    let radius = this.getAttribute("orbitRadius") || 0;
    if (radius > 0) {
      targetThree.position.x = Math.cos(angle) * radius;
      targetThree.position.z = Math.sin(angle) * radius;
    }

    // Resolve orbit target (e.g. "Earth" for Moon)
    let targetName = this.getAttribute("orbitTarget") || "";
    if (targetName) {
      game.scene.traverse(function(child) {
        if (child.name === targetName && !orbitTargetObj) {
          orbitTargetObj = child;
        }
      });
    }

    // Load texture by asset name
    let texName = this.getAttribute("textureName") || "";
    if (texName) {
      this.erth.asset.image.findByName(texName).then(function(ref) {
        if (ref) {
          erth.asset.image.createTexture(ref).then(function(tex) {
            const mesh = targetThree;
            // Match reference color response: albedo textures should be sRGB.
            if ("colorSpace" in tex && THREE.SRGBColorSpace) tex.colorSpace = THREE.SRGBColorSpace;
            if ("encoding" in tex && THREE.sRGBEncoding) tex.encoding = THREE.sRGBEncoding;
            tex.needsUpdate = true;
            if (game && game.renderer && game.renderer.capabilities) {
              tex.anisotropy = Math.max(1, Math.min(8, game.renderer.capabilities.getMaxAnisotropy()));
            }
            mesh.material.map = tex;
            if (mesh.material.roughness !== undefined) mesh.material.roughness = 0.92;
            if (mesh.material.metalness !== undefined) mesh.material.metalness = 0.0;
            mesh.material.needsUpdate = true;
            loadedTexture = tex;
          });
        }
      });
    }
  };

  this.update = function(deltaTime) {
    const dt = Math.min(deltaTime, 0.1);
    let paused = this.erth.store.get("solarPaused");
    let focusedTarget = this.erth.store.get("solarFocusTarget") || "";
    let focusMode = !!focusedTarget;

    let speed = this.erth.store.get("solarSpeed") || 1;
    let orbitSpd = this.getAttribute("orbitSpeed") || 0;
    let rotSpd = this.getAttribute("rotationSpeed") || 0;
    let radius = this.getAttribute("orbitRadius") || 0;

    // Orbital motion: remains stopped while focused/paused.
    if (!paused && radius > 0) {
      angle += dt * orbitSpd * speed * 0.3;

      let cx = 0;
      let cz = 0;
      if (orbitTargetObj) {
        orbitTargetObj.getWorldPosition(tempVec);
        cx = tempVec.x;
        cz = tempVec.z;
      }

      targetThree.position.x = cx + Math.cos(angle) * radius;
      targetThree.position.z = cz + Math.sin(angle) * radius;
    }

    // Self rotation:
    // - normal mode: full speed
    // - focused pause mode: continue at 0.5x for subtle spin
    if (rotSpd > 0) {
      if (!paused) {
        targetThree.rotation.y += dt * rotSpd * speed * 0.5;
      } else if (focusMode) {
        targetThree.rotation.y += dt * rotSpd * speed * 0.25;
      }
