    if (initialScale && targetThree) {
      targetThree.scale.copy(initialScale);
    }
  };

  this.dispose = function() {
    if (loadedTexture) {
      loadedTexture.dispose();
      loadedTexture = null;
    }
    game = null;
    orbitTargetObj = null;
    tempVec = null;
    initialScale = null;
    targetThree = null;
  };

