    if (closeBtnText) closeBtnText.setProperties({ fontSize: sf(16) });
    for (let i = 0; i < rowTextRefs.length; i++) rowTextRefs[i].setProperties({ fontSize: sf(10) });
    if (separator) separator.setProperties({ height: 1, marginTop: sf(2), marginBottom: sf(2) });
    factText.setProperties({ fontSize: sf(9) });
  }

  function buildPanel() {
    panelRef = new UIKit.Container({
      positionType: "absolute",
      positionLeft: "2%",
      positionBottom: "2%",
      width: "22%",
      flexDirection: "column",
      gap: 8,
      padding: 14,
      borderRadius: 18,
      borderWidth: 1,
      borderColor: 0x1b2230,
      backgroundColor: 0x05070d,
      backgroundOpacity: 0.9,
      pointerEvents: "auto",
      zIndex: 100,
      visibility: "hidden"
    });

    let header = new UIKit.Container({
      flexDirection: "row",
      justifyContent: "space-between",
      alignItems: "center",
      width: "100%",
      gap: 8,
      visibility: "visible"
    });

    titleText = new UIKit.Text({
      text: "",
      fontSize: 16,
      fontWeight: "bold",
      color: 0xffffff,
      pointerEvents: "none",
      visibility: "hidden"
    });
    closeBtn = new UIKit.Container({
      width: 32,
      height: 32,
      borderRadius: 16,
      justifyContent: "center",
      alignItems: "center",
      backgroundColor: 0x0f1723,
      backgroundOpacity: 0.8,
      borderWidth: 1,
      borderColor: 0x2e3a51,
      pointerEvents: "auto",
      cursor: "pointer",
      visibility: "hidden",
      onClick: function() {
        if (!store) return;
        store.set("solarClearSelection", true);
      }
    });
    closeBtnText = new UIKit.Text({
      text: "×",
      fontSize: 16,
      color: 0xa9b1bf,
      pointerEvents: "none",
      visibility: "hidden"
    });
    closeBtn.add(closeBtnText);
    header.add(titleText);
    header.add(closeBtn);
    panelRef.add(header);

    rowTextRefs = [];
    const labels = ["Diameter", "Distance", "Temperature", "Moons", "Day length", "Year length"];
    for (let i = 0; i < labels.length; i++) {
      const row = new UIKit.Text({
        text: "",
        fontSize: 10,
        color: 0xf3f5fa,
        pointerEvents: "none",
        visibility: "hidden"
      });
      rowTextRefs.push(row);
      panelRef.add(row);
    }

    separator = new UIKit.Container({
      width: "100%",
      height: 1,
      backgroundColor: 0x242b39,
      backgroundOpacity: 1,
      visibility: "hidden",
      pointerEvents: "none"
    });
    panelRef.add(separator);

    factText = new UIKit.Text({
      text: "",
      fontSize: 9,
      color: 0xa7b0bf,
      pointerEvents: "none",
      visibility: "hidden"
    });
    panelRef.add(factText);
    return panelRef;
  }

  function parseInfoParts(info) {
    const chunks = String(info || "").split("|").map(function(s) { return s.trim(); });
    while (chunks.length < 7) chunks.push("");
    return {
      diameter: chunks[0].replace(/^Diameter:\s*/i, ""),
      distance: chunks[1].replace(/^(Dist|Distance):\s*/i, ""),
      temperature: chunks[2].replace(/^(Temp|Temperature):\s*/i, ""),
      moons: chunks[3].replace(/^Moons:\s*/i, ""),
      dayLength: chunks[4].replace(/^Day:\s*/i, ""),
      yearLength: chunks[5].replace(/^Year:\s*/i, ""),
      funFact: chunks[6]
    };
  }

  function refreshInfo() {
    if (!store || !panelRef || !titleText || !factText) return;
    const selected = store.get("solarSelectedPlanet") || "";
    const info = store.get("solarSelectedPlanetInfo") || "";
    if (!selected) {
      panelRef.setProperties({ visibility: "hidden" });
      titleText.setProperties({ text: "", visibility: "hidden" });
      if (closeBtn) closeBtn.setProperties({ visibility: "hidden" });
      if (closeBtnText) closeBtnText.setProperties({ visibility: "hidden" });
      for (let i = 0; i < rowTextRefs.length; i++) rowTextRefs[i].setProperties({ text: "", visibility: "hidden" });
      if (separator) separator.setProperties({ visibility: "hidden" });
      factText.setProperties({ text: "", visibility: "hidden" });
      lastSelected = "";
      return;
    }
    const accent = PLANET_ACCENT[selected] || 0xffffff;
    const parts = parseInfoParts(info);
    panelRef.setProperties({ borderColor: accent, visibility: "visible" });
    titleText.setProperties({ text: selected, color: 0xffffff, visibility: "visible" });
    if (closeBtn) closeBtn.setProperties({ visibility: "visible" });
    if (closeBtnText) closeBtnText.setProperties({ visibility: "visible" });
    const values = [parts.diameter, parts.distance, parts.temperature, parts.moons, parts.dayLength, parts.yearLength];
    const labels = ["Diameter", "Distance", "Temperature", "Moons", "Day length", "Year length"];
    for (let i = 0; i < rowTextRefs.length; i++) rowTextRefs[i].setProperties({ text: labels[i] + ": " + values[i], visibility: "visible" });
    if (separator) separator.setProperties({ visibility: "visible" });
    factText.setProperties({ text: parts.funFact ? parts.funFact : "", visibility: parts.funFact ? "visible" : "hidden" });
    lastSelected = selected;
  }

  function resetUiState() {
    panelRef = null;
    titleText = null;
    closeBtn = null;
    closeBtnText = null;
    rowTextRefs = [];
    factText = null;
    separator = null;
    lastSelected = "";
    lastViewportW = -1;
  }

  this._buildUIKitContent = function() {
    if (!this._uiRoot) return;
    resetUiState();
    this._uiRoot.add(buildPanel());
    lastViewportW = typeof window !== "undefined" ? window.innerWidth : -1;
    applyResponsiveLayout();
  };

  this.init = function(_game) {
    store = this.erth ? this.erth.store : null;
    this._uikitCtx = uikit.createPlayContext(_game);
    this._uiRoot = uikit.buildRoot(this._uikitCtx);
    this._buildUIKitContent();
    uikit.attach(this, this._uikitCtx);
  };

  this.update = function(deltaTime) {
    if (!this._uiRoot) return;
    uikit.tick(this, deltaTime);
    refreshInfo();
    if (typeof window !== "undefined" && window.innerWidth !== lastViewportW) {
      lastViewportW = window.innerWidth;
      applyResponsiveLayout();
    }
  };

  this.dispose = function() {
    uikit.teardown(this);
    resetUiState();
    store = null;
  };

  this.onEditorAdded = async function(editor) {
    if (!this._uiRoot) {
      this._uikitCtx = await uikit.createEditorContext(editor);
      this._uiRoot = uikit.buildRoot(this._uikitCtx);
      this._buildUIKitContent();
    } else if (!this._uiAttached) {
      this._uikitCtx = await uikit.createEditorContext(editor);
    }
    uikit.attach(this, this._uikitCtx);
  };

  this.onEditorDispose = function() {
    uikit.teardown(this);
    resetUiState();
  };

