  function createPlayContext(g) {
    return {
      kind: "play",
      renderer: (g.app && g.app.renderer) || g.renderer,
      getUICamera: function () { return g.uiCamera; },
      gameLike: g,
    };
  }

  async function createEditorContext(editor) {
    const uiCamera = await editor.ensureUICamera();
    const gameLike = {
      renderer: editor.renderer,
      uiCamera: uiCamera,
      scene: editor.scene,
      app: { renderer: editor.renderer },
    };
    return {
      kind: "editor",
      renderer: editor.renderer,
      getUICamera: function () { return uiCamera; },
      gameLike: gameLike,
    };
  }

  function buildRoot(ctx, properties) {
    const overrides = properties || {};
    const root = new UIKit.Fullscreen(ctx.renderer, {
      pixelSize: overrides.pixelSize !== undefined ? overrides.pixelSize : 0.002,
      pointerEvents: overrides.pointerEvents || "listener",
      visibility: overrides.visibility || "visible",
    });
    root.userData.isRuntimeOnly = true;
    return root;
  }

  function attach(behavior, ctx) {
    if (!behavior._uiRoot) return false;
    if (behavior._uiAttached) return true;
    const uiCamera = ctx.getUICamera();
    if (!uiCamera) return false;
    UIKitPointerEvents.initialize(ctx.gameLike);
    uiCamera.add(behavior._uiRoot);
    UIKitPointerEvents.registerRoot(behavior._uiRoot);
    behavior._uiAttached = true;
    return true;
  }

  function tick(behavior, deltaTime) {
    if (!behavior._uikitCtx) return;
    if (!behavior._uiAttached) attach(behavior, behavior._uikitCtx);
    if (behavior._uiAttached) UIKitPointerEvents.update(deltaTime || 16);
  }

  function teardown(behavior) {
    if (behavior._uiRoot) {
      try { UIKitPointerEvents.unregisterRoot(behavior._uiRoot); } catch (_e) { /* not registered */ }
      if (behavior._uiRoot.parent) behavior._uiRoot.parent.remove(behavior._uiRoot);
      if (behavior._uiRoot.dispose) behavior._uiRoot.dispose();
      behavior._uiRoot = null;
    }
    try { UIKitPointerEvents.deinitialize(); } catch (_e) { /* ignore */ }
    behavior._uiAttached = false;
    behavior._uikitCtx = null;
  }

