code: |-
  @import "uikit-dual-mode" as uikit;

  // Island Defense — Phase 1 MVP
  // Single-behavior UIKit port matching the math-meteors / 2048 pattern.
  // Audio imports declared in stemscript but playback wiring is Phase 2.
  // Dual-mode UIKit helper lives in `imports/uikit-dual-mode.yaml`.

  let game;

  // ─── Layout / colors ────────────────────────────────────────────────────
  const PANEL_W = 260; // right-side test panel width
  const HUD_H = 56; // top HUD strip height
  const GROUND_H_FRAC = 0.34; // ground band as fraction of (screen height - HUD)
  const CASTLE_W = 110;
  const CASTLE_H = 130;
  const CASTLE_MARGIN_X = 90; // distance from screen edge to castle left
  const HP_BAR_H = 8;
  const UNIT_W = 22;
  const UNIT_H = 28;
  const UNIT_HP_BAR_H = 4;
  const UNIT_SPAWN_MARGIN = 70; // distance from castle to spawn point
  const ATTACK_RANGE = 26; // melee engagement distance (px)
  const ATTACK_COOLDOWN_MS = 700;
  const BANNER_FADE_MS = 1800;

  const COLOR_BG = "#1e6091"; // ocean blue
  const COLOR_GROUND = "#c19a6b"; // sandy beige
  const COLOR_BLUE = "#3498db";
  const COLOR_BLUE_DARK = "#1f5f8b";
  const COLOR_RED = "#e74c3c";
  const COLOR_RED_DARK = "#922b21";
  const COLOR_HP_BG = "#2c2c2c";
  const COLOR_HP_GOOD = "#2ecc71";
  const COLOR_HP_WARN = "#f39c12";
  const COLOR_HP_BAD = "#e74c3c";
  const COLOR_PANEL = "#0a1929";
  const COLOR_PANEL_HEADER = "#5dade2";
  const COLOR_BTN = "#34495e";
  const COLOR_BTN_ACTIVE = "#27ae60";
  const COLOR_BTN_HOVER = "#5dade2";
  const COLOR_TEXT_LIGHT = "#ecf0f1";
  const COLOR_TEXT_MUTED = "#95a5a6";

  // ─── Helpers ────────────────────────────────────────────────────────────
  function hpColor(frac) {
      if (frac > 0.6) return COLOR_HP_GOOD;
      if (frac > 0.3) return COLOR_HP_WARN;
      return COLOR_HP_BAD;
  }

  // ─── Behavior lifecycle ─────────────────────────────────────────────────

  this._initState = function () {
      this._castleHPMax = this.getAttribute("castleHP") || 100;
      this._warriorHPBase = this.getAttribute("warriorHP") || 30;
      this._warriorAttack = this.getAttribute("warriorAttack") || 5;
      this._warriorSpeed = this.getAttribute("warriorSpeedPxPerSec") || 30;
      this._aiSpawnEasy = this.getAttribute("aiSpawnEasyMs") || 4000;
      this._aiSpawnMedium = this.getAttribute("aiSpawnMediumMs") || 2500;
      this._aiSpawnHard = this.getAttribute("aiSpawnHardMs") || 1500;
      this._aiHardHpMul = this.getAttribute("aiHardHpMul") || 1.5;
      this._totalRounds = this.getAttribute("totalRounds") || 3;

      this._difficulty = "medium";
      this._round = 0;
      this._battleActive = false;
      this._blueCastleHP = this._castleHPMax;
      this._redCastleHP = this._castleHPMax;
      this._units = [];
      this._aiSpawnTimer = 0;
      this._gameTime = 0;
      this._bannerExpireMs = 0;
      this._bannerActive = false;
      this._gameResult = null;
      this._screenW = 0;
      this._screenH = 0;
      this._battlefieldW = 0;
      this._diffButtons = {};
  };

  // Build the entire UIKit tree (called in both play and editor mode).
  this._buildUIKitContent = function () {
      this._battlefield = new UIKit.Container({
          positionType: "absolute",
          positionTop: 0,
          positionLeft: 0,
          positionBottom: 0,
          positionRight: PANEL_W,
          backgroundColor: COLOR_BG,
          pointerEvents: "none",
          visibility: "visible",
      });
      this._uiRoot.add(this._battlefield);

      this._groundBand = new UIKit.Container({
          positionType: "absolute",
          positionLeft: 0,
          positionRight: 0,
          backgroundColor: COLOR_GROUND,
          pointerEvents: "none",
          visibility: "visible",
      });
      this._battlefield.add(this._groundBand);

      this._buildCastle("blue");
      this._buildCastle("red");
      this._buildHud();
      this._buildTestPanel();
      this._buildBanner();
  };

  this.init = function (_game) {
      game = _game;
      this._initState();
      this._uikitCtx = uikit.createPlayContext(game);
      this._uiRoot = uikit.buildRoot(this._uikitCtx);
      this._buildUIKitContent();
      uikit.attach(this, this._uikitCtx);
  };

  // ─── UI construction: Castle ────────────────────────────────────────────

  this._buildCastle = function (team) {
      const isBlue = team === "blue";
      const main = isBlue ? COLOR_BLUE_DARK : COLOR_RED_DARK;
      const rim = isBlue ? COLOR_BLUE : COLOR_RED;

      const root = new UIKit.Container({
          positionType: "absolute",
          width: CASTLE_W,
          height: CASTLE_H,
          backgroundColor: main,
          borderRadius: 6,
          borderColor: rim,
          borderWidth: 3,
          flexDirection: "column",
          justifyContent: "flex-end",
          alignItems: "center",
          paddingBottom: 8,
          pointerEvents: "none",
          visibility: "visible",
      });
      // Roof crenellations row (3 colored squares on top)
      const roof = new UIKit.Container({
          positionType: "absolute",
          positionTop: -10,
          positionLeft: 0,
          positionRight: 0,
          flexDirection: "row",
          justifyContent: "space-around",
          visibility: "visible",
      });
      for (let i = 0; i < 3; i++) {
          roof.add(
              new UIKit.Container({
                  width: 18,
                  height: 14,
                  backgroundColor: rim,
                  borderRadius: 2,
                  visibility: "visible",
              }),
          );
      }
      root.add(roof);

      // Door
      root.add(
          new UIKit.Container({
              width: 32,
              height: 38,
              backgroundColor: "#2c1810",
              borderRadius: 4,
              borderColor: rim,
              borderWidth: 2,
              visibility: "visible",
          }),
      );

      // HP bar above castle
      const hpRoot = new UIKit.Container({
          positionType: "absolute",
          positionTop: -34,
          positionLeft: -10,
          positionRight: -10,
          height: HP_BAR_H + 12,
          flexDirection: "column",
          visibility: "visible",
      });
      const hpLabel = new UIKit.Text({
          text: (isBlue ? "BLUE" : "RED") + " " + this._castleHPMax + " / " + this._castleHPMax,
          fontSize: 11,
          fontWeight: "bold",
          color: isBlue ? COLOR_BLUE : COLOR_RED,
          textAlign: "center",
          visibility: "visible",
      });
      hpRoot.add(hpLabel);
      const hpTrack = new UIKit.Container({
          width: "100%",
          height: HP_BAR_H,
          backgroundColor: COLOR_HP_BG,
          borderRadius: HP_BAR_H / 2,
          visibility: "visible",
      });
      const hpFill = new UIKit.Container({
          width: "100%",
          height: HP_BAR_H,
          backgroundColor: COLOR_HP_GOOD,
          borderRadius: HP_BAR_H / 2,
          visibility: "visible",
      });
      hpTrack.add(hpFill);
      hpRoot.add(hpTrack);
      root.add(hpRoot);

      this._battlefield.add(root);
      if (isBlue) {
          this._blueCastle = {root: root, hpFill: hpFill, hpLabel: hpLabel};
      } else {
          this._redCastle = {root: root, hpFill: hpFill, hpLabel: hpLabel};
      }
  };

  // ─── UI construction: HUD ───────────────────────────────────────────────

  this._buildHud = function () {
      this._hud = new UIKit.Container({
          positionType: "absolute",
          positionTop: 0,
          positionLeft: 0,
          positionRight: 0,
          height: HUD_H,
          paddingTop: 12,
          paddingLeft: 24,
          paddingRight: 24,
          flexDirection: "row",
          justifyContent: "space-between",
          alignItems: "center",
          pointerEvents: "none",
          visibility: "visible",
      });
      this._battlefield.add(this._hud);

      this._hudBlue = new UIKit.Text({
          text: "BLUE: " + this._castleHPMax,
          fontSize: 22,
          fontWeight: "bold",
          color: COLOR_BLUE,
          visibility: "visible",
      });
      this._hud.add(this._hudBlue);

      this._hudRound = new UIKit.Text({
          text: "Press Start Battle",
          fontSize: 18,
          fontWeight: "bold",
          color: COLOR_TEXT_LIGHT,
          visibility: "visible",
      });
      this._hud.add(this._hudRound);

      this._hudRed = new UIKit.Text({
          text: "RED: " + this._castleHPMax,
          fontSize: 22,
          fontWeight: "bold",
          color: COLOR_RED,
          visibility: "visible",
      });
      this._hud.add(this._hudRed);
  };

  // ─── UI construction: Test Panel ────────────────────────────────────────

  this._buildTestPanel = function () {
      const self = this; // @check-ok
      this._panel = new UIKit.Container({
          positionType: "absolute",
          positionTop: 0,
          positionRight: 0,
          positionBottom: 0,
          width: PANEL_W,
          backgroundColor: COLOR_PANEL,
          paddingTop: 16,
          paddingBottom: 16,
          paddingLeft: 14,
          paddingRight: 14,
          flexDirection: "column",
          gap: 12,
          pointerEvents: "auto",
          visibility: "visible",
      });
      this._uiRoot.add(this._panel);

      // Title
      this._panel.add(
          new UIKit.Text({
              text: "ISLAND DEFENSE",
              fontSize: 18,
              fontWeight: "bold",
              color: COLOR_PANEL_HEADER,
              textAlign: "center",
              visibility: "visible",
          }),
      );
      this._panel.add(
          new UIKit.Text({
              text: "Test Panel",
              fontSize: 11,
              color: COLOR_TEXT_MUTED,
              textAlign: "center",
              visibility: "visible",
          }),
      );

      // Difficulty section
      this._panelSection("Difficulty");
      const diffRow = new UIKit.Container({
          flexDirection: "row",
          gap: 6,
          justifyContent: "space-between",
          visibility: "visible",
      });
      this._panel.add(diffRow);
      this._diffButtons.easy = this._panelButton(diffRow, "Easy", () => self._setDifficulty("easy"), {
          width: 70,
          isSmall: true,
      });
      this._diffButtons.medium = this._panelButton(diffRow, "Medium", () => self._setDifficulty("medium"), {
          width: 70,
          isSmall: true,
      });
      this._diffButtons.hard = this._panelButton(diffRow, "Hard", () => self._setDifficulty("hard"), {
          width: 70,
          isSmall: true,
      });
      this._refreshDifficultyButtons();

      // Battle section
      this._panelSection("Battle");
      this._panelButton(this._panel, "Start Battle", () => self._startBattle(), {color: COLOR_BTN_ACTIVE});

      // Spawn section
      this._panelSection("Spawn Blue Warriors");
      const spawnRow = new UIKit.Container({
          flexDirection: "row",
          gap: 6,
          justifyContent: "space-between",
          visibility: "visible",
      });
      this._panel.add(spawnRow);
      this._panelButton(spawnRow, "+1", () => self._spawnBlueWarriors(1), {width: 70, isSmall: true});
      this._panelButton(spawnRow, "+3", () => self._spawnBlueWarriors(3), {width: 70, isSmall: true});
      this._panelButton(spawnRow, "+5", () => self._spawnBlueWarriors(5), {width: 70, isSmall: true});

      // Banner preview
      this._panelSection("Banner Preview");
      const bannerRow = new UIKit.Container({
          flexDirection: "row",
          gap: 6,
          justifyContent: "space-between",
          visibility: "visible",
      });
      this._panel.add(bannerRow);
      this._panelButton(bannerRow, "R1", () => self._showBanner("Round 1 — Fight!", "#ecf0f1"), {
          width: 70,
          isSmall: true,
      });
      this._panelButton(bannerRow, "R2", () => self._showBanner("Round 2 — Fight!", "#f39c12"), {
          width: 70,
          isSmall: true,
      });
      this._panelButton(bannerRow, "R3", () => self._showBanner("Round 3 — Final!", "#e67e22"), {
          width: 70,
          isSmall: true,
      });

      // End-game
      this._panelSection("End Game");
      const endRow = new UIKit.Container({
          flexDirection: "row",
          gap: 6,
          justifyContent: "space-between",
          visibility: "visible",
      });
      this._panel.add(endRow);
      this._panelButton(endRow, "Victory", () => self._showBanner("VICTORY!", COLOR_HP_GOOD, true), {
          width: 110,
          isSmall: true,
      });
      this._panelButton(endRow, "Defeat", () => self._showBanner("DEFEAT", COLOR_HP_BAD, true), {
          width: 110,
          isSmall: true,
      });

      // Reset
      this._panelSection(" ");
      this._panelButton(this._panel, "Reset Battle", () => self._resetBattle(), {color: "#7f8c8d"});

      // Footer note
      this._panel.add(
          new UIKit.Text({
              text: "Phase 1 MVP: pixel-art sprites,\nanimations, audio playback,\ncamera pan/zoom — see\nisland-defense-todo.md.",
              fontSize: 10,
              color: COLOR_TEXT_MUTED,
              textAlign: "center",
              marginTop: 8,
              visibility: "visible",
          }),
      );
  };

  this._panelSection = function (label) {
      this._panel.add(
          new UIKit.Text({
              text: label,
              fontSize: 12,
              fontWeight: "bold",
              color: COLOR_PANEL_HEADER,
              marginTop: 8,
              visibility: "visible",
          }),
