    for (let i = 0; i < playerIds.length; i++) {
      let pid = playerIds[i];
      let data = remoteData[pid];

      if (!vehicleMeshes[pid]) {
        // Create new vehicle mesh
        let mesh = buildVehicle(data.vehicleName);
        mesh.userData.isRuntimeOnly = true;
        mesh.position.set(data.x, data.y, data.z);
        mesh.rotation.set(data.rx, data.ry, data.rz);
        parentObj.add(mesh);
        vehicleMeshes[pid] = mesh;

        // Create name label
        let label = createNameLabel(data.username);
        label.userData.isRuntimeOnly = true;
        label.position.set(0, LABEL_HEIGHT, 0);
        mesh.add(label);
        nameLabels[pid] = label;

        _tmpVec.set(data.x, data.y, data.z);
        targetPositions[pid] = _tmpVec.clone();
        _tmpEuler.set(data.rx, data.ry, data.rz);
        targetRotations[pid] = _tmpEuler.clone();
      } else {
        // Update targets for interpolation
        targetPositions[pid].set(data.x, data.y, data.z);
        targetRotations[pid].set(data.rx, data.ry, data.rz);
      }
    }

    // Interpolate positions and rotations
    let factor = 1 - Math.exp(-LERP_SPEED * dt);
    let activeIds = Object.keys(vehicleMeshes);
    for (let j = 0; j < activeIds.length; j++) {
      let id = activeIds[j];
      let mesh = vehicleMeshes[id];

      if (!remoteData[id]) {
        // Player left — remove mesh
        parentObj.remove(mesh);
        delete vehicleMeshes[id];
        delete nameLabels[id];
        delete targetPositions[id];
        delete targetRotations[id];
        continue;
      }

      let tp = targetPositions[id];
      let tr = targetRotations[id];
      mesh.position.lerp(tp, factor);
      mesh.rotation.x += (tr.x - mesh.rotation.x) * factor;
      mesh.rotation.y += (tr.y - mesh.rotation.y) * factor;
      mesh.rotation.z += (tr.z - mesh.rotation.z) * factor;
    }
  };

  this.dispose = function() {
    // Remove all vehicle meshes
    let ids = Object.keys(vehicleMeshes);
    for (let i = 0; i < ids.length; i++) {
      if (parentObj) parentObj.remove(vehicleMeshes[ids[i]]);
    }
    vehicleMeshes = {};
    nameLabels = {};
    targetPositions = {};
    targetRotations = {};

    // Dispose all geometries and materials
    for (let g = 0; g < geometries.length; g++) {
      geometries[g].dispose();
    }
    for (let m = 0; m < materials.length; m++) {
      if (materials[m].map) materials[m].map.dispose();
      materials[m].dispose();
    }
    geometries = [];
    materials = [];
  };

  this.onEditorAdded = function() {
    // No editor preview for runtime-only procedural geometry
  };

  this.onEditorDispose = function() {
    // Nothing to clean up in editor
  };

