  description: "100 shootable balloon targets scattered across the world"
  tags:
    - gameplay
  attributes: {}
  documentation: "Spawns 100 balloon targets with spheres and strings. Balloons bob gently. Writes balloon data to fp3_balloons store for collision detection. Listens to fp3_balloonsHit store to hide shot balloons."
code: |
  const SEA_LEVEL = 0;
  const GROUND_LEVEL = 10;
  const BALLOON_COUNT = 100;

  let game;
  let store;
  const disposables = [];
  const balloons = [];
  let lastHitIndices = null;

  function trackGeo(geo) { disposables.push(geo); return geo; }
  function trackMat(mat) { disposables.push(mat); return mat; }

  const BALLOON_COLORS = [
    0xFF0000, 0x00FF00, 0x0000FF, 0xFFFF00,
    0xFF00FF, 0x00FFFF, 0xFF6600, 0xFF0066
  ];

  this.init = function(_game) {
    game = _game;
    store = this.erth.store;

    const sphereGeo = trackGeo(new THREE.SphereGeometry(1, 8, 8));
    const stringGeo = trackGeo(new THREE.CylinderGeometry(0.02, 0.02, 3, 4));
    const stringMat = trackMat(new THREE.MeshStandardNodeMaterial({ color: 0xCCCCCC }));

    const balloonStore = [];

    for (let i = 0; i < BALLOON_COUNT; i++) {
      const color = BALLOON_COLORS[Math.floor(Math.random() * BALLOON_COLORS.length)];
      const mat = trackMat(new THREE.MeshStandardNodeMaterial({ color, transparent: true, opacity: 1.0 }));
      const scale = 0.5 + Math.random() * 1.5;

      const group = new THREE.Group();
      group.userData.isRuntimeOnly = true;

      const sphere = new THREE.Mesh(sphereGeo, mat);
      sphere.scale.setScalar(scale);
      sphere.userData.isRuntimeOnly = true;
      group.add(sphere);

      const string = new THREE.Mesh(stringGeo, stringMat);
      string.position.set(0, -scale - 1.5, 0);
      string.scale.set(1, scale, 1);
      string.userData.isRuntimeOnly = true;
      group.add(string);

      const x = -300 + Math.random() * 600;
      const z = -1000 + Math.random() * 2000;
      const y = GROUND_LEVEL + 5 + Math.random() * 45;

      group.position.set(x, y, z);

      this.gameObject._internal.three.add(group);

      const bData = {
        mesh: group,
        baseY: y,
        phase: Math.random() * Math.PI * 2,
        alive: true,
        radius: scale
      };
      balloons.push(bData);

      balloonStore.push({
        position: { x, y, z },
        radius: scale,
        alive: true
      });
    }

    // Write balloon data for collision detection
    store.set('fp3_balloons', balloonStore);
  };

  this.update = function(deltaTime) {
    if (!game) return;

    // Poll for balloon hit events
    const hitIndices = store.get('fp3_balloonsHit');
    if (hitIndices && hitIndices !== lastHitIndices) {
      lastHitIndices = hitIndices;
      if (Array.isArray(hitIndices)) {
        for (let h = 0; h < hitIndices.length; h++) {
          const idx = hitIndices[h];
          if (idx >= 0 && idx < balloons.length && balloons[idx].alive) {
            balloons[idx].alive = false;
            balloons[idx].mesh.visible = false;
          }
        }
      }
    }

    const time = Date.now() * 0.001;

    for (let i = 0; i < balloons.length; i++) {
      const b = balloons[i];
      if (!b.alive) continue;
      b.mesh.position.y = b.baseY + Math.sin(time + b.phase) * 0.02;
    }
  };

  this.dispose = function() {
    for (const b of balloons) {
      if (b.mesh.parent) b.mesh.parent.remove(b.mesh);
    }
    for (const d of disposables) {
      if (d.dispose) d.dispose();
    }
    disposables.length = 0;
    balloons.length = 0;
  };

  this.onEditorAdded = function() {
    // No editor preview for runtime-only procedural geometry
  };

  this.onEditorDispose = function() {
    // Nothing to clean up in editor
  };

