config:
  name: "FP3 Vehicle Builder"
  id: "fp3.vehicleBuilder"
  author: "fly-pieter-3"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  priority: 0
  description: "Procedurally builds vehicle geometry for 5 vehicle types based on store selection"
  tags:
    - gameplay
  attributes: {}
  documentation: Procedurally builds vehicle geometry for 5 vehicle types (cessna, f16, apache, tank, cyberpink).
    Reads fp3_vehicleName from store, constructs geometry as children of gameObject, and writes stats/parts back to store.

code: |
  let game;
  let group = null;
  let allGeometries = [];
  let allMaterials = [];

  let GROUND_LEVEL = 10;

  function makeMat(color, opts) {
    opts = opts || {};
    let params = { color: color };
    if (opts.transparent) { params.transparent = true; params.opacity = opts.opacity || 1; }
    if (opts.shininess !== undefined) { params.shininess = opts.shininess; }
    if (opts.emissive !== undefined) { params.emissive = opts.emissive; }
    if (opts.emissiveIntensity !== undefined) { params.emissiveIntensity = opts.emissiveIntensity; }
    let mat = new THREE.MeshStandardNodeMaterial(params);
    allMaterials.push(mat);
    return mat;
  }

  function makeGeo(GeoCtor, args) {
    let geo = new (Function.prototype.bind.apply(GeoCtor, [null].concat(args)));
    allGeometries.push(geo);
    return geo;
  }

  function addMesh(parent, geo, mat, pos, rot) {
    let mesh = new THREE.Mesh(geo, mat);
    if (pos) { mesh.position.set(pos[0], pos[1], pos[2]); }
    if (rot) {
      if (rot[0]) mesh.rotation.x = rot[0];
      if (rot[1]) mesh.rotation.y = rot[1];
      if (rot[2]) mesh.rotation.z = rot[2];
    }
    mesh.userData = mesh.userData || {};
    mesh.userData.isRuntimeOnly = true;
    parent.add(mesh);
    return mesh;
  }

  this.init = function(_game) {
    game = _game;
  };

  this.onStart = function() {
    let vehicleName = this.erth.store.get('fp3_vehicleName') || 'cessna';
    this.buildVehicle(vehicleName);
  };

  this.buildVehicle = function(name) {
    group = this.gameObject._internal.three;

    // Hide placeholder mesh
    group.traverse(function(child) {
      if (child.isMesh && child.material) {
        if (Array.isArray(child.material)) {
          child.material.forEach(function(m) { m.visible = false; });
        } else {
          child.material.visible = false;
        }
      }
    });

    let parts = {};
    let stats = {};

    if (name === 'cessna') {
      this.buildCessna(parts);
      stats = { minSpeed: 0, maxSpeed: 2.5, takeoffSpeed: 0.28, speedIncrement: 0.10, rollSpeed: 1.44, maxRoll: Math.PI / 2, yawRate: 5, pitchSpeed: 0.9 };
    } else if (name === 'f16') {
      this.buildF16(parts);
      stats = { minSpeed: 0, maxSpeed: 2.5, takeoffSpeed: 0.28, speedIncrement: 0.02, rollSpeed: 1.44, maxRoll: Math.PI / 2, yawRate: 1, pitchSpeed: 0.9 };
    } else if (name === 'apache') {
      this.buildApache(parts);
      stats = { minSpeed: 0, maxSpeed: 5, takeoffSpeed: 0.28, speedIncrement: 0.15, rollSpeed: 1.44, maxRoll: Math.PI / 2, yawRate: 2, pitchSpeed: 0.9 };
    } else if (name === 'tank') {
      this.buildTank(parts);
      stats = { minSpeed: 0, maxSpeed: 0.2, takeoffSpeed: 0.28, speedIncrement: 0.02, rollSpeed: 1.44, maxRoll: Math.PI / 2, yawRate: 1, pitchSpeed: 0.9 };
    } else if (name === 'cyberpink') {
