    // Tail rotor
    parts.tailRotor = addMesh(group, makeGeo(THREE.BoxGeometry, [1.5, 0.1, 0.2]), rotorMat, [0.4, 0.5, 5.8], null);

    // Stub wings
    addMesh(group, makeGeo(THREE.BoxGeometry, [5, 0.2, 1]), bodyMat, [0, 0.2, 0], null);

    // Hellfire missiles at wing hardpoints
    let missilePositions = [-2, -1, 1, 2];
    for (let i = 0; i < missilePositions.length; i++) {
      addMesh(group, makeGeo(THREE.CylinderGeometry, [0.1, 0.1, 1.2, 8]), missileMat, [missilePositions[i], 0, 0], [Math.PI / 2, 0, 0]);
