  // ─── TANK ────────────────────────────────────────────────
  this.buildTank = function(parts) {
    let bodyMat = makeMat(0x4B5320);
    let trackMat = makeMat(0x1a1a1a);
    let turretMat = makeMat(0x3B4210);

    // Body hull
