    // Turret body
    parts.tankTurret = addMesh(group, makeGeo(THREE.BoxGeometry, [1.8, 1, 2]), turretMat, [0, 1.8, 0], null);

    // Gun barrel
    addMesh(group, makeGeo(THREE.CylinderGeometry, [0.15, 0.15, 3, 8]), turretMat, [0, 1.8, -2.5], [Math.PI / 2, 0, 0]);

    // Front armor plate
    addMesh(group, makeGeo(THREE.BoxGeometry, [3.2, 0.3, 0.8]), bodyMat, [0, 0.8, 1.8], [-Math.PI / 6, 0, 0]);

    // Lower group to ground
    group.position.y = 0.3;
  };

  // ─── CYBERPINK ───────────────────────────────────────────
  this.buildCyberpink = function(parts) {
    let bodyMat = makeMat(0xff69b4, { shininess: 80 });
    let wingMat = makeMat(0xff1493, { shininess: 80 });
    let glassMat = makeMat(0xffb6ed, { transparent: true, opacity: 0.7, shininess: 100 });
    let neonMat = makeMat(0xff69b4, { emissive: 0xff00ff, emissiveIntensity: 0.8 });
    let thrusterMat = makeMat(0xff1493, { emissive: 0xff00ff, emissiveIntensity: 0.5 });

    // Main body
    addMesh(group, makeGeo(THREE.BoxGeometry, [2.5, 1, 5]), bodyMat, null, null);

    // Cab
    addMesh(group, makeGeo(THREE.BoxGeometry, [2.4, 0.8, 2]), bodyMat, [0, 0.8, -0.5], null);

    // Windshield
    addMesh(group, makeGeo(THREE.BoxGeometry, [2.3, 0.7, 0.2]), glassMat, [0, 0.5, -1.5], [-Math.PI / 12, 0, 0]);

    // Wings
    addMesh(group, makeGeo(THREE.BoxGeometry, [8, 0.2, 2]), wingMat, [0, 0, 0], null);

    // Wing tip left
    addMesh(group, makeGeo(THREE.BoxGeometry, [0.2, 0.8, 1.5]), wingMat, [-4, 0.3, 0], null);

    // Wing tip right
    addMesh(group, makeGeo(THREE.BoxGeometry, [0.2, 0.8, 1.5]), wingMat, [4, 0.3, 0], null);

    // Rear stabilizer
    addMesh(group, makeGeo(THREE.BoxGeometry, [2, 0.2, 1]), wingMat, [0, 0.3, 2.5], null);

    // Vertical fin
    addMesh(group, makeGeo(THREE.BoxGeometry, [0.2, 0.8, 1]), wingMat, [0, 0.6, 2.5], null);

    // Thruster left
    addMesh(group, makeGeo(THREE.CylinderGeometry, [0.3, 0.4, 0.5, 8]), thrusterMat, [-1, -0.2, 2.7], [Math.PI / 2, 0, 0]);

    // Thruster right
    addMesh(group, makeGeo(THREE.CylinderGeometry, [0.3, 0.4, 0.5, 8]), thrusterMat, [1, -0.2, 2.7], [Math.PI / 2, 0, 0]);

    // Neon underglow strips
    // Left strip
    addMesh(group, makeGeo(THREE.BoxGeometry, [0.1, 0.05, 4.5]), neonMat, [-1.2, -0.5, 0], null);
    // Right strip
    addMesh(group, makeGeo(THREE.BoxGeometry, [0.1, 0.05, 4.5]), neonMat, [1.2, -0.5, 0], null);
    // Front strip
    addMesh(group, makeGeo(THREE.BoxGeometry, [2.3, 0.05, 0.1]), neonMat, [0, -0.5, -2.4], null);
    // Rear strip
    addMesh(group, makeGeo(THREE.BoxGeometry, [2.3, 0.05, 0.1]), neonMat, [0, -0.5, 2.4], null);
  };

  this.dispose = function() {
    allGeometries.forEach(function(g) { g.dispose(); });
    allMaterials.forEach(function(m) { m.dispose(); });
    allGeometries = [];
    allMaterials = [];
  };

  this.onEditorAdded = function() {
    // No editor preview for runtime-only procedural geometry
  };

  this.onEditorDispose = function() {
    // Nothing to clean up in editor
  };

