    fp3_Digit5: { action: true, bindings: [{ keyboard: Digit5 }] }
code: |
  // ============================================================
  // FP3 Input Controller
  // Captures keyboard, mouse (pointer lock), gamepad, and touch.
  // All state written to erth.store as fp3_inputState object.
  // One-shot toggles written as separate store keys.
  // ============================================================

  let game;
  let store;
  let pointerCanvas;
  let virtualDispatcher;

  // Mouse state
  const MOUSE_TIMEOUT = 2000;
  let mouseX = 0;
  let mouseY = 0;
  let lastMouseMoveTime = 0;
  let isPointerLocked = false;

  // Keyboard state
  let keys = {};

  // Touch state
  let touchX = 0;
  let touchY = 0;
  let touchFire = false;
  let touchTurbo = false;
  let touchActive = false;

  // Gamepad deadzone
  const GP_DEADZONE = 0.15;

  // Event listener references for cleanup (only canvas click for pointer-lock)
  let onClick;
  // Edge-detection state for one-shot keys
  let _kPrev = {};
  let _shiftRightPrev = false;

  function applyDeadzone(val) {
    return Math.abs(val) < GP_DEADZONE ? 0 : val;
  }

  this.init = function(_game) {
    game = _game;
    store = this.erth.store;
    pointerCanvas = game && game.renderer ? game.renderer.domElement : null;

    // Initialize store defaults
    store.set('fp3_inputState', {
      keys: {
        KeyW: false, KeyS: false,
        ArrowUp: false, ArrowDown: false,
        ArrowLeft: false, ArrowRight: false,
        KeyQ: false, KeyE: false,
        Space: false, KeyG: false, KeyB: false,
        ShiftRight: false, KeyV: false, KeyM: false,
        Tab: false, Escape: false
      },
      mouseX: 0,
      mouseY: 0,
      leftJoystickData: { x: 0, y: 0 },
      rightJoystickData: { x: 0, y: 0 },
      lastMouseMoveTime: 0
    });

    // Click on canvas to request pointer lock; rest of input is polled per-frame.
    if (pointerCanvas) {
      onClick = function() {
        if (isPointerLocked) return;
        const req = pointerCanvas.requestPointerLock ||
                    pointerCanvas.mozRequestPointerLock ||
                    pointerCanvas.webkitRequestPointerLock;
        if (req) req.call(pointerCanvas);
      };
      pointerCanvas.addEventListener('click', onClick); // @check-ok pointer lock request
    }

    // --- Touch input via VirtualInputDispatcher ---
    try {
      let im = game.inputManager;
      if (im && im.getVirtualDispatcher) {
        virtualDispatcher = im.getVirtualDispatcher();
        if (virtualDispatcher) {
          virtualDispatcher.setAxisListener("move", function(data) {
            touchX = data.x || 0;
            touchY = data.y || 0;
            if (Math.abs(touchX) > 0.01 || Math.abs(touchY) > 0.01) {
              touchActive = true;
            }
          });
          virtualDispatcher.setAxisListener("look", function(data) {
            // Right joystick: throttle (Y) / yaw (X)
            let rx = data.x || 0;
            let ry = data.y || 0;
            if (Math.abs(rx) > 0.01 || Math.abs(ry) > 0.01) {
              touchActive = true;
            }
          });
          virtualDispatcher.setButtonListener("jump", function(pressed) {
            touchFire = pressed;
            touchActive = true;
          });
          virtualDispatcher.setButtonListener("interact", function(pressed) {
            touchTurbo = pressed;
            touchActive = true;
          });
        }
      }
    } catch (e) {
      // VirtualInputDispatcher not available — touch input disabled
    }
  };

  function pollKeysAndPointer() {
    if (!game || !game.inputManager) return;
    const im = game.inputManager;

    // Held-key map (mirror DOM key codes the rest of the file expects)
    const codeMap = {
      KeyW: 'fp3_KeyW', KeyS: 'fp3_KeyS', KeyQ: 'fp3_KeyQ', KeyE: 'fp3_KeyE',
      KeyG: 'fp3_KeyG', KeyB: 'fp3_KeyB', KeyV: 'fp3_KeyV', KeyM: 'fp3_KeyM',
      ArrowUp: 'fp3_Up', ArrowDown: 'fp3_Down', ArrowLeft: 'fp3_Left', ArrowRight: 'fp3_Right',
      Space: 'fp3_Space', ShiftRight: 'fp3_ShiftR', Tab: 'fp3_Tab', Escape: 'fp3_Escape',
    };
    for (const code in codeMap) {
      keys[code] = !!im.getAction(codeMap[code]);
    }

    // One-shot toggles edge-detected
    function edge(code) {
      const cur = !!keys[code];
      const fired = cur && !_kPrev[code];
      _kPrev[code] = cur;
      return fired;
    }
    if (edge('KeyG')) store.set('fp3_toggleGear', true);
    if (edge('KeyV')) store.set('fp3_toggleCamera', true);
    if (edge('KeyM')) store.set('fp3_toggleMute', true);
    if (edge('Tab')) store.set('fp3_toggleLeaderboard', true);
    if (edge('Escape')) store.set('fp3_togglePause', true);
    if (edge('Space')) store.set('fp3_shootMissile', true);

    // Quick vehicle select 1-5
    const slots = ['fp3_Digit1','fp3_Digit2','fp3_Digit3','fp3_Digit4','fp3_Digit5'];
    for (let i = 0; i < slots.length; i++) {
      const cur = !!im.getAction(slots[i]);
      const k = '_slot' + i;
      if (cur && !_kPrev[k]) store.set('fp3_selectVehicle', i + 1);
      _kPrev[k] = cur;
    }

    // Pointer-lock state + view motion
    isPointerLocked = (typeof document !== "undefined") && document.pointerLockElement === pointerCanvas;
    if (isPointerLocked) {
      const vx = im.getMotion ? (im.getMotion('view_x') || 0) : 0;
      const vy = im.getMotion ? (im.getMotion('view_y') || 0) : 0;
      if (vx !== 0 || vy !== 0) {
        mouseX += vx * 0.002;
        if (mouseX > Math.PI) mouseX -= Math.PI * 2;
        if (mouseX < -Math.PI) mouseX += Math.PI * 2;
        mouseY += vy * 0.002;
        mouseY = Math.max(-Math.PI / 2, Math.min(Math.PI / 2, mouseY));
        lastMouseMoveTime = Date.now();
      }
    }
  }

  this.update = function(deltaTime) {
    if (!store) return;

    pollKeysAndPointer();

    // --- Mouse auto-center ---
    let now = Date.now();
    if (now - lastMouseMoveTime > MOUSE_TIMEOUT) {
      // Smoothly return mouse toward 0
      let decay = 1 - Math.min(deltaTime * 2, 1);
      mouseX *= decay;
      mouseY *= decay;
      if (Math.abs(mouseX) < 0.001) mouseX = 0;
      if (Math.abs(mouseY) < 0.001) mouseY = 0;
    }

    // --- Touch joystick data ---
    let leftJoy = { x: 0, y: 0 };
    let rightJoy = { x: 0, y: 0 };

    // Read touch axes from VirtualInputDispatcher state
    try {
      let im = game.inputManager;
      if (im) {
        let moveX = im.getMotion ? im.getMotion('lateral') : 0;
        let moveY = im.getMotion ? im.getMotion('forward') : 0;
        if (Math.abs(moveX) > 0.01 || Math.abs(moveY) > 0.01) {
          leftJoy.x = moveX; // roll
          leftJoy.y = moveY; // pitch
        }
        let lookX = im.getMotion ? im.getMotion('look') : 0;
        if (Math.abs(lookX) > 0.01) {
          rightJoy.x = lookX; // yaw
        }
      }
    } catch (e) {}

    // --- Gamepad polling ---
    let gp = null;
    try {
      let gamepads = window.navigator.getGamepads ? window.navigator.getGamepads() : []; // @check-ok gamepad API
      for (let i = 0; i < gamepads.length; i++) {
        if (gamepads[i] && gamepads[i].connected) {
          gp = gamepads[i];
          break;
        }
      }
    } catch (e) {}

    if (gp) {
      // Left stick: pitch (Y) / roll (X)
      let lx = gp.axes.length > 0 ? applyDeadzone(gp.axes[0]) : 0;
      let ly = gp.axes.length > 1 ? applyDeadzone(gp.axes[1]) : 0;
      // Right stick: throttle (Y) / yaw (X)
      let rx = gp.axes.length > 2 ? applyDeadzone(gp.axes[2]) : 0;
      let ry = gp.axes.length > 3 ? applyDeadzone(gp.axes[3]) : 0;

      leftJoy.x = lx;
      leftJoy.y = ly;
      rightJoy.x = rx;
      rightJoy.y = ry;

      // A button (index 0) → shoot
      let aPressed = gp.buttons.length > 0 && gp.buttons[0].pressed;
      if (aPressed) store.set('fp3_shootMissile', true);

      // B button (index 1) → toggle gear
      let bPressed = gp.buttons.length > 1 && gp.buttons[1].pressed;
      if (bPressed) store.set('fp3_toggleGear', true);
    }

    // Touch button overrides
    if (touchFire) store.set('fp3_shootMissile', true);
    if (touchTurbo) keys['ShiftRight'] = true;

    // --- Write composite input state to store ---
    store.set('fp3_inputState', {
      keys: {
        KeyW: !!keys['KeyW'],
        KeyS: !!keys['KeyS'],
        ArrowUp: !!keys['ArrowUp'],
        ArrowDown: !!keys['ArrowDown'],
        ArrowLeft: !!keys['ArrowLeft'],
        ArrowRight: !!keys['ArrowRight'],
        KeyQ: !!keys['KeyQ'],
        KeyE: !!keys['KeyE'],
        Space: !!keys['Space'],
        KeyG: !!keys['KeyG'],
        KeyB: !!keys['KeyB'],
        ShiftRight: !!keys['ShiftRight'],
        KeyV: !!keys['KeyV'],
        KeyM: !!keys['KeyM'],
        Tab: !!keys['Tab'],
        Escape: !!keys['Escape']
      },
      mouseX: mouseX,
      mouseY: mouseY,
      leftJoystickData: leftJoy,
      rightJoystickData: rightJoy,
      lastMouseMoveTime: lastMouseMoveTime
    });
  };

  this.dispose = function() {
    if (onClick && pointerCanvas) pointerCanvas.removeEventListener('click', onClick);
    onClick = null;
    _kPrev = {};

    // Exit pointer lock if active
    if (typeof document !== "undefined" && document.exitPointerLock && isPointerLocked) {
      document.exitPointerLock();
    }

    // Clean up VirtualInputDispatcher listeners
    if (virtualDispatcher) {
      try {
        virtualDispatcher.setAxisListener("move", function() {});
        virtualDispatcher.setAxisListener("look", function() {});
        virtualDispatcher.setButtonListener("jump", function() {});
        virtualDispatcher.setButtonListener("interact", function() {});
      } catch (e) {}
      virtualDispatcher = null;
    }
    touchX = 0;
    touchY = 0;
    touchFire = false;
    touchTurbo = false;
    touchActive = false;

    keys = {};
    mouseX = 0;
    mouseY = 0;
    isPointerLocked = false;
  };

