  const BANDS = [
    { minAlt: 50, maxAlt: 100, count: 20, minW: 10, maxW: 30, minH: 3, maxH: 8, minD: 10, maxD: 20, opacity: [0.7, 0.9] },
    { minAlt: 150, maxAlt: 250, count: 15, minW: 20, maxW: 50, minH: 4, maxH: 10, minD: 15, maxD: 30, opacity: [0.5, 0.7] },
    { minAlt: 400, maxAlt: 600, count: 10, minW: 40, maxW: 80, minH: 2, maxH: 5, minD: 30, maxD: 60, opacity: [0.3, 0.5] },
  ];

  const RECYCLE_DIST = 800;
  const SPAWN_RADIUS = 400;

  function rand(min, max) { return min + Math.random() * (max - min); }

  function createCloudGroup(THREE, band) {
    const group = new THREE.Group();
    group.userData.isRuntimeOnly = true;
    const puffCount = 3 + Math.floor(Math.random() * 3); // 3-5
    const opacity = rand(band.opacity[0], band.opacity[1]);
    const mat = trackMat(new THREE.MeshStandardNodeMaterial({
      color: 0xffffff,
      transparent: true,
      opacity: opacity,
      depthWrite: false,
    }));

    for (let i = 0; i < puffCount; i++) {
      const w = rand(band.minW * 0.4, band.maxW * 0.6);
      const h = rand(band.minH * 0.5, band.maxH * 0.7);
      const d = rand(band.minD * 0.4, band.maxD * 0.6);
      const geo = trackGeo(new THREE.BoxGeometry(w, h, d));
      const mesh = new THREE.Mesh(geo, mat);
      mesh.position.set(
        rand(-band.maxW * 0.3, band.maxW * 0.3),
        rand(-h * 0.3, h * 0.3),
        rand(-band.maxD * 0.3, band.maxD * 0.3)
      );
      mesh.userData.isRuntimeOnly = true;
      group.add(mesh);
    }

    group.position.set(
      rand(-SPAWN_RADIUS, SPAWN_RADIUS),
      rand(band.minAlt, band.maxAlt),
      rand(-SPAWN_RADIUS, SPAWN_RADIUS)
    );
    group.userData.band = band;
    return group;
  }

  this.init = function(_game) {
    game = _game;

    cloudContainer = new THREE.Group();
    cloudContainer.userData.isRuntimeOnly = true;

    for (const band of BANDS) {
      for (let i = 0; i < band.count; i++) {
        const cloud = createCloudGroup(THREE, band);
        cloudContainer.add(cloud);
        allClouds.push(cloud);
      }
    }

    this.gameObject._internal.three.add(cloudContainer);
  };

  this.update = function(delta) {
    const store = this.erth.store;
    const playerPos = store.get('fp3_playerPosition');
    if (!playerPos) return;

    const px = playerPos.x || 0;
    const pz = playerPos.z || 0;

    for (let i = 0; i < allClouds.length; i++) {
      const cloud = allClouds[i];
      const dx = cloud.position.x - px;
      const dz = cloud.position.z - pz;
      const dist = Math.sqrt(dx * dx + dz * dz);

      if (dist > RECYCLE_DIST) {
        const band = cloud.userData.band;
        const angle = Math.random() * Math.PI * 2;
        const r = rand(100, SPAWN_RADIUS);
        cloud.position.x = px + Math.cos(angle) * r;
        cloud.position.z = pz + Math.sin(angle) * r;
        cloud.position.y = rand(band.minAlt, band.maxAlt);
      }
    }
  };

  this.dispose = function() {
    if (cloudContainer && cloudContainer.parent) {
      cloudContainer.parent.remove(cloudContainer);
    }
    for (let i = disposables.length - 1; i >= 0; i--) {
      disposables[i].dispose();
    }
    disposables.length = 0;
    allClouds.length = 0;
    cloudContainer = null;
  };

  this.onEditorAdded = function() {
    // No editor preview for runtime-only procedural geometry
  };

  this.onEditorDispose = function() {
    // Nothing to clean up in editor
  };

