config:
  name: "FP3 Camera Controller"
  id: "fp3.cameraController"
  author: "fly-pieter-3"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  priority: 0
  description: "Third-person chase + cockpit camera with dynamic FOV and shadow light follow"
  tags:
    - gameplay
  throttleConfig:
    throttlePriority: "CRITICAL"
    enableFrustumCulling: false
    enableDistanceThrottling: false
    requiresConsistentUpdates: true
  attributes:
    fovSmoothing:
      name: "FOV Smoothing"
      type: "number"
      default: 0.2
      min: 0.01
      max: 1
  documentation: >
    Third-person chase camera and cockpit (first-person) camera with dynamic FOV,
    head bob, head tilt, mouse auto-center, and directional shadow light follow.
    Toggle modes with V key. Configure attributes in the editor to tune gameplay behavior.

code: |
  // ============================================================
  // Fly Pieter 3 — Camera Controller
  // Third-person chase + cockpit camera with dynamic FOV,
  // head bob, head tilt, and shadow light follow.
  // ============================================================

  // ── Constants ───────────────────────────────────────────────
  const GROUND_LEVEL = 10;
  const MOUSE_TIMEOUT = 2000;
  const COCKPIT_OFFSET = new THREE.Vector3(0, 0.3, -1.5);

  const MIN_FOV = 75;
  const MAX_FOV_INCREASE = 5;
  const TURBO_EXTRA_FOV = 5;

  const HEAD_BOB_AMOUNT = 0.05;
  const HEAD_TILT_AMOUNT = -0.05;

  const CHASE_DISTANCE = 10;
  const CHASE_HEIGHT_BASE = 2;
  const CHASE_HEIGHT_RANGE = 5;
  const CHASE_MIN_HEIGHT = 1;
  const CHASE_LERP = 0.1;
  const MOUSE_AUTO_CENTER_LERP = 0.02;

  const LIGHT_OFFSET = new THREE.Vector3(100, 100, 50);

  // ── FOV multiplier per vehicle ──────────────────────────────
  const FOV_SCALE = {
    cessna: 1.0,
    f16: 0.1,
    a10: 0.1,
    cyberpink: 0.1
  };

  // ── Pre-allocated vectors (never allocate in update) ────────
  const _idealOffset = new THREE.Vector3();
  const _cockpitPos = new THREE.Vector3();
  const _lookTarget = new THREE.Vector3();
  const _lightPos = new THREE.Vector3();
  const _lightTargetPos = new THREE.Vector3();

  // ── State ───────────────────────────────────────────────────
  let game;
  let erth;
  let camera;
  let player;
  let sunLight = null;
  let isThirdPerson = true;

  // ── Helpers ─────────────────────────────────────────────────
  function findSunLight() {
    if (sunLight) return sunLight;
    game.scene.traverse(function (child) {
      if (child.isDirectionalLight && !sunLight) {
        sunLight = child;
      }
    });
    return sunLight;
  }

  // ── Lifecycle ───────────────────────────────────────────────

  this.init = function (_game) {
    game = _game;
    erth = this.erth;
    camera = game.camera;
    player = this.gameObject._internal.three;

    // Disable built-in camera controller
    if (game.cameraControl && game.cameraControl.enabled) {
      game.cameraControl.enabled = false;
    }

    // Initialize store
    erth.store.set("fp3_isThirdPerson", true);
    erth.store.set("fp3_showCrosshair", false);
  };

  this.update = function (deltaTime) {
    const dt = Math.min(deltaTime, 0.1);
    if (!player || !camera) return;

    // Wait for vehicle to be ready
    const vehicleReady = erth.store.get("fp3_vehicleReady");
    if (!vehicleReady) return;

    // ── Read shared state ──────────────────────────────────
    const inputState = erth.store.get("fp3_inputState");
    const flightState = erth.store.get("fp3_flightState");
    if (!inputState || !flightState) return;

    const mouseX = inputState.mouseX || 0;
    const mouseY = inputState.mouseY || 0;
    const keys = inputState.keys || {};
    const lastMouseMoveTime = inputState.lastMouseMoveTime || 0;

    const currentSpeed = flightState.speed || 0;
    const vehicleName = flightState.vehicleName || "cessna";
    const minSpeed = flightState.minSpeed || 0;
    const maxSpeed = flightState.maxSpeed || 1;

    const currentTime = Date.now();

    // ── Camera toggle (one-shot from input controller) ─────
    const toggleCamera = erth.store.get("fp3_toggleCamera");
    if (toggleCamera) {
      isThirdPerson = !isThirdPerson;
      erth.store.set("fp3_isThirdPerson", isThirdPerson);
      erth.store.set("fp3_showCrosshair", !isThirdPerson);
      erth.store.set("fp3_toggleCamera", false);
    }

    // ── Mouse auto-center ──────────────────────────────────
    let effectiveMouseX = mouseX;
    let effectiveMouseY = mouseY;

    if (currentTime - lastMouseMoveTime > MOUSE_TIMEOUT) {
      const lerpFactor = MOUSE_AUTO_CENTER_LERP * dt * 60;
      effectiveMouseX += (0 - effectiveMouseX) * lerpFactor;
      effectiveMouseY += (0 - effectiveMouseY) * lerpFactor;
    }

    if (isThirdPerson) {
      // ── Third-Person Chase Camera ────────────────────────
      _idealOffset.set(
        Math.sin(effectiveMouseX) * CHASE_DISTANCE,
        Math.max(CHASE_HEIGHT_BASE + Math.sin(effectiveMouseY) * CHASE_HEIGHT_RANGE, CHASE_MIN_HEIGHT),
        Math.cos(effectiveMouseX) * CHASE_DISTANCE
      );
      _idealOffset.applyMatrix4(player.matrixWorld);

      // Guard: skip if matrix produced non-finite values (prevents NaN infecting camera forever)
      if (!isFinite(_idealOffset.x) || !isFinite(_idealOffset.y) || !isFinite(_idealOffset.z)) {
        return;
      }

      camera.position.lerp(_idealOffset, CHASE_LERP);
      camera.position.y = Math.max(camera.position.y, GROUND_LEVEL + 0.5);

      _lookTarget.copy(player.position);
      _lookTarget.y += 1;
      if (isFinite(_lookTarget.x) && isFinite(_lookTarget.y) && isFinite(_lookTarget.z)) {
        camera.lookAt(_lookTarget);
      }
    } else {
      // ── Cockpit (First Person) Camera ────────────────────
      _cockpitPos.copy(COCKPIT_OFFSET);
      player.localToWorld(_cockpitPos);

      // Guard: skip if player world matrix produced non-finite values
      if (!isFinite(_cockpitPos.x) || !isFinite(_cockpitPos.y) || !isFinite(_cockpitPos.z)) {
        return;
      }

      camera.position.copy(_cockpitPos);
      camera.quaternion.copy(player.quaternion);

      // Head bob based on speed
      const speedFactor = maxSpeed > 0 ? currentSpeed / maxSpeed : 0;
      const bobOffset = Math.sin(currentTime * 0.1 * speedFactor) * HEAD_BOB_AMOUNT * speedFactor;
      camera.position.y += bobOffset;

      // Head tilt during turns
      camera.rotation.z += Math.sin(player.rotation.z) * HEAD_TILT_AMOUNT;
    }

    // ── Dynamic FOV ────────────────────────────────────────
    const speedRange = maxSpeed - minSpeed;
    const speedRatio = speedRange > 0 ? (currentSpeed - minSpeed) / speedRange : 0;
    const fovScale = FOV_SCALE[vehicleName] !== undefined ? FOV_SCALE[vehicleName] : 1.0;
    const baseFovIncrease = speedRatio * MAX_FOV_INCREASE * fovScale;
    const turboFovIncrease = keys["ShiftRight"] ? TURBO_EXTRA_FOV * speedRatio : 0;
    const targetFOV = MIN_FOV + baseFovIncrease + turboFovIncrease;

    const fovSmooth = this.getAttribute("fovSmoothing") || 0.2;
    camera.fov += (targetFOV - camera.fov) * fovSmooth;
    camera.updateProjectionMatrix();

    // ── Shadow light follow ────────────────────────────────
    const light = findSunLight();
    if (light) {
      _lightPos.copy(player.position).add(LIGHT_OFFSET);
      light.position.copy(_lightPos);
      if (light.target) {
        _lightTargetPos.copy(player.position);
        light.target.position.copy(_lightTargetPos);
      }
    }
  };

  this.onStop = function () {
    // Re-enable built-in camera controller on cleanup
    if (game && game.cameraControl) {
      game.cameraControl.enabled = true;
    }
  };

