config:
  priority: 0
  name: "FP3-Fireworks"
  id: "fp3.fireworks"
  author: "fly-pieter-3"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  description: "Random celebratory firework bursts over the runway"
  tags:
    - gameplay
  attributes: {}
  documentation: "Launches firework bursts every 5-10 seconds. Each burst creates 25 small box particles that expand outward and fade. Particles are recycled after fadeout."
code: |
  const SEA_LEVEL = 0;
  const GROUND_LEVEL = 10;
  const PARTICLES_PER_BURST = 25;
  const MAX_BURSTS = 5;

  let game;
  const disposables = [];
  const bursts = [];
  let nextLaunch = 0;
  let particleGeo = null;

  function trackGeo(geo) { disposables.push(geo); return geo; }
  function trackMat(mat) { disposables.push(mat); return mat; }

  const FIREWORK_COLORS = [
    0xFF0000, 0x00FF00, 0x3333FF, 0xFFFF00,
    0xFF00FF, 0x00FFFF, 0xFFAA00, 0xFF3399
  ];

  this.init = function(_game) {
    game = _game;

    particleGeo = trackGeo(new THREE.BoxGeometry(0.3, 0.3, 0.3));
    nextLaunch = 2; // first launch after 2 seconds
  };

  this.update = function(deltaTime) {
    if (!game || !particleGeo) return;
    const dt = Math.min(deltaTime, 0.1);

    nextLaunch -= dt;

    // Launch new burst
    if (nextLaunch <= 0) {
      nextLaunch = 5 + Math.random() * 5;

      // Find a recyclable burst or create new one
      let burst = bursts.find(b => !b.active);
      if (!burst && bursts.length < MAX_BURSTS) {
        burst = {
          active: false,
          particles: [],
          group: new THREE.Group()
        };
        burst.group.userData.isRuntimeOnly = true;
        this.gameObject._internal.three.add(burst.group);

        const color = FIREWORK_COLORS[Math.floor(Math.random() * FIREWORK_COLORS.length)];
        const mat = trackMat(new THREE.MeshStandardNodeMaterial({
          color,
          emissive: color,
          emissiveIntensity: 0.5,
          transparent: true,
          opacity: 1.0
        }));

        for (let i = 0; i < PARTICLES_PER_BURST; i++) {
          const mesh = new THREE.Mesh(particleGeo, mat.clone());
          mesh.userData.isRuntimeOnly = true;
          mesh.visible = false;
          burst.group.add(mesh);
          disposables.push(mesh.material);

          burst.particles.push({
            mesh,
            vx: 0, vy: 0, vz: 0
          });
        }
        bursts.push(burst);
      }

      if (burst) {
        // Position burst
        const bx = -100 + Math.random() * 200;
        const bz = -50 + Math.random() * 100;
        const by = GROUND_LEVEL + 50 + Math.random() * 100;

        const color = FIREWORK_COLORS[Math.floor(Math.random() * FIREWORK_COLORS.length)];

        burst.active = true;
        burst.age = 0;
        burst.group.position.set(bx, by, bz);

        for (const p of burst.particles) {
          p.mesh.visible = true;
          p.mesh.position.set(0, 0, 0);
          p.mesh.material.opacity = 1.0;
          p.mesh.material.color.setHex(color);
          p.mesh.material.emissive.setHex(color);

          // Random direction
          const theta = Math.random() * Math.PI * 2;
          const phi = Math.random() * Math.PI;
          const speed = 5 + Math.random() * 15;
          p.vx = Math.sin(phi) * Math.cos(theta) * speed;
          p.vy = Math.sin(phi) * Math.sin(theta) * speed;
          p.vz = Math.cos(phi) * speed;
        }
      }
    }

    // Update active bursts
    for (const burst of bursts) {
      if (!burst.active) continue;

      burst.age += dt;

      if (burst.age > 3) {
        burst.active = false;
        for (const p of burst.particles) {
          p.mesh.visible = false;
        }
        continue;
      }

      const fadeStart = 1.5;
      for (const p of burst.particles) {
        // Move with drag
        const drag = 0.97;
        p.vx *= drag;
        p.vy *= drag;
        p.vz *= drag;
        p.vy -= 3 * dt; // gravity

        p.mesh.position.x += p.vx * dt;
        p.mesh.position.y += p.vy * dt;
        p.mesh.position.z += p.vz * dt;

        // Fade out
        if (burst.age > fadeStart) {
          const fade = 1 - (burst.age - fadeStart) / (3 - fadeStart);
          p.mesh.material.opacity = Math.max(0, fade);
        }
      }
    }
  };

  this.dispose = function() {
    for (const burst of bursts) {
      if (burst.group.parent) burst.group.parent.remove(burst.group);
    }
    for (const d of disposables) {
      if (d.dispose) d.dispose();
    }
    disposables.length = 0;
    bursts.length = 0;
  };

  this.onEditorAdded = function() {
    // No editor preview for runtime-only procedural geometry
  };

  this.onEditorDispose = function() {
    // Nothing to clean up in editor
  };

