    - ui
  attributes: {}
  documentation: "Fullscreen pause overlay toggled by fp3_togglePause store key. Shows PAUSED title, Resume button (restores playing state and pointer lock), and Toggle Sound button (sets fp3_toggleMute). Hidden by default."
code: |
  // ============================================================
  // FP3 Pause Menu
  // ESC-toggle pause overlay with resume and sound toggle.
  // Reads fp3_togglePause, writes fp3_gameState, fp3_toggleMute.
  // ============================================================

  let game;
  let store;
  let fullscreen = null;
  let rootParented = false;
  let overlay = null;
  let isVisible = false;
  let lastToggleVal = null;

  function parentToCamera() {
    if (rootParented || !fullscreen) return;
    if (game.uiCamera) {
      game.uiCamera.add(fullscreen);
      rootParented = true;
    }
  }

  this.init = function(_game) {
    game = _game;
    store = this.erth.store;
  };

  this.onStart = function() {
    UIKitPointerEvents.initialize(game);

    fullscreen = new UIKit.Fullscreen(game.renderer, { visibility: 'visible' });
    parentToCamera();

    // ── Overlay ──
    overlay = new UIKit.Container({
      width: '100%',
      height: '100%',
      backgroundColor: 'rgba(0,0,0,0.75)',
      flexDirection: 'column',
      justifyContent: 'center',
      alignItems: 'center',
      gap: 24,
      visibility: 'hidden'
    });
    fullscreen.add(overlay);

    // ── Title ──
    let title = new UIKit.Text({
      text: 'PAUSED',
      fontSize: 48,
      fontWeight: 'bold',
      color: '#ffffff',
      visibility: 'visible'
    });
    overlay.add(title);

    // ── Resume button ──
    let resumeBtn = new UIKit.Container({
      width: 200,
      height: 50,
      backgroundColor: '#00aa44',
      borderRadius: 10,
      justifyContent: 'center',
      alignItems: 'center',
      pointerEvents: 'auto',
      cursor: 'pointer',
      visibility: 'visible',
      onClick: function() {
        isVisible = false;
        overlay.setProperties({ visibility: 'hidden' });
        store.set('fp3_gameState', 'playing');

        // Request pointer lock
        let canvas = game.renderer && game.renderer.domElement;
        if (canvas && canvas.requestPointerLock) {
          canvas.requestPointerLock();
        }
      }
    });
    let resumeText = new UIKit.Text({
      text: 'Resume',
      fontSize: 22,
      fontWeight: 'bold',
      color: '#ffffff',
      visibility: 'visible'
    });
    resumeBtn.add(resumeText);
    overlay.add(resumeBtn);

    // ── Toggle Sound button ──
    let soundBtn = new UIKit.Container({
      width: 200,
      height: 50,
      backgroundColor: 'rgba(255,255,255,0.15)',
      borderRadius: 10,
      borderWidth: 1,
      borderColor: 'rgba(255,255,255,0.3)',
      justifyContent: 'center',
      alignItems: 'center',
      pointerEvents: 'auto',
      cursor: 'pointer',
      visibility: 'visible',
      onClick: function() {
        store.set('fp3_toggleMute', true);
      }
    });
    let soundText = new UIKit.Text({
      text: 'Toggle Sound',
      fontSize: 18,
      color: '#ffffff',
      visibility: 'visible'
    });
    soundBtn.add(soundText);
    overlay.add(soundBtn);

    UIKitPointerEvents.registerRoot(fullscreen);
  };

  this.update = function(deltaTime) {
    if (!rootParented) parentToCamera();

    // ── Toggle on store key change ──
    let toggleVal = store.get('fp3_togglePause');
    if (toggleVal !== null && toggleVal !== undefined && toggleVal !== lastToggleVal) {
      lastToggleVal = toggleVal;
      isVisible = !isVisible;

      if (isVisible) {
        overlay.setProperties({ visibility: 'visible' });
        store.set('fp3_gameState', 'paused');

        // Release pointer lock
        if (document.exitPointerLock) {
          document.exitPointerLock();
        }
      } else {
        overlay.setProperties({ visibility: 'hidden' });
        store.set('fp3_gameState', 'playing');

        // Re-acquire pointer lock
        let canvas = game.renderer && game.renderer.domElement;
        if (canvas && canvas.requestPointerLock) {
          canvas.requestPointerLock();
        }
      }
    }

    UIKitPointerEvents.update(deltaTime);
  };

  this.dispose = function() {
    UIKitPointerEvents.unregisterRoot(fullscreen);
    UIKitPointerEvents.deinitialize();
    if (fullscreen && fullscreen.parent) {
      fullscreen.parent.remove(fullscreen);
    }
    fullscreen = null;
    overlay = null;
    game = null;
    store = null;
  };

