config:
  name: FP3 Procedural Audio
  id: fp3.proceduralAudio
  author: fly-pieter-3
  isScript: true
  main: script.js
  version: 1.0.0
  priority: 90
  description: "Generates all game audio procedurally using Web Audio API — engine, wheels, missiles, explosions, gear clunks"
  documentation: "Creates engine sound (sawtooth oscillator), ground roll (filtered noise), missile launch, explosion, air raid siren, and landing gear clunk sounds. All procedural via AudioContext. Adapts engine tone for helicopter vehicles. Defers AudioContext creation to first user interaction."
  tags:
    - audio
    - gameplay
    - effects
  attributes: {}
code: |
  // ============================================================
  // FP3 Procedural Audio
  // All game audio generated via Web Audio API.
  // Reads: fp3_flightState, fp3_toggleMute, fp3_shootMissile,
  //        fp3_createExplosion, fp3_landingGearDown, fp3_vehicleName
  // ============================================================

  let game;

  // --- Audio context and nodes ---
  let audioCtx = null;
  let masterGain = null;

  // Engine sound
  let engineOsc = null;
  let engineGain = null;
  let vibratoOsc = null;
  let vibratoGain = null;

  // Helicopter rotor
  let rotorOsc1 = null;
  let rotorOsc2 = null;
  let rotorGain = null;

  // Ground roll noise
  let groundNoiseSource = null;
  let groundNoiseGain = null;
  let groundNoiseFilter = null;
  let groundNoiseBuffer = null;

  // State
  let isMuted = false;
  let isHelicopter = false;
  let audioStarted = false;
  let previousGearDown = true;
  let startAudioBound = null;

  // --- Pre-allocated ---
  const ENGINE_BASE_FREQ = 80;
  const ENGINE_MAX_FREQ = 200;
  const HELI_BASE_FREQ = 40;
  const HELI_MAX_FREQ = 100;
  const ENGINE_GAIN_BASE = 0.03;
  const RAMP_TIME = 0.05;
  const GROUND_NOISE_FILTER_MIN = 800;
  const GROUND_NOISE_FILTER_MAX = 2000;

  // Guard against NaN/Infinity crashing Web Audio API
  function safeRamp(param, value, time) {
    if (!param || !isFinite(value) || !isFinite(time)) return;
    param.linearRampToValueAtTime(value, time);
  }
  function safeExpRamp(param, value, time) {
    if (!param || !isFinite(value) || !isFinite(time) || value <= 0) return;
    param.exponentialRampToValueAtTime(value, time);
  }

  // --- Noise buffer creation ---
  function createNoiseBuffer(ctx, duration) {
    const sampleRate = ctx.sampleRate;
    const length = sampleRate * duration;
    const buffer = ctx.createBuffer(1, length, sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < length; i++) {
      data[i] = Math.random() * 2 - 1;
    }
    return buffer;
  }

  // --- One-shot sound helpers ---
  function playMissileSound() {
    if (!audioCtx || isMuted) return;
    const now = audioCtx.currentTime;

    // White noise burst
    const noiseSource = audioCtx.createBufferSource();
    noiseSource.buffer = groundNoiseBuffer || createNoiseBuffer(audioCtx, 0.15);
    const noiseGain = audioCtx.createGain();
    noiseGain.gain.setValueAtTime(0.15, now);
    if (Number.isFinite((now + 0.1))) noiseGain.gain.exponentialRampToValueAtTime(0.001, now + 0.1);
    noiseSource.connect(noiseGain);
    noiseGain.connect(masterGain);
    noiseSource.start(now);
    noiseSource.stop(now + 0.12);

    // High-freq oscillator
    const osc = audioCtx.createOscillator();
    osc.type = 'square';
    osc.frequency.setValueAtTime(2000, now);
    if (Number.isFinite((now + 0.1))) osc.frequency.exponentialRampToValueAtTime(400, now + 0.1);
    const oscGain = audioCtx.createGain();
    oscGain.gain.setValueAtTime(0.08, now);
    if (Number.isFinite((now + 0.1))) oscGain.gain.exponentialRampToValueAtTime(0.001, now + 0.1);
    osc.connect(oscGain);
    oscGain.connect(masterGain);
    osc.start(now);
    osc.stop(now + 0.12);
  }

  function playExplosionSound() {
    if (!audioCtx || isMuted) return;
    const now = audioCtx.currentTime;

    // Low frequency noise burst
    const noiseSource = audioCtx.createBufferSource();
    noiseSource.buffer = groundNoiseBuffer || createNoiseBuffer(audioCtx, 0.6);
    const filter = audioCtx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 400;
    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.001, now);
    if (Number.isFinite((now + 0.01))) gain.gain.linearRampToValueAtTime(0.25, now + 0.01);
    if (Number.isFinite((now + 0.5))) gain.gain.exponentialRampToValueAtTime(0.001, now + 0.5);
    noiseSource.connect(filter);
    filter.connect(gain);
    gain.connect(masterGain);
    noiseSource.start(now);
    noiseSource.stop(now + 0.55);

    // Sub bass thump
    const osc = audioCtx.createOscillator();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(60, now);
    if (Number.isFinite((now + 0.3))) osc.frequency.exponentialRampToValueAtTime(20, now + 0.3);
    const oscGain = audioCtx.createGain();
    oscGain.gain.setValueAtTime(0.2, now);
    if (Number.isFinite((now + 0.4))) oscGain.gain.exponentialRampToValueAtTime(0.001, now + 0.4);
    osc.connect(oscGain);
    oscGain.connect(masterGain);
    osc.start(now);
    osc.stop(now + 0.45);
  }

  function playGearClunk() {
    if (!audioCtx || isMuted) return;
    const now = audioCtx.currentTime;

    // Short mechanical clunk — brief noise + low tone
    const noiseSource = audioCtx.createBufferSource();
    noiseSource.buffer = groundNoiseBuffer || createNoiseBuffer(audioCtx, 0.1);
    const filter = audioCtx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = 600;
    filter.Q.value = 2;
    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.12, now);
    if (Number.isFinite((now + 0.08))) gain.gain.exponentialRampToValueAtTime(0.001, now + 0.08);
    noiseSource.connect(filter);
    filter.connect(gain);
    gain.connect(masterGain);
    noiseSource.start(now);
    noiseSource.stop(now + 0.1);

    // Metallic ping
    const osc = audioCtx.createOscillator();
    osc.type = 'triangle';
    osc.frequency.value = 180;
    const oscGain = audioCtx.createGain();
    oscGain.gain.setValueAtTime(0.06, now);
    if (Number.isFinite((now + 0.06))) oscGain.gain.exponentialRampToValueAtTime(0.001, now + 0.06);
    osc.connect(oscGain);
    oscGain.connect(masterGain);
    osc.start(now);
    osc.stop(now + 0.08);
  }

  function playAirRaidSiren() {
    if (!audioCtx || isMuted) return;
    const now = audioCtx.currentTime;
    const duration = 2.0;

    const osc1 = audioCtx.createOscillator();
    osc1.type = 'sawtooth';
    osc1.frequency.setValueAtTime(300, now);
    if (Number.isFinite((now + duration * 0.5))) osc1.frequency.linearRampToValueAtTime(800, now + duration * 0.5);
    if (Number.isFinite((now + duration))) osc1.frequency.linearRampToValueAtTime(300, now + duration);

    const osc2 = audioCtx.createOscillator();
    osc2.type = 'sawtooth';
    osc2.frequency.setValueAtTime(302, now);
    if (Number.isFinite((now + duration * 0.5))) osc2.frequency.linearRampToValueAtTime(804, now + duration * 0.5);
    if (Number.isFinite((now + duration))) osc2.frequency.linearRampToValueAtTime(302, now + duration);

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.001, now);
    if (Number.isFinite((now + 0.2))) gain.gain.linearRampToValueAtTime(0.06, now + 0.2);
    if (Number.isFinite((now + duration - 0.3))) gain.gain.setValueAtTime(0.06, now + duration - 0.3);
    if (Number.isFinite((now + duration))) gain.gain.linearRampToValueAtTime(0.001, now + duration);

    osc1.connect(gain);
    osc2.connect(gain);
    gain.connect(masterGain);
    osc1.start(now);
    osc2.start(now);
    osc1.stop(now + duration + 0.05);
    osc2.stop(now + duration + 0.05);
  }

  // --- Setup persistent audio nodes ---
  function setupEngine() {
    if (isHelicopter) {
      // Helicopter rotor — dual oscillators for blade pass
      rotorOsc1 = audioCtx.createOscillator();
      rotorOsc1.type = 'sawtooth';
      rotorOsc1.frequency.value = HELI_BASE_FREQ;

      rotorOsc2 = audioCtx.createOscillator();
      rotorOsc2.type = 'square';
      rotorOsc2.frequency.value = HELI_BASE_FREQ * 2;

      rotorGain = audioCtx.createGain();
      rotorGain.gain.value = 0;

      rotorOsc1.connect(rotorGain);
      rotorOsc2.connect(rotorGain);
      rotorGain.connect(masterGain);
      rotorOsc1.start();
      rotorOsc2.start();
    } else {
      // Fixed-wing engine — sawtooth + vibrato
      engineOsc = audioCtx.createOscillator();
      engineOsc.type = 'sawtooth';
      engineOsc.frequency.value = ENGINE_BASE_FREQ;

      engineGain = audioCtx.createGain();
      engineGain.gain.value = 0;

      // Vibrato modulation
      vibratoOsc = audioCtx.createOscillator();
      vibratoOsc.type = 'sine';
      vibratoOsc.frequency.value = 5;
      vibratoGain = audioCtx.createGain();
      vibratoGain.gain.value = 3; // subtle freq modulation depth
      vibratoOsc.connect(vibratoGain);
      vibratoGain.connect(engineOsc.frequency);
      vibratoOsc.start();

      engineOsc.connect(engineGain);
      engineGain.connect(masterGain);
      engineOsc.start();
    }
  }

  function setupGroundNoise() {
    groundNoiseBuffer = createNoiseBuffer(audioCtx, 2);

    groundNoiseFilter = audioCtx.createBiquadFilter();
    groundNoiseFilter.type = 'bandpass';
    groundNoiseFilter.frequency.value = GROUND_NOISE_FILTER_MIN;
    groundNoiseFilter.Q.value = 1;

    groundNoiseGain = audioCtx.createGain();
    groundNoiseGain.gain.value = 0;

    groundNoiseFilter.connect(groundNoiseGain);
    groundNoiseGain.connect(masterGain);

    // Start looping noise source
    groundNoiseSource = audioCtx.createBufferSource();
    groundNoiseSource.buffer = groundNoiseBuffer;
    groundNoiseSource.loop = true;
    groundNoiseSource.connect(groundNoiseFilter);
    groundNoiseSource.start();
  }

  function startAudioSystem() {
    if (audioStarted) return;
    audioStarted = true;

    audioCtx = new AudioContext();
    masterGain = audioCtx.createGain();
    masterGain.gain.value = 1;
    masterGain.connect(audioCtx.destination);

    setupEngine();
    setupGroundNoise();
  }

  this.init = function (_game) {
    game = _game;
  };

  this.onStart = function () {
    // Detect vehicle type
    const vehicleName = this.erth.store.get('fp3_vehicleName') || '';
    isHelicopter = vehicleName.toLowerCase().indexOf('heli') >= 0
      || vehicleName.toLowerCase().indexOf('chopper') >= 0;

    // Read initial gear state
    const gearState = this.erth.store.get('fp3_landingGearDown');
    previousGearDown = gearState !== undefined ? gearState : true;

    // AudioContext unlock polled per-frame via InputManager.
    this._primaryPrev = 0;
  };

  this.update = function (deltaTime) {
    // First-interaction unlock for AudioContext (browser autoplay policy)
    if (!audioStarted && game && game.inputManager) {
      const im = game.inputManager;
      const primary = im.getMotion ? (im.getMotion('primary') || 0) : 0;
      const fwd = im.getMotion ? (im.getMotion('forward') || 0) : 0;
      const lat = im.getMotion ? (im.getMotion('lateral') || 0) : 0;
      const jump = !!im.getAction('jump');
      if ((this._primaryPrev <= 0.5 && primary > 0.5) || jump || Math.abs(fwd) > 0.1 || Math.abs(lat) > 0.1) {
        startAudioSystem();
      }
      this._primaryPrev = primary;
    }

    // --- Mute toggle ---
    const toggleMute = this.erth.store.get('fp3_toggleMute');
    if (toggleMute) {
      this.erth.store.delete('fp3_toggleMute');
      isMuted = !isMuted;
      if (masterGain) {
        masterGain.gain.value = isMuted ? 0 : 1;
      }
    }

    if (!audioCtx || isMuted) {
      // Still check one-shot triggers to consume them
      if (this.erth.store.get('fp3_shootMissile')) {
        this.erth.store.delete('fp3_shootMissile');
      }
      if (this.erth.store.get('fp3_createExplosion')) {
        this.erth.store.delete('fp3_createExplosion');
      }
      return;
    }

    const state = this.erth.store.get('fp3_flightState');
    if (!state) return;

    const throttle = state.throttle || 0;
    const speed = state.speed || 0;
    const isAirborne = !!state.isAirborne;
    const engineOn = state.engineOn !== false;
    const now = audioCtx.currentTime;

    // --- Engine sound update ---
    if (engineOn) {
      if (isHelicopter && rotorOsc1 && rotorGain) {
        const targetFreq = HELI_BASE_FREQ + throttle * (HELI_MAX_FREQ - HELI_BASE_FREQ);
        safeRamp(rotorOsc1.frequency, targetFreq, now + RAMP_TIME);
        safeRamp(rotorOsc2.frequency, targetFreq * 2, now + RAMP_TIME);
        const speedFactor = Math.min(1, speed / 2);
        safeRamp(rotorGain.gain,
          ENGINE_GAIN_BASE * 1.5 * Math.max(0.3, speedFactor),
          now + RAMP_TIME
        );
      } else if (engineOsc && engineGain) {
        const targetFreq = ENGINE_BASE_FREQ + throttle * (ENGINE_MAX_FREQ - ENGINE_BASE_FREQ);
        safeRamp(engineOsc.frequency, targetFreq, now + RAMP_TIME);
        const speedFactor = Math.min(1, speed / 2);
        safeRamp(engineGain.gain,
          ENGINE_GAIN_BASE * Math.max(0.15, speedFactor),
          now + RAMP_TIME
        );
      }
    } else {
      // Engine off — silence
      safeRamp(engineGain && engineGain.gain, 0, now + RAMP_TIME);
      safeRamp(rotorGain && rotorGain.gain, 0, now + RAMP_TIME);
    }

    // --- Ground roll noise ---
    if (groundNoiseGain && groundNoiseFilter) {
      if (!isAirborne && speed > 0.1) {
        const speedNorm = Math.min(1, speed / 3);
        safeRamp(groundNoiseGain.gain,
          0.04 * speedNorm,
          now + RAMP_TIME
        );
        safeRamp(groundNoiseFilter.frequency,
          GROUND_NOISE_FILTER_MIN + speedNorm * (GROUND_NOISE_FILTER_MAX - GROUND_NOISE_FILTER_MIN),
          now + RAMP_TIME
        );
      } else {
        safeRamp(groundNoiseGain.gain, 0, now + RAMP_TIME);
      }
    }

    // --- One-shot triggers ---
    if (this.erth.store.get('fp3_shootMissile')) {
      this.erth.store.delete('fp3_shootMissile');
      playMissileSound();
    }

    if (this.erth.store.get('fp3_createExplosion')) {
      this.erth.store.delete('fp3_createExplosion');
      playExplosionSound();
    }

    if (this.erth.store.get('fp3_airRaidSiren')) {
      this.erth.store.delete('fp3_airRaidSiren');
      playAirRaidSiren();
    }

    // --- Landing gear clunk on state change ---
    const gearDown = this.erth.store.get('fp3_landingGearDown');
    if (gearDown !== undefined && gearDown !== previousGearDown) {
      previousGearDown = gearDown;
      playGearClunk();
    }
  };

  this.dispose = function () {
    this._primaryPrev = 0;

    // Stop and disconnect all nodes
    if (engineOsc) { engineOsc.stop(); engineOsc.disconnect(); engineOsc = null; }
    if (engineGain) { engineGain.disconnect(); engineGain = null; }
    if (vibratoOsc) { vibratoOsc.stop(); vibratoOsc.disconnect(); vibratoOsc = null; }
    if (vibratoGain) { vibratoGain.disconnect(); vibratoGain = null; }
    if (rotorOsc1) { rotorOsc1.stop(); rotorOsc1.disconnect(); rotorOsc1 = null; }
    if (rotorOsc2) { rotorOsc2.stop(); rotorOsc2.disconnect(); rotorOsc2 = null; }
    if (rotorGain) { rotorGain.disconnect(); rotorGain = null; }
    if (groundNoiseSource) { groundNoiseSource.stop(); groundNoiseSource.disconnect(); groundNoiseSource = null; }
    if (groundNoiseFilter) { groundNoiseFilter.disconnect(); groundNoiseFilter = null; }
    if (groundNoiseGain) { groundNoiseGain.disconnect(); groundNoiseGain = null; }
    if (masterGain) { masterGain.disconnect(); masterGain = null; }
    if (audioCtx) { audioCtx.close(); audioCtx = null; }

    groundNoiseBuffer = null;
    game = null;
  };

