config:
  name: FP3 Landing Gear
  id: fp3.landingGear
  author: fly-pieter-3
  isScript: true
  main: script.js
  version: 1.0.0
  priority: 50
  description: "Animates landing gear retraction/extension with auto-management on takeoff and landing approach"
  documentation: "Lerps landing gear parts (wheels, struts) between extended and retracted positions. On mobile, auto-retracts on takeoff and auto-extends on landing approach. On desktop, shows one-time tips about the G key. Reads vehicle parts from fp3_vehicleParts store and writes fp3_landingGearDown for physics drag."
  tags:
    - gameplay
    - animation
    - vehicle
  attributes: {}
code: |
  // ============================================================
  // FP3 Landing Gear
  // Animates gear retraction/extension with auto-management.
  // Reads: fp3_toggleGear, fp3_flightState, fp3_vehicleParts,
  //        fp3_vehicleName
  // Writes: fp3_landingGearDown, fp3_combatMessage
  // ============================================================

  let game;

  // --- state ---
  let landingGearDown = true;
  let landingGearTarget = 1; // 1 = extended, 0 = retracted
  const LERP_SPEED = 0.05;
  const GROUND_LEVEL = 0;
  const APPROACH_ALT = GROUND_LEVEL + 15;

  // --- original positions (populated in onStart) ---
  let leftWheelOrigY = -0.6;
  let rightWheelOrigY = -0.6;
  let noseWheelOrigY = -0.6;
  let leftStrutOrigY = -0.35;
  let rightStrutOrigY = -0.35;
  let noseStrutOrigY = -0.35;

  // --- retracted offsets ---
  const RETRACT_OFFSET = 1.0;

  // --- part refs ---
  let leftWheel = null;
  let rightWheel = null;
  let noseWheel = null;
  let leftStrut = null;
  let rightStrut = null;
  let noseStrut = null;
  let hasParts = false;

  // --- auto-management ---
  let wasAirborne = false;
  let reachedCruise = false;
  let shownDesktopGearUpTip = false;
  let shownDesktopGearDownTip = false;
  let isMobile = false;
  let previousGearDown = true;

  this.init = function (_game) {
    game = _game;
  };

  this.onStart = function () {
    isMobile = ('ontouchstart' in document);

    // Read stored vehicle parts
    const parts = this.erth.store.get('fp3_vehicleParts');
    if (parts && parts.landingGear) {
      const gear = parts.landingGear;
      leftWheel = gear.leftWheel || null;
      rightWheel = gear.rightWheel || null;
      noseWheel = gear.noseWheel || null;
      leftStrut = gear.leftStrut || null;
      rightStrut = gear.rightStrut || null;
      noseStrut = gear.noseStrut || null;

      // Store original positions
      if (leftWheel) leftWheelOrigY = leftWheel.position.y;
      if (rightWheel) rightWheelOrigY = rightWheel.position.y;
      if (noseWheel) noseWheelOrigY = noseWheel.position.y;
      if (leftStrut) leftStrutOrigY = leftStrut.position.y;
      if (rightStrut) rightStrutOrigY = rightStrut.position.y;
      if (noseStrut) noseStrutOrigY = noseStrut.position.y;

      hasParts = !!(leftWheel || rightWheel || noseWheel);
    }

    // Initialize store
    this.erth.store.set('fp3_landingGearDown', landingGearDown);
  };

  this.update = function (deltaTime) {
    if (!hasParts) return;

    const flightState = this.erth.store.get('fp3_flightState');
    if (!flightState) return;

    const isAirborne = !!flightState.isAirborne;
    const speed = flightState.speed || 0;
    const altitude = flightState.altitude || 0;

    // --- Manual toggle ---
    const toggleGear = this.erth.store.get('fp3_toggleGear');
    if (toggleGear) {
      this.erth.store.delete('fp3_toggleGear');
      landingGearDown = !landingGearDown;
      landingGearTarget = landingGearDown ? 1 : 0;
      this.erth.store.set('fp3_landingGearDown', landingGearDown);
      this.erth.store.set('fp3_combatMessage', {
        text: landingGearDown ? 'Gear DOWN' : 'Gear UP',
        duration: 2
      });
    }

    // --- Auto-management on takeoff ---
    if (!wasAirborne && isAirborne && landingGearDown) {
      if (isMobile) {
        // Auto retract on mobile
        landingGearDown = false;
        landingGearTarget = 0;
        this.erth.store.set('fp3_landingGearDown', false);
        this.erth.store.set('fp3_combatMessage', {
          text: 'Auto gear UP',
          duration: 2
        });
      } else if (!shownDesktopGearUpTip) {
        shownDesktopGearUpTip = true;
        this.erth.store.set('fp3_combatMessage', {
          text: 'Tip: press G to retract gear (go faster!)',
          duration: 4
        });
      }
    }

    // Track cruise altitude
    if (isAirborne && altitude > APPROACH_ALT + 10) {
      reachedCruise = true;
    }

    // --- Auto-management on landing approach ---
    if (isAirborne && altitude < APPROACH_ALT && !landingGearDown && reachedCruise) {
      if (isMobile) {
        // Auto extend on mobile
        landingGearDown = true;
        landingGearTarget = 1;
        this.erth.store.set('fp3_landingGearDown', true);
        this.erth.store.set('fp3_combatMessage', {
          text: 'Auto gear DOWN',
          duration: 2
        });
        reachedCruise = false;
      } else if (!shownDesktopGearDownTip) {
        shownDesktopGearDownTip = true;
        this.erth.store.set('fp3_combatMessage', {
          text: 'Tip: press G to lower gear',
          duration: 4
        });
      }
    }

    // Reset cruise tracking on landing
    if (!isAirborne) {
      reachedCruise = false;
    }

    wasAirborne = isAirborne;

    // --- Animate gear parts ---
    // Lerp current positions toward target
    const extendedFactor = landingGearTarget;
    const currentFactor = leftWheel
      ? (leftWheel.position.y - (leftWheelOrigY + RETRACT_OFFSET)) / (-RETRACT_OFFSET)
      : extendedFactor;
    const t = currentFactor + (extendedFactor - currentFactor) * LERP_SPEED;

    // Wheels: extended = origY, retracted = origY + RETRACT_OFFSET
    if (leftWheel) leftWheel.position.y = leftWheelOrigY + RETRACT_OFFSET * (1 - t);
    if (rightWheel) rightWheel.position.y = rightWheelOrigY + RETRACT_OFFSET * (1 - t);
    if (noseWheel) noseWheel.position.y = noseWheelOrigY + RETRACT_OFFSET * (1 - t);

    // Struts: extended = origY, retracted = origY + RETRACT_OFFSET
    if (leftStrut) leftStrut.position.y = leftStrutOrigY + RETRACT_OFFSET * (1 - t);
    if (rightStrut) rightStrut.position.y = rightStrutOrigY + RETRACT_OFFSET * (1 - t);
    if (noseStrut) noseStrut.position.y = noseStrutOrigY + RETRACT_OFFSET * (1 - t);

    // --- Sound trigger on gear state change ---
    if (previousGearDown !== landingGearDown) {
      previousGearDown = landingGearDown;
      // Gear sound is handled by FP3-Procedural-Audio via store watch
    }
  };

  this.dispose = function () {
    leftWheel = null;
    rightWheel = null;
    noseWheel = null;
    leftStrut = null;
    rightStrut = null;
    noseStrut = null;
    game = null;
  };

meta:
  tool: StemStudio
