config:
  priority: 0
  name: FP3 Start Screen
  id: fp3.startScreen
  author: fly-pieter-3
  isScript: true
  main: script.js
  version: 1.0.0
  description: "Start screen with username input and vehicle selection grid. Stores fp3_username, fp3_vehicleName, fp3_gameState."
  tags:
    - gameplay
    - ui
  attributes: {}
  documentation: "Fullscreen start screen overlay. Title, subtitle, username input (UIKit.Input), 5 vehicle selection cards (Cessna, F-16, Apache, Tank, Cyberpink) with click selection via UIKitPointerEvents, and a green Start button. Defaults to Cessna and a random callsign. On start, writes fp3_username, fp3_vehicleName, sets fp3_gameState to playing, hides overlay, and requests pointer lock."
code: |
  // ============================================================
  // FP3 Start Screen
  // Username input + vehicle selection + start button.
  // Writes fp3_username, fp3_vehicleName, fp3_gameState.
  // ============================================================

  let game;
  let store;
  let fullscreen = null;
  let rootParented = false;
  let selectedVehicle = 'cessna';
  let vehicleCards = [];
  let usernameInput = null;
  let defaultUsername = 'Pilot_' + String(Math.floor(1000 + Math.random() * 9000));

  let VEHICLES = [
    { name: 'cessna',   label: 'Cessna',   color: '#ffffff', stats: 'SPD:3 ARM:1 AGI:4' },
    { name: 'f16',      label: 'F-16',     color: '#888888', stats: 'SPD:5 ARM:3 AGI:5' },
    { name: 'apache',   label: 'Apache',   color: '#556b2f', stats: 'SPD:2 ARM:5 AGI:3' },
    { name: 'tank',     label: 'Tank',     color: '#556b2f', stats: 'SPD:1 ARM:5 AGI:1' },
    { name: 'cyberpink',label: 'Cyberpink', color: '#ff69b4', stats: 'SPD:4 ARM:2 AGI:5' }
  ];

  function parentToCamera() {
    if (rootParented || !fullscreen) return;
    if (game.uiCamera) {
      game.uiCamera.add(fullscreen);
      rootParented = true;
    }
  }

  function updateCardHighlights() {
    for (let i = 0; i < vehicleCards.length; i++) {
      let card = vehicleCards[i];
      let isSelected = (card.vehicleName === selectedVehicle);
      card.container.setProperties({
        borderColor: isSelected ? '#00ff00' : 'rgba(255,255,255,0.3)',
        borderWidth: isSelected ? 3 : 1
      });
    }
  }

  this.init = function(_game) {
    game = _game;
    store = this.erth.store;
  };

  this.onStart = function() {
    // Initialize pointer events for click handling
    UIKitPointerEvents.initialize(game);

    fullscreen = new UIKit.Fullscreen(game.renderer, { visibility: 'visible' });
    parentToCamera();

    // ── Main overlay container ──
    let overlay = new UIKit.Container({
      width: '100%',
      height: '100%',
      backgroundColor: 'rgba(0,0,0,0.85)',
      flexDirection: 'column',
      justifyContent: 'center',
      alignItems: 'center',
      gap: 20,
      padding: 30,
      visibility: 'visible'
    });
    fullscreen.add(overlay);

    // ── Title ──
    let title = new UIKit.Text({
      text: 'FLY PIETER 3',
      fontSize: 48,
      fontWeight: 'bold',
      color: '#ffffff',
      visibility: 'visible'
    });
    overlay.add(title);

    // ── Subtitle ──
    let subtitle = new UIKit.Text({
      text: 'A multiplayer flight simulator',
      fontSize: 18,
      color: 'rgba(255,255,255,0.6)',
      visibility: 'visible'
    });
    overlay.add(subtitle);

    // ── Username input ──
    let inputRow = new UIKit.Container({
      flexDirection: 'column',
      alignItems: 'center',
      gap: 8,
      visibility: 'visible'
    });
    overlay.add(inputRow);

    let inputLabel = new UIKit.Text({
      text: 'CALLSIGN',
      fontSize: 12,
      color: 'rgba(255,255,255,0.5)',
      fontWeight: 'bold',
      visibility: 'visible'
    });
    inputRow.add(inputLabel);

    usernameInput = new UIKit.Input({
      width: 250,
      height: 36,
      fontSize: 16,
      color: '#ffffff',
      backgroundColor: 'rgba(255,255,255,0.1)',
      borderRadius: 6,
      borderWidth: 1,
      borderColor: 'rgba(255,255,255,0.3)',
      padding: 8,
      placeholder: 'Enter callsign...',
      value: defaultUsername,
      visibility: 'visible'
    });
    inputRow.add(usernameInput);

    // ── Vehicle selection label ──
    let vehicleLabel = new UIKit.Text({
      text: 'SELECT VEHICLE',
      fontSize: 12,
      color: 'rgba(255,255,255,0.5)',
      fontWeight: 'bold',
      visibility: 'visible'
    });
    overlay.add(vehicleLabel);

    // ── Vehicle grid ──
    let vehicleGrid = new UIKit.Container({
      flexDirection: 'row',
      justifyContent: 'center',
      alignItems: 'center',
      gap: 12,
      flexWrap: 'wrap',
      visibility: 'visible'
    });
    overlay.add(vehicleGrid);

    for (let i = 0; i < VEHICLES.length; i++) {
      (function(v) {
        let isSelected = (v.name === selectedVehicle);
        let card = new UIKit.Container({
          width: 120,
          height: 90,
          backgroundColor: 'rgba(255,255,255,0.08)',
          borderRadius: 8,
          borderWidth: isSelected ? 3 : 1,
          borderColor: isSelected ? '#00ff00' : 'rgba(255,255,255,0.3)',
          flexDirection: 'column',
          justifyContent: 'center',
          alignItems: 'center',
          gap: 6,
          padding: 8,
          pointerEvents: 'auto',
          cursor: 'pointer',
          visibility: 'visible',
          onClick: function() {
            selectedVehicle = v.name;
            updateCardHighlights();
          }
        });

        let colorSwatch = new UIKit.Container({
          width: 20,
          height: 20,
          backgroundColor: v.color,
          borderRadius: 10,
          visibility: 'visible'
        });
        card.add(colorSwatch);

        let nameText = new UIKit.Text({
          text: v.label,
          fontSize: 14,
          fontWeight: 'bold',
          color: '#ffffff',
          visibility: 'visible'
        });
        card.add(nameText);

        let statsText = new UIKit.Text({
          text: v.stats,
          fontSize: 9,
          color: 'rgba(255,255,255,0.5)',
          visibility: 'visible'
        });
        card.add(statsText);

        vehicleGrid.add(card);
        vehicleCards.push({ container: card, vehicleName: v.name });
      })(VEHICLES[i]);
    }

    // ── Start button ──
    let startBtn = new UIKit.Container({
      width: 200,
      height: 50,
      backgroundColor: '#00aa44',
      borderRadius: 10,
      justifyContent: 'center',
      alignItems: 'center',
      pointerEvents: 'auto',
      cursor: 'pointer',
      visibility: 'visible',
      onClick: function() {
        let username = defaultUsername;
        if (usernameInput && usernameInput.value && usernameInput.value.trim().length > 0) {
          username = usernameInput.value.trim();
        }
        store.set('fp3_username', username);
        store.set('fp3_vehicleName', selectedVehicle);
        store.set('fp3_gameState', 'playing');

        // Hide overlay
        fullscreen.setProperties({ visibility: 'hidden' });

        // Request pointer lock
        let canvas = game.renderer && game.renderer.domElement;
        if (canvas && canvas.requestPointerLock) {
          canvas.requestPointerLock();
        }
      }
    });
    let startText = new UIKit.Text({
      text: 'START',
      fontSize: 22,
      fontWeight: 'bold',
      color: '#ffffff',
      visibility: 'visible'
    });
    startBtn.add(startText);
    overlay.add(startBtn);

    UIKitPointerEvents.registerRoot(fullscreen);

    // Set initial game state
    store.set('fp3_gameState', 'menu');
  };

  this.update = function(deltaTime) {
    if (!rootParented) parentToCamera();
    UIKitPointerEvents.update(deltaTime);
  };

  this.dispose = function() {
    UIKitPointerEvents.unregisterRoot(fullscreen);
    UIKitPointerEvents.deinitialize();
    if (fullscreen && fullscreen.parent) {
      fullscreen.parent.remove(fullscreen);
    }
    fullscreen = null;
    vehicleCards = [];
    usernameInput = null;
    game = null;
    store = null;
  };

meta:
  tool: StemStudio
  type: behavior
  exportVersion: 1
config:
  priority: 0
  name: "FP3 Flight Physics"
  id: "fp3.flightPhysics"
  author: "fly-pieter-3"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  description: "Throttle-based flight physics with lift, drag, stall, gravity, ground clamping"
  tags:
    - gameplay
  attributes: {}
  documentation: |
    Complete flight physics model ported from fly.pieter.com.
    Reads input from fp3_inputState store key, vehicle config from fp3_vehicleStats,
    and writes computed flight state to fp3_flightState and fp3_playerPosition.
    Handles throttle spool, aerodynamic lift/drag, stall modeling, ground clamping,
    landing detection, and FOV speed effects.
code: |
  // ── Pre-allocated vectors & quaternions (NEVER allocate in update) ──
  let game;

  const _forward = new THREE.Vector3();
  const _up = new THREE.Vector3(0, 1, 0);
  const _velocity = new THREE.Vector3();
  const _moveDir = new THREE.Vector3();
  const _euler = new THREE.Euler(0, 0, 0, 'YXZ');
  const _quat = new THREE.Quaternion();
  const _positionDelta = new THREE.Vector3();

  // ── Physics constants (exact from source) ──
  const MAX_THRUST = 0.005;
  const IDLE_THRUST = 0.0001;
  const DRAG_COEFFICIENT = 0.012;
  const GEAR_DRAG_PENALTY = 0.015;
  const GRAVITY_PITCH_FACTOR = 0.008;
  const GEAR_SHAKE_AMOUNT = 0.015;
  const SPEEDBRAKE_DRAG = 0.03;

  const CL_SLOPE = 0.1;
  const STALL_AOA = 15;
  const STALL_DROP = 0.5;

  const CD_PARASITIC = 0.02;
  const CD_INDUCED_FACTOR = 0.05;

  const CONTROL_AUTHORITY_MIN = 0.3;
  const STALL_SPEED_KMH = 83;

  const GRAVITY_ACCEL = 9.8;
  const PHYSICS_SCALE = 0.015;

  const THROTTLE_RESPONSE = 0.05;
  const rollRecoverySpeed = 0.9;
  const liftFactor = 1.8;
  const gravityFactor = 0.1;
  const minLiftSpeed = 0.2115;

  const SEA_LEVEL = 0;
  const GROUND_LEVEL = 10;

  const normalFOV = 75;
  const MIN_FOV = 75;
  const MAX_FOV_INCREASE = 5;
  const TURBO_EXTRA_FOV = 5;
  const TURBO_SPEED_MULTIPLIER = 5;

  // ── Flight state ──
  let currentSpeed = 0;
  let currentRoll = 0;
  let currentPitch = 0;
  let currentHeading = 0;
  let verticalVelocity = 0;
  let throttle = 0;
  let targetThrottle = 0;
  let engineOn = true;
  let speedbrakesDeployed = false;
  let currentAoA = 0;
  let isAirborne = false;
  let isTurbo = false;

  // ── Pure physics functions ──

  function getLiftCoefficient(aoaDegrees) {
    const absAoA = Math.abs(aoaDegrees);
    if (absAoA <= STALL_AOA) {
      return Math.sign(aoaDegrees || 1) * CL_SLOPE * absAoA;
    } else {
      const stallLift = CL_SLOPE * STALL_AOA;
      const postStallFactor = Math.max(STALL_DROP, 1 - (absAoA - STALL_AOA) * 0.05);
      return Math.sign(aoaDegrees || 1) * stallLift * postStallFactor;
    }
  }

  function getDragCoefficient(liftCoeff) {
    return CD_PARASITIC + CD_INDUCED_FACTOR * liftCoeff * liftCoeff;
  }

  function getControlAuthority(speedKmh) {
    if (speedKmh < 40) {
      return 0.05 + (speedKmh / 40) * 0.15;
    }
    if (speedKmh <= STALL_SPEED_KMH) {
      return 0.2 + ((speedKmh - 40) / (STALL_SPEED_KMH - 40)) * 0.1;
    }
    return Math.min(1.0, CONTROL_AUTHORITY_MIN + (speedKmh - STALL_SPEED_KMH) / 100);
  }

  function getTerrainHeight(x, z) {
    const carrierX = -600;
    const carrierZ = 0;
    if (Math.abs(x - carrierX) <= 25 && Math.abs(z - carrierZ) <= 80) {
      return GROUND_LEVEL;
    }
    if (x < -450) {
      return SEA_LEVEL;
    }
    return GROUND_LEVEL;
  }

  // ── Lifecycle ──

  this.init = function(_game) {
    game = _game;

    currentSpeed = 0;
    currentRoll = 0;
    currentPitch = 0;
    currentHeading = 0;
    verticalVelocity = 0;
    throttle = 0;
    targetThrottle = 0;
    engineOn = true;
    speedbrakesDeployed = false;
    currentAoA = 0;
    isAirborne = false;
    isTurbo = false;
  };

  this.update = function(deltaTime) {
    if (!game) return;

    const store = this.erth.store;
    const player = this.gameObject;

    // ── Guard: wait for vehicle to be ready ──
    const vehicleReady = store.get('fp3_vehicleReady');
    if (!vehicleReady) return;

    // ── Read shared state ──
    const inputState = store.get('fp3_inputState') || {};
    const vehicleStats = store.get('fp3_vehicleStats') || {};
    const vehicleParts = store.get('fp3_vehicleParts') || {};
    const landingGearDown = store.get('fp3_landingGearDown') !== false;

    const vehicleType = vehicleStats.type || 'plane';
    const isTank = vehicleType === 'tank';

    // ── Vehicle stats with defaults ──
    const maxSpeed = vehicleStats.maxSpeed || 3.5;
    const minSpeed = vehicleStats.minSpeed || 0;
    const rollSpeed = vehicleStats.rollSpeed || 0.03;
    const pitchSpeed = vehicleStats.pitchSpeed || 0.02;
    const yawRate = vehicleStats.yawRate || 0.01;
    const pitchMultiplier = vehicleStats.pitchMultiplier || 1;

    // ── Input reading ──
    const keys = inputState.keys || {};
    const joystickX = inputState.joystickX || 0;
    const joystickY = inputState.joystickY || 0;
    const hasJoystick = inputState.hasJoystick || false;

    const dt = Math.min(deltaTime, 0.1);
    const dt60 = dt * 60;

    // ── Rotor animation (apache) ──
    if (vehicleParts.mainRotor) {
      const rotorSpeed = 0.2 + throttle * 0.8;
      vehicleParts.mainRotor.rotation.y += rotorSpeed * dt60 * 0.5;
      if (vehicleParts.mainRotor2) {
        vehicleParts.mainRotor2.rotation.y += rotorSpeed * dt60 * 0.5;
      }
    }
    if (vehicleParts.tailRotor) {
      const rotorSpeed = 0.2 + throttle * 0.8;
      vehicleParts.tailRotor.rotation.z += rotorSpeed * dt60 * 0.8;
    }

    // ── Propeller spin (cessna) ──
    if (vehicleParts.propeller) {
      vehicleParts.propeller.rotation.z += (0.1 + throttle * 0.9) * dt60 * 0.6;
    }

    // ── Tank movement (ground-only, turret rotation) ──
    if (isTank) {
      const tankSpeed = vehicleStats.tankSpeed || 0.05;
      const turnSpeed = vehicleStats.turnSpeed || 0.03;

      if (keys.KeyW || keys.ArrowUp) {
        _forward.set(0, 0, -1).applyQuaternion(player.quaternion);
        player.position.addScaledVector(_forward, tankSpeed * dt60);
      }
      if (keys.KeyS || keys.ArrowDown) {
        _forward.set(0, 0, -1).applyQuaternion(player.quaternion);
        player.position.addScaledVector(_forward, -tankSpeed * dt60 * 0.5);
      }
      if (keys.ArrowLeft || keys.KeyA) {
        player.rotation.y += turnSpeed * dt60;
      }
      if (keys.ArrowRight || keys.KeyD) {
        player.rotation.y -= turnSpeed * dt60;
      }

      // Turret rotation
      if (vehicleParts.turret) {
        if (keys.KeyQ) vehicleParts.turret.rotation.y += 0.02 * dt60;
        if (keys.KeyE) vehicleParts.turret.rotation.y -= 0.02 * dt60;
      }

      // Ground clamp tank
      const terrainY = getTerrainHeight(player.position.x, player.position.z);
      player.position.y = terrainY + 1;

      store.set('fp3_flightState', {
        speed: 0,
        altitude: player.position.y,
        heading: THREE.MathUtils.radToDeg(player.rotation.y) % 360,
        throttle: 0,
        isAirborne: false,
        currentAoA: 0,
        verticalSpeed: 0,
        speedKmh: 0,
        isStalling: false,
        engineOn: true,
        speedbrakesDeployed: false
      });
      store.set('fp3_playerPosition', player.position.clone());
      return;
    }

    // ══════════════════════════════════════════
    //  AIRCRAFT PHYSICS (planes & helicopters)
    // ══════════════════════════════════════════

    const terrainHeight = getTerrainHeight(player.position.x, player.position.z);
    const isOnGround = player.position.y <= terrainHeight + 1.1;

    // ── 1. Throttle control ──
    isTurbo = !!keys.ShiftRight;

    if (keys.KeyW || keys.ArrowUp) {
      targetThrottle = Math.min(targetThrottle + 0.02, isTurbo ? 1.5 : 1.0);
    }
    if (keys.KeyS || keys.ArrowDown) {
      targetThrottle = Math.max(targetThrottle - 0.02, 0);
    }
    if (isTurbo) {
      targetThrottle = Math.max(targetThrottle, 1.0);
    }

    // ── 2. Smooth throttle spool ──
    throttle += (targetThrottle - throttle) * THROTTLE_RESPONSE;

    // ── 3. Thrust ──
    const idleThrust = IDLE_THRUST;
    const thrust = engineOn ? (idleThrust + throttle * (MAX_THRUST - idleThrust)) : 0;

    // ── 4. Speed in km/h for authority calculations ──
    const speedKmh = currentSpeed * 3600;

    // ── 5. Drag ──
    const speedSquared = currentSpeed * currentSpeed;
    let drag = speedSquared * DRAG_COEFFICIENT;
    if (landingGearDown && isAirborne) {
      drag += speedSquared * GEAR_DRAG_PENALTY;
    }
    if (speedbrakesDeployed) {
      drag += speedSquared * SPEEDBRAKE_DRAG;
    }

    // ── 6. Gravity pitch effect ──
    const pitchEffect = isOnGround ? 0 : -Math.sin(currentPitch) * GRAVITY_PITCH_FACTOR;

    // ── 7. Ground friction / braking ──
    if (isOnGround && (keys.KeyB || keys.Space)) {
      drag += currentSpeed * 0.05;
    }

    // ── 8. Net acceleration ──
    const netAccel = (thrust - drag + pitchEffect) * dt60;

    // ── 9. Update speed ──
    currentSpeed += netAccel;
    const effectiveMaxSpeed = isTurbo ? maxSpeed * TURBO_SPEED_MULTIPLIER : maxSpeed;
    currentSpeed = Math.max(minSpeed, Math.min(effectiveMaxSpeed, currentSpeed));

    // ── 10. Control authority ──
    const controlAuth = getControlAuthority(speedKmh);

    // ── 11. Roll control ──
    let rollInput = 0;
    if (keys.ArrowLeft) rollInput = 1;
    if (keys.ArrowRight) rollInput = -1;
    if (hasJoystick && Math.abs(joystickX) > 0.1) {
      rollInput = -joystickX;
    }
    currentRoll += rollInput * rollSpeed * controlAuth * dt60;

    // ── 12. Roll recovery ──
    currentRoll *= (1 - rollRecoverySpeed * dt);

    // Clamp roll
    currentRoll = Math.max(-Math.PI / 2, Math.min(Math.PI / 2, currentRoll));

    // ── 13. Pitch control ──
    let pitchInput = 0;
    if (keys.KeyW || keys.ArrowUp) pitchInput = 0; // W is throttle only
    if (keys.ArrowUp) pitchInput = 1;
    if (keys.ArrowDown) pitchInput = -1;
    // Override: use dedicated pitch keys
    if (keys.ArrowUp && !keys.KeyW) pitchInput = 1;
    if (keys.ArrowDown && !keys.KeyS) pitchInput = -1;
    if (hasJoystick && Math.abs(joystickY) > 0.1) {
      pitchInput = -joystickY;
    }

    const speedPitchMult = Math.min(1, speedKmh / 100) * pitchMultiplier;
    currentPitch += pitchInput * pitchSpeed * controlAuth * speedPitchMult * dt60;

    // Clamp pitch
    currentPitch = Math.max(-Math.PI / 3, Math.min(Math.PI / 3, currentPitch));

    // ── 14. Yaw from roll coupling ──
    const yawFromRoll = Math.sin(currentRoll) * yawRate * controlAuth * dt60;
    currentHeading += yawFromRoll;

    // ── 15. Apply rotation ──
    _euler.set(currentPitch, currentHeading, currentRoll, 'YXZ');
    player.rotation.copy(_euler);

    // ── 16. Forward movement ──
    _forward.set(0, 0, -1);
    _quat.setFromEuler(_euler);
    _forward.applyQuaternion(_quat);

    _positionDelta.copy(_forward).multiplyScalar(currentSpeed * dt60);
    player.position.add(_positionDelta);

    // ── 17. Angle of attack ──
    const pitchDegrees = THREE.MathUtils.radToDeg(currentPitch);
    const horizontalSpeed = Math.sqrt(
      _forward.x * _forward.x * currentSpeed * currentSpeed +
      _forward.z * _forward.z * currentSpeed * currentSpeed
    );
    const flightPathAngle = horizontalSpeed > 0.001
      ? THREE.MathUtils.radToDeg(Math.atan2(verticalVelocity, horizontalSpeed))
      : 0;
    currentAoA = pitchDegrees - flightPathAngle;

    // ── 18. Lift computation ──
    const cl = getLiftCoefficient(currentAoA);
    const liftForce = currentSpeed > minLiftSpeed
      ? cl * speedSquared * liftFactor
      : 0;

    // ── 19. Gravity ──
    const gravity = GRAVITY_ACCEL * PHYSICS_SCALE * gravityFactor * dt;

    // ── 20. Net vertical velocity ──
    verticalVelocity += (liftForce - gravity) * dt;

    // Clamp vertical velocity to prevent runaway values
    verticalVelocity = Math.max(-10, Math.min(10, verticalVelocity));

    // Apply vertical velocity
    player.position.y += verticalVelocity * dt60;

    // ── 21. Ground clamping ──
    if (player.position.y < terrainHeight + 1) {
      player.position.y = terrainHeight + 1;
      verticalVelocity = Math.max(0, verticalVelocity);

      if (isAirborne) {
        // Landing detected
        isAirborne = false;
      }

      // Ground: zero out pitch and roll gradually
      if (currentSpeed < 0.05) {
        currentPitch *= 0.95;
        currentRoll *= 0.95;
      }
    } else {
      isAirborne = true;
    }

    // ── 22. Gear shake ──
    if (landingGearDown && isAirborne && currentSpeed > 0.5) {
      player.position.y += (Math.random() - 0.5) * GEAR_SHAKE_AMOUNT;
    }

    // ── 23. Speedbrake toggle (handled via input, just track state) ──
    if (inputState.speedbrakeToggle) {
      speedbrakesDeployed = !speedbrakesDeployed;
    }

    // ── 24. Engine toggle ──
    if (inputState.engineToggle) {
      engineOn = !engineOn;
      if (!engineOn) {
        targetThrottle = 0;
      }
    }

    // ── 25. Stall detection ──
    const isStalling = isAirborne && speedKmh < STALL_SPEED_KMH && Math.abs(currentAoA) > STALL_AOA;

    // ── 26. FOV update ──
    if (game.camera) {
      const speedRatio = Math.min(currentSpeed / effectiveMaxSpeed, 1);
      let targetFOV = normalFOV + speedRatio * MAX_FOV_INCREASE;
      if (isTurbo) {
        targetFOV += TURBO_EXTRA_FOV;
      }
      targetFOV = Math.max(MIN_FOV, targetFOV);
      game.camera.fov += (targetFOV - game.camera.fov) * 0.05;
      game.camera.updateProjectionMatrix();
    }

    // ── 27. Landing health refuel near runway ──
    if (isOnGround && currentSpeed < 0.1) {
      const nearRunway = player.position.x > -100 && player.position.x < 100
        && player.position.z > -200 && player.position.z < 200;
      if (nearRunway) {
        // Signal refuel/repair via store
        store.set('fp3_landingRefuel', true);
      } else {
        store.set('fp3_landingRefuel', false);
      }
    } else {
      store.set('fp3_landingRefuel', false);
    }

    // ── Safety: reset if position goes non-finite ──
    if (!isFinite(player.position.x) || !isFinite(player.position.y) || !isFinite(player.position.z)) {
      player.position.set(0, GROUND_LEVEL + 1, 0);
      player.rotation.set(0, 0, 0);
      currentSpeed = 0;
      verticalVelocity = 0;
      currentPitch = 0;
      currentRoll = 0;
      throttle = 0;
      targetThrottle = 0;
    }

    // ── 28. Write flight state to store ──
    store.set('fp3_flightState', {
      speed: currentSpeed,
      altitude: player.position.y,
      heading: THREE.MathUtils.radToDeg(currentHeading) % 360,
      throttle: throttle,
      isAirborne: isAirborne,
      currentAoA: currentAoA,
      verticalSpeed: verticalVelocity,
      speedKmh: speedKmh,
      isStalling: isStalling,
      engineOn: engineOn,
      speedbrakesDeployed: speedbrakesDeployed
    });

    store.set('fp3_playerPosition', player.position.clone());
  };

  this.dispose = function() {
    // No geometry/materials/textures created by this behavior.
    // Clear references.
    game = null;
  };

