  documentation: "Renders a complete flight HUD using UIKit. Bottom-left panel shows speed, altitude, throttle bar, and vertical speed. Bottom-right shows health bar. Top-center shows heading compass. Center shows stall/speedbrake/gear warnings. Includes a simplified artificial horizon. Updates at 20Hz for performance."
code: |
  // ============================================================
  // FP3 HUD
  // Full flight heads-up display using UIKit.
  // Reads fp3_flightState and fp3_health from erth.store.
  // ============================================================

  let game;
  let store;
  let fullscreen = null;
  let ui = {};
  let updateTimer = 0;
  let stallFlashTimer = 0;
  let stallVisible = false;
  let MAX_HEALTH = 100;
  let UPDATE_INTERVAL = 0.05; // 20Hz
  let cameraRetryId = null;

  // Cardinal direction helper
  function getCardinal(heading) {
    let h = ((heading % 360) + 360) % 360;
    if (h >= 337.5 || h < 22.5) return 'N';
    if (h >= 22.5 && h < 67.5) return 'NE';
    if (h >= 67.5 && h < 112.5) return 'E';
    if (h >= 112.5 && h < 157.5) return 'SE';
    if (h >= 157.5 && h < 202.5) return 'S';
    if (h >= 202.5 && h < 247.5) return 'SW';
    if (h >= 247.5 && h < 292.5) return 'W';
    return 'NW';
  }

  function getHealthColor(pct) {
    if (pct > 0.6) return '#00cc00';
    if (pct > 0.3) return '#cccc00';
    return '#cc0000';
  }

  this.init = function(_game) {
    game = _game;
    store = this.erth.store;
  };

  this.onStart = function() {
    fullscreen = new UIKit.Fullscreen(game.renderer, { visibility: 'visible' });

    let addToCamera = function() {
