        game.uiCamera.add(fullscreen);
        cameraRetryId = null;
      } else {
        cameraRetryId = setTimeout(addToCamera, 100);
      }
    };
    addToCamera();

    // ── Bottom-left: Flight instruments panel ──
    ui.flightPanel = new UIKit.Container({
      width: 210,
      height: 140,
      backgroundColor: 'rgba(0,0,0,0.6)',
