code: |-
  @import "terrain" as T;
  @import "spherical-math" as S;

  const LOG_TAG = "[tinyskies.globeLandmarks]";

  // Soft circular sprite for the shrine sparkle particle system. See
  // tinyskiesGlobeVegetation.yaml for the same helper (intentionally
  // duplicated rather than @imported because the @import host is asset
  // scripts, and a shared "common-vfx" asset would have to ship as its
  // own @import script — defer to a follow-up if more behaviors need it).
  function buildSoftSpriteTexture() {
    const canvas = document.createElement("canvas"); // @check-ok
    canvas.width = 64;
    canvas.height = 64;
    const ctx = canvas.getContext("2d");
    if (!ctx) return null;
    const grad = ctx.createRadialGradient(32, 32, 0, 32, 32, 32);
    grad.addColorStop(0, "rgba(255,255,255,1)");
    grad.addColorStop(0.4, "rgba(255,255,255,0.6)");
    grad.addColorStop(1, "rgba(255,255,255,0)");
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, 64, 64);
    const tex = new THREE.CanvasTexture(canvas);
    tex.colorSpace = THREE.SRGBColorSpace;
    return tex;
  }

  // -----------------------------------------------------------------
  // Helpers
  // -----------------------------------------------------------------

  function applyRimLight(mat, rimColorHex, intensity, power) {
    const TSL = THREE.TSL;
    const c = new THREE.Color(rimColorHex);
    const viewDir = TSL.normalize(TSL.cameraPosition.sub(TSL.positionWorld));
    // dFdx/dFdy-derived normal — no `normal` attribute needed, so the material compiles cleanly in shadow / AO passes that strip lighting attrs (avoids TSL "Vertex attribute 'normal' not found" warnings that pin frame budget).
    const nW = TSL.normalize(TSL.cross(TSL.dFdx(TSL.positionWorld), TSL.dFdy(TSL.positionWorld)));
    const fresnel = TSL.float(1.0).sub(TSL.dot(viewDir, nW).abs());
    const rim = TSL.vec3(c.r, c.g, c.b)
      .mul(TSL.float(intensity))
      .mul(TSL.pow(fresnel, TSL.float(power)));
    mat.emissiveNode = rim;
    mat.needsUpdate = true;
  }

  function createTeardropGeo() {
    const segments = 10;
    const points = [];
    for (let i = 0; i <= segments; i++) {
      const t = i / segments;
      const r = Math.pow(Math.sin(t * Math.PI), 0.35) * Math.pow(1 - t, 0.5);
      points.push(new THREE.Vector2(r, t));
    }
    const geo = new THREE.LatheGeometry(points, 6);
    const bottomColor = new THREE.Color(0.3, 0.55, 0.2);
    const topColor = new THREE.Color(0.7, 0.92, 0.6);
    const posAttr = geo.attributes.position;
    const colors = new Float32Array(posAttr.count * 3);
    for (let i = 0; i < posAttr.count; i++) {
      const t = Math.max(0, Math.min(1, posAttr.getY(i)));
      const c = bottomColor.clone().lerp(topColor, t);
      const ao = THREE.MathUtils.lerp(0.1, 1.0, Math.min(1, t * 2.0));
      c.multiplyScalar(ao);
      colors[i * 3]     = c.r;
      colors[i * 3 + 1] = c.g;
      colors[i * 3 + 2] = c.b;
    }
    geo.setAttribute("color", new THREE.Float32BufferAttribute(colors, 3));
    return geo;
  }

  // Generic geometry-bucket merge (replaces source's BufferGeometryUtils.mergeGeometries).
  // All inputs share the same vertex layout we synthesize: position + normal + index.
  function mergeGeoBucket(geos) {
    if (geos.length === 0) return null;
    let totalVerts = 0;
    let totalIdx = 0;
    let hasIndex = false;
    for (const g of geos) {
      if (!g.attributes.normal) g.computeVertexNormals();
      totalVerts += g.attributes.position.count;
      if (g.index) { totalIdx += g.index.count; hasIndex = true; }
    }
    const positions = new Float32Array(totalVerts * 3);
    const normals = new Float32Array(totalVerts * 3);
    const indices = hasIndex ? new Uint32Array(totalIdx) : null;
    let vOffset = 0;
    let iOffset = 0;
    for (const g of geos) {
      const pos = g.attributes.position;
      const norm = g.attributes.normal;
      for (let i = 0; i < pos.count; i++) {
        const idx = (vOffset + i) * 3;
        positions[idx]     = pos.getX(i);
        positions[idx + 1] = pos.getY(i);
        positions[idx + 2] = pos.getZ(i);
        normals[idx]     = norm ? norm.getX(i) : 0;
        normals[idx + 1] = norm ? norm.getY(i) : 1;
        normals[idx + 2] = norm ? norm.getZ(i) : 0;
      }
      if (indices && g.index) {
        for (let i = 0; i < g.index.count; i++) indices[iOffset + i] = g.index.getX(i) + vOffset;
        iOffset += g.index.count;
      } else if (indices) {
        // Pad with sequential indices for an unindexed contributor in an indexed bucket.
        for (let i = 0; i < pos.count; i++) indices[iOffset + i] = vOffset + i;
        iOffset += pos.count;
      }
      vOffset += pos.count;
    }
    const merged = new THREE.BufferGeometry();
    merged.setAttribute("position", new THREE.Float32BufferAttribute(positions, 3));
    merged.setAttribute("normal", new THREE.Float32BufferAttribute(normals, 3));
    if (indices) merged.setIndex(new THREE.BufferAttribute(indices, 1));
    for (const g of geos) g.dispose();
    return merged;
  }

  // -----------------------------------------------------------------
  // Stonehenge geometry (source Globe.ts:4357 buildStonehenge)
  // Returns { group, floatingMeshes } — floating meshes get bobbed in update.
  // -----------------------------------------------------------------

  function buildStonehenge(rand) {
    const sarsenMat = new THREE.MeshStandardNodeMaterial({ color: 0x9a9080, flatShading: true, roughness: 0.85, metalness: 0 });
    const lintelMat = new THREE.MeshStandardNodeMaterial({ color: 0xb0a898, flatShading: true, roughness: 0.85, metalness: 0 });
    const altarMat  = new THREE.MeshStandardNodeMaterial({ color: 0x706860, flatShading: true, roughness: 0.85, metalness: 0 });
    applyRimLight(sarsenMat, 0xffe8d0, 0.42, 2.8);
    applyRimLight(lintelMat, 0xfff0dd, 0.4, 2.75);
    applyRimLight(altarMat,  0xd8d0c4, 0.35, 2.85);

    const staticBuckets = { sarsen: [], lintel: [], altar: [] };
    const SC = 2.2;

    const R_OUT = 0.095 * SC, R_IN = 0.056 * SC;
    const OUTER_H = 0.040 * SC, OUTER_W = 0.012 * SC, OUTER_D = 0.010 * SC;
    const INNER_H = 0.054 * SC, INNER_W = 0.014 * SC, INNER_D = 0.012 * SC;
    const LINTEL_H = 0.009 * SC, LINTEL_D = 0.011 * SC;
    const HALF_GAP = 0.009 * SC;
    const OUTER_CHORD = 2 * R_OUT * Math.sin(Math.PI / 10) * 1.08;
    const INNER_LINTEL_W = INNER_W * 2 + HALF_GAP * 2 + 0.004 * SC;

    const outerFallen = []; for (let i = 0; i < 10; i++) outerFallen.push(rand() < 0.28);
    const outerYaw = []; for (let i = 0; i < 10; i++) outerYaw.push((rand() - 0.5) * 0.35);
    const skipLintel = []; for (let i = 0; i < 10; i++) skipLintel.push(rand() < 0.10);
    const innerFallenTri = Math.floor(rand() * 5);
    const innerHasFallen = rand() < 0.45;
    const innerFallenSign = rand() < 0.5 ? -1 : 1;

    const g = new THREE.Group();
    g.userData.isRuntimeOnly = true;
    const floatingMeshes = [];

    const tagFloat = (mesh, baseY) => {
      mesh.userData.isFloating = rand() > 0.35;
      mesh.userData.baseY = baseY;
      mesh.userData.amp = (0.016 + rand() * 0.022) * SC;
      mesh.userData.speed = 0.55 + rand() * 0.55;
      mesh.userData.phase = rand() * Math.PI * 2;
      mesh.userData.tiltX = (rand() - 0.5) * 1.2;
      mesh.userData.tiltZ = (rand() - 0.5) * 1.2;
      if (mesh.userData.isFloating) floatingMeshes.push(mesh);
    };

    // Outer sarsen ring (10 uprights)
    for (let i = 0; i < 10; i++) {
      const a = (i / 10) * Math.PI * 2;
      const px = Math.sin(a) * R_OUT;
      const pz = Math.cos(a) * R_OUT;
      if (outerFallen[i]) {
        const geo = new THREE.BoxGeometry(OUTER_W, OUTER_H, OUTER_D);
        geo.translate(0, OUTER_H / 2, 0);
        geo.rotateX(Math.PI / 2);
        geo.translate(0, OUTER_D / 2, 0);
        geo.rotateY(a + outerYaw[i]);
        geo.translate(px, 0, pz);
        staticBuckets.sarsen.push(geo);
      } else {
        const geo = new THREE.BoxGeometry(OUTER_W, OUTER_H, OUTER_D);
        const mesh = new THREE.Mesh(geo, sarsenMat);
        mesh.position.set(px, OUTER_H / 2, pz);
        mesh.userData.isRuntimeOnly = true;
        tagFloat(mesh, OUTER_H / 2);
        g.add(mesh);
      }
    }
    // Outer lintels
    for (let i = 0; i < 10; i++) {
      const j = (i + 1) % 10;
      if (outerFallen[i] || outerFallen[j] || skipLintel[i]) continue;
      const midA = ((i + 0.5) / 10) * Math.PI * 2;
      const baseY = OUTER_H + LINTEL_H / 2;
      const geo = new THREE.BoxGeometry(OUTER_CHORD, LINTEL_H, LINTEL_D);
      const mesh = new THREE.Mesh(geo, lintelMat);
      mesh.rotation.y = midA;
      mesh.position.set(Math.sin(midA) * R_OUT, baseY, Math.cos(midA) * R_OUT);
      mesh.userData.isRuntimeOnly = true;
      tagFloat(mesh, baseY);
      g.add(mesh);
    }
    // Inner horseshoe — 5 trilithons
    for (let i = 0; i < 5; i++) {
      const a = -Math.PI * 0.8 + (i / 4) * Math.PI * 1.6;
      const rx = Math.sin(a) * R_IN;
      const rz = Math.cos(a) * R_IN;
      const tx = Math.cos(a);
      const tz = -Math.sin(a);
      const thisFallen = innerHasFallen && i === innerFallenTri;
      for (const sign of [-1, 1]) {
        const px = rx + tx * sign * HALF_GAP;
        const pz = rz + tz * sign * HALF_GAP;
        if (thisFallen && sign === innerFallenSign) {
          const geo = new THREE.BoxGeometry(INNER_W, INNER_H, INNER_D);
          geo.translate(0, INNER_H / 2, 0);
          geo.rotateX(Math.PI / 2);
          geo.translate(0, INNER_D / 2, 0);
          geo.rotateY(a + Math.PI);
          geo.translate(px, 0, pz);
          staticBuckets.sarsen.push(geo);
        } else {
          const geo = new THREE.BoxGeometry(INNER_W, INNER_H, INNER_D);
          const mesh = new THREE.Mesh(geo, sarsenMat);
          mesh.position.set(px, INNER_H / 2, pz);
          mesh.userData.isRuntimeOnly = true;
          tagFloat(mesh, INNER_H / 2);
          g.add(mesh);
        }
      }
      if (!thisFallen) {
        const baseY = INNER_H + LINTEL_H / 2;
        const geo = new THREE.BoxGeometry(INNER_LINTEL_W, LINTEL_H, LINTEL_D);
        const mesh = new THREE.Mesh(geo, lintelMat);
        mesh.rotation.y = a;
        mesh.position.set(rx, baseY, rz);
        mesh.userData.isRuntimeOnly = true;
        tagFloat(mesh, baseY);
        g.add(mesh);
      }
    }
    // Altar
    {
      const baseY = 0.0025 * SC;
      const geo = new THREE.BoxGeometry(0.022 * SC, 0.005 * SC, 0.013 * SC);
      const mesh = new THREE.Mesh(geo, altarMat);
      mesh.position.set(0, baseY, 0);
      mesh.userData.isRuntimeOnly = true;
      tagFloat(mesh, baseY);
      g.add(mesh);
    }
    // Heel stone
    {
      const baseY = OUTER_H * 0.43;
      const geo = new THREE.CylinderGeometry(0.005 * SC, 0.008 * SC, OUTER_H * 0.85, 5);
      const mesh = new THREE.Mesh(geo, altarMat);
      mesh.rotation.z = 0.13;
      mesh.position.set(0, baseY, R_OUT + 0.032 * SC);
      mesh.userData.isRuntimeOnly = true;
      tagFloat(mesh, baseY);
      g.add(mesh);
    }
    // Merge static (fallen / ground) geometry per material
    const mats = { sarsen: sarsenMat, lintel: lintelMat, altar: altarMat };
    for (const key of Object.keys(staticBuckets)) {
      const merged = mergeGeoBucket(staticBuckets[key]);
      if (merged) {
        const mesh = new THREE.Mesh(merged, mats[key]);
        mesh.userData.isRuntimeOnly = true;
        g.add(mesh);
      }
    }
    return { group: g, floatingMeshes };
  }

  // -----------------------------------------------------------------
  // Observatory geometry (source Globe.ts:4529 buildObservatory)
  // -----------------------------------------------------------------

  function buildObservatory(rand) {
    const stoneMat   = new THREE.MeshStandardNodeMaterial({ color: 0xd0c8b8, flatShading: true, roughness: 0.8, metalness: 0 });
    const stoneDkMat = new THREE.MeshStandardNodeMaterial({ color: 0xa89880, flatShading: true, roughness: 0.85, metalness: 0 });
    const domeMat    = new THREE.MeshStandardNodeMaterial({ color: 0xb0b8c4, flatShading: true, roughness: 0.5, metalness: 0.05 });
    const slitMat    = new THREE.MeshStandardNodeMaterial({ color: 0x333340, flatShading: true });
    const windowMat  = new THREE.MeshStandardNodeMaterial({ color: 0x5a90b8, flatShading: true });
    const frameMat   = new THREE.MeshStandardNodeMaterial({ color: 0x555555, flatShading: true });
    const doorMat    = new THREE.MeshStandardNodeMaterial({ color: 0x5a4030, flatShading: true });
    const stepMat    = new THREE.MeshStandardNodeMaterial({ color: 0xb8b0a0, flatShading: true });
    const finderMat  = new THREE.MeshStandardNodeMaterial({ color: 0x777777, flatShading: true });
    applyRimLight(stoneMat,   0xc8d8f0, 0.42, 2.65);
    applyRimLight(stoneDkMat, 0xb8c8e0, 0.38, 2.7);
    applyRimLight(domeMat,    0xd0e0f8, 0.48, 2.4);
    applyRimLight(slitMat,    0x8899aa, 0.22, 3.2);
    applyRimLight(windowMat,  0x88c8f8, 0.45, 2.5);
    applyRimLight(frameMat,   0xccd0dd, 0.35, 2.8);
    applyRimLight(doorMat,    0xffccb8, 0.32, 2.75);
    applyRimLight(stepMat,    0xd8d0c8, 0.36, 2.65);
    applyRimLight(finderMat,  0xccd0dd, 0.38, 2.7);

    const buckets = { stone: [], stoneDk: [], dome: [], slit: [], window: [], frame: [], door: [], step: [], finder: [] };
    const SC = 2.5;

    const foundW = 0.115 * SC, foundD = 0.095 * SC, foundH = 0.05 * SC;
    const foundGeo = new THREE.BoxGeometry(foundW, foundH, foundD);
    foundGeo.translate(0, -foundH / 2, 0);
    buckets.stone.push(foundGeo);

    const corniceGeo = new THREE.BoxGeometry(foundW + 0.005 * SC, 0.004 * SC, foundD + 0.005 * SC);
    corniceGeo.translate(0, 0.002 * SC, 0);
    buckets.stoneDk.push(corniceGeo);

    const baseW = 0.12 * SC, baseD = 0.10 * SC, baseH = 0.03 * SC;
    const baseGeo = new THREE.BoxGeometry(baseW, baseH, baseD);
    baseGeo.translate(0, baseH / 2, 0);
    buckets.stone.push(baseGeo);

    const pillarW = 0.018 * SC;
    for (const dx of [-1, 1]) for (const dz of [-1, 1]) {
      const pillar = new THREE.BoxGeometry(pillarW, baseH + 0.004 * SC, pillarW);
      pillar.translate(dx * (baseW / 2), baseH / 2, dz * (baseD / 2));
      buckets.stoneDk.push(pillar);
    }

    const stairW = 0.03 * SC;
    for (let i = 0; i < 3; i++) {
      const step = new THREE.BoxGeometry(stairW, 0.004 * SC, 0.008 * SC);
      step.translate(0, 0.002 * SC + i * 0.004 * SC, baseD / 2 + 0.015 * SC - i * 0.006 * SC);
      buckets.step.push(step);
    }

    const roofGeo = new THREE.BoxGeometry(baseW + 0.01 * SC, 0.003 * SC, baseD + 0.01 * SC);
    roofGeo.translate(0, baseH + 0.0015 * SC, 0);
    buckets.stoneDk.push(roofGeo);

    const railH = 0.008 * SC, railT = 0.002 * SC;
    for (const dz of [-1, 1]) {
      const rail = new THREE.BoxGeometry(baseW + 0.01 * SC, railH, railT);
      rail.translate(0, baseH + 0.003 * SC + railH / 2, dz * (baseD / 2 + 0.004 * SC));
      buckets.frame.push(rail);
    }
    for (const dx of [-1, 1]) {
      const rail = new THREE.BoxGeometry(railT, railH, baseD + 0.01 * SC);
      rail.translate(dx * (baseW / 2 + 0.004 * SC), baseH + 0.003 * SC + railH / 2, 0);
      buckets.frame.push(rail);
    }

    const doorW = 0.018 * SC, doorH = 0.022 * SC;
    const doorGeo = new THREE.BoxGeometry(doorW, doorH, 0.004 * SC);
    doorGeo.translate(0, doorH / 2 + 0.012 * SC, baseD / 2 + 0.001 * SC);
    buckets.door.push(doorGeo);
    const dFrameGeo = new THREE.BoxGeometry(doorW + 0.004 * SC, doorH + 0.002 * SC, 0.002 * SC);
    dFrameGeo.translate(0, doorH / 2 + 0.013 * SC, baseD / 2 + 0.002 * SC);
    buckets.frame.push(dFrameGeo);

    const winSize = 0.012 * SC;
    for (const side of [-1, 1]) for (const xOff of [-0.035 * SC, 0.035 * SC]) {
      const winGeo = new THREE.BoxGeometry(winSize, winSize, 0.003 * SC);
      winGeo.translate(xOff, baseH * 0.55, (baseD / 2 + 0.001 * SC) * side);
      buckets.window.push(winGeo);
      const fr = new THREE.BoxGeometry(winSize + 0.004 * SC, winSize + 0.004 * SC, 0.002 * SC);
      fr.translate(xOff, baseH * 0.55, (baseD / 2 + 0.002 * SC) * side);
      buckets.frame.push(fr);
    }

    const drumR = 0.045 * SC, drumH = 0.015 * SC, drumY = baseH + 0.003 * SC;
    const drumGeo = new THREE.CylinderGeometry(drumR, drumR + 0.002 * SC, drumH, 24);
    drumGeo.translate(0, drumY + drumH / 2, 0);
    buckets.stone.push(drumGeo);
    const bandGeo = new THREE.CylinderGeometry(drumR + 0.003 * SC, drumR + 0.003 * SC, 0.003 * SC, 24);
    bandGeo.translate(0, drumY + drumH, 0);
    buckets.stoneDk.push(bandGeo);

    const domeR = drumR + 0.001 * SC;
    const domeY = drumY + drumH + 0.001 * SC;
    const profile = [];
    for (let i = 0; i <= 16; i++) {
      const angle = (i / 16) * Math.PI * 0.5;
      profile.push(new THREE.Vector2(Math.cos(angle) * domeR, Math.sin(angle) * domeR));
    }
    const domeGeo = new THREE.LatheGeometry(profile, 24);
    domeGeo.translate(0, domeY, 0);
    buckets.dome.push(domeGeo);

    const slitAngle = rand() * Math.PI * 2;
    const stripeW = 0.01 * SC;
    for (let i = 0; i < 16; i++) {
      const a0 = (i / 16) * Math.PI, a1 = ((i + 1) / 16) * Math.PI;
      const y0 = domeY + Math.sin(a0) * domeR, y1 = domeY + Math.sin(a1) * domeR;
      const r0 = Math.cos(a0) * (domeR + 0.001 * SC), r1 = Math.cos(a1) * (domeR + 0.001 * SC);
      const segH = Math.sqrt((y1 - y0) ** 2 + (r1 - r0) ** 2);
      const segGeo = new THREE.BoxGeometry(stripeW, segH, 0.003 * SC);
      segGeo.rotateX(Math.atan2(r1 - r0, y1 - y0));
      segGeo.translate(0, (y0 + y1) / 2, (r0 + r1) / 2);
      segGeo.rotateY(slitAngle);
      buckets.slit.push(segGeo);
    }

    const scopeR = 0.007 * SC;
    const scopeGeo = new THREE.CylinderGeometry(scopeR, scopeR * 0.85, domeR * 1.2, 12);
    scopeGeo.rotateX(-(Math.PI * 0.30));
    scopeGeo.translate(0, domeY + domeR * 0.42, domeR * 0.22);
    scopeGeo.rotateY(slitAngle);
    buckets.finder.push(scopeGeo);
    const shieldGeo = new THREE.CylinderGeometry(scopeR * 1.3, scopeR * 1.1, 0.012 * SC, 12);
    shieldGeo.rotateX(-(Math.PI * 0.30));
    shieldGeo.translate(0, domeY + domeR * 0.68, domeR * 0.40);
    shieldGeo.rotateY(slitAngle);
    buckets.slit.push(shieldGeo);
    const mountGeo = new THREE.BoxGeometry(0.01 * SC, 0.015 * SC, 0.01 * SC);
    mountGeo.translate(0, domeY + domeR * 0.25, domeR * 0.1);
    mountGeo.rotateY(slitAngle);
    buckets.frame.push(mountGeo);

    const secW = 0.035 * SC;
    const secGeo = new THREE.BoxGeometry(secW, 0.02 * SC, secW);
    secGeo.translate(-baseW * 0.35, baseH + 0.01 * SC, -baseD * 0.35);
    buckets.stone.push(secGeo);
    const secDome = new THREE.SphereGeometry(secW * 0.45, 12, 8, 0, Math.PI * 2, 0, Math.PI / 2);
    secDome.translate(-baseW * 0.35, baseH + 0.02 * SC, -baseD * 0.35);
