config:
  name: "TinySkies Globe Visual"
  id: "tinyskies.globeVisual"
  author: "script-wizard"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  description: "Procedural deformed globe + atmosphere shell. Sphere vertices are radially displaced by simplex-noise terrain and colored by biome (ocean / shallow / beach / grass / rock / snow). Atmosphere uniform glow color stays driven by the day/night cycle."
  documentation: "Generates a SphereGeometry, walks every vertex (segments+1)² and displaces radially via terrain.surfaceDisplacementAt(seed, terrainType, n). Per-vertex colors written from terrain elevation/depth for biome shading. Atmosphere shell unchanged. Surface still tagged userData.tinyskiesGlobeSurface=true so the paintball system can find it. The day/night ocean tint store key (`tinyskies/oceanShallow`) is no longer consumed — vertex colors dominate; atmosphere glow stays live."
  tags:
    - visual
    - environment
    - terrain
  priority: 0
  throttleConfig:
    throttlePriority: "HIGH"
    enableFrustumCulling: false
    enableDistanceThrottling: false
    requiresConsistentUpdates: false
  attributes:
    radius:
      name: "Globe Radius"
      type: "number"
      default: 5
      min: 0.5
      max: 200
    segments:
      name: "Sphere Segments"
      type: "number"
      default: 128
      min: 32
      max: 512
    terrainSeed:
