      min: 1
      max: 1000000
    terrainType:
      name: "Terrain Type"
      type: "string"
      default: "default"
    atmosphereGlow:
      name: "Atmosphere Glow"
      type: "color"
      default: "#eeddbb"
    atmosphereScale:
      name: "Atmosphere Shell Scale"
