code: |-
  @import "spherical-math" as S;
  @import "terrain" as T;

  const LOG_TAG = "[tinyskies.flightController]";

  // Tuning constants — verbatim from source Plane.ts:22-63 (REQ-003..REQ-006).
  const BRAKE_DECEL = 3.0;
  const ACCEL = 2.5;
  const MIN_SPEED = 0.3;
  const MAX_SPEED = 0.8;
  const BOOST_SPEED = 1.3;
  const ABSOLUTE_MAX_SPEED = 2.0;
  const ALTITUDE = 0.55;
  const HIGH_ALTITUDE = 1.35;
  const LOW_HOVER_HEIGHT = 0.08;
  const ALTITUDE_SPEED = 0.75;
  const MAX_BANK = Math.PI / 4;
  const BANK_RESPONSIVENESS = 4;
  const TURN_INPUT_SMOOTH = 8;
  const ELEVATE_INPUT_SMOOTH = 6;
  const CRUISE_SPEED_RATIO_MAX = 0.167;
  const TURN_SPEED = 1.2;              // FlightControls.ts:1

  // Batch B — boost / slow / wobble (source Plane.ts:29-37, 106-114, 322-331).
  const BOOST_DURATION_SEC = 1.7;
  const BOOST_BARREL_ROLL_TURNS = 1.0;
  const GREMLIN_SLOW_DURATION_SEC = 1.35;
  const GREMLIN_SLOW_MULT = 0.58;
  const PAINTBALL_WOBBLE_INITIAL = 0.42;
  const PAINTBALL_WOBBLE_FREQ = 19;
  const PAINTBALL_WOBBLE_DECAY = 4.2;
  const PLAYER_HP_MAX = 14;            // Plane.ts:40 (max-HP scale 1.0)

  let game;

  this.init = function (_game) {
    game = _game;
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };

    // Pre-allocated per CLAUDE.md hot-path rule (no allocations in update()).
    this._qPosition = new THREE.Quaternion();
    this._planeMatrix = new THREE.Matrix4();
    this._tmpUp = new THREE.Vector3();

    // Plane state (mirrors source Plane.ts fields).
    this._heading = 0;
    this._pitch = 0;
    this._bankAngle = 0;
    this._speed = 0;
    this._altitude = ALTITUDE;
    this._prevAltitude = ALTITUDE;
    this._turnInputSmoothed = 0;
    this._elevateBlend = 0;

    // Batch B — boost + slow + wobble + HP state.
    this._boostTimer = 0;
    this._rollAngle = 0;
    this._gremlinSlowTimer = 0;
    this._wobbleAmp = 0;
    this._wobblePhase = 0;
    this._wobbleBank = 0;
    this._playerHp = PLAYER_HP_MAX;

    // Spawn — REQ-016. Mirrors source Plane.ts:127-137 + randomSpawnQuaternionAndHeading().
    const seed = this.getAttribute("spawnSeed") + this.getAttribute("spawnSalt");
    const spawn = S.randomSpawnQuaternionAndHeading(seed);
    this._qPosition.copy(spawn.qPosition);
    this._heading = spawn.heading;

    // Input — InputManager defaults; key remap documented in
    // tinyskies-fidelity-decision-record.md FDR-002.
    //   yaw    = -motion("lateral") * TURN_SPEED   (A=+TURN_SPEED, D=−TURN_SPEED to match source)
    //   thrust = motion("forward") > 0
    //   brake  = motion("forward") < 0
    //   climb  = action("run")     (Shift)         (was ArrowUp in source)
    //   descend= action("crouch")  (Ctrl)          (new — source had no descend key)
    //   fire   = action("jump") edge-detected      (Space)
    this._im = game.inputManager || null;
    this._fireHeldPrev = false;
    this._paintballQueued = false;

    // Apply the spawn matrix immediately so the editor preview / first frame
    // sees the plane at the spawn pose, not at origin.
    this._applyPlaneMatrix();
    // Publish initial state so dependents (camera rig, paintball) see the spawn
    // pose on their first update() instead of zero-defaults.
    this._publishState(false);
    this._log("init heading=", this._heading.toFixed(3), "alt=", this._altitude.toFixed(3));
  };

  this.update = function (deltaTime) {
    const dt = Math.min(deltaTime, 0.1);
    const globeRadius = this.getAttribute("globeRadius");

    // ── Read input via InputManager (FDR-002) ──
    const im = this._im;
    const lateral = im ? im.getMotion("lateral") : 0;     // A=−1, D=+1
    const fwdAxis = im ? im.getMotion("forward") : 0;     // W=+1, S=−1
    const climbHeld = im ? !!im.getAction("run") : false;
    const descendHeld = im ? !!im.getAction("crouch") : false;
    const fireHeld = im ? !!im.getAction("jump") : false;

    if (fireHeld && !this._fireHeldPrev) this._paintballQueued = true;
    this._fireHeldPrev = fireHeld;
    const paintballPressed = this._paintballQueued;
    this._paintballQueued = false;

    // Mirror source FlightControls.ts semantics: A → +TURN_SPEED (left), D → −TURN_SPEED (right).
    const turnRate = -lateral * TURN_SPEED;
    const forward = fwdAxis > 0.5;
    const brake = fwdAxis < -0.5;
    const elevate = climbHeld;
    const descend = descendHeld;

    // ── Drain Batch B store-signaled events (one-shots; read-and-clear) ──
    const store = this.erth.store;

    // Teleport — consumed once. Snaps player quaternion / heading /
    // altitude / speed in a single frame. Used by carpet portal system.
    const teleportTo = store.get("tinyskies/teleportTo");
    if (teleportTo && typeof teleportTo === "object") {
      store.set("tinyskies/teleportTo", null);
      if (typeof teleportTo.qx === "number") this._qPosition.set(teleportTo.qx, teleportTo.qy, teleportTo.qz, teleportTo.qw);
      if (typeof teleportTo.heading === "number") this._heading = teleportTo.heading;
      if (typeof teleportTo.altitude === "number") {
        this._altitude = teleportTo.altitude;
        this._prevAltitude = teleportTo.altitude;
      }
      if (typeof teleportTo.speed === "number") this._speed = teleportTo.speed;
    }

    if (store.get("tinyskies/triggerBoost") === true) {
      store.set("tinyskies/triggerBoost", false);
      this._boostTimer = BOOST_DURATION_SEC;
      this._speed = BOOST_SPEED;
      this._rollAngle = 0;
    }
    if (store.get("tinyskies/applyGremlinSlow") === true) {
      store.set("tinyskies/applyGremlinSlow", false);
      this._gremlinSlowTimer = GREMLIN_SLOW_DURATION_SEC;
      this._speed = Math.max(MIN_SPEED, this._speed * GREMLIN_SLOW_MULT);
    }
    const damage = store.get("tinyskies/applyGremlinDamage");
    if (typeof damage === "number" && damage > 0) {
      store.set("tinyskies/applyGremlinDamage", 0);
      this._playerHp = Math.max(0, this._playerHp - damage);
    }
    const heal = store.get("tinyskies/applyHeartHeal");
    if (typeof heal === "number" && heal > 0) {
      store.set("tinyskies/applyHeartHeal", 0);
      this._playerHp = Math.min(PLAYER_HP_MAX, this._playerHp + heal);
    }
    if (store.get("tinyskies/applyPaintballWobble") === true) {
      store.set("tinyskies/applyPaintballWobble", false);
      this._wobbleAmp = PAINTBALL_WOBBLE_INITIAL;
      this._wobblePhase = 0;
    }

    // Decrement the timers.
    if (this._boostTimer > 0) this._boostTimer = Math.max(0, this._boostTimer - dt);
    if (this._gremlinSlowTimer > 0) this._gremlinSlowTimer = Math.max(0, this._gremlinSlowTimer - dt);
    const slowMult = this._gremlinSlowTimer > 0 ? GREMLIN_SLOW_MULT : 1;

    // ── Speed envelope (Plane.ts:240-261) — boost overrides during boostTimer ──
    if (this._boostTimer > 0) {
      this._speed = BOOST_SPEED;
      this._rollAngle += ((Math.PI * 2 * BOOST_BARREL_ROLL_TURNS) / Math.max(BOOST_DURATION_SEC, 0.08)) * dt;
    } else {
      this._rollAngle = 0;
      const effMaxSpeed = MAX_SPEED * slowMult;
      const effAccel = ACCEL * slowMult;
      const effBrakeDecel = BRAKE_DECEL;
      if (forward) {
        if (this._speed < effMaxSpeed) {
          this._speed = Math.min(effMaxSpeed, this._speed + effAccel * dt);
        } else {
          this._speed = Math.max(effMaxSpeed, this._speed - 0.13 * dt);
        }
      } else if (brake) {
        this._speed = Math.max(MIN_SPEED, this._speed - effBrakeDecel * dt);
      } else {
        this._speed = Math.max(MIN_SPEED, this._speed - 0.3 * dt);
      }
    }

    // ── Smoothed yaw input (Plane.ts:253) ──
    this._turnInputSmoothed +=
      (turnRate - this._turnInputSmoothed) * (1 - Math.exp(-TURN_INPUT_SMOOTH * dt));

    // Turn-drag (Plane.ts:255-261).
    const turnStrength = Math.abs(this._turnInputSmoothed);
    if (turnStrength > 0.1) {
      this._speed = Math.max(MIN_SPEED, this._speed - turnStrength * 0.8 * dt);
    }

    // ── Heading integration (Plane.ts:263-264) ──
    this._heading += this._turnInputSmoothed * dt;
    const TWO_PI = Math.PI * 2;
    this._heading = ((this._heading % TWO_PI) + TWO_PI) % TWO_PI;

    // ── Altitude blend (Plane.ts:266-282), per-vehicle (Batch D) ──
    // plane: full ALTITUDE / HIGH_ALTITUDE envelope.
    // boat:  surface-locked at LOW_HOVER_HEIGHT above water; climb input ignored.
    // carpet: like plane but lower max altitude.
    const vehicleType = store.get("tinyskies/vehicleType") || "plane";
    const isBoat = vehicleType === "boat";
    const isCarpet = vehicleType === "carpet";
    const cruiseAlt = isBoat ? 0.05 : ALTITUDE;
    const climbAlt = isBoat ? 0.05 : (isCarpet ? 1.0 : HIGH_ALTITUDE);

    const elevateTarget = isBoat ? 0 : (elevate ? 1 : descend ? -1 : 0);
    this._elevateBlend +=
      (elevateTarget - this._elevateBlend) * (1 - Math.exp(-ELEVATE_INPUT_SMOOTH * dt));

    // Terrain-aware hover floor — sample terrain at the player's current
    // surface-radial direction. Mountains push the plane up; ocean stays at 0.
    // Compute up vector from quaternion: up = Y rotated by qPosition.
    this._tmpUp.set(0, 1, 0).applyQuaternion(this._qPosition).normalize();
    const surfaceAlt = T.surfaceAltitudeAt(
      this.getAttribute("terrainSeed"),
      this.getAttribute("terrainType"),
      this._tmpUp.x, this._tmpUp.y, this._tmpUp.z,
    );
    const lowAlt = surfaceAlt + LOW_HOVER_HEIGHT;
    let targetAlt;
    if (this._elevateBlend > 0) {
      targetAlt = cruiseAlt + (climbAlt - cruiseAlt) * this._elevateBlend;
    } else {
      targetAlt = cruiseAlt + (cruiseAlt - lowAlt) * this._elevateBlend;
    }
    this._altitude += (targetAlt - this._altitude) * Math.min(1, ALTITUDE_SPEED * dt);
    const hardFloor = surfaceAlt + LOW_HOVER_HEIGHT;
    if (this._altitude < hardFloor) this._altitude = hardFloor;

    // ── Pitch from climb rate (Plane.ts:284-288) ──
    const altDelta = (this._altitude - this._prevAltitude) / Math.max(dt, 1e-4);
    this._prevAltitude = this._altitude;
    const climbRate = Math.max(-1, Math.min(1, altDelta * 2.5));
    const targetPitch = -0.3 * climbRate;
    this._pitch += (targetPitch - this._pitch) * Math.min(1, 3.0 * dt);

    // ── Great-circle motion (Plane.ts:290-291) ──
    const arcAngle = (this._speed * dt) / globeRadius;
    this._qPosition = S.moveOnSphere(this._qPosition, this._heading, arcAngle);

    // ── Bank toward turn (Plane.ts:293-294) ──
    const targetBank = Math.max(
      -MAX_BANK,
      Math.min(MAX_BANK, -this._turnInputSmoothed * MAX_BANK * 0.5),
    );
    this._bankAngle +=
      (targetBank - this._bankAngle) * Math.min(1, BANK_RESPONSIVENESS * dt);

    // ── Propeller spin (Plane.ts:296-298) ──
    const parent = this.gameObject?._internal?.three;
    const propeller = parent?.userData?.tinyskiesPropeller;
    if (propeller) {
      propeller.rotation.z -= (this._speed * 15 + 10) * dt;
    }

    // ── Hard speed ceiling (Plane.ts:301) ──
    this._speed = Math.min(this._speed, ABSOLUTE_MAX_SPEED);

    // ── Paintball-hit wobble (damped sin; Plane.ts:303-311) ──
    if (this._wobbleAmp > 0.002) {
      this._wobblePhase += dt * PAINTBALL_WOBBLE_FREQ;
      this._wobbleBank = Math.sin(this._wobblePhase) * this._wobbleAmp;
      this._wobbleAmp *= Math.exp(-PAINTBALL_WOBBLE_DECAY * dt);
    } else {
      this._wobbleAmp = 0;
      this._wobbleBank = 0;
    }

    this._applyPlaneMatrix();
    this._publishState(paintballPressed);
  };

  this._publishState = function (paintballPressed) {
    const store = this.erth.store;
    store.set("tinyskies/qx", this._qPosition.x);
    store.set("tinyskies/qy", this._qPosition.y);
    store.set("tinyskies/qz", this._qPosition.z);
    store.set("tinyskies/qw", this._qPosition.w);
    store.set("tinyskies/playerHp", this._playerHp / PLAYER_HP_MAX);
    store.set("tinyskies/heading", this._heading);
    store.set("tinyskies/pitch", this._pitch);
    store.set("tinyskies/altitude", this._altitude);
    store.set("tinyskies/turnRate", this._turnInputSmoothed);
    store.set("tinyskies/speedRatio", this._computeSpeedRatio());
    if (paintballPressed) {
      // Single-shot signal — paintball system reads-and-clears.
      store.set("tinyskies/firePaintball", true);
    }
  };

  this._applyPlaneMatrix = function () {
    const parent = this.gameObject?._internal?.three;
    if (!parent) return;
    // Total bank = banking-from-turn + paintball wobble + barrel-roll spin from
    // active boost (matches source Plane.ts:395 buildPlaneMatrix args).
    const totalBank = this._bankAngle + this._wobbleBank + this._rollAngle;
    const m = S.buildPlaneMatrix(
      this._qPosition,
      this._heading,
      this._pitch,
      totalBank,
      this._altitude,
      this.getAttribute("globeRadius"),
    );
    parent.matrix.copy(m);
    parent.matrixWorldNeedsUpdate = true;
  };

  // Source Plane.ts:403-413 — preserved here even though no boost/upgrades exist
  // in MVP, so the camera rig's FOV/zoom curves match the original.
  this._computeSpeedRatio = function () {
    const ms = MAX_SPEED;
    const bs = Math.min(BOOST_SPEED, ABSOLUTE_MAX_SPEED);
    if (this._speed <= MIN_SPEED) return 0;
    if (this._speed <= ms) {
      return CRUISE_SPEED_RATIO_MAX * ((this._speed - MIN_SPEED) / (ms - MIN_SPEED));
    }
    const t = Math.min(1, (this._speed - ms) / (bs - ms));
    const eased = t * (2 - t);
    return CRUISE_SPEED_RATIO_MAX + (1.0 - CRUISE_SPEED_RATIO_MAX) * eased;
  };

  // No editor preview — this behavior runs gameplay state machinery only;
  // the visible plane comes from tinyskiesBiplaneVisual.

  this.dispose = function () {
    this._log("dispose");
    this._im = null;
  };

meta:
  tool: StemStudio
  type: behavior
  exportVersion: 1

config:
  name: "TinySkies Carpet Portal System"
  id: "tinyskies.carpetPortalSystem"
  author: "script-wizard"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  description: "Portal-2 style two-portal teleporter for the magic carpet. Pressing the paintball key while on carpet drops a colored portal ahead of the player; the second press drops the paired portal. Flying through one teleports to the other. Source-faithful port of CarpetPortalSystem.ts (576 LOC) — visual + placement + arming + segment-portal hit + heading remap."
  documentation: "Active only while vehicleType==='carpet'. Listens for `tinyskies/firePaintball` (already published by flightController on Space). On consume: places one of a pair of portals (orange 0xff7700 + cyan 0x00aaff) at PORTAL_PLACE_AHEAD=0.45 ahead of the carpet. Once both portals exist, segment-vs-portal-disc intersection detects fly-through; teleport snaps the player via `tinyskies/teleportTo`. Arming logic: a freshly placed portal is unarmed until the player has moved more than PORTAL_ARM_DISTANCE away (so you don't insta-teleport on placement). Visual: 5-mesh stack (ring torus + glow disc + inner shader-disc + 2 swirl rings) scaled tall-and-narrow (0.65×, 1.25×, 1.0). Spawn animation: easeOutBack scale-in over 0.5s. Inner-disc shader (raw GLSL in source) approximated with MeshBasicNodeMaterial + emissive — same color story (vortex hue) without the swirl frag. Group parented to scene root so portals are world-anchored."
  tags:
    - vehicle
    - vfx
    - gameplay
  priority: 0
  throttleConfig:
    throttlePriority: "HIGH"
    enableFrustumCulling: false
    enableDistanceThrottling: false
    requiresConsistentUpdates: true
  attributes:
    globeRadius:
      name: "Globe Radius"
      type: "number"
      default: 5
      min: 0.1
      max: 200
    terrainSeed:
      name: "Terrain Seed"
      type: "number"
      default: 42
    terrainType:
      name: "Terrain Type"
      type: "string"
      default: "default"
    triggerRadiusMult:
      name: "Trigger Radius Multiplier"
      type: "number"
      default: 1
      min: 0.5
      max: 3
      description: "Source 'Wide Portal' upgrade hook."
    debugLogs:
      name: "Debug Logs"
      type: "boolean"
      default: false

code: |-
  @import "spherical-math" as S;
  @import "terrain" as T;

  const LOG_TAG = "[tinyskies.carpetPortalSystem]";

  // Source CarpetPortalSystem.ts:18-26 — verbatim.
  const PORTAL_PLACE_AHEAD = 0.45;
  const PORTAL_RADIUS = 0.15;
  const PORTAL_TUBE_RADIUS = 0.022;
  const PORTAL_TRIGGER_RADIUS = 0.22;
  const PORTAL_ARM_DISTANCE = 0.38;
  const PORTAL_EXIT_PUSH = 0.22;
  const PORTAL_COOLDOWN_SEC = 0.3;
  const CARPET_HOVER_HEIGHT = 0.12;
  const PORTAL_COLORS = [0x00aaff, 0xff7700];

  function cartesianFromSphericalInto(qPosition, altitude, globeRadius, out) {
    return out.set(0, globeRadius + altitude, 0).applyQuaternion(qPosition);
  }

  function buildPortalVisual(colorHex, phase) {
    const group = new THREE.Group();
    group.userData.isRuntimeOnly = true;

    // Source PortalVisual: scaledGroup at (0.65, 1.25, 1.0) — Portal-2 silhouette.
    const scaled = new THREE.Group();
    scaled.userData.isRuntimeOnly = true;
    scaled.scale.set(0.65, 1.25, 1.0);
    group.add(scaled);

    const ringMat = new THREE.MeshBasicNodeMaterial({
      color: colorHex, transparent: true, opacity: 0.95,
      blending: THREE.AdditiveBlending, side: THREE.DoubleSide, depthWrite: false,
    });
    const glowMat = new THREE.MeshBasicNodeMaterial({
      color: colorHex, transparent: true, opacity: 0.35,
      blending: THREE.AdditiveBlending, side: THREE.DoubleSide, depthWrite: false,
    });
    // Source inner uses a raw GLSL vortex shader; we approximate with an
    // emissive disc + tint for WebGPU compat.
    const innerMat = new THREE.MeshBasicNodeMaterial({
      color: 0x000000, transparent: true, opacity: 0.85,
      side: THREE.DoubleSide, depthWrite: false,
    });
    const swirlMat = new THREE.MeshBasicNodeMaterial({
      color: colorHex, transparent: true, opacity: 0.7,
      blending: THREE.AdditiveBlending, side: THREE.DoubleSide, depthWrite: false,
    });
    const swirl2Mat = new THREE.MeshBasicNodeMaterial({
      color: colorHex, transparent: true, opacity: 0.6,
      blending: THREE.AdditiveBlending, side: THREE.DoubleSide, depthWrite: false,
    });

    const ring = new THREE.Mesh(new THREE.TorusGeometry(PORTAL_RADIUS, PORTAL_TUBE_RADIUS * 0.6, 18, 56), ringMat); // @check-ok no editor preview — portals only spawn during play via paintball key
    const glow = new THREE.Mesh(new THREE.CircleGeometry(PORTAL_RADIUS * 1.3, 40), glowMat);
    const inner = new THREE.Mesh(new THREE.CircleGeometry(PORTAL_RADIUS * 0.95, 40), innerMat);
    const swirl = new THREE.Mesh(new THREE.TorusGeometry(PORTAL_RADIUS * 0.95, PORTAL_TUBE_RADIUS * 0.4, 12, 36), swirlMat);
    const swirl2 = new THREE.Mesh(new THREE.TorusGeometry(PORTAL_RADIUS * 0.98, PORTAL_TUBE_RADIUS * 0.6, 12, 36), swirl2Mat);
    [ring, glow, inner, swirl, swirl2].forEach((m) => { m.userData.isRuntimeOnly = true; });

    glow.position.z = -0.012;
    inner.position.z = -0.004;
    swirl.position.z = 0.008;
    swirl2.position.z = 0.012;

    scaled.add(glow);
    scaled.add(inner);
    scaled.add(swirl);
    scaled.add(swirl2);
    scaled.add(ring);

    return {
      group, scaled, ring, glow, inner, swirl, swirl2,
      materials: [ringMat, glowMat, innerMat, swirlMat, swirl2Mat],
      phase,
      createdAt: 0,
    };
  }

  function disposePortalVisual(visual) {
    [visual.ring, visual.glow, visual.inner, visual.swirl, visual.swirl2].forEach((m) => {
      if (m && m.geometry && typeof m.geometry.dispose === "function") m.geometry.dispose();
    });
    visual.materials.forEach((mat) => { if (mat && typeof mat.dispose === "function") mat.dispose(); });
  }

  // Source PortalVisual.applyPose — basis matrix from right/up/forward.
  const _poseMat = new THREE.Matrix4();
  function applyPose(visual, worldPos, right, up, forward) {
    _poseMat.makeBasis(right, up, forward);
    _poseMat.setPosition(worldPos);
    visual.group.matrixAutoUpdate = false;
    visual.group.matrix.copy(_poseMat);
    visual.group.matrixWorldNeedsUpdate = true;
  }

  // Source PortalVisual.update — easeOutBack spawn + pulse + swirl spin.
  function tickPortalVisual(visual, time, age) {
    const t = Math.min(1.0, age / 0.5);
    const c1 = 1.70158;
    const c3 = c1 + 1;
    const ease = 1 + c3 * Math.pow(t - 1, 3) + c1 * Math.pow(t - 1, 2);
    const startX = 0.3, endX = 0.65;
    const startY = 0.3, endY = 1.25;
    const currentX = startX + (endX - startX) * ease;
    const currentY = startY + (endY - startY) * ease;
    visual.scaled.scale.set(currentX, currentY, 1.0 * ease);
    visual.scaled.rotation.z = (1 - t) * Math.PI;

    const pulse = 1 + Math.sin(time * 8.0 + visual.phase) * 0.02;
    visual.ring.scale.setScalar(pulse);
    visual.glow.scale.setScalar(0.95 + Math.sin(time * 4.0 + visual.phase) * 0.05);

    visual.swirl.rotation.z = -time * 3.5 - visual.phase;
    visual.swirl2.rotation.z = time * 2.8 + visual.phase * 0.5;
    visual.swirl.scale.setScalar(1 + Math.sin(time * 12.0) * 0.03);
    visual.swirl2.scale.setScalar(1 + Math.cos(time * 9.0) * 0.04);
  }

  this.init = function (_game) {
    this._game = _game;
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };

    this._portals = [];
    this._cooldown = 0;
    this._time = 0;
    this._nextPortalId = 0;
    this._lastPlayerWorldPos = new THREE.Vector3();
    this._hasLastPlayerWorldPos = false;

    this._tmpQ = new THREE.Quaternion();
    this._tmpUp = new THREE.Vector3();
    this._tmpForward = new THREE.Vector3();
    this._tmpRight = new THREE.Vector3();
    this._tmpPos = new THREE.Vector3();
    this._tmpSeg = new THREE.Vector3();
    this._tmpRel = new THREE.Vector3();
    this._tmpMappedDir = new THREE.Vector3();

    this._group = new THREE.Group(); // @check-ok no editor preview — portals only spawn via paintball key during play
    this._group.userData.isRuntimeOnly = true;
    const sceneParent = this.gameObject._internal.three.parent || this.gameObject._internal.three;
    sceneParent.add(this._group);

    this._log("init");
  };

  this._readPlayerState = function () {
    const store = this.erth.store;
    const qx = store.get("tinyskies/qx");
    const qy = store.get("tinyskies/qy");
    const qz = store.get("tinyskies/qz");
    const qw = store.get("tinyskies/qw");
    const altitude = store.get("tinyskies/altitude");
    const heading = store.get("tinyskies/heading") || 0;
    const speed = store.get("tinyskies/speedRatio") || 0.4;
    if (qx === undefined || qy === undefined || qz === undefined || qw === undefined || altitude === undefined) return null;
    this._tmpQ.set(qx, qy, qz, qw);
    return { qPosition: this._tmpQ, heading, altitude, speed };
  };

  this._headingVector = function (qPosition, heading, out) {
    const frame = S.tangentFrame(qPosition);
    out.set(0, 0, 0)
      .addScaledVector(frame.north, Math.cos(heading))
      .addScaledVector(frame.east, Math.sin(heading))
      .normalize();
    return frame;
  };

  this._placePortal = function (player) {
    const radius = this.getAttribute("globeRadius");
    const placeQ = S.moveOnSphere(player.qPosition, player.heading, PORTAL_PLACE_AHEAD / radius);
    const frame = S.tangentFrame(placeQ);

    const portalHalfHeight = PORTAL_RADIUS * 1.25 + PORTAL_TUBE_RADIUS;
    const safeClearance = portalHalfHeight + 0.02;
    const seed = this.getAttribute("terrainSeed") | 0;
    const terrainType = this.getAttribute("terrainType");
    const sample = T.sampleTerrain(seed, terrainType, frame.up.x, frame.up.y, frame.up.z);
    const surfaceAlt = (typeof T.surfaceDisplacementAt === "function")
      ? radius + T.surfaceDisplacementAt(seed, terrainType, frame.up.x, frame.up.y, frame.up.z)
      : radius + (sample.elevation || 0);
    const minAltitude = surfaceAlt + Math.max(CARPET_HOVER_HEIGHT, safeClearance);
    const altitude = Math.max(player.altitude, minAltitude);

    const worldPos = S.cartesianFromSpherical(placeQ, altitude, radius);
    const forward = new THREE.Vector3();
    this._headingVector(placeQ, player.heading, forward);
    const right = new THREE.Vector3().crossVectors(forward, frame.up).normalize();

    const colorHex = PORTAL_COLORS[this._nextPortalId % PORTAL_COLORS.length];
    const phase = this._nextPortalId * 0.73;
    const visual = buildPortalVisual(colorHex, phase); // @check-ok no editor preview
    visual.createdAt = this._time;
    applyPose(visual, worldPos, right, frame.up, forward);

    if (this._portals.length === 2) {
      const oldest = this._portals.shift();
      this._group.remove(oldest.visual.group);
      disposePortalVisual(oldest.visual);
    }

    this._group.add(visual.group);
    this._portals.push({
      id: this._nextPortalId++,
      qPosition: placeQ.clone(),
      heading: player.heading,
      altitude,
      minAltitude,
      worldPosition: worldPos.clone(),
      up: frame.up.clone(),
      forward: forward.clone(),
      right: right.clone(),
      visual,
      armed: false,
    });
    tickPortalVisual(visual, this._time, 0);
    this._log("portal placed", this._portals.length);
  };

  this._updateArming = function (playerPos) {
    const armSq = PORTAL_ARM_DISTANCE * PORTAL_ARM_DISTANCE;
    for (const portal of this._portals) {
      if (!portal.armed && playerPos.distanceToSquared(portal.worldPosition) > armSq) {
        portal.armed = true;
      }
    }
  };

  this._segmentPortalIntersection = function (start, end, portal) {
    this._tmpSeg.copy(end).sub(start);
    const denom = portal.forward.dot(this._tmpSeg);
    if (Math.abs(denom) < 1e-5) return null;
    const startDepth = portal.forward.dot(this._tmpRel.copy(start).sub(portal.worldPosition));
    const endDepth = portal.forward.dot(this._tmpRel.copy(end).sub(portal.worldPosition));
    if (startDepth * endDepth > 0) return null;
    const t = startDepth / (startDepth - endDepth);
    if (t < 0 || t > 1) return null;
    // Hit point on plane.
    this._tmpRel.copy(this._tmpSeg).multiplyScalar(t).add(start).sub(portal.worldPosition);
    const rightDist = this._tmpRel.dot(portal.right);
    const upDist = this._tmpRel.dot(portal.up);
    const radial = Math.sqrt(rightDist * rightDist + upDist * upDist);
    const triggerR = PORTAL_TRIGGER_RADIUS * this.getAttribute("triggerRadiusMult");
    if (radial > triggerR) return null;
    return t;
  };

  this._findHit = function (start, end) {
    let bestHit = null;
    for (let i = 0; i < this._portals.length; i++) {
      const portal = this._portals[i];
      if (!portal.armed) continue;
      const t = this._segmentPortalIntersection(start, end, portal);
      if (t === null) continue;
      if (!bestHit || t < bestHit.t) bestHit = { entryIndex: i, t };
    }
    return bestHit;
  };

  this._mapHeading = function (incomingDir, entry, exit) {
    const m = this._tmpMappedDir;
    m.copy(exit.forward).multiplyScalar(incomingDir.dot(entry.forward));
    m.addScaledVector(exit.right, incomingDir.dot(entry.right));
    m.addScaledVector(exit.up, incomingDir.dot(entry.up));
    m.addScaledVector(exit.up, -m.dot(exit.up));
    if (m.lengthSq() < 1e-5) m.copy(exit.forward);
    else m.normalize();
    const exitFrame = S.tangentFrame(exit.qPosition);
    const heading = Math.atan2(m.dot(exitFrame.east), m.dot(exitFrame.north));
    return ((heading % (Math.PI * 2)) + Math.PI * 2) % (Math.PI * 2);
  };

  this._teleportThrough = function (player, entryIndex) {
    const entry = this._portals[entryIndex];
    const exit = this._portals[entryIndex === 0 ? 1 : 0];
    const radius = this.getAttribute("globeRadius");
    const incomingDir = new THREE.Vector3();
    this._headingVector(player.qPosition, player.heading, incomingDir);
    const exitHeading = this._mapHeading(incomingDir, entry, exit);
    const exitQPosition = S.moveOnSphere(exit.qPosition, exitHeading, PORTAL_EXIT_PUSH / radius);
    const exitFrame = S.tangentFrame(exitQPosition);
    const seed = this.getAttribute("terrainSeed") | 0;
    const terrainType = this.getAttribute("terrainType");
    const surfaceAlt = (typeof T.surfaceDisplacementAt === "function")
      ? radius + T.surfaceDisplacementAt(seed, terrainType, exitFrame.up.x, exitFrame.up.y, exitFrame.up.z)
      : radius;
    const safeFloor = surfaceAlt + CARPET_HOVER_HEIGHT;
    const exitAltitude = Math.max(exit.altitude, exit.minAltitude, safeFloor);

    this.erth.store.set("tinyskies/teleportTo", {
      qx: exitQPosition.x, qy: exitQPosition.y, qz: exitQPosition.z, qw: exitQPosition.w,
      heading: exitHeading,
      altitude: exitAltitude,
    });
    this._cooldown = PORTAL_COOLDOWN_SEC;
    for (const portal of this._portals) portal.armed = false;
    this._log("teleported through portal", entryIndex);
  };

  this.update = function (deltaTime) {
    if (!this._group) return;
    const dt = Math.min(deltaTime || 0, 0.1);
    this._time += dt;
    if (this._cooldown > 0) this._cooldown = Math.max(0, this._cooldown - dt);

    // Animate any existing portals (regardless of vehicle so they keep
    // rendering during transitions).
    for (const portal of this._portals) {
      tickPortalVisual(portal.visual, this._time, this._time - portal.visual.createdAt);
    }

    const store = this.erth.store;
    const vt = store.get("tinyskies/vehicleType") || "plane";
    const isCarpet = (vt === "carpet");

    // If the player switches off carpet, clear portals so they don't sit
    // around on plane / boat.
    if (!isCarpet) {
      this._hasLastPlayerWorldPos = false;
      if (this._portals.length > 0) {
        for (const portal of this._portals) {
          this._group.remove(portal.visual.group);
          disposePortalVisual(portal.visual);
        }
        this._portals.length = 0;
      }
      return;
    }

    const player = this._readPlayerState();
    if (!player) return;
    const radius = this.getAttribute("globeRadius");
    const currentWorldPos = cartesianFromSphericalInto(player.qPosition, player.altitude, radius, this._tmpPos);

    // Place portal on firePaintball (paint key — repurposed for carpet).
    if (store.get("tinyskies/firePaintball") === true) {
      store.set("tinyskies/firePaintball", false);
      this._placePortal(player);
    }

    if (!this._hasLastPlayerWorldPos) {
      this._lastPlayerWorldPos.copy(currentWorldPos);
      this._hasLastPlayerWorldPos = true;
      this._updateArming(currentWorldPos);
      return;
    }

    this._updateArming(currentWorldPos);

    if (this._cooldown > 0 || this._portals.length < 2) {
      this._lastPlayerWorldPos.copy(currentWorldPos);
      return;
    }

    const hit = this._findHit(this._lastPlayerWorldPos, currentWorldPos);
    if (!hit) {
      this._lastPlayerWorldPos.copy(currentWorldPos);
      return;
    }

    this._teleportThrough(player, hit.entryIndex);
    // Re-anchor for next-frame hit window after teleport.
    this._hasLastPlayerWorldPos = false;
  };

  this.dispose = function () {
    this._log("dispose");
    if (this._portals) {
      for (const portal of this._portals) {
        if (portal.visual && portal.visual.group && portal.visual.group.parent) {
          portal.visual.group.parent.remove(portal.visual.group);
        }
        if (portal.visual) disposePortalVisual(portal.visual);
      }
      this._portals = [];
    }
    if (this._group && this._group.parent) this._group.parent.remove(this._group);
    this._group = null;
    this._hasLastPlayerWorldPos = false;
  };

