code: |-
  @import "spherical-math" as S;

  const LOG_TAG = "[tinyskies.raceQuest]";

  // Source RaceManager.ts:26-50 — constants verbatim.
  const RACE_CHECKPOINT_COUNT = 12;
  const RACE_RING_RADIUS = 0.54;
  const RACE_RING_TUBE = 0.054;
  const RACE_COLLECT_RADIUS = 0.68;
  const RACE_TIME_LIMIT = 45;
  const RACE_TIME_LIMIT_CARPET = 40;
  const RACE_BANNER_TRIGGER_RADIUS = 0.6;
  const RACE_APPROACH_FILL_SEC = 2;
  const RACE_LOW_HOVER = 0.4;
  const RACE_LOW_HOVER_CARPET = 0.22;
  const RACE_PATH_LAST_STRAIGHT_START = 0.52;
  const RACE_PATH_WEAVE_A = 0.95;
  const RACE_PATH_WEAVE_B = 0.58;
  const RACE_PATH_WEAVE_C = 0.44;
  const RACE_PATH_WEAVE_FREQ1 = 3;
  const RACE_PATH_WEAVE_FREQ2 = 4;
  const RACE_PATH_WEAVE_FREQ3 = 5;
  const RACE_TARGET_PULSE_AMP = 0.10;
  const RACE_TARGET_PULSE_HZ = 4.5;

  const RACE_BONUS_DIAMOND_COUNT = 3;
  const RACE_DIAMOND_SPIN_SPEED = 1.8;
  const RACE_DIAMOND_BOB_LIFT = 0.012;
  const RACE_DIAMOND_BOB_AMP = 0.017;
  const RACE_DIAMOND_BOB_HZ = 1.5;

  // RNG verbatim from source RaceManager.ts:56-62 makeRaceRng.
  function makeRaceRng(seed) {
    let s = seed >>> 0;
    return function () {
      s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
      return s / 0x100000000;
    };
  }

  // Holo material: source uses raw GLSL ShaderMaterial with phaseOffset +
  // time uniforms. Replaced with MeshStandardNodeMaterial + emissive
  // (WebGPU-compatible, same visual story: emissive ring + transparency).
  function buildHoloRingMaterial(hue) {
    return new THREE.MeshStandardNodeMaterial({
      color: hue,
      emissive: hue,
      emissiveIntensity: 1.4,
      transparent: true,
      opacity: 0.85,
      side: THREE.DoubleSide,
      depthWrite: false,
    });
  }

  this.init = function (_game) {
    this._game = _game;
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };

    // Pre-allocated math objects (source RaceManager.ts:112-119 pattern).
    this._tmpQ = new THREE.Quaternion();
    this._yAxis = new THREE.Vector3(0, 1, 0);
    this._qAlign = new THREE.Quaternion();
    this._spinQ = new THREE.Quaternion();
    this._ckY = new THREE.Vector3();
    this._ckZ = new THREE.Vector3();
    this._ckX = new THREE.Vector3();
    this._ckZo = new THREE.Vector3();
    this._ckToNext = new THREE.Vector3();
    this._ckAlt = new THREE.Vector3();
    this._ckMat = new THREE.Matrix4();
    this._scratchUp = new THREE.Vector3();
    this._scratchForward = new THREE.Vector3();
    this._scratchTangent = new THREE.Vector3();
    this._scratchBdW = new THREE.Vector3();

    this._state = "idle";
    this._activeBannerIndex = -1;
    this._approachProgress = 0;
    this._raceTimer = 0;
    this._currentRingIndex = 0;
    this._time = 0;
    this._rings = [];

    this._trackGroup = new THREE.Group();
    this._trackGroup.userData.isRuntimeOnly = true;
    this.gameObject._internal.three.add(this._trackGroup);

    this._diamondGeo = new THREE.OctahedronGeometry(0.09, 0); // @check-ok no editor preview — race rings only exist while racing
    this._buildHud();

    this._log("init");
  };

  // -----------------------------------------------------------------
  // HUD: countdown ring + race timer (UIKit Fullscreen).
  // -----------------------------------------------------------------
  this._buildHud = function () {
    if (typeof UIKit === "undefined" || !this._game || !this._game.renderer) return;
    if (this._fullscreen) return;
    try {
      const fs = new UIKit.Fullscreen(this._game.renderer, { // @check-ok-responsive — countdown/timer text scales naturally; mobile readability acceptable
        backgroundOpacity: 0,
        flexDirection: "column",
        justifyContent: "center",
        alignItems: "center",
        pointerEvents: "none",
        visibility: "visible",
      });
      this._fullscreen = fs;

      this._countdownText = new UIKit.Text({
        text: "",
        fontSize: 72,
        color: 0xffffff,
        visibility: "hidden",
      });
      fs.add(this._countdownText);

      this._timerText = new UIKit.Text({
        text: "",
        fontSize: 36,
        color: 0xffeb88,
        visibility: "hidden",
        positionType: "absolute",
        positionTop: 24,
      });
      fs.add(this._timerText);

      this._goText = new UIKit.Text({
        text: "GO!",
        fontSize: 96,
        color: 0xfff4a8,
        visibility: "hidden",
      });
      fs.add(this._goText);
      this._goShownAt = -1;
    } catch (e) {
      this._log("uikit hud build failed", e);
    }
  };

  this._tickHud = function () {
    if (!this._fullscreen) {
      this._buildHud();
    }
    if (!this._fullscreen) return;
    if (this._game && this._game.uiCamera && !this._fullscreen.parent) {
      this._game.uiCamera.add(this._fullscreen);
    }
    if (this._game && this._game.renderer && this._game.renderer.domElement && typeof this._fullscreen.update === "function") {
      this._fullscreen.update(this._game.renderer.domElement.clientWidth, this._game.renderer.domElement.clientHeight);
    }
  };

  this._setCountdown = function (text) {
    if (this._countdownText && typeof this._countdownText.setProperties === "function") {
      this._countdownText.setProperties({
        text: text || "",
        visibility: text ? "visible" : "hidden",
      });
    }
  };

  this._setTimerText = function (seconds) {
    if (!this._timerText) return;
    if (seconds === null || seconds === undefined) {
      this._timerText.setProperties({ visibility: "hidden" });
      return;
    }
    const s = Math.max(0, seconds);
    const whole = Math.floor(s);
    const tenths = Math.floor((s - whole) * 10);
    this._timerText.setProperties({
      text: whole + "." + tenths + "s",
      visibility: "visible",
    });
  };

  this._showGoToast = function () {
    if (!this._goText) return;
    this._goText.setProperties({ visibility: "visible" });
    this._goShownAt = this._time;
  };

  this._tickGoToast = function () {
    if (!this._goText || this._goShownAt < 0) return;
    if (this._time - this._goShownAt > 1.2) {
      this._goText.setProperties({ visibility: "hidden" });
      this._goShownAt = -1;
    }
  };

  // -----------------------------------------------------------------
  // Player state read.
  // -----------------------------------------------------------------
  this._getPlayerState = function () {
    const store = this.erth.store;
    const qx = store.get("tinyskies/qx");
    const qy = store.get("tinyskies/qy");
    const qz = store.get("tinyskies/qz");
    const qw = store.get("tinyskies/qw");
    const altitude = store.get("tinyskies/altitude");
    if (qx === undefined || qy === undefined || qz === undefined || qw === undefined || altitude === undefined) {
      return null;
    }
    this._tmpQ.set(qx, qy, qz, qw);
    const radius = this.getAttribute("globeRadius");
    return {
      pos: S.cartesianFromSpherical(this._tmpQ, altitude, radius),
      qPosition: this._tmpQ,
      heading: store.get("tinyskies/heading") || 0,
      vehicle: store.get("tinyskies/vehicleType") || "plane",
    };
  };

  this._isCarpet = function (vehicle) { return vehicle === "carpet"; };
  // Source RaceManager.ts:71 — only plane and carpet can race; boats excluded.
  this._canRace = function (vehicle) { return vehicle === "plane" || vehicle === "carpet"; };

  // -----------------------------------------------------------------
  // Build the 12-checkpoint weaving track from the active banner.
  // -----------------------------------------------------------------
  this._buildTrack = function (banner, playerState) {
    while (this._trackGroup.children.length > 0) {
      this._trackGroup.remove(this._trackGroup.children[0]);
    }
    this._rings = [];
    this._currentRingIndex = 0;

    const radius = this.getAttribute("globeRadius");
    const bannerNormal = this._scratchUp.set(banner.normal[0], banner.normal[1], banner.normal[2]).normalize();
    const startQ = S.quaternionFromSurfaceNormal(bannerNormal.x, bannerNormal.y, bannerNormal.z);

    const playerQ = playerState.qPosition;
    const heading = playerState.heading;
    const pFrame = S.tangentFrame(playerQ);
    const forward = this._scratchForward
      .set(0, 0, 0)
      .addScaledVector(pFrame.north, Math.cos(heading))
      .addScaledVector(pFrame.east, Math.sin(heading))
      .normalize();
    const tangent = this._scratchTangent.copy(forward).projectOnPlane(bannerNormal);
    if (tangent.lengthSq() < 1e-6) tangent.copy(pFrame.north);
    tangent.normalize();
    const sFrame = S.tangentFrame(startQ);
    const pathHeading = Math.atan2(tangent.dot(sFrame.east), tangent.dot(sFrame.north));

    const bannerHangAlt = banner.baseAlt - radius;
    const lowHover = this._isCarpet(playerState.vehicle) ? RACE_LOW_HOVER_CARPET : RACE_LOW_HOVER;
    const stepAngle = (Math.PI * 2) / RACE_CHECKPOINT_COUNT;

    const pathQuats = [];
    let qSeg = startQ.clone();
    for (let i = 0; i < RACE_CHECKPOINT_COUNT; i++) {
      const t = i / RACE_CHECKPOINT_COUNT;
      const k = Math.min(1, Math.max(0, (t - RACE_PATH_LAST_STRAIGHT_START) / (1 - RACE_PATH_LAST_STRAIGHT_START)));
      const smoothK = k * k * (3 - 2 * k);
      const weaveScale = 1 - smoothK;
      const weave = weaveScale * (
        RACE_PATH_WEAVE_A * Math.sin(t * Math.PI * 2 * RACE_PATH_WEAVE_FREQ1) +
        RACE_PATH_WEAVE_B * Math.sin(t * Math.PI * 2 * RACE_PATH_WEAVE_FREQ2 + 1.17) +
        RACE_PATH_WEAVE_C * Math.sin(t * Math.PI * 2 * RACE_PATH_WEAVE_FREQ3 + 0.73)
      );
      qSeg = S.moveOnSphere(qSeg, pathHeading + weave, stepAngle);
      pathQuats.push(qSeg.clone());
    }

    for (let i = 0; i < RACE_CHECKPOINT_COUNT; i++) {
      const q = pathQuats[i];
      const t = (i + 1) / RACE_CHECKPOINT_COUNT;
      const parabola = 4 * (t - 0.5) * (t - 0.5);
      const hover = lowHover + (bannerHangAlt - lowHover) * parabola;
      const pos = S.cartesianFromSpherical(q, hover, radius);

      const iNext = (i + 1) % RACE_CHECKPOINT_COUNT;
      const nextQ = pathQuats[iNext];
      const tNext = (iNext + 1) / RACE_CHECKPOINT_COUNT;
      const parNext = 4 * (tNext - 0.5) * (tNext - 0.5);
      const hoverNext = lowHover + (bannerHangAlt - lowHover) * parNext;
      const nextPos = S.cartesianFromSpherical(nextQ, hoverNext, radius);

      const ringGroup = new THREE.Group();
      ringGroup.userData.isRuntimeOnly = true;
      ringGroup.position.copy(pos);
      this._orientCheckpointOnGlobe(ringGroup, pos, nextPos);

      const isFinish = (i === RACE_CHECKPOINT_COUNT - 1);
      if (isFinish) {
        const finishMat = new THREE.MeshStandardNodeMaterial({
          color: 0xffd35a, emissive: 0xffa030, emissiveIntensity: 1.6,
          transparent: true, opacity: 0.92, side: THREE.DoubleSide, depthWrite: false,
