        const finishTorus = new THREE.Mesh(
          new THREE.TorusGeometry(RACE_RING_RADIUS * 1.15, RACE_RING_TUBE * 1.4, 14, 36),
          finishMat,
        );
        finishTorus.userData.isRuntimeOnly = true;
        ringGroup.add(finishTorus);
        const centerSphere = new THREE.Mesh(
          new THREE.SphereGeometry(0.08, 12, 8),
          new THREE.MeshStandardNodeMaterial({
            color: 0xffffff, emissive: 0xffe8a8, emissiveIntensity: 2.4,
          }),
        );
        centerSphere.userData.isRuntimeOnly = true;
        ringGroup.add(centerSphere);
        this._trackGroup.add(ringGroup);
        this._rings.push({
          worldPos: pos.clone(),
          ringGroup,
          holoMat: null,
          finishMat,
          bonusDiamond: null,
          collected: false,
        });
        continue;
      }

      const phaseOffset = (i * 1.17) % (Math.PI * 2);
      const holoMat = buildHoloRingMaterial(0x6cd0ff);
      const torus = new THREE.Mesh(
        new THREE.TorusGeometry(RACE_RING_RADIUS, RACE_RING_TUBE, 12, 32),
        holoMat,
      );
      torus.userData.isRuntimeOnly = true;
      ringGroup.add(torus);
      this._trackGroup.add(ringGroup);
      this._rings.push({
        worldPos: pos.clone(),
        ringGroup,
        holoMat,
        finishMat: null,
        bonusDiamond: null,
        collected: false,
        phaseOffset,
      });
    }

    // Bonus diamonds — source RaceManager.ts:399-437 selects 3 random non-
    // finish rings via a banner-seeded RNG.
    const torusOnly = this._rings.filter((r) => r.holoMat != null);
    const nTorus = torusOnly.length;
    const pickN = Math.min(RACE_BONUS_DIAMOND_COUNT, nTorus);
    if (pickN > 0) {
      const seedAttr = this.getAttribute("seed") | 0;
      const rand = makeRaceRng(seedAttr ^ Math.imul(banner.index, 1009) ^ 0xace1f00d);
      const order = [];
      for (let j = 0; j < nTorus; j++) order.push(j);
      for (let s = order.length - 1; s > 0; s--) {
        const j = Math.floor(rand() * (s + 1));
        const tmp = order[s]; order[s] = order[j]; order[j] = tmp;
      }
      for (let p = 0; p < pickN; p++) {
        const rec = torusOnly[order[p]];
        const dPhase = (p * 2.31 + banner.index * 0.37) % (Math.PI * 2);
        this._attachBonusDiamond(rec, dPhase);
      }
    }
    // Source RaceManager.ts:439-464 — guarantee a diamond on the second-to-last ring.
    const lastRingRec = this._rings[this._rings.length - 2];
    if (lastRingRec && !lastRingRec.bonusDiamond) {
      const dPhase = (banner.index * 0.91 + 2.718) % (Math.PI * 2);
      this._attachBonusDiamond(lastRingRec, dPhase);
    }
  };

  this._attachBonusDiamond = function (rec, dPhase) {
    const dMat = new THREE.MeshStandardNodeMaterial({
      color: 0x88f0ff, emissive: 0x88e8ff, emissiveIntensity: 2.0,
      transparent: true, opacity: 0.95,
    });
    const dMesh = new THREE.Mesh(this._diamondGeo, dMat);
    dMesh.userData.isRuntimeOnly = true;
    dMesh.position.copy(rec.worldPos);
    this._trackGroup.add(dMesh);
    rec.bonusDiamond = {
      mesh: dMesh,
      material: dMat,
      upAxis: rec.worldPos.clone().normalize(),
      spinAngle: 0,
      phaseOffset: dPhase,
    };
