      if (Math.abs(yAxis.y) < 0.85) this._ckAlt.set(0, 1, 0);
      else this._ckAlt.set(1, 0, 0);
      zAxis = this._ckZ.crossVectors(this._ckAlt, yAxis).normalize();
    } else {
      zAxis = zFlat.normalize();
    }
    const xAxis = this._ckX.crossVectors(yAxis, zAxis).normalize();
    const zOrtho = this._ckZo.crossVectors(xAxis, yAxis).normalize();
    this._ckMat.makeBasis(xAxis, yAxis, zOrtho);
    group.quaternion.setFromRotationMatrix(this._ckMat);
  };

  // -----------------------------------------------------------------
  // Update — state machine.
  // -----------------------------------------------------------------
  this.update = function (deltaTime) {
    const dt = Math.min(deltaTime, 0.1);
    this._time = (this._time || 0) + dt;
    this._tickHud();
    this._tickGoToast();

    const playerState = this._getPlayerState();
    if (!playerState) return;
    const playerPos = playerState.pos;

    if (!this._canRace(playerState.vehicle)) {
      if (this._state !== "idle") this._abort();
      return;
    }

    const banners = this.erth.store.get(this.getAttribute("raceBannersStoreKey"));
    if (!banners || !Array.isArray(banners) || banners.length === 0) return;

    if (this._state === "idle" || this._state === "approaching") {
      let nearestIdx = -1;
      let nearestD = Infinity;
      for (let i = 0; i < banners.length; i++) {
        const b = banners[i];
        const dx = playerPos.x - b.worldPos[0];
        const dy = playerPos.y - b.worldPos[1];
        const dz = playerPos.z - b.worldPos[2];
        const d = Math.sqrt(dx * dx + dy * dy + dz * dz);
        if (d < nearestD) { nearestD = d; nearestIdx = b.index; }
      }

      if (this._state === "idle") {
        if (nearestD < RACE_BANNER_TRIGGER_RADIUS && nearestIdx >= 0) {
          this._state = "approaching";
          this._activeBannerIndex = nearestIdx;
          this._approachProgress = 0;
          this._setCountdown("3");
          this._log("approaching banner", nearestIdx);
        }
      } else {
        if (nearestD >= RACE_BANNER_TRIGGER_RADIUS || nearestIdx !== this._activeBannerIndex || this._activeBannerIndex < 0) {
          this._state = "idle";
          this._setCountdown(null);
        } else {
          this._approachProgress += dt / RACE_APPROACH_FILL_SEC;
          const p = Math.min(1, this._approachProgress);
          if (p < 1 / 3) this._setCountdown("3");
          else if (p < 2 / 3) this._setCountdown("2");
          else this._setCountdown("1");
          if (this._approachProgress >= 1) {
            this._startRaceAfterApproach(banners, playerState);
          }
        }
      }
      return;
    }

    if (this._state === "racing") {
      this._raceTimer -= dt;
      this._setTimerText(this._raceTimer);

      for (let ri = 0; ri < this._rings.length; ri++) {
        const r = this._rings[ri];
        if (r.collected) continue;

        if (ri === this._currentRingIndex && r.holoMat) {
          const pulse = 1 + RACE_TARGET_PULSE_AMP * Math.sin(this._time * RACE_TARGET_PULSE_HZ);
          r.ringGroup.scale.setScalar(pulse);
        } else if (r.holoMat) {
          r.ringGroup.scale.setScalar(1);
        }

        if (r.bonusDiamond) {
          const bd = r.bonusDiamond;
          const bob = RACE_DIAMOND_BOB_LIFT + Math.sin(this._time * RACE_DIAMOND_BOB_HZ + bd.phaseOffset) * RACE_DIAMOND_BOB_AMP;
          bd.mesh.position.copy(r.worldPos).addScaledVector(bd.upAxis, bob);
          bd.spinAngle += RACE_DIAMOND_SPIN_SPEED * dt;
          this._qAlign.setFromUnitVectors(this._yAxis, bd.upAxis);
          this._spinQ.setFromAxisAngle(this._yAxis, bd.spinAngle);
          bd.mesh.quaternion.copy(this._qAlign).multiply(this._spinQ);
        }
      }

      const target = this._rings[this._currentRingIndex];
      if (target && !target.collected) {
        const dx = playerPos.x - target.worldPos.x;
        const dy = playerPos.y - target.worldPos.y;
        const dz = playerPos.z - target.worldPos.z;
        const d = Math.sqrt(dx * dx + dy * dy + dz * dz);
        if (d < RACE_COLLECT_RADIUS) {
          const isFinishBanner = (this._currentRingIndex === RACE_CHECKPOINT_COUNT - 1);
          this.erth.store.set("tinyskies/raceSfxCue", isFinishBanner ? "celebrate_1" : "chime_1");
          target.collected = true;
          target.ringGroup.visible = false;
          if (target.bonusDiamond) {
            target.bonusDiamond.mesh.getWorldPosition(this._scratchBdW);
            target.bonusDiamond.mesh.visible = false;
            this.erth.store.set("tinyskies/bonusDiamondCollected", {
              x: this._scratchBdW.x, y: this._scratchBdW.y, z: this._scratchBdW.z,
            });
          }
          this._currentRingIndex++;
          if (this._currentRingIndex >= RACE_CHECKPOINT_COUNT) {
            this._win();
            return;
          }
        }
      }

      if (this._raceTimer <= 0) this._cleanupLose();
    }
  };

  this._startRaceAfterApproach = function (banners, playerState) {
    const banner = banners.find((b) => b.index === this._activeBannerIndex);
    if (!banner) {
      this._state = "idle";
      this._setCountdown(null);
      return;
    }
    this.erth.store.set(this.getAttribute("raceBannersVisibilityCommandKey"), {
      visible: false, exceptIndex: -1,
    });
    this._buildTrack(banner, playerState);
    this._state = "racing";
    this._setCountdown(null);
    this._raceTimer = this._isCarpet(playerState.vehicle) ? RACE_TIME_LIMIT_CARPET : RACE_TIME_LIMIT;
    this._setTimerText(this._raceTimer);
    this.erth.store.set("tinyskies/raceSfxCue", "race_start_1");
    this._showGoToast();
    this._log("race started, banner", banner.index);
  };

  this._win = function () {
    const counterKey = this.getAttribute("raceWonStoreKey");
    const prev = this.erth.store.get(counterKey) || 0;
    this.erth.store.set(counterKey, prev + 1);
    this.erth.store.set(this.getAttribute("raceXpStoreKey"), {
      amount: this.getAttribute("raceXpAmount"),
      source: "race",
    });
    this.erth.store.set("tinyskies/raceSfxCue", "cheer_1");
    this._log("race won, lifetime wins", prev + 1);
    this._cleanupAfterRace();
  };

  this._cleanupLose = function () {
    this._log("race lost");
    this._cleanupAfterRace();
  };

  this._cleanupAfterRace = function () {
    this._state = "idle";
    while (this._trackGroup.children.length > 0) {
      this._trackGroup.remove(this._trackGroup.children[0]);
    }
    for (const r of this._rings) {
