code: |-
  @import "terrain" as T;

  const LOG_TAG = "[tinyskies.floatingLanterns]";

  // Match source FloatingLanterns.ts:21-28.
  const CLUSTER_ALTITUDE = 0.55;
  const CLUSTER_SPREAD = 0.4;
  const SWAY_SPEED = 0.35;
  const SWAY_AMP = 0.018;
  const BOB_SPEED = 0.6;
  const BOB_AMP = 0.012;

  function seededRandom(seed) {
    let s = seed >>> 0;
    if (s === 0) s = 1;
    return function () {
      s = (s * 16807) % 2147483647;
      return (s - 1) / 2147483646;
    };
  }

  function makeLanternSprite() {
    const size = 64;
    const canvas = document.createElement("canvas");
    canvas.width = size;
    canvas.height = size;
    const ctx = canvas.getContext("2d");
    const grad = ctx.createRadialGradient(size / 2, size / 2, 0, size / 2, size / 2, size / 2);
    // Match source FloatingLanterns.ts fragment palette: bright core → warm red → deep red.
    grad.addColorStop(0.0, "rgba(255,180,90,1.0)");
    grad.addColorStop(0.45, "rgba(220,50,20,0.85)");
    grad.addColorStop(0.75, "rgba(140,15,5,0.45)");
    grad.addColorStop(1.0, "rgba(60,5,2,0)");
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, size, size);
    const tex = new THREE.CanvasTexture(canvas);
    tex.colorSpace = THREE.SRGBColorSpace;
    return tex;
  }

  let game;

  this.init = function (_game) {
    game = _game;
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };
    this._buildVisuals(this.gameObject._internal.three);
    const lanterns = this._lanterns;
    this._log("init", lanterns ? lanterns.length : 0, "lanterns");
  };

  this.onEditorAdded = function (editor) {
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };
    this._buildVisuals(this.gameObject._internal.three);
    if (this._opacityUniform) this._opacityUniform.value = 0.5;
  };

  this.onEditorAttributesUpdated = function () {
    this._teardownVisuals();
    this._buildVisuals(this.gameObject._internal.three);
  };

  this.onEditorDispose = function () {
    this._teardownVisuals();
  };

  this.update = function (deltaTime) {
