    if (this._opacityUniform) {
      const w = this.erth.store.get("tinyskies/nightWeight");
      const nightWeight = typeof w === "number" ? w : 1;
      this._opacityUniform.value = 0.3 + 0.7 * nightWeight;
    }
  };

  this._buildVisuals = function (parent) {
    const TSL = THREE.TSL;
    const globeRadius = this.getAttribute("globeRadius");
    const clusterCount = this.getAttribute("clusterCount");
    const lanternsPerCluster = this.getAttribute("lanternsPerCluster");
    const seed = this.getAttribute("seed");

    const root = new THREE.Group();
    root.name = "tinyskiesFloatingLanternsRoot";
    root.userData.isRuntimeOnly = true;

    this._spriteTex = makeLanternSprite();
    const totalCount = clusterCount * lanternsPerCluster;
    const positions = new Float32Array(totalCount * 3);
    const sizes = new Float32Array(totalCount);
    const lanterns = [];
    const terrainSeed = this.getAttribute("terrainSeed");
    const terrainType = this.getAttribute("terrainType");
    const landOnly = !!this.getAttribute("landOnly");

    for (let c = 0; c < clusterCount; c++) {
      const rand = seededRandom(seed + c * 1000003);
      // Random surface point for the cluster center — re-roll up to N times if
      // landOnly and the rolled point falls in ocean.
      let nx = 0, ny = 0, nz = 0;
      const maxAttempts = landOnly ? 24 : 1;
      for (let attempt = 0; attempt < maxAttempts; attempt++) {
        const theta = rand() * Math.PI * 2;
        const phi = Math.acos(2 * rand() - 1);
        nx = Math.sin(phi) * Math.cos(theta);
        ny = Math.sin(phi) * Math.sin(theta);
        nz = Math.cos(phi);
        if (!landOnly) break;
        const sample = T.sampleTerrain(terrainSeed, terrainType, nx, ny, nz);
        if (sample.isLand) break;
      }
      // Lift cluster altitude above whatever terrain is at this point.
      const surfaceDisp = T.surfaceDisplacementAt(terrainSeed, terrainType, nx, ny, nz);
      const refUp = new THREE.Vector3(0, 1, 0);
      const surfaceNormal = new THREE.Vector3(nx, ny, nz);
      const baseCenter = surfaceNormal.clone().multiplyScalar(globeRadius + surfaceDisp + CLUSTER_ALTITUDE);
      // Tangent frame at this point: derive east from arbitrary perpendicular to up.
      const upLocal = surfaceNormal.clone();
      const tmp = Math.abs(upLocal.y) < 0.95 ? refUp.clone() : new THREE.Vector3(1, 0, 0);
      const east = new THREE.Vector3().crossVectors(upLocal, tmp).normalize();
      const north = new THREE.Vector3().crossVectors(east, upLocal).normalize();

      for (let i = 0; i < lanternsPerCluster; i++) {
        const idx = c * lanternsPerCluster + i;
        const localR = (rand() * 0.7 + 0.3) * CLUSTER_SPREAD;
        const localTheta = rand() * Math.PI * 2;
        const offsetEast = Math.cos(localTheta) * localR;
        const offsetNorth = Math.sin(localTheta) * localR;
        // Random small altitude offset (lanterns drift at slightly varied heights).
        const altOffset = (rand() - 0.5) * 0.1;
        const basePos = baseCenter.clone()
          .addScaledVector(east, offsetEast)
          .addScaledVector(north, offsetNorth)
          .addScaledVector(upLocal, altOffset);

        positions[idx * 3] = basePos.x;
        positions[idx * 3 + 1] = basePos.y;
        positions[idx * 3 + 2] = basePos.z;
        sizes[idx] = 14 + rand() * 12; // pixel size

        lanterns.push({
          basePos: basePos,
          up: upLocal,
          east: east,
          phase: rand() * Math.PI * 2,
          bobPhase: rand() * Math.PI * 2,
        });
      }
    }

    const geo = new THREE.BufferGeometry();
    geo.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    geo.setAttribute("aSize", new THREE.BufferAttribute(sizes, 1));

    const opacityUniform = TSL.uniform(1.0);

    const mat = new THREE.PointsNodeMaterial({
      map: this._spriteTex,
      transparent: true,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
    });
    mat.sizeNode = TSL.attribute("aSize");
    mat.colorNode = TSL.vec4(TSL.float(2.0), TSL.float(2.0), TSL.float(2.0), opacityUniform);
    mat.opacityNode = opacityUniform;

    const points = new THREE.Points(geo, mat);
    points.frustumCulled = false;
    points.userData.isRuntimeOnly = true;
    root.add(points);
    parent.add(root);

    this._root = root;
    this._mesh = points;
    this._mat = mat;
    this._geo = geo;
    this._positions = positions;
    this._posAttr = geo.attributes.position;
    this._lanterns = lanterns;
    this._opacityUniform = opacityUniform;
    this._time = 0;
  };

  this._teardownVisuals = function () {
    if (this._geo) this._geo.dispose();
    if (this._mat) this._mat.dispose();
    if (this._spriteTex) {
      this._spriteTex.dispose();
      this._spriteTex = null;
    }
    if (this._root && this._root.parent) this._root.parent.remove(this._root);
    this._root = null;
    this._mesh = null;
    this._mat = null;
    this._geo = null;
    this._positions = null;
    this._posAttr = null;
    this._lanterns = null;
    this._opacityUniform = null;
  };

  this.dispose = function () {
    this._log("dispose");
    if (this._spriteTex) this._spriteTex.dispose();
    this._teardownVisuals();
  };

