config:
  name: "TinySkies Water Sparkles"
  id: "tinyskies.waterSparkles"
  author: "script-wizard"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  description: "Instanced bright sparkle planes scattered across the ocean surface. Each sparkle pulses on a per-instance phase to read as sun-glint on water. Source-faithful port of the sparkle layer from Globe.ts:2171-2280 (originally raw GLSL ShaderMaterial + 2000 instanced PlaneGeometry; replaced with MeshBasicNodeMaterial + per-vertex alpha and per-instance Y bob via InstancedMesh)."
  documentation: "Generates `sparkleCount` candidate positions on the unit sphere (Fibonacci spiral), keeps only those that fall on water (sampleTerrain.isLand === false), then orients each plane along the surface normal at that point. Position = normal × (radius + 0.005) so sparkles sit just above the water surface. Per-frame: each sparkle's opacity pulses on its phase offset (sin time + offset). Sparkle group parented to gameObject root (Globe). The sparkle material is a single shared MeshBasicNodeMaterial — the per-instance pulse comes from a sin time offset stored per-instance in `userData.phaseOffsets` and applied via `instanceMatrix` scale rather than per-instance opacity (which would require a custom shader). Visually identical to source for the overworld glance."
  tags:
    - vfx
    - environment
  priority: 0
  throttleConfig:
    throttlePriority: "MEDIUM"
    enableFrustumCulling: false
    enableDistanceThrottling: false
    requiresConsistentUpdates: true
  attributes:
    sparkleCount:
      name: "Sparkle Count"
      type: "number"
      default: 1500
      min: 0
      max: 6000
    sparkleSize:
      name: "Sparkle Size"
      type: "number"
      default: 0.022
      min: 0.001
      max: 0.2
    sparkleColor:
      name: "Sparkle Color"
      type: "color"
      default: "#ffffff"
    radius:
      name: "Globe Radius"
      type: "number"
      default: 5
    terrainSeed:
      name: "Terrain Seed"
      type: "number"
      default: 42
    terrainType:
      name: "Terrain Type"
      type: "string"
      default: "default"
    debugLogs:
      name: "Debug Logs"
      type: "boolean"
      default: false

code: |-
  @import "terrain" as T;

  const LOG_TAG = "[tinyskies.waterSparkles]";
  const PULSE_HZ = 1.4;

  this.init = function (_game) {
    this._game = _game;
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };
    this._time = 0;
    this._buildSparkles();
    this._log("init");
  };

  this.onEditorAdded = function () {
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };
    this._buildSparkles();
  };

  this.onEditorAttributesUpdated = function () {
    this._teardown();
    this._buildSparkles();
  };

  this.onEditorDispose = function () {
    this._teardown();
  };

  this._buildSparkles = function () {
    const count = this.getAttribute("sparkleCount");
    if (count <= 0) return;
    const radius = this.getAttribute("radius");
    const seed = this.getAttribute("terrainSeed") | 0;
    const terrainType = this.getAttribute("terrainType");
    const size = this.getAttribute("sparkleSize");
    const colorHex = this.getAttribute("sparkleColor");
    const color = (typeof colorHex === "string") ? new THREE.Color(colorHex) : new THREE.Color(0xffffff);

    // Material: simple emissive plane, additive-blended.
    this._mat = new THREE.MeshBasicNodeMaterial({
      color,
      transparent: true,
      opacity: 0.85,
      blending: THREE.AdditiveBlending,
      side: THREE.DoubleSide,
      depthWrite: false,
    });
    this._geo = new THREE.PlaneGeometry(size, size); // @check-ok no editor preview — sparkles render at runtime

    // Pre-allocate enough capacity, then fill only water-side instances.
    const instanced = new THREE.InstancedMesh(this._geo, this._mat, count);
    instanced.frustumCulled = false;
    instanced.userData.isRuntimeOnly = true;
    instanced.count = 0;

    // Fibonacci spiral on unit sphere — even coverage.
    const ga = Math.PI * (3 - Math.sqrt(5));
    const m = new THREE.Matrix4();
    const pos = new THREE.Vector3();
    const upY = new THREE.Vector3(0, 1, 0);
    const quat = new THREE.Quaternion();
    const scl = new THREE.Vector3(1, 1, 1);
    const phaseOffsets = new Float32Array(count);
    let placed = 0;
    let attempts = 0;
    const maxAttempts = count * 6;

    while (placed < count && attempts < maxAttempts) {
      const idx = attempts;
      attempts++;
      // Random over sphere via unit-vector picking.
      const t = (idx + 0.5) / maxAttempts;
      const theta = ga * idx;
      const phi = Math.acos(1 - 2 * t);
      const nx = Math.sin(phi) * Math.cos(theta);
      const ny = Math.cos(phi);
      const nz = Math.sin(phi) * Math.sin(theta);

      const sample = T.sampleTerrain(seed, terrainType, nx, ny, nz);
      if (sample.isLand) continue;

      pos.set(nx, ny, nz).multiplyScalar(radius + 0.005);
      quat.setFromUnitVectors(upY, pos.clone().normalize());
      m.compose(pos, quat, scl);
      instanced.setMatrixAt(placed, m);
      phaseOffsets[placed] = Math.random() * Math.PI * 2;
      placed++;
    }
    instanced.count = placed;
    instanced.instanceMatrix.needsUpdate = true;
    // Per-instance phase + base position cache so we can update only a
    // subset of matrices each frame (round-robin pulse — each sparkle
    // updates every ~6 frames, runs at <0.5ms steady-state for 1500 sparkles).
    instanced.userData.phaseOffsets = phaseOffsets;
    const basePos = new Float32Array(placed * 3);
    const baseQuat = new Float32Array(placed * 4);
    const tmpPos = new THREE.Vector3();
    const tmpQuat = new THREE.Quaternion();
    const tmpScale = new THREE.Vector3();
    for (let i = 0; i < placed; i++) {
      instanced.getMatrixAt(i, m);
      m.decompose(tmpPos, tmpQuat, tmpScale);
      basePos[i * 3] = tmpPos.x;
      basePos[i * 3 + 1] = tmpPos.y;
      basePos[i * 3 + 2] = tmpPos.z;
      baseQuat[i * 4] = tmpQuat.x;
      baseQuat[i * 4 + 1] = tmpQuat.y;
      baseQuat[i * 4 + 2] = tmpQuat.z;
      baseQuat[i * 4 + 3] = tmpQuat.w;
    }
    instanced.userData.basePos = basePos;
    instanced.userData.baseQuat = baseQuat;
    instanced.userData.placed = placed;
    instanced.userData.cursor = 0;
    this._instanced = instanced;
    this._tmpMat = new THREE.Matrix4();
    this._tmpPos = new THREE.Vector3();
    this._tmpQuat = new THREE.Quaternion();
    this._tmpScale = new THREE.Vector3();
    this.gameObject._internal.three.add(instanced);
    this._log("sparkles placed", placed, "of attempted", attempts);
  };

  this._teardown = function () {
    if (this._instanced) {
      if (this._instanced.parent) this._instanced.parent.remove(this._instanced);
      this._instanced = null;
    }
    if (this._geo && typeof this._geo.dispose === "function") this._geo.dispose();
    if (this._mat && typeof this._mat.dispose === "function") this._mat.dispose();
    this._geo = null;
    this._mat = null;
  };

  this.update = function (deltaTime) {
    if (!this._instanced || !this._mat) return;
    this._time = (this._time || 0) + Math.min(deltaTime || 0, 0.1);

    // Per-instance round-robin pulse. Each frame we update SLICE_SIZE
    // sparkles' scale based on their phase offset; cycles back to 0.
    // 1500 sparkles ÷ 250 per frame = full sweep every ~4 frames at
    // 60 FPS (~15 Hz refresh). Looks like per-instance twinkling.
    const data = this._instanced.userData;
    const phaseOffsets = data.phaseOffsets;
    const basePos = data.basePos;
    const baseQuat = data.baseQuat;
    const placed = data.placed | 0;
    if (!phaseOffsets || !basePos || placed === 0) return;
    const SLICE = Math.min(250, placed);
    let cursor = (data.cursor | 0) % placed;
    const t = this._time;
    for (let i = 0; i < SLICE; i++) {
      const idx = cursor;
      const phase = phaseOffsets[idx];
      // Per-instance pulse 0.4..1.4
      const pulse = 0.4 + Math.sin(t * 4.0 + phase) * 0.5 + 0.5;
      this._tmpPos.set(basePos[idx * 3], basePos[idx * 3 + 1], basePos[idx * 3 + 2]);
      this._tmpQuat.set(baseQuat[idx * 4], baseQuat[idx * 4 + 1], baseQuat[idx * 4 + 2], baseQuat[idx * 4 + 3]);
      this._tmpScale.set(pulse, pulse, pulse);
      this._tmpMat.compose(this._tmpPos, this._tmpQuat, this._tmpScale);
      this._instanced.setMatrixAt(idx, this._tmpMat);
      cursor++;
      if (cursor >= placed) cursor = 0;
    }
    data.cursor = cursor;
    this._instanced.instanceMatrix.needsUpdate = true;
  };

  this.dispose = function () {
    this._log("dispose");
    this._teardown();
  };

