config:
  name: "TinySkies Day/Night Cycle"
  id: "tinyskies.dayNightCycle"
  author: "script-wizard"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  description: "195s wall-clock cycle blending day → evening → night → day. Drives scene background, fog, hemisphere/ambient/directional lights, and publishes nightWeight/dayWeight/sunDirection/oceanShallow/oceanDeep/atmosphereGlow store keys for ambience consumers."
  documentation: "Verbatim port of source DayNightCycle.ts (195s cycle: 60s day → 15s transition → 30s evening → 15s transition → 60s night → 15s back-to-day). moonProgress / getRainWeight / getMusicWeights are MVP-deferred (no moon, weather, audio yet). Caches the engine's hemisphere/ambient/directional light refs in init() so update() doesn't re-traverse the scene each frame. Mutates scene.fog.color/near/far in place; scene.background is replaced with a Color when needed. Editor preview locked to the day preset (no animation in editor)."
  tags:
    - environment
    - master
  priority: 0
  throttleConfig:
    throttlePriority: "CRITICAL"
    enableFrustumCulling: false
    enableDistanceThrottling: false
    requiresConsistentUpdates: true
  attributes:
    worldSeed:
      name: "World Seed (cycle phase offset)"
      type: "number"
      default: 42
      min: 0
      max: 1000000
    cycleSecondsOverride:
      name: "Cycle Length Override (s, 0 = source default 195)"
      type: "number"
      default: 0
      min: 0
      max: 1200
    debugLogs:
      name: "Debug Logs"
      type: "boolean"
      default: false

code: |-
  const LOG_TAG = "[tinyskies.dayNightCycle]";

  // Source DayNightCycle.ts cycle layout (TOTAL_CYCLE = 195s).
  const TOTAL_CYCLE_DEFAULT = 195;

  // Sky presets ported verbatim from source SkyPresets.ts.
  // (Drop fields the MVP doesn't use: sun2*, fill*, fill2*, back*, oceanFoam,
  // flareColorScale, cloudOpacity — they exist in source for the secondary suns,
  // ocean foam ring, and lens-flare which are deferred.)
  const DAY_PRESET = {
    fogColor: 0x60ccde, fogNear: 15, fogFar: 40,
    backgroundColor: 0xa8c8e8,
    hemiSkyColor: 0x80ccdd, hemiGroundColor: 0x66aa44, hemiIntensity: 1.75,
    ambientColor: 0xffffff, ambientIntensity: 1.25,
    sunColor: 0xfff0d0, sunIntensity: 5.0,
    oceanShallow: 0x2a8ca0, oceanDeep: 0x1560a0,
    atmosphereGlow: 0xbbddcc,
    stars: false, aurora: false,
  };
  const EVENING_PRESET = {
    fogColor: 0xc07848, fogNear: 12, fogFar: 35,
    backgroundColor: 0xc07848,
    hemiSkyColor: 0xff9944, hemiGroundColor: 0x554422, hemiIntensity: 0.94,
    ambientColor: 0xffd8a0, ambientIntensity: 0.44,
    sunColor: 0xffaa40, sunIntensity: 3.5,
    oceanShallow: 0x5a4a98, oceanDeep: 0x302868,
    atmosphereGlow: 0xffcc44,
    stars: false, aurora: false,
  };
  const NIGHT_PRESET = {
    fogColor: 0x08142c, fogNear: 10, fogFar: 30,
    backgroundColor: 0x08142c,
    hemiSkyColor: 0x283c80, hemiGroundColor: 0x10202c, hemiIntensity: 0.625,
    ambientColor: 0x7088bb, ambientIntensity: 0.375,
    sunColor: 0x102060, sunIntensity: 1.25,
    oceanShallow: 0x081838, oceanDeep: 0x040c20,
    atmosphereGlow: 0x2850aa,
    stars: true, aurora: true,
  };

  // Cycle segments — verbatim from source DayNightCycle.ts:27-34.
  // [endSec, fromPreset, toPreset, isTransition].
  function getSegments() {
    return [
      [60,  DAY_PRESET,     DAY_PRESET,     false],
      [75,  DAY_PRESET,     EVENING_PRESET, true],
      [105, EVENING_PRESET, EVENING_PRESET, false],
      [120, EVENING_PRESET, NIGHT_PRESET,   true],
      [180, NIGHT_PRESET,   NIGHT_PRESET,   false],
      [195, NIGHT_PRESET,   DAY_PRESET,     true],
    ];
  }

  function lerp(a, b, t) { return a + (b - a) * t; }
  function lerpColorHexInto(out, a, b, t) {
    out.set(a);
    const tmp = new THREE.Color(b);
    out.lerp(tmp, t);
  }

  let game;

  this.init = function (_game) {
    game = _game;
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };

    // Pre-allocated working color set (hot-path rule).
    this._cBackground = new THREE.Color();
    this._cFog = new THREE.Color();
    this._cHemiSky = new THREE.Color();
    this._cHemiGround = new THREE.Color();
    this._cAmbient = new THREE.Color();
    this._cSun = new THREE.Color();
    this._cOceanShallow = new THREE.Color();
    this._cOceanDeep = new THREE.Color();
    this._cAtmosGlow = new THREE.Color();

    // Sun direction (matches source Game.ts:1187 fixed sun position).
    this._sunDir = new THREE.Vector3(10, 12, 5).normalize();

    // Pre-allocated publish-side Color objects. The cycle copies into these
    // each frame; consumers read them fresh from the store and (per their own
    // discipline) `.copy()` into their local material uniforms. The store
    // reference itself is set once in init() so no allocations land in update().
    this._pubOceanShallow = new THREE.Color();
    this._pubOceanDeep = new THREE.Color();
    this._pubAtmosGlow = new THREE.Color();

    // Cache engine light refs once. Source has 3 directional lights; the engine
    // provides exactly one configurable `Directional Light`. The hemisphere /
    // ambient lights live on the scene root after the stemscript `scene lighting`
    // command runs.
    this._hemiLight = null;
    this._ambientLight = null;
    this._dirLight = null;
    this._cacheLightRefs();

    // Publish stable references — values mutate in-place each frame in update().
    const store = this.erth.store;
    store.set("tinyskies/sunDirection", this._sunDir);
    store.set("tinyskies/oceanShallow", this._pubOceanShallow);
    store.set("tinyskies/oceanDeep", this._pubOceanDeep);
    store.set("tinyskies/atmosphereGlow", this._pubAtmosGlow);
    this._log("init");
  };

  this._cacheLightRefs = function () {
    if (!game || !game.scene) return;
    game.scene.traverse((obj) => {
      if (!obj) return;
      if (obj.isHemisphereLight && !this._hemiLight) this._hemiLight = obj;
      else if (obj.isAmbientLight && !this._ambientLight) this._ambientLight = obj;
      else if (obj.isDirectionalLight && !this._dirLight) this._dirLight = obj;
    });
  };

  this._getCycleTime = function () {
    const totalCycle = this.getAttribute("cycleSecondsOverride") || TOTAL_CYCLE_DEFAULT;
    const worldSeed = this.getAttribute("worldSeed");
    const offsetSec = worldSeed % totalCycle;
    const now = Date.now() / 1000;
    return ((now + offsetSec) % totalCycle + totalCycle) % totalCycle;
  };

  this._computePreset = function (out) {
    const time = this._getCycleTime();
    const segments = getSegments();
    let segStart = 0;
    let from = DAY_PRESET, to = DAY_PRESET, t = 0, isTransition = false;
    for (const seg of segments) {
      const segEnd = seg[0];
      if (time < segEnd) {
        from = seg[1];
        to = seg[2];
        isTransition = seg[3];
        if (isTransition) {
          const dur = segEnd - segStart;
          const raw = (time - segStart) / dur;
          t = raw * raw * (3 - 2 * raw); // smoothstep
        } else {
          t = 0;
        }
        break;
      }
      segStart = segEnd;
    }
    out.fogNear = lerp(from.fogNear, to.fogNear, t);
    out.fogFar = lerp(from.fogFar, to.fogFar, t);
    out.hemiIntensity = lerp(from.hemiIntensity, to.hemiIntensity, t);
    out.ambientIntensity = lerp(from.ambientIntensity, to.ambientIntensity, t);
    out.sunIntensity = lerp(from.sunIntensity, to.sunIntensity, t);
    lerpColorHexInto(this._cBackground, from.backgroundColor, to.backgroundColor, t);
    lerpColorHexInto(this._cFog, from.fogColor, to.fogColor, t);
    lerpColorHexInto(this._cHemiSky, from.hemiSkyColor, to.hemiSkyColor, t);
    lerpColorHexInto(this._cHemiGround, from.hemiGroundColor, to.hemiGroundColor, t);
    lerpColorHexInto(this._cAmbient, from.ambientColor, to.ambientColor, t);
    lerpColorHexInto(this._cSun, from.sunColor, to.sunColor, t);
    lerpColorHexInto(this._cOceanShallow, from.oceanShallow, to.oceanShallow, t);
    lerpColorHexInto(this._cOceanDeep, from.oceanDeep, to.oceanDeep, t);
    lerpColorHexInto(this._cAtmosGlow, from.atmosphereGlow, to.atmosphereGlow, t);
    out.timeOfDay = (t < 0.5 ? from : to).stars ? "night" :
                    (t < 0.5 ? from : to).backgroundColor === EVENING_PRESET.backgroundColor ? "evening" : "day";
  };

  this._computeNightWeight = function () {
    const time = this._getCycleTime();
    const totalCycle = this.getAttribute("cycleSecondsOverride") || TOTAL_CYCLE_DEFAULT;
    // Source DayNightCycle.ts:158-170 — assumes the standard 195s layout. If a
    // user overrides cycle length, scale segment boundaries proportionally.
    const k = totalCycle / TOTAL_CYCLE_DEFAULT;
    const t60 = 60 * k, t75 = 75 * k, t105 = 105 * k, t120 = 120 * k, t180 = 180 * k, t195 = 195 * k;
    let w = 0;
    if (time < t60) w = 0;
    else if (time < t75) { const tx = (time - t60) / (t75 - t60); w = tx * tx * (3 - 2 * tx) * 0.5; }
    else if (time < t105) w = 0.5;
    else if (time < t120) { const tx = (time - t105) / (t120 - t105); w = 0.5 + tx * tx * (3 - 2 * tx) * 0.5; }
    else if (time < t180) w = 1;
    else if (time < t195) { const tx = (time - t180) / (t195 - t180); w = 1 - tx * tx * (3 - 2 * tx); }
    return w;
  };

  this.update = function () {
    if (!game || !game.scene) return;
    if (!this._hemiLight || !this._ambientLight || !this._dirLight) {
      this._cacheLightRefs();
    }
    const out = { fogNear: 0, fogFar: 0, hemiIntensity: 0, ambientIntensity: 0, sunIntensity: 0, timeOfDay: "day" };
    this._computePreset(out);

    // Scene background — the engine sets this as a Color via `scene background`
    // command; mutate that color in-place if possible.
    if (game.scene.background && game.scene.background.isColor) {
      game.scene.background.copy(this._cBackground);
    } else if (!this._installedBackground) {
      // First-time fallback: install a Color we own so future frames can mutate
      // it in place without allocating. Guarded by `!_installedBackground` so
      // this path runs at most once.
      const installed = new THREE.Color().copy(this._cBackground);                  // @check-ok one-shot fallback when stemscript didn't set scene.background
      game.scene.background = installed;
      this._installedBackground = installed;
    }

    // Fog mutation.
    if (game.scene.fog) {
      if (game.scene.fog.color && game.scene.fog.color.copy) {
        game.scene.fog.color.copy(this._cFog);
      }
      // Linear Fog has near/far; FogExp2 has only density.
      if (typeof game.scene.fog.near === "number") game.scene.fog.near = out.fogNear;
      if (typeof game.scene.fog.far === "number") game.scene.fog.far = out.fogFar;
    }

    // Lights — refs cached at init.
    if (this._hemiLight) {
      this._hemiLight.color.copy(this._cHemiSky);
      this._hemiLight.groundColor.copy(this._cHemiGround);
      this._hemiLight.intensity = out.hemiIntensity;
    }
    if (this._ambientLight) {
      this._ambientLight.color.copy(this._cAmbient);
      this._ambientLight.intensity = out.ambientIntensity;
    }
    if (this._dirLight) {
      this._dirLight.color.copy(this._cSun);
      this._dirLight.intensity = out.sunIntensity;
    }

    // Update published colors in place — references were registered once in init().
    this._pubOceanShallow.copy(this._cOceanShallow);
    this._pubOceanDeep.copy(this._cOceanDeep);
    this._pubAtmosGlow.copy(this._cAtmosGlow);

    const store = this.erth.store;
    const nightWeight = this._computeNightWeight();
    store.set("tinyskies/nightWeight", nightWeight);
    store.set("tinyskies/dayWeight", 1 - nightWeight);
    store.set("tinyskies/timeOfDay", out.timeOfDay);
  };

  // No editor preview — the editor maintains its own scene state and shouldn't
  // be animated by gameplay behaviors. Per CLAUDE.md memory feedback_no_empty_editor_stubs.md,
  // no empty stub is added either; the cycle simply doesn't run in editor.

  this.dispose = function () {
    this._log("dispose");
    this._hemiLight = null;
    this._ambientLight = null;
    this._dirLight = null;
  };

