config:
  name: "TinySkies Globe Monuments"
  id: "tinyskies.globeMonuments"
  author: "script-wizard"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  description: "Final pair of source-deferred landmarks: 1 victory-memorial Statue (procedural figure with vertical beacon beam) and 2 MoonstoneRuin halves (procedural angular crystal-ring fragments with sparse hovering dust). Source loads /3D/statue.glb + /3D/moonstone_left.glb / moonstone_right.glb which we don't have, so geometry is procedural; placement rules and state machine kept verbatim from source. Fidelity tradeoffs documented in FDR-006."
  documentation: "Statue (Globe.ts:3212) source is gated by post-victory ProgressionManager flag `moonFrozenByEternalFlames`; we ship it unconditionally with the same flat-lowland site selection (seed 626262+seed) and add a vertical TSL beacon beam — visually it reads as a memorial. MoonstoneRuins (Globe.ts:3411) source has 2 halves placed in inland sites (seed 771133+seed) with idle/raising/floating phases driven by `cycleStartAt` timestamps — we only ship the idle phase (gentle hover) since the cinematic union flow is gameplay-driven (we have no MoonstoneCinematic controller). Per-half hovering dust uses InstancedMesh of small sprites with TSL-driven sin motion (engine VFX retrofit possible — see FDR-006)."
  tags:
    - visual
    - environment
    - landmarks
  priority: 0
  throttleConfig:
    throttlePriority: "HIGH"
    enableFrustumCulling: false
    enableDistanceThrottling: false
    requiresConsistentUpdates: true
  attributes:
    radius:
      name: "Globe Radius"
      type: "number"
      default: 5
      min: 0.5
      max: 200
    terrainSeed:
