      description: "When true, statue spawns regardless of store-key gate. Default true matches the existing FDR-006 behavior; set false to require the store-key gate (which any future ProgressionManager port can flip)."
    statueStoreKey:
      name: "Statue Visibility Store Key"
      type: "string"
      default: "tinyskies/statueEnabled"
      description: "When `statueAlwaysVisible` is false, the statue spawns only if `this.erth.store.get(<this key>) === true`. Mirrors source `ProgressionManager.moonFrozenByEternalFlames` victory gate."
    moonstoneRuinCount:
      name: "Moonstone Ruin Count"
      type: "number"
