      max: 6
    moonstoneCinematicStoreKey:
      name: "Moonstone Cinematic Trigger Store Key"
      type: "string"
      default: "tinyskies/moonstoneCinematicTrigger"
      description: "Reserved for a future controller. When set to true via `this.erth.store.set(<this key>, true)`, the moonstone halves run a raise → float → union sequence. Currently logs the trigger; full state machine is FDR-006 followup."
    debugLogs:
      name: "Debug Logs"
      type: "boolean"
      default: false

code: |-
  @import "terrain" as T;
  @import "spherical-math" as S;

  const LOG_TAG = "[tinyskies.globeMonuments]";
  const MOONSTONE_FLOAT_HEIGHT = 0.82;
  const MOONSTONE_HOVER_AMPLITUDE = 0.025;

  function buildSoftSpriteTexture() {
    const canvas = document.createElement("canvas"); // @check-ok
    canvas.width = 64;
    canvas.height = 64;
    const ctx = canvas.getContext("2d");
    if (!ctx) return null;
    const grad = ctx.createRadialGradient(32, 32, 0, 32, 32, 32);
    grad.addColorStop(0, "rgba(255,255,255,1)");
    grad.addColorStop(0.4, "rgba(255,255,255,0.6)");
    grad.addColorStop(1, "rgba(255,255,255,0)");
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, 64, 64);
    const tex = new THREE.CanvasTexture(canvas);
    tex.colorSpace = THREE.SRGBColorSpace;
    return tex;
  }

  // Walks every mesh vertex transformed to world space, returns the smallest
  // projection along `normal`. Used by GLB grounding so models rest on the
  // surface regardless of model-space pivot. Source Globe.ts uses the same
  // helper inline in createPyramid / createStatue / createMoonstoneRuins.
  function minVertexProjectionAlongNormal(root, normal) {
    let minVal = Infinity;
    const v = new THREE.Vector3();
    root.updateMatrixWorld(true);
    root.traverse((child) => {
      if (!child.isMesh) return;
      const pos = child.geometry?.attributes?.position;
      if (!pos) return;
      for (let i = 0; i < pos.count; i++) {
        v.fromBufferAttribute(pos, i);
        v.applyMatrix4(child.matrixWorld);
        const d = v.dot(normal);
        if (d < minVal) minVal = d;
      }
    });
    return minVal;
  }

  function applyRimLight(mat, rimColorHex, intensity, power) {
    const TSL = THREE.TSL;
    const c = new THREE.Color(rimColorHex);
    const viewDir = TSL.normalize(TSL.cameraPosition.sub(TSL.positionWorld));
    // dFdx/dFdy-derived normal — no `normal` attribute needed, so the material compiles cleanly in shadow / AO passes that strip lighting attrs (avoids TSL "Vertex attribute 'normal' not found" warnings that pin frame budget).
    const nW = TSL.normalize(TSL.cross(TSL.dFdx(TSL.positionWorld), TSL.dFdy(TSL.positionWorld)));
    const fresnel = TSL.float(1.0).sub(TSL.dot(viewDir, nW).abs());
    const rim = TSL.vec3(c.r, c.g, c.b).mul(TSL.float(intensity)).mul(TSL.pow(fresnel, TSL.float(power)));
    mat.emissiveNode = rim;
    mat.needsUpdate = true;
  }

  // -----------------------------------------------------------------
  // Procedural statue substitute (source loads /3D/statue.glb).
  // Geometry: pedestal + tapering torso + sphere head + outstretched arms.
  // Topped with a TSL additive beacon beam (the source attaches a
  // PackageQuest beam group with color 0x88ccff).
  // -----------------------------------------------------------------

  function buildStatue() {
    const TSL = THREE.TSL;
    const g = new THREE.Group();
    g.userData.isRuntimeOnly = true;

    const stoneMat = new THREE.MeshStandardNodeMaterial({ color: 0xb8b3a8, flatShading: true, roughness: 0.85, metalness: 0 });
    applyRimLight(stoneMat, 0xe8e0d0, 0.42, 2.7);
    const detailMat = new THREE.MeshStandardNodeMaterial({ color: 0x8e8884, flatShading: true, roughness: 0.85, metalness: 0 });
    applyRimLight(detailMat, 0xd0c8b8, 0.36, 2.7);

    // Pedestal (3-tier)
    const pedBot = new THREE.BoxGeometry(0.20, 0.04, 0.20); pedBot.translate(0, 0.02, 0);
    const pedMid = new THREE.BoxGeometry(0.16, 0.03, 0.16); pedMid.translate(0, 0.055, 0);
    const pedTop = new THREE.BoxGeometry(0.13, 0.025, 0.13); pedTop.translate(0, 0.0825, 0);
    const pedBotMesh = new THREE.Mesh(pedBot, detailMat); pedBotMesh.userData.isRuntimeOnly = true; g.add(pedBotMesh);
    const pedMidMesh = new THREE.Mesh(pedMid, stoneMat);  pedMidMesh.userData.isRuntimeOnly = true; g.add(pedMidMesh);
    const pedTopMesh = new THREE.Mesh(pedTop, detailMat); pedTopMesh.userData.isRuntimeOnly = true; g.add(pedTopMesh);

    // Body (tapered cylinder)
    const bodyY = 0.095;
    const bodyH = 0.18;
    const body = new THREE.CylinderGeometry(0.030, 0.045, bodyH, 12);
    body.translate(0, bodyY + bodyH / 2, 0);
    const bodyMesh = new THREE.Mesh(body, stoneMat); bodyMesh.castShadow = true; bodyMesh.userData.isRuntimeOnly = true; g.add(bodyMesh);

    // Robe folds (vertical stripes at the base)
    for (let i = 0; i < 6; i++) {
      const a = (i / 6) * Math.PI * 2;
      const fold = new THREE.BoxGeometry(0.008, 0.12, 0.008);
      fold.translate(Math.cos(a) * 0.04, bodyY + 0.06, Math.sin(a) * 0.04);
      const foldMesh = new THREE.Mesh(fold, detailMat);
      foldMesh.userData.isRuntimeOnly = true;
      g.add(foldMesh);
    }

    // Outstretched arms (boxes rotated outward)
    const armY = bodyY + bodyH * 0.85;
    for (const side of [-1, 1]) {
      const arm = new THREE.BoxGeometry(0.06, 0.014, 0.014);
      arm.translate(side * 0.05, armY, 0);
      arm.rotateZ(side * -0.3);
      const armMesh = new THREE.Mesh(arm, stoneMat);
      armMesh.userData.isRuntimeOnly = true;
      g.add(armMesh);
      // Hand
      const hand = new THREE.SphereGeometry(0.012, 7, 5);
      hand.translate(side * 0.085, armY + side * 0.015, 0);
      const handMesh = new THREE.Mesh(hand, stoneMat);
      handMesh.userData.isRuntimeOnly = true;
      g.add(handMesh);
    }

    // Head
    const headY = bodyY + bodyH + 0.018;
    const head = new THREE.SphereGeometry(0.025, 12, 10);
    head.translate(0, headY + 0.025, 0);
    const headMesh = new THREE.Mesh(head, stoneMat); headMesh.castShadow = true; headMesh.userData.isRuntimeOnly = true; g.add(headMesh);

    // Crown / halo (thin torus above head)
    const halo = new THREE.TorusGeometry(0.022, 0.003, 6, 16);
    halo.rotateX(Math.PI / 2);
    halo.translate(0, headY + 0.062, 0);
    const haloMat = new THREE.MeshStandardNodeMaterial({ color: 0xd8c890, flatShading: true, roughness: 0.4, metalness: 0.6 });
    haloMat.emissiveNode = TSL.vec3(0.9, 0.78, 0.5).mul(TSL.float(0.8));
    const haloMesh = new THREE.Mesh(halo, haloMat); haloMesh.userData.isRuntimeOnly = true; g.add(haloMesh);

    // Beacon beam — vertical cylinder above the statue with TSL fade.
    // Length-fade from base (full) to top (transparent).
    const beamH = 2.0;
    const beamGeo = new THREE.CylinderGeometry(0.018, 0.05, beamH, 12, 1, true);
    beamGeo.translate(0, headY + 0.08 + beamH / 2, 0);
    const beamMat = new THREE.MeshBasicNodeMaterial({
      transparent: true,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
      side: THREE.DoubleSide,
    });
    const beamColor = TSL.vec3(0.55, 0.78, 1.0); // 0x88ccff source color
    const lenFade = TSL.float(1.0).sub(TSL.uv().y);
    beamMat.colorNode = beamColor;
    beamMat.opacityNode = lenFade.mul(TSL.float(0.55));
    const beam = new THREE.Mesh(beamGeo, beamMat);
    beam.userData.isRuntimeOnly = true;
    g.add(beam);

    return g;
  }

  // -----------------------------------------------------------------
  // Procedural moonstone-ruin half. Source has GLB-loaded ornate ring
  // halves; we substitute with an arched crystal slab — angular,
  // glowing, blue-white. Two halves per ruin, mirrored.
  // -----------------------------------------------------------------

  function buildMoonstoneHalf(mirrored) {
    const TSL = THREE.TSL;
    const g = new THREE.Group();
    g.userData.isRuntimeOnly = true;

    const baseMat = new THREE.MeshStandardNodeMaterial({
      color: 0xc8d8e8,
      flatShading: true,
      roughness: 0.45,
      metalness: 0.15,
    });
    baseMat.emissiveNode = TSL.vec3(0.55, 0.7, 0.95).mul(TSL.float(0.45));
    applyRimLight(baseMat, 0xfff1c0, 0.7, 2.6);

    const detailMat = new THREE.MeshStandardNodeMaterial({
      color: 0xa8b8d0,
      flatShading: true,
      roughness: 0.55,
      metalness: 0.2,
    });
    detailMat.emissiveNode = TSL.vec3(0.4, 0.55, 0.85).mul(TSL.float(0.32));

    // Build a half-arch — 5 faceted blocks following a quarter-circle arc.
    // Source's GLB is one large ring half ~0.875 max-dim; we approximate
    // with ~7 segments curving from base to apex.
    const SEGMENTS = 7;
    const archR = 0.30;
    const archH = 0.36;
    const sideSign = mirrored ? -1 : 1;
    for (let i = 0; i < SEGMENTS; i++) {
      const t = i / (SEGMENTS - 1);
      const angle = sideSign * (Math.PI * 0.5 * t);
      const x = sideSign * Math.cos(angle - sideSign * Math.PI * 0.5) * archR;
      const y = archH * t;
      const z = 0;
      const segH = 0.10 - t * 0.04;
      const segW = 0.08 - t * 0.02;
      const segD = 0.05;
      const block = new THREE.BoxGeometry(segW, segH, segD);
      // Tilt to follow the arc
      block.rotateZ(-sideSign * angle);
      block.translate(x, y, z);
      const mesh = new THREE.Mesh(block, i % 2 === 0 ? baseMat : detailMat);
      mesh.castShadow = true;
      mesh.receiveShadow = true;
      mesh.userData.isRuntimeOnly = true;
      g.add(mesh);
    }
    // A small angular crystal at the apex
    const apex = new THREE.OctahedronGeometry(0.05, 0);
    apex.translate(0, archH + 0.02, 0);
    const apexMesh = new THREE.Mesh(apex, baseMat);
    apexMesh.castShadow = true;
    apexMesh.userData.isRuntimeOnly = true;
    g.add(apexMesh);

    // Buried base anchor (so the half reads as ruin)
    const buried = new THREE.BoxGeometry(0.12, 0.09, 0.10);
    buried.translate(sideSign * archR * 0.7, -0.03, 0);
    buried.rotateZ(sideSign * 0.2);
    const buriedMesh = new THREE.Mesh(buried, detailMat);
    buriedMesh.userData.isRuntimeOnly = true;
    g.add(buriedMesh);

    return g;
  }

  // -----------------------------------------------------------------
  // Lifecycle
  // -----------------------------------------------------------------

  let game;

  this.init = function (_game) {
    game = _game;
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };
    this._buildVisuals(this.gameObject._internal.three);
    this._registerParticleSystemsWithBatchedRenderer();
    this._log("init");
  };

  this.onEditorAdded = function () {
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };
    this._buildVisuals(this.gameObject._internal.three);
  };

  this.onEditorAttributesUpdated = function () {
    this._teardownVisuals();
    this._buildVisuals(this.gameObject._internal.three);
  };

  this.onEditorDispose = function () {
    this._teardownVisuals();
  };

  this.dispose = function () {
    this._log("dispose");
    this._teardownVisuals();
  };

  // Source Globe.ts:5660-5700 idle moonstone update — gentle hover via
  // sin(time * 0.7) * 0.02 along normal + tiny tangent/bitangent jitter.
  // We restrict to the idle phase because we don't have the cinematic
  // post-union state machine.
  this.update = function (deltaTime) {
    if (!this._root) return;
    const dt = Math.min(deltaTime, 0.1);
    this._time = (this._time || 0) + dt;
    const t = this._time;

    // Cinematic trigger hook — store-key polling. When a future controller
    // sets this key to true, the moonstone halves enter a raise → float
    // sequence. We log the rising edge here; the full state machine is
    // FDR-006 followup work (see source Globe.ts:5660-5731 update branch
    // for the raise/floating/postUnion phases).
    const triggerKey = this.getAttribute("moonstoneCinematicStoreKey");
    if (triggerKey) {
      const triggered = this.erth.store.get(triggerKey) === true;
      if (triggered && !this._cinematicTriggered) {
        this._cinematicTriggered = true;
        this._log("moonstone cinematic trigger received — full state machine is FDR-006 followup");
      } else if (!triggered && this._cinematicTriggered) {
        this._cinematicTriggered = false;
      }
    }

    // Hover the moonstone halves
    if (this._moonstoneRuins) {
      for (let i = 0; i < this._moonstoneRuins.length; i++) {
        const ruin = this._moonstoneRuins[i];
        const hover = Math.sin(t * 0.7 + i * 1.31) * MOONSTONE_HOVER_AMPLITUDE;
        const k = i * 2.31;
        const wobble = 0.1;
        ruin.root.position.copy(ruin.basePosition);
        ruin.root.position.addScaledVector(ruin.normal, hover);
        ruin.root.position.addScaledVector(ruin.tangent, Math.sin(t * 19.2 + k) * 0.012 * wobble);
        ruin.root.position.addScaledVector(ruin.bitangent, Math.cos(t * 16.7 + k * 1.3) * 0.012 * wobble);
        ruin.root.quaternion.copy(ruin.restQuaternion);
        ruin.root.rotateOnWorldAxis(ruin.tangent, Math.sin(t * 21.4 + k) * 0.02);
        ruin.root.rotateOnWorldAxis(ruin.bitangent, Math.cos(t * 18.9 + k * 0.9) * 0.02);
      }
    }

    // Moonstone dust is now driven by the engine BatchedRenderer; no
    // per-frame matrix update needed in this behavior.
  };

  // -----------------------------------------------------------------
  // Builders
  // -----------------------------------------------------------------

  this._buildVisuals = function (parent) {
    const radius = this.getAttribute("radius");
    const seed = this.getAttribute("terrainSeed");
    const terrainType = this.getAttribute("terrainType");

    const root = new THREE.Group();
    root.name = "tinyskiesGlobeMonuments";
    root.userData.isRuntimeOnly = true;

    this._moonstoneRuins = [];
    this._particleEmitters = null;
    this._batchedRenderer = null;
    this._time = 0;

    if (this.getAttribute("statueEnabled")) {
      this._buildStatue(root, radius, seed, terrainType);
    }
    this._buildMoonstoneRuins(root, radius, seed, terrainType, this.getAttribute("moonstoneRuinCount"));

    parent.add(root);
    this._root = root;
  };

  // Source Globe.ts:3212 createStatue — picks 1 flat lowland (relax-cap
  // roughness retry; we simplify to a single 0.14 cap). Source seeds
  // 626262+seed (search), 919191+seed (spin).
  this._buildStatue = function (root, radius, seed, terrainType) {
    const rand = S.seededRandom(626262 + seed);
    const propSink = T.getPropTerrainSink();
    const REF_UP = new THREE.Vector3(0, 1, 0);
    const MIN_E = 0.02, MAX_E = 0.32;
    const INLAND_CHECKS = 8, INLAND_CHECK_DIST = 0.07, MAX_WATER = 0.26;
    const ROUGH_RING_DIST = 0.09;

    const ROUGHNESS_CAPS = [0.14, 0.22, 0.3];
    let chosen = null;
    for (const cap of ROUGHNESS_CAPS) {
      const pool = [];
      let attempts = 0;
      while (attempts < 12000 && pool.length < 400) {
        attempts++;
        const theta = rand() * Math.PI * 2;
        const phi = Math.acos(2 * rand() - 1);
        const nx = Math.sin(phi) * Math.cos(theta);
        const ny = Math.cos(phi);
        const nz = Math.sin(phi) * Math.sin(theta);
        const sample = T.sampleTerrain(seed, terrainType, nx, ny, nz);
        if (!sample.isLand) continue;
        if (sample.elevation < MIN_E || sample.elevation > MAX_E) continue;
        if (T.waterRatioAround(seed, terrainType, nx, ny, nz, INLAND_CHECK_DIST, INLAND_CHECKS) > MAX_WATER) continue;
        const rough = T.terrainRingElevationRoughness(seed, terrainType, nx, ny, nz, ROUGH_RING_DIST);
        if (rough > cap) continue;
        pool.push({ normal: new THREE.Vector3(nx, ny, nz), elevation: sample.elevation, rough });
      }
      if (pool.length > 0) {
        pool.sort((a, b) => a.rough - b.rough || a.elevation - b.elevation);
        chosen = pool[0].normal;
        break;
      }
    }
    if (!chosen) return;

    const spin = S.seededRandom(919191 + seed);
    const disp = T.surfaceDisplacementAt(seed, terrainType, chosen.x, chosen.y, chosen.z);
    const surfaceR = radius + disp - propSink;

    // GLB-template clone path. Source Globe.ts:3286-3382 loads /3D/statue.glb
    // at TARGET_MAX_DIM=0.42 with the ProgressionManager
    // `moonFrozenByEternalFlames` victory gate. We replicate the geometry
    // load via the imported StatueModel template; the gate is now a store
    // key (`tinyskies/statueEnabled`, default false) so any future
    // ProgressionManager port can flip it without touching this behavior.
    const TARGET_MAX_DIM = 0.42;
    const statueTemplate = game?.scene?.getObjectByName?.("StatueModel") || null;
    const gateKey = this.getAttribute("statueStoreKey") || "tinyskies/statueEnabled";
    const gateOpen = this.getAttribute("statueAlwaysVisible") === true
      || this.erth.store.get(gateKey) === true;
    if (!gateOpen) {
      this._log("statue gated by store key", gateKey, "— skipping spawn");
      // Track the chosen normal so re-spawn (if the gate later opens via
      // store update) lands at the same site.
      this._statuePendingSite = chosen.clone();
      return;
    }

    let statue;
    if (statueTemplate) {
      statue = statueTemplate.clone(true);
      statue.userData = statue.userData || {};
      statue.userData.isRuntimeOnly = true;
      statue.traverse((c) => {
        if (c) {
          c.userData = c.userData || {};
          c.userData.isRuntimeOnly = true;
          if (c.isMesh) { c.castShadow = true; c.receiveShadow = true; }
          c.visible = true;
        }
      });
      statue.visible = true;
      const box = new THREE.Box3().setFromObject(statue);
      const size = new THREE.Vector3();
      box.getSize(size);
      const maxDim = Math.max(size.x, size.y, size.z, 1e-4);
      statue.scale.setScalar(TARGET_MAX_DIM / maxDim);
    } else {
      statue = buildStatue();
    }

    statue.position.copy(chosen.clone().multiplyScalar(surfaceR));
    statue.quaternion.setFromUnitVectors(REF_UP, chosen);
    statue.rotateY(spin() * Math.PI * 2);
    if (statueTemplate) {
      statue.updateMatrixWorld(true);
      const lift = surfaceR - minVertexProjectionAlongNormal(statue, chosen);
      if (Number.isFinite(lift)) statue.position.addScaledVector(chosen, lift);
    }
    root.add(statue);
    this._log("statue placed at elevation",
      T.sampleTerrain(seed, terrainType, chosen.x, chosen.y, chosen.z).elevation.toFixed(3),
      statueTemplate ? "(GLB)" : "(procedural fallback)");
  };

  // Source Globe.ts:3411 createMoonstoneRuins — places `count` halves at
  // inland sites (seed 771133+seed). Idle hover only; cinematic union
  // phase deferred (no controller in our port).
  this._buildMoonstoneRuins = function (root, radius, seed, terrainType, count) {
    if (count === 0) return;
    const rand = S.seededRandom(771133 + seed);
    const propSink = T.getPropTerrainSink();
    const REF_UP = new THREE.Vector3(0, 1, 0);
    const MIN_E = 0.06, MAX_E = 0.7, MIN_SEP = 0.84;
    const INLAND_CHECKS = 8, INLAND_CHECK_DIST = 0.07, MAX_WATER = 0.26;
    const ROUGH_RING_DIST = 0.085, MAX_ROUGH = 0.26;

    const candidates = [];
    let attempts = 0;
    while (attempts < 8000 && candidates.length < 220) {
      attempts++;
      const theta = rand() * Math.PI * 2;
      const phi = Math.acos(2 * rand() - 1);
      const nx = Math.sin(phi) * Math.cos(theta);
      const ny = Math.cos(phi);
      const nz = Math.sin(phi) * Math.sin(theta);
      const sample = T.sampleTerrain(seed, terrainType, nx, ny, nz);
      if (!sample.isLand) continue;
      if (sample.elevation < MIN_E || sample.elevation > MAX_E) continue;
      if (T.waterRatioAround(seed, terrainType, nx, ny, nz, INLAND_CHECK_DIST, INLAND_CHECKS) > MAX_WATER) continue;
      if (T.terrainRingElevationRoughness(seed, terrainType, nx, ny, nz, ROUGH_RING_DIST) > MAX_ROUGH) continue;
      candidates.push({ normal: new THREE.Vector3(nx, ny, nz), elevation: sample.elevation });
    }
    candidates.sort((a, b) => a.elevation - b.elevation);

    const chosen = [];
    for (const c of candidates) {
      if (chosen.length >= count) break;
      let tooClose = false;
      for (const v of chosen) { if (c.normal.dot(v) > MIN_SEP) { tooClose = true; break; } }
      if (!tooClose) chosen.push(c.normal);
    }
    if (chosen.length === 0) return;

    const spin = S.seededRandom(991122 + seed);

    for (let i = 0; i < chosen.length; i++) {
      const normal = chosen[i];
      const disp = T.surfaceDisplacementAt(seed, terrainType, normal.x, normal.y, normal.z);
      const surfaceR = radius + disp - propSink;
      const basePosition = normal.clone().multiplyScalar(surfaceR);

      // GLB-template clone path. Source Globe.ts:3504-3577 alternates
      // /3D/moonstone_left.glb and /3D/moonstone_right.glb at
      // TARGET_MAX_DIM=0.875 with BURY_DEPTH_RATIO=0.44 (sink along
      // normal so the half reads as ruin). The per-half tilt
      // (TILT_ORNATE_TOWARD_SKY=0.36, TILT_DIAGONAL=0.

meta:
  tool: StemStudio
  type: behavior
  exportVersion: 1

config:
  name: "TinySkies Sky Gremlins"
  id: "tinyskies.skyGremlins"
  author: "script-wizard"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  description: "Flying gremlin enemies that chase the player and shoot paintballs back. Capped MVP — Gremlin King + Hearts pickups deferred."
  documentation: "Pool of `gremlinCount` (default 3) procedural gremlins flying on the globe. Each has spherical state (qPosition, heading, altitude), HP, fire cooldown. AI per gremlin: when player within DETECT_RANGE, turn-toward-player and orbit at STANDOFF_IDEAL; when aim aligned and cooldown ready, fire a paintball projectile that flies toward the player. Player paintball vs gremlin: read `tinyskies/gremlinHits` queue published by paintballSystem; apply 1 damage per hit; on death, fall + respawn after 13-19s. Gremlin paintball vs player (HIT_RADIUS 0.22): push slow/wobble/damage signals into store for the flightController. HP bar billboard above each gremlin tracks remaining HP. Source SkyGremlins.ts is 1507 lines (King variant + retaliate mode + complex armor mesh + multiple shooting patterns); the WebGPU port ships only the basic gremlin (one type). Documented in tinyskies-fidelity-decision-record.md."
  tags:
    - gameplay
    - enemy
  priority: 0
  throttleConfig:
    throttlePriority: "HIGH"
    enableFrustumCulling: false
    enableDistanceThrottling: false
    requiresConsistentUpdates: true
  attributes:
    globeRadius:
      name: "Globe Radius"
      type: "number"
      default: 5
      min: 0.5
      max: 200
    gremlinCount:
      name: "Gremlin Count"
      type: "number"
      default: 3
      min: 1
      max: 12
    seed:
      name: "Spawn Seed"
      type: "number"
      default: 42
      min: 1
      max: 1000000
    kingKillThreshold:
      name: "King Kill Threshold"
      type: "number"
      default: 5
      min: 0
      max: 50
      description: "After this many basic-gremlin kills in a session, the Gremlin King spawns once. Set 0 to spawn the King immediately at scene init; set high to disable until late session."
    kingEnabled:
      name: "King Enabled"
      type: "boolean"
      default: true
    debugLogs:
      name: "Debug Logs"
      type: "boolean"
      default: false

code: |-
  @import "spherical-math" as S;

  const LOG_TAG = "[tinyskies.skyGremlins]";

  // Constants — verbatim from source SkyGremlins.ts:50-103.
  const GREMLIN_HP_MAX = 3;
  const GREMLIN_ALTITUDE_MIN = 0.52;
  const GREMLIN_ALTITUDE_MAX = 0.65;
  const GREMLIN_CRUISE_SPEED = 0.34;
  const GREMLIN_CHASE_SPEED = 0.5;
  const GREMLIN_BOB_SPEED = 2.8;
  const GREMLIN_BOB_AMP = 0.08;
  const GREMLIN_FLAP_SPEED = 11.5;
  const GREMLIN_FLAP_AMP = 0.72;
  const GREMLIN_DETECT_RANGE = 2.25;
  const GREMLIN_STANDOFF_IDEAL = 1.15;
  const GREMLIN_STANDOFF_MIN = 0.92;
  // Source-faithful (SkyGremlins.ts:79). When the gremlin is below this distance,
  // steer tangent-and-retreat instead of straight at the player so the player
  // can yaw around and re-acquire it. Without this, the gremlin closes to 0
  // distance during a player 180° turn and ends up "glued" to the wing.
  const GREMLIN_FIRE_RANGE = 1.6;
  // Gremlin King — promoted in FDR-006 followup. Source SkyGremlins.ts:50-94.
  // Spawns once after `kingKillThreshold` basic gremlins are downed (default 5,
  // matching source's narrative beat). HP 10 (vs 3), longer fire range, slower
  // cooldown. Red/dark recoloring of the same procedural mesh — source's
  // multi-material body/belly/wing scheme is approximated via a single
  // material colorOverride in buildGremlinMesh.
  const GREMLIN_KING_HP_MAX = 10;
  const GREMLIN_KING_FIRE_RANGE = 2.55;
  const GREMLIN_KING_FIRE_COOLDOWN_MIN = 2.5;
  const GREMLIN_KING_FIRE_COOLDOWN_MAX = 3.85;
  const GREMLIN_FIRE_DOT = 0.82;
  const GREMLIN_AIM_TURN_RATE = 9.0;
  const GREMLIN_FIRE_COOLDOWN_MIN = 1.85;
  const GREMLIN_FIRE_COOLDOWN_MAX = 2.95;
  const GREMLIN_RESPAWN_MIN_SEC = 13.0;
  const GREMLIN_RESPAWN_MAX_SEC = 19.0;
  const GREMLIN_HIT_RADIUS = 0.16;          // player paintball hit-radius vs gremlin
  const PLAYER_HIT_RADIUS = 0.22;           // gremlin paintball hit-radius vs player
  const GREMLIN_FALL_SEC = 0.8;
  const GREMLIN_FALL_SPEED = 0.95;
  const GREMLIN_SHOT_SPEED = 2.85;
  const GREMLIN_SHOT_LIFETIME_SEC = 4.0;
  const HP_BAR_RADIAL_LIFT = 0.12;
  const HP_BAR_W = 0.135;
  const HP_BAR_H = 0.0145;

  function seededRandom(seed) {
    let s = seed >>> 0;
    if (s === 0) s = 1;
    return function () { s = (s * 16807) % 2147483647; return (s - 1) / 2147483646; };
  }

  function buildGremlinMesh() {
    const root = new THREE.Group();
    // Body: green sphere. No editor preview by design — gremlins only spawn at
    // runtime under their AI; an empty editor stub would be bloat per CLAUDE.md
    // memory feedback_no_empty_editor_stubs.md.
    const bodyMat = new THREE.MeshStandardNodeMaterial({ color: 0x4a7c3b, roughness: 0.55, metalness: 0.05, flatShading: true });
    const body = new THREE.Mesh(new THREE.SphereGeometry(0.06, 8, 8), bodyMat);     // @check-ok runtime-only enemy mesh
    root.add(body);
    // Head: smaller sphere out front (toward -Z).
    const headMat = new THREE.MeshStandardNodeMaterial({ color: 0x68a355, roughness: 0.55, metalness: 0.05, flatShading: true });
    const head = new THREE.Mesh(new THREE.SphereGeometry(0.045, 8, 8), headMat);
    head.position.set(0, 0.02, -0.06);
    root.add(head);
    // Eyes — bright yellow cubes.
    const eyeMat = new THREE.MeshBasicNodeMaterial({ color: 0xffcc00 });
    const eyeL = new THREE.Mesh(new THREE.BoxGeometry(0.012, 0.012, 0.012), eyeMat);
    eyeL.position.set(-0.018, 0.025, -0.085);
    root.add(eyeL);
    const eyeR = new THREE.Mesh(new THREE.BoxGeometry(0.012, 0.012, 0.012), eyeMat);
    eyeR.position.set(0.018, 0.025, -0.085);
    root.add(eyeR);
    // Tail — cone pointing back.
    const tailMat = new THREE.MeshStandardNodeMaterial({ color: 0x4a7c3b, roughness: 0.55, metalness: 0.05, flatShading: true });
    const tail = new THREE.Mesh(new THREE.ConeGeometry(0.012, 0.08, 4), tailMat);
    tail.position.set(0, 0, 0.07);
    tail.rotation.x = Math.PI / 2;
    root.add(tail);
    // Wings — 2 flapping planes.
    const wingMat = new THREE.MeshStandardNodeMaterial({ color: 0x2d1b38, roughness: 0.5, metalness: 0.05, flatShading: true, side: THREE.DoubleSide });
    const wingL = new THREE.Mesh(new THREE.PlaneGeometry(0.13, 0.07), wingMat);
    wingL.position.set(-0.04, 0.02, 0.0);
    wingL.rotation.y = -Math.PI / 2;
    const wingR = new THREE.Mesh(new THREE.PlaneGeometry(0.13, 0.07), wingMat);
    wingR.position.set(0.04, 0.02, 0.0);
    wingR.rotation.y = Math.PI / 2;
    root.add(wingL);
    root.add(wingR);
    // Track wings + materials for flap animation + dispose.
    root.userData.wingL = wingL;
    root.userData.wingR = wingR;
    root.userData.materials = [bodyMat, headMat, eyeMat, tailMat, wingMat];
    return root;
  }

  function buildHpBar() {
    const root = new THREE.Group();
    root.renderOrder = 5;
    const trackMat = new THREE.MeshBasicNodeMaterial({
      color: new THREE.Color(0x000000),
      transparent: true,
      opacity: 0.6,
      depthWrite: false,
    });
    const track = new THREE.Mesh(new THREE.PlaneGeometry(HP_BAR_W, HP_BAR_H), trackMat);
    root.add(track);
    const fillMat = new THREE.MeshBasicNodeMaterial({
      color: new THREE.Color(0xa8e0ff),
      transparent: true,
      opacity: 0.95,
      depthWrite: false,
    });
    const fill = new THREE.Mesh(new THREE.PlaneGeometry(HP_BAR_W - 0.005, HP_BAR_H * 0.6), fillMat);
    fill.position.z = 0.001;
    root.add(fill);
    root.userData.fill = fill;
    root.userData.fillW = HP_BAR_W - 0.005;
    root.userData.materials = [trackMat, fillMat];
    return root;
  }

  let game;

  this.init = function (_game) {
    game = _game;
    this._log = (...args) => {
      if (this.getAttribute("debugLogs")) console.log(LOG_TAG, this.gameObject?.name ?? "?", "·", ...args);
    };

    this._tmpV = new THREE.Vector3();
    this._tmpV2 = new THREE.Vector3();
    this._tmpV3 = new THREE.Vector3();
    this._tmpQ = new THREE.Quaternion();
    this._camWorld = new THREE.Vector3();
    this._playerWorld = new THREE.Vector3();
    this._playerQ = new THREE.Quaternion();

    this._rand = seededRandom(this.getAttribute("seed"));
    this._time = 0;
    this._buildVisuals(this.gameObject._internal.three);
    // Seed the published positions list (paintballSystem reads it).
    this._publishGremlinPositions();
    const gs = this._gremlins;
    this._log("init", gs ? gs.length : 0, "gremlins");
  };

  this.update = function (deltaTime) {
    const gremlins = this._gremlins;
    if (!gremlins || !game || !game.camera) return;
    const dt = Math.min(deltaTime, 0.1);
    this._time += dt;
    const globeRadius = this.getAttribute("globeRadius");

    // ── Drain `tinyskies/gremlinHits` queue (paintballSystem writes here). ──
    const hits = this.erth.store.get("tinyskies/gremlinHits");
    if (Array.isArray(hits) && hits.length > 0) {
      for (const h of hits) {
        const idx = typeof h === "number" ? h : h && h.index;
        if (typeof idx !== "number" || idx < 0 || idx >= gremlins.length) continue;
        this._damageGremlin(gremlins[idx]);
      }
      hits.length = 0; // drain in place
    }

    // ── Read player position. ──
    const qx = this.erth.store.get("tinyskies/qx");
    const qw = this.erth.store.get("tinyskies/qw");
    const planeAlt = this.erth.store.get("tinyskies/altitude");
    let playerKnown = false;
    if (qx !== undefined && qw !== undefined && typeof planeAlt === "number") {
      this._playerQ.set(qx, this.erth.store.get("tinyskies/qy") || 0, this.erth.store.get("tinyskies/qz") || 0, qw);
      const playerWorld = S.cartesianFromSpherical(this._playerQ, planeAlt, globeRadius);
      this._playerWorld.copy(playerWorld);
      playerKnown = true;
    }
    game.camera.getWorldPosition(this._camWorld);

    // ── Per-gremlin update. ──
    for (let i = 0; i < gremlins.length; i++) {
      const g = gremlins[i];
      this._updateGremlin(g, dt, playerKnown, globeRadius);
    }

    // ── Per-projectile (gremlin shot) update. ──
    if (this._shots) this._updateShots(dt, playerKnown, globeRadius);

    this._publishGremlinPositions();
  };

  this._updateGremlin = function (g, dt, playerKnown, globeRadius) {
    if (!g.alive) {
      g.respawnTimer -= dt;
      // While dead, fall toward globe (visual).
      if (g.fallTimer > 0) {
        g.fallTimer -= dt;
        g.altitude = Math.max(0.05, g.altitude - GREMLIN_FALL_SPEED * dt);
        this._poseGremlin(g, globeRadius);
      } else {
        g.mesh.visible = false;
        g.hpBar.visible = false;
      }
      if (g.respawnTimer <= 0) this._respawnGremlin(g, globeRadius);
      return;
    }

    // ── AI: chase or cruise ──
    let targetSpeed = GREMLIN_CRUISE_SPEED;
    let targetHeadingDelta = 0;

    if (playerKnown) {
      const myWorld = S.cartesianFromSpherical(g.qPos, g.altitude, globeRadius);
      const distToPlayer = myWorld.distanceTo(this._playerWorld);
      g.distToPlayer = distToPlayer;
      if (distToPlayer < GREMLIN_DETECT_RANGE) {
        // Compute desired heading toward player on the tangent plane.
        const frame = S.tangentFrame(g.qPos);
        // Vector from gremlin to player projected onto tangent plane.
        this._tmpV.copy(this._playerWorld).sub(myWorld);
        const radial = this._tmpV.dot(frame.up);
        this._tmpV.addScaledVector(frame.up, -radial);
        if (this._tmpV.lengthSq() > 1e-6) {
          this._tmpV.normalize();
          let desiredHeading = Math.atan2(this._tmpV.dot(frame.east), this._tmpV.dot(frame.north));

          // Standoff offset: when too close, rotate the desired heading off
          // the player so the gremlin orbits/retreats instead of closing further.
          // The pick-side hash uses the gremlin's qPos so each gremlin orbits
          // a consistent direction (no flip-flopping on frame boundaries).
          const orbitSign = ((g.qPos.x + g.qPos.z) > 0) ? 1 : -1;
          let standoffOffset = 0;
          if (distToPlayer < GREMLIN_STANDOFF_MIN) {
            // Very close — mostly retreat (135° off the player vector).
            standoffOffset = orbitSign * (Math.PI * 0.75);
          } else if (distToPlayer < GREMLIN_STANDOFF_IDEAL) {
            // Inside the standoff sweet spot — pure tangent orbit (90°).
            standoffOffset = orbitSign * (Math.PI * 0.5);
          }
          desiredHeading += standoffOffset;

          // Smooth turn toward desired heading.
          let headingDiff = desiredHeading - g.heading;
          while (headingDiff > Math.PI) headingDiff -= Math.PI * 2;
          while (headingDiff < -Math.PI) headingDiff += Math.PI * 2;
          targetHeadingDelta = headingDiff * Math.min(1, GREMLIN_AIM_TURN_RATE * dt);
        }
        targetSpeed = distToPlayer > GREMLIN_STANDOFF_IDEAL ? GREMLIN_CHASE_SPEED : GREMLIN_CRUISE_SPEED * 0.7;

        // Fire when in range + aim aligned + cooldown ready. King uses its
        // own (longer) fire range and (slower) cooldown — source
        // SkyGremlins.ts:84-94, 1182.
        const fireRange = g.isKing ? GREMLIN_KING_FIRE_RANGE : GREMLIN_FIRE_RANGE;
        if (distToPlayer < fireRange && g.fireCooldown <= 0) {
          // Aim alignment check.
          const fwd = frame.north.clone().multiplyScalar(Math.cos(g.heading)).addScaledVector(frame.east, Math.sin(g.heading));
          const toPlayer = this._tmpV2.copy(this._playerWorld).sub(myWorld).normalize();
          const aimDot = fwd.dot(toPlayer);
          if (aimDot > GREMLIN_FIRE_DOT) {
            this._fireShot(g, myWorld, fwd, globeRadius);
            g.fireCooldown = g.isKing
              ? GREMLIN_KING_FIRE_COOLDOWN_MIN + this._rand() * (GREMLIN_KING_FIRE_COOLDOWN_MAX - GREMLIN_KING_FIRE_COOLDOWN_MIN)
              : GREMLIN_FIRE_COOLDOWN_MIN + this._rand() * (GREMLIN_FIRE_COOLDOWN_MAX - GREMLIN_FIRE_COOLDOWN_MIN);
          }
        }
      } else {
        g.distToPlayer = Infinity;
      }
    }

    if (g.fireCooldown > 0) g.fireCooldown -= dt;

    g.heading += targetHeadingDelta;
    const arc = (targetSpeed * dt) / globeRadius;
    g.qPos = S.moveOnSphere(g.qPos, g.heading, arc);

    // Bob altitude with sin.
    g.bobPhase += dt * GREMLIN_BOB_SPEED;
    g.altitude = g.baseAltitude + Math.sin(g.bobPhase) * GREMLIN_BOB_AMP * 0.05;

    // Wing flap.
    g.flapPhase += dt * GREMLIN_FLAP_SPEED;
    if (g.mesh.userData.wingL && g.mesh.userData.wingR) {
      const flap = Math.sin(g.flapPhase) * GREMLIN_FLAP_AMP;
      g.mesh.userData.wingL.rotation.x = flap;
      g.mesh.userData.wingR.rotation.x = -flap;
    }

    this._poseGremlin(g, globeRadius);

    // HP bar billboard + fill scale.
    if (g.hpBar) {
      const myWorld = S.cartesianFromSpherical(g.qPos, g.altitude, globeRadius);
      this._tmpV.copy(myWorld).normalize();
      g.hpBar.position.copy(myWorld).addScaledVector(this._tmpV, HP_BAR_RADIAL_LIFT);
      game.camera.getWorldQuaternion(this._tmpQ);
      g.hpBar.quaternion.copy(this._tmpQ);
      const hpMax = g.isKing ? GREMLIN_KING_HP_MAX : GREMLIN_HP_MAX;
      const ratio = Math.max(0, Math.min(1, g.hp / hpMax));
      const fill = g.hpBar.userData.fill;
      const fillW = g.hpBar.userData.fillW;
      const w = Math.max(0.001, fillW * ratio);
      fill.scale.set(w / fillW, 1, 1);
      fill.position.x = -fillW * 0.5 + w * 0.5;
      g.hpBar.visible = g.hp < hpMax;
    }
  };

  this._poseGremlin = function (g, globeRadius) {
    // Build matrix using same pattern as plane (heading, no pitch, no bank).
    const m = S.buildPlaneMatrix(g.qPos, g.heading, 0, 0, g.altitude, globeRadius);
    g.mesh.matrixAutoUpdate = false;
    g.mesh.matrix.copy(m);
    g.mesh.matrixWorldNeedsUpdate = true;
    g.mesh.visible = true;
  };

  this._fireShot = function (g, myWorld, fwd, globeRadius) {
    const shots = this._shots;
    if (!shots) return;
    const slot = this._findShotSlot();
    if (slot === -1) return;
    const shot = shots[slot];
    shot.alive = true;
    shot.life = 0;
    // Aim straight at the player (lead = none for MVP).
    this._tmpV.copy(this._playerWorld).sub(myWorld).normalize();
    shot.vel.copy(this._tmpV).multiplyScalar(GREMLIN_SHOT_SPEED);
    shot.mesh.position.copy(myWorld).addScaledVector(fwd, 0.1);
    shot.mesh.visible = true;
  };

  this._findShotSlot = function () {
    if (!this._shots) return -1;
    for (let i = 0; i < this._shots.length; i++) {
      if (!this._shots[i].alive) return i;
    }
    return -1;
  };

  this._updateShots = function (dt, playerKnown, globeRadius) {
    for (let i = 0; i < this._shots.length; i++) {
      const sh = this._shots[i];
      if (!sh.alive) continue;
      sh.life += dt;
      sh.mesh.position.addScaledVector(sh.vel, dt);
      // Hit player?
      if (playerKnown && sh.mesh.position.distanceTo(this._playerWorld) < PLAYER_HIT_RADIUS) {
