        this.erth.store.set("tinyskies/applyGremlinSlow", true);
        this.erth.store.set("tinyskies/applyPaintballWobble", true);
        const prev = this.erth.store.get("tinyskies/applyGremlinDamage");
        this.erth.store.set("tinyskies/applyGremlinDamage", (typeof prev === "number" ? prev : 0) + 1);
        sh.alive = false;
        sh.mesh.visible = false;
        continue;
      }
      // Despawn after lifetime or if too far from globe origin.
      if (sh.life >= GREMLIN_SHOT_LIFETIME_SEC || sh.mesh.position.length() > globeRadius * 2.5) {
        sh.alive = false;
        sh.mesh.visible = false;
      }
    }
  };

  this._damageGremlin = function (g) {
    if (!g.alive) return;
    g.hp -= 1;
    if (g.hp <= 0) {
      g.alive = false;
      g.fallTimer = GREMLIN_FALL_SEC;
      g.respawnTimer = GREMLIN_RESPAWN_MIN_SEC + this._rand() * (GREMLIN_RESPAWN_MAX_SEC - GREMLIN_RESPAWN_MIN_SEC);
      // Track basic-gremlin kills for King-spawn trigger. King kill ends the
      // session-long counter (King doesn't trigger another King).
      if (!g.isKing) {
        this._sessionKills = (this._sessionKills || 0) + 1;
        // Publish for any HUD that wants to surface the count
        this.erth.store.set("tinyskies/gremlinSessionKills", this._sessionKills);
        // King spawn check — only one King at a time, only if enabled
        if (this.getAttribute("kingEnabled")
            && !this._kingSpawned
            && this._sessionKills >= this.getAttribute("kingKillThreshold")
            && this._kingState && !this._kingState.alive) {
          this._spawnKing(this._kingState);
        }
      } else {
        this._log("Gremlin King defeated! +120 XP (source SKY_GREMLIN_KING_XP)");
        // Publish king-defeated event for any progression listener
        this.erth.store.set("tinyskies/kingDefeated", true);
        this._kingSpawned = false; // allow respawn after the king's respawn timer
      }
      this._log(g.isKing ? "KING down — respawn in" : "gremlin down — respawn in", g.respawnTimer.toFixed(1), "s");
    }
  };

  this._spawnKing = function (kingState) {
    if (!kingState || kingState.alive) return;
    const globeRadius = this.getAttribute("globeRadius");
    this._respawnGremlin(kingState, globeRadius);
    this._kingSpawned = true;
    this._log("Gremlin King spawned at session-kill", this._sessionKills);
  };

  this._respawnGremlin = function (g, globeRadius) {
    const spawn = S.randomSpawnQuaternionAndHeading(this.getAttribute("seed") + Math.floor(this._rand() * 1e6));
    g.qPos.copy(spawn.qPosition);
    g.heading = spawn.heading;
    g.baseAltitude = GREMLIN_ALTITUDE_MIN + this._rand() * (GREMLIN_ALTITUDE_MAX - GREMLIN_ALTITUDE_MIN);
    g.altitude = g.baseAltitude;
    g.hp = g.isKing ? GREMLIN_KING_HP_MAX : GREMLIN_HP_MAX;
    g.alive = true;
    g.fallTimer = 0;
    g.fireCooldown = g.isKing
      ? GREMLIN_KING_FIRE_COOLDOWN_MIN + this._rand() * (GREMLIN_KING_FIRE_COOLDOWN_MAX - GREMLIN_KING_FIRE_COOLDOWN_MIN)
      : GREMLIN_FIRE_COOLDOWN_MIN + this._rand() * (GREMLIN_FIRE_COOLDOWN_MAX - GREMLIN_FIRE_COOLDOWN_MIN);
    g.bobPhase = this._rand() * Math.PI * 2;
    g.flapPhase = this._rand() * Math.PI * 2;
    g.distToPlayer = Infinity;
    g.mesh.visible = true;
    g.hpBar.visible = false;
  };

  this._publishGremlinPositions = function () {
    const arr = this._gremlinPositions;
    const gremlins = this._gremlins;
    if (!arr || !gremlins) return;
    const globeRadius = this.getAttribute("globeRadius");
    for (let i = 0; i < gremlins.length; i++) {
      const g = gremlins[i];
      if (g.alive) {
        const w = S.cartesianFromSpherical(g.qPos, g.altitude, globeRadius);
        arr[i].x = w.x;
        arr[i].y = w.y;
        arr[i].z = w.z;
        arr[i].alive = true;
        arr[i].hitRadius = GREMLIN_HIT_RADIUS;
      } else {
        arr[i].alive = false;
      }
    }
  };

  this._buildVisuals = function (parent) {
