  function playSound(key, volume) {
    if (!audioCtx || !buffers[key]) return;
    let source = audioCtx.createBufferSource();
    source.buffer = buffers[key];
    let gain = audioCtx.createGain();
    gain.gain.value = volume || 0.5;
    source.connect(gain);
    gain.connect(audioCtx.destination);
    source.start(0);
  }

  this.init = function(_game) {
    game = _game;
    store = this.erth.store;
    try {
      audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    } catch (e) {
      audioCtx = null;
    }
    loadSound("bounceSound", "BBBounce", "bounce");
    loadSound("catchSound", "BBCatch", "catch");
    loadSound("throwSound", "BBThrow", "throw");
    loadSound("scoreSound", "BBScore", "score");
  };

  this.update = function(deltaTime) {
    if (!store) return;
    let evt = store.get("bb_audio") || "";
    if (evt && evt !== lastAudioEvent) {
      lastAudioEvent = evt;
      let sep = evt.indexOf(":");
      let sep2 = evt.indexOf(":", sep + 1);
      let name = evt.substring(0, sep);
      let vol = parseFloat(evt.substring(sep + 1, sep2)) || 0.5;
      playSound(name, vol);
    }
  };

  this.dispose = function() {
    if (audioCtx) {
      audioCtx.close().catch(function() {});
      audioCtx = null;
    }
    buffers = {};
    game = null;
    store = null;
  };

