  let wallMeshes = [];
  let redBasketMesh = null;
  let blueBasketMesh = null;
  const erth = this.erth;
  const attributes = this.attributes;

  function addMesh(geo, mat, parent) {
    let m = new THREE.Mesh(geo, mat);
    m.userData.isRuntimeOnly = true;
    m.castShadow = true;
    m.receiveShadow = true;
    parent.add(m);
    meshes.push(m);
    geos.push(geo);
    return m;
  }

  function cleanup() {
    for (let i = 0; i < meshes.length; i++) {
      if (meshes[i].parent) meshes[i].parent.remove(meshes[i]);
    }
    for (let i = 0; i < geos.length; i++) geos[i].dispose();
    for (let i = 0; i < mats.length; i++) mats[i].dispose();
    for (let i = 0; i < lightObjs.length; i++) {
      if (lightObjs[i].parent) lightObjs[i].parent.remove(lightObjs[i]);
      if (lightObjs[i].dispose) lightObjs[i].dispose();
    }
    for (let i = 0; i < loadedTextures.length; i++) loadedTextures[i].dispose();
    meshes = [];
    geos = [];
    mats = [];
    lightObjs = [];
    loadedTextures = [];
    wallMeshes = [];
    floorMesh = null;
    redBasketMesh = null;
    blueBasketMesh = null;
  }

  function buildCourt(parent) {
    // Materials
    let floorMat = new THREE.MeshStandardNodeMaterial({ color: 0xaaaaaa, roughness: 0.8, metalness: 0.3 });
    let wallMat = new THREE.MeshStandardNodeMaterial({ color: 0x888888, roughness: 0.8, metalness: 0.3 });
    let redBasketMat = new THREE.MeshStandardNodeMaterial({ color: 0xff4444, roughness: 0.8, metalness: 0.2 });
    let blueBasketMat = new THREE.MeshStandardNodeMaterial({ color: 0x4444ff, roughness: 0.8, metalness: 0.2 });
    mats.push(floorMat, wallMat, redBasketMat, blueBasketMat);

    // Floor: 14 x 10 plane, rotated flat
    let floorGeo = new THREE.PlaneGeometry(14, 10);
    floorMesh = addMesh(floorGeo, floorMat, parent);
    floorMesh.rotation.x = -Math.PI / 2;

    // Walls — PlaneGeometry facing inward
    let largerGeo = new THREE.PlaneGeometry(14, 5);
    let smallerGeo = new THREE.PlaneGeometry(10, 5);

    // Back wall (z = -5, facing +z)
    let backWall = addMesh(largerGeo.clone(), wallMat, parent);
    backWall.position.set(0, 2.5, -5);
    geos.push(backWall.geometry);
    wallMeshes.push(backWall);

    // Front wall (z = 5, facing -z)
    let frontWall = addMesh(largerGeo.clone(), wallMat, parent);
    frontWall.rotation.y = Math.PI;
    frontWall.position.set(0, 2.5, 5);
    geos.push(frontWall.geometry);
    wallMeshes.push(frontWall);

    // Left wall (x = -7, facing +x)
    let leftWall = addMesh(smallerGeo.clone(), wallMat, parent);
    leftWall.rotation.y = Math.PI / 2;
    leftWall.position.set(-7, 2.5, 0);
    geos.push(leftWall.geometry);
    wallMeshes.push(leftWall);

    // Right wall (x = 7, facing -x)
    let rightWall = addMesh(smallerGeo.clone(), wallMat, parent);
    rightWall.rotation.y = -Math.PI / 2;
    rightWall.position.set(7, 2.5, 0);
    geos.push(rightWall.geometry);
    wallMeshes.push(rightWall);

    // Clean up template geometries
    largerGeo.dispose();
    smallerGeo.dispose();

    // Baskets (plane sprites on walls)
    let basketGeo = new THREE.PlaneGeometry(3, 1.5);

    // Red basket on left wall (team 0 scores here -> team 1 gets points)
    redBasketMesh = addMesh(basketGeo.clone(), redBasketMat, parent);
    redBasketMesh.rotation.y = Math.PI / 2;
    redBasketMesh.position.set(-6.99, 3.75, 0);
    geos.push(redBasketMesh.geometry);

    // Blue basket on right wall
    blueBasketMesh = addMesh(basketGeo.clone(), blueBasketMat, parent);
    blueBasketMesh.rotation.y = -Math.PI / 2;
    blueBasketMesh.position.set(6.99, 3.75, 0);
    geos.push(blueBasketMesh.geometry);

    basketGeo.dispose();

    // Point lights (source: 3 lights for court illumination)
    let pl1 = new THREE.PointLight(0xffffff, 0.5);
    pl1.position.set(4, 6, -2);
    pl1.userData.isRuntimeOnly = true;
