    pl2.position.set(-4, 6, -2);
    pl2.userData.isRuntimeOnly = true;
    parent.add(pl2);
    lightObjs.push(pl2);

    let pl3 = new THREE.PointLight(0xffffff, 0.2);
    pl3.position.set(0, 6, 2);
    pl3.castShadow = true;
    pl3.shadow.mapSize.set(1024, 1024);
    pl3.userData.isRuntimeOnly = true;
    parent.add(pl3);
    lightObjs.push(pl3);
  }

  function applyTexture(attrName, assetName, onLoad) {
    let ref = attributes[attrName];
    if (ref) {
      erth.asset.image.createTexture(ref).then(onLoad).catch(function() {});
    } else {
      erth.asset.image.findByName(assetName).then(function(r) { // @check-ok fallback asset names
        if (r) erth.asset.image.createTexture(r).then(onLoad).catch(function() {});
      }).catch(function() {});
