  }

  function loadTextures() {
    // Floor texture — tiled 7x5, nearest filter for pixel art
    applyTexture("floorTexture", "BBFloor", function(tex) {
      tex.wrapS = THREE.RepeatWrapping;
      tex.wrapT = THREE.RepeatWrapping;
      tex.repeat.set(7, 5);
      tex.minFilter = THREE.NearestFilter;
      tex.magFilter = THREE.NearestFilter;
      loadedTextures.push(tex);
      if (floorMesh) {
        floorMesh.material.map = tex;
        floorMesh.material.color.setHex(0xffffff);
        floorMesh.material.needsUpdate = true;
      }
    });

    // Wall texture
    applyTexture("wallTexture", "BBWall", function(tex) {
      tex.wrapS = THREE.RepeatWrapping;
      tex.wrapT = THREE.RepeatWrapping;
      tex.minFilter = THREE.NearestFilter;
      tex.magFilter = THREE.NearestFilter;
      loadedTextures.push(tex);
      for (let i = 0; i < wallMeshes.length; i++) {
        wallMeshes[i].material.map = tex;
        wallMeshes[i].material.color.setHex(0xffffff);
        wallMeshes[i].material.needsUpdate = true;
      }
    });

    // Red basket texture
    applyTexture("redBasketTexture", "BBRedBasket", function(tex) {
      tex.minFilter = THREE.NearestFilter;
      tex.magFilter = THREE.NearestFilter;
      loadedTextures.push(tex);
      if (redBasketMesh) {
        redBasketMesh.material.map = tex;
        redBasketMesh.material.color.setHex(0xffffff);
        redBasketMesh.material.needsUpdate = true;
      }
    });

    // Blue basket texture
    applyTexture("blueBasketTexture", "BBBlueBasket", function(tex) {
      tex.minFilter = THREE.NearestFilter;
      tex.magFilter = THREE.NearestFilter;
      loadedTextures.push(tex);
      if (blueBasketMesh) {
        blueBasketMesh.material.map = tex;
        blueBasketMesh.material.color.setHex(0xffffff);
        blueBasketMesh.material.needsUpdate = true;
      }
    });
  }

  // --- Editor mode ---
  this.onEditorAdded = function(editor) {
