    loadTextures();
  };

  this.onEditorDispose = function() {
    cleanup();
  };

  // --- Play mode ---
  this.init = function(_game) {
    buildCourt(this.gameObject._internal.three);
    loadTextures();
  };

  this.dispose = function() {
    cleanup();
    for (let i = 0; i < meshes.length; i++) {
      if (meshes[i].parent) meshes[i].parent.remove(meshes[i]);
    }
    for (let i = 0; i < lightObjs.length; i++) {
      if (lightObjs[i].parent) lightObjs[i].parent.remove(lightObjs[i]);
    }
  };

