config:
  name: "BB Game Manager"
  id: "bball.gameManager"
  author: "script-wizard"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  priority: 0
  description: "Match lifecycle, remote player management, team assignment,
    scoring, and UIKit HUD for BBall."
  tags:
    - gameplay
  attributes: {}
  documentation: Match lifecycle, remote player management, team assignment, scoring, and
    UIKit HUD for BBall. Configure attributes in the editor to tune gameplay
    behavior.

code: |
  // Source: matchDurationTicks = 20*60*5 = 6000 (5 min at 20Hz)
  const MATCH_DURATION_TICKS = 6000;
  const RESET_BALL_DURATION = 60;
  const TICK_RATE = 1 / 20;
  const MAX_PLAYERS_PER_TEAM = 3;
  const SYNC_INTERVAL = 0.25; // sync match state at 4Hz (slow-changing data)

  let game = null;
  let store = null;
  let mp = null;

  // Match state
  let matchState = "waiting"; // "waiting" | "playing" | "ended"
  let ticksLeft = 0;
  let scoreTimer = 0;
  let team0Score = 0;
  let team1Score = 0;

  let accumulator = 0;
  let syncTimer = 0;

  // Remote player tracking
  let remotePlayers = new Map();
  let playerAddedToken = null;
  let playerRemovedToken = null;
  let playerDataChangedToken = null;

  // HUD
  let hudContainer = null;
  let timerText = null;
  let scoreText = null;
  let statusText = null;
  let hudMeshes = [];
  let hudGeos = [];
  let hudMats = [];

  // Team assignments: Map<sessionId, teamIndex>
  let teamAssignments = new Map();
  let team0Count = 0;
  let team1Count = 0;
  let previewTime = 0;

  function formatTime(ticks) {
    let seconds = Math.ceil(ticks / 20);
    let min = Math.floor(seconds / 60);
    let sec = seconds % 60;
    return (min < 10 ? "0" : "") + min + ":" + (sec < 10 ? "0" : "") + sec;
  }

  function assignTeam(sessionId) {
    if (teamAssignments.has(sessionId)) return teamAssignments.get(sessionId);
    let teamIdx = team0Count <= team1Count ? 0 : 1;
    if (teamIdx === 0 && team0Count >= MAX_PLAYERS_PER_TEAM) teamIdx = 1;
    if (teamIdx === 1 && team1Count >= MAX_PLAYERS_PER_TEAM) teamIdx = 0;
    teamAssignments.set(sessionId, teamIdx);
    if (teamIdx === 0) team0Count++;
    else team1Count++;
    return teamIdx;
  }

  function removeTeamAssignment(sessionId) {
    if (!teamAssignments.has(sessionId)) return;
    let teamIdx = teamAssignments.get(sessionId);
    if (teamIdx === 0) team0Count = Math.max(0, team0Count - 1);
    else team1Count = Math.max(0, team1Count - 1);
    teamAssignments.delete(sessionId);
  }

  // --- Remote player avatar creation ---
  const createRemoteAvatar = async (sessionId, playerData) => {
    let group = new THREE.Group();
    group.name = "RemotePlayer_" + sessionId;
    group.userData.isRuntimeOnly = true;

    let teamIdx = parseInt(playerData.get("bb_team")) || 0;
    let name = playerData.get("bb_name") || "GUEST";

    group.userData.bb_team = teamIdx;
    group.userData.bb_name = name;
    group.userData.bb_isLocal = false;
    group.userData.bb_angleX = 0;
    group.userData.bb_angleY = 0;
    group.userData.bb_catching = false;
    group.userData.bb_hasBall = false;

    let gameObject = this.erth.object.createFromThreeObject(group);
    await this.erth.scene.addObject(gameObject, this.gameObject);

    // Attach character model behavior
    if (typeof game.addBehaviorToObject === "function") {
      game.addBehaviorToObject(group, "bball.characterModel", { teamIndex: teamIdx });
    }

    // Apply initial position
    applyRemotePos(group, playerData);

    remotePlayers.set(sessionId, { group: group });
  }

  function destroyRemoteAvatar(sessionId) {
    let remote = remotePlayers.get(sessionId);
    if (!remote) return;
    if (remote.group) {
      // Remove children and dispose
      while (remote.group.children.length > 0) {
        let child = remote.group.children[0];
        remote.group.remove(child);
        if (child.geometry) child.geometry.dispose();
        if (child.material) child.material.dispose();
      }
      if (remote.group.parent) remote.group.parent.remove(remote.group);
    }
    remotePlayers.delete(sessionId);
  }

  function applyRemotePos(group, playerData) {
    let posRaw = playerData.get("bb_pos");
    if (posRaw) {
      try {
        let pos = JSON.parse(posRaw);
        group.position.x = pos.x || 0;
        group.position.z = pos.z || 0;
      } catch (e) {}
    }

    // Jump height
    let jumpRaw = playerData.get("bb_jump");
    if (jumpRaw) {
      try {
        let j = JSON.parse(jumpRaw);
        let timer = j.timer || 0;
        let withBall = j.withBall || false;
        if (timer === 0) {
          group.position.y = 0;
        } else {
          let dur = withBall ? 20 : 25;
          let n = dur - timer;
          let boost = withBall ? 0.4 : 0.5;
          group.position.y = Math.max(0, boost * n - 0.05 * (n - 1) * n / 2);
        }
      } catch (e) {}
    }

    // Update userData for character model
    group.userData.bb_angleY = parseFloat(playerData.get("bb_ay")) || 0;
    group.userData.bb_angleX = parseFloat(playerData.get("bb_ax")) || 0;
    group.userData.bb_catching = playerData.get("bb_catching") === "1";
    group.userData.bb_name = playerData.get("bb_name") || "GUEST";

    let ballOwner = store ? (store.get("bb_ball_owner") || "") : "";
    group.userData.bb_hasBall = ballOwner === group.name.replace("RemotePlayer_", "");
  }

  // --- HUD ---
  function buildHUD() {
    if (!game || !game.uiCamera) return;

    hudContainer = new THREE.Group();
    hudContainer.userData.isRuntimeOnly = true;
    game.uiCamera.add(hudContainer);

    // Score text (canvas texture)
    updateHUDCanvas();
  }

  function buildPreviewHUD(camera) {
    if (hudContainer) return;
    hudContainer = new THREE.Group();
    hudContainer.userData.isRuntimeOnly = true;
    camera.add(hudContainer);
    matchState = "playing";
    ticksLeft = MATCH_DURATION_TICKS - 420;
    team0Score = 12;
    team1Score = 9;
    scoreTimer = 8;
    updateHUDCanvas();
  }

  function updateHUDCanvas() {
    // Cleanup previous
    for (let i = 0; i < hudMeshes.length; i++) {
      if (hudMeshes[i].parent) hudMeshes[i].parent.remove(hudMeshes[i]);
    }
    for (let i = 0; i < hudGeos.length; i++) hudGeos[i].dispose();
    for (let i = 0; i < hudMats.length; i++) hudMats[i].dispose();
    hudMeshes = [];
    hudGeos = [];
    hudMats = [];

    if (!hudContainer) return;

    let canvas = document.createElement("canvas"); // @check-ok
    canvas.width = 512;
    canvas.height = 128;
    let ctx = canvas.getContext("2d");

    // Background
    ctx.fillStyle = "rgba(0,0,0,0.5)";
    ctx.fillRect(0, 0, 512, 128);

    if (matchState === "waiting") {
      ctx.fillStyle = "#ffffff";
      ctx.font = "bold 28px sans-serif";
      ctx.textAlign = "center";
      ctx.fillText("Waiting for players...", 256, 50);
      let needed = 0;
      if (team0Count === 0) needed++;
      if (team1Count === 0) needed++;
      if (needed > 0) {
        ctx.font = "20px sans-serif";
        ctx.fillText("Need " + needed + " more team(s)", 256, 90);
      }
    } else if (matchState === "playing") {
      // Timer
      ctx.fillStyle = "#ffffff";
      ctx.font = "bold 32px sans-serif";
      ctx.textAlign = "center";
      ctx.fillText(formatTime(ticksLeft), 256, 40);

      // Scores
      ctx.font = "bold 40px sans-serif";
      ctx.fillStyle = "#ff4444";
      ctx.textAlign = "right";
      ctx.fillText("" + team0Score, 220, 100);

      ctx.fillStyle = "#ffffff";
      ctx.textAlign = "center";
      ctx.fillText("-", 256, 100);

      ctx.fillStyle = "#4444ff";
      ctx.textAlign = "left";
      ctx.fillText("" + team1Score, 292, 100);

      // Score freeze message
      if (scoreTimer > 0) {
        ctx.fillStyle = "#ffff44";
        ctx.font = "bold 24px sans-serif";
        ctx.textAlign = "center";
        ctx.fillText("Scoooore!", 256, 128);
      }
    } else if (matchState === "ended") {
      ctx.fillStyle = "#ffffff";
      ctx.font = "bold 28px sans-serif";
      ctx.textAlign = "center";
      if (team0Score > team1Score) {
        ctx.fillStyle = "#ff4444";
        ctx.fillText("Team RED wins!", 256, 45);
      } else if (team1Score > team0Score) {
        ctx.fillStyle = "#4444ff";
        ctx.fillText("Team BLUE wins!", 256, 45);
      } else {
        ctx.fillText("It's a tie!", 256, 45);
      }
      ctx.fillStyle = "#ffffff";
      ctx.font = "bold 36px sans-serif";
      ctx.fillText(team0Score + " - " + team1Score, 256, 95);
    }

    let tex = new THREE.CanvasTexture(canvas);
    let geo = new THREE.PlaneGeometry(0.5, 0.125);
    let mat = new THREE.MeshBasicNodeMaterial({ map: tex, transparent: true, depthTest: false });
    let mesh = new THREE.Mesh(geo, mat);
    mesh.userData.isRuntimeOnly = true;
    mesh.position.set(0, 0.42, -1);
    mesh.renderOrder = 9999;
    hudContainer.add(mesh);
    hudMeshes.push(mesh);
    hudGeos.push(geo);
    hudMats.push(mat);
  }

  function cleanupHUD() {
    for (let i = 0; i < hudMeshes.length; i++) {
      if (hudMeshes[i].parent) hudMeshes[i].parent.remove(hudMeshes[i]);
    }
    for (let i = 0; i < hudGeos.length; i++) hudGeos[i].dispose();
    for (let i = 0; i < hudMats.length; i++) hudMats[i].dispose();
    hudMeshes = [];
    hudGeos = [];
    hudMats = [];
    if (hudContainer && hudContainer.parent) hudContainer.parent.remove(hudContainer);
    hudContainer = null;
  }

  // --- Host-only match management ---
  function hostTick() {
    if (matchState === "waiting") {
      // Check if both teams have players
      if (team0Count > 0 && team1Count > 0) {
        matchState = "playing";
        ticksLeft = MATCH_DURATION_TICKS;
        scoreTimer = 0;
        team0Score = 0;
        team1Score = 0;
        store.set("bb_match_state", "playing");
      }
    } else if (matchState === "playing") {
      ticksLeft--;

      // Score timer countdown
      if (scoreTimer > 0) {
        scoreTimer--;
        store.set("bb_score_timer", scoreTimer);
      }

      // Handle scoring event from ball controller
      let scoringTeam = store.get("bb_scoring_team");
      if (scoringTeam !== undefined && scoringTeam !== null && scoringTeam >= 0 && scoreTimer === 0) {
        // Apply score
        if (scoringTeam === 0) team0Score += 2;
        else team1Score += 2;
        scoreTimer = RESET_BALL_DURATION;
        store.set("bb_score_timer", scoreTimer);
        store.set("bb_team0_score", team0Score);
        store.set("bb_team1_score", team1Score);
        store.set("bb_scoring_team", -1); // consumed
      }

      // Match end
      if (ticksLeft <= 0) {
        matchState = "ended";
        store.set("bb_match_state", "ended");
      }

      store.set("bb_match_ticks", ticksLeft);
    }
  }

  // --- Init ---
  this.init = function(_game) {
    game = _game;
    store = this.erth.store;
    mp = game.multiplayerState;

    // Initialize store
    store.set("bb_match_state", "waiting");
    store.set("bb_match_ticks", 0);
    store.set("bb_score_timer", 0);
    store.set("bb_team0_score", 0);
    store.set("bb_team1_score", 0);
    store.set("bb_ball_owner", "");
    store.set("bb_scoring_team", -1);

    // Auto-assign local player to a team
    let mySession = (mp && mp.player) ? mp.player.sessionId : "local";
    let myTeam = assignTeam(mySession);
    let playerObj = game.scene ? game.scene.getObjectByName("Player") : null;
    if (playerObj) {
      playerObj.userData.bb_team = myTeam;
      // Position based on team
      let startX = myTeam === 0 ? -5 : 5;
      playerObj.position.x = startX;
      playerObj.position.z = 0;
    }
    if (mp) {
      mp.setPlayerData("bb_team", "" + myTeam);
    }

    // Build HUD
    buildHUD();

    // Multiplayer listeners
    if (!mp) return;

    playerAddedToken = mp.addOnPlayerAddedListener(function(player) {
      let sessionId = player.sessionId;
      if (remotePlayers.has(sessionId)) return;
      if (mp.player && sessionId === mp.player.sessionId) return;

      // Auto-assign team
      let teamIdx = assignTeam(sessionId);

      createRemoteAvatar(sessionId, player.data);

      // Position based on team
      let remote = remotePlayers.get(sessionId);
      if (remote && remote.group) {
        let startX = teamIdx === 0 ? -5 : 5;
        remote.group.position.x = startX;
        remote.group.userData.bb_team = teamIdx;
      }
    });

    playerRemovedToken = mp.addOnPlayerRemovedListener(function(player) {
      let sessionId = player.sessionId;
      removeTeamAssignment(sessionId);
      destroyRemoteAvatar(sessionId);

      // Check if match should end (not enough players)
      if (mp.isHost() && matchState === "playing") {
        if (team0Count === 0 || team1Count === 0) {
          matchState = "ended";
          store.set("bb_match_state", "ended");
        }
      }
    });

    playerDataChangedToken = mp.addOnPlayerDataChangedListener(function(player, key) {
      let sessionId = player.sessionId;
      if (mp.player && sessionId === mp.player.sessionId) return;
      let remote = remotePlayers.get(sessionId);
      if (!remote) return;

      if (key === "bb_pos" || key === "bb_jump" || key === "bb_ay" || key === "bb_ax" || key === "bb_catching") {
        applyRemotePos(remote.group, player.data);
      }
      if (key === "bb_name") {
        remote.group.userData.bb_name = player.data.get("bb_name") || "GUEST";
      }
      if (key === "bb_team") {
        let newTeam = parseInt(player.data.get("bb_team")) || 0;
        remote.group.userData.bb_team = newTeam;
      }
    });
  };

  this.onEditorAdded = function(editor) {
    this._editorCamera = editor.camera;
    previewTime = 0;
    buildPreviewHUD(editor.camera);
  };

  this.onEditorUpdate = function() {
    if (!hudContainer) return;
    previewTime += 0.016;
    ticksLeft = MATCH_DURATION_TICKS - Math.floor(previewTime * 20);
    if (ticksLeft < 0) ticksLeft = MATCH_DURATION_TICKS;
    scoreTimer = Math.floor((Math.sin(previewTime * 3) * 0.5 + 0.5) * 10);
    updateHUDCanvas();
  };

  this.onEditorAttributesUpdated = function() {
    cleanupHUD();
    previewTime = 0;
    if (this._editorCamera) {
      buildPreviewHUD(this._editorCamera);
    }
  };

  this.onEditorDispose = function() {
    cleanupHUD();
    previewTime = 0;
  };

  let hudUpdateTimer = 0;
  const HUD_UPDATE_INTERVAL = 0.1;

  this.update = function(deltaTime) {
    let isHost = !mp || mp.isHost();

    if (isHost) {
      accumulator += deltaTime;
      while (accumulator >= TICK_RATE) {
        accumulator -= TICK_RATE;
        hostTick();
      }

      // Sync match state at lower rate
      syncTimer += deltaTime;
      if (syncTimer >= SYNC_INTERVAL) {
        syncTimer = 0;
        if (mp) {
          mp.setBehaviorData(this.gameObject, this.id, "match", JSON.stringify({
            state: matchState,
            ticksLeft: ticksLeft,
            scoreTimer: scoreTimer,
            team0Score: team0Score,
            team1Score: team1Score,
            team0Count: team0Count,
            team1Count: team1Count
          }));
        }
      }
    } else {
      // Non-host: read state from store (set by onStateUpdated)
      matchState = store.get("bb_match_state") || "waiting";
      ticksLeft = store.get("bb_match_ticks") || 0;
      scoreTimer = store.get("bb_score_timer") || 0;
      team0Score = store.get("bb_team0_score") || 0;
      team1Score = store.get("bb_team1_score") || 0;
    }

    // Update remote player ball-holding state
    let ballOwner = store.get("bb_ball_owner") || "";
    remotePlayers.forEach(function(remote, sessionId) {
      if (remote.group) {
        remote.group.userData.bb_hasBall = ballOwner === sessionId;
      }
    });

    // Update HUD periodically
    hudUpdateTimer += deltaTime;
    if (hudUpdateTimer >= HUD_UPDATE_INTERVAL) {
      hudUpdateTimer = 0;
      updateHUDCanvas();
    }
  };

  this.onStateUpdated = function(key, value) {
    if (!mp || mp.isHost()) return;
    if (key === "match" && value) {
      try {
        let m = JSON.parse(value);
        matchState = m.state || "waiting";
        ticksLeft = m.ticksLeft || 0;
        scoreTimer = m.scoreTimer || 0;
        team0Score = m.team0Score || 0;
        team1Score = m.team1Score || 0;
        team0Count = m.team0Count || 0;
        team1Count = m.team1Count || 0;
        store.set("bb_match_state", matchState);
        store.set("bb_match_ticks", ticksLeft);
        store.set("bb_score_timer", scoreTimer);
        store.set("bb_team0_score", team0Score);
        store.set("bb_team1_score", team1Score);
      } catch (e) {}
    }
  };

  this.dispose = function() {
    if (mp) {
      if (playerAddedToken) mp.removeOnPlayerAddedListener(playerAddedToken);
      if (playerRemovedToken) mp.removeOnPlayerRemovedListener(playerRemovedToken);
      if (playerDataChangedToken) mp.removeOnPlayerDataChangedListener(playerDataChangedToken);
    }

    remotePlayers.forEach(function(remote) {
      if (remote.group) {
        while (remote.group.children.length > 0) {
          let child = remote.group.children[0];
          remote.group.remove(child);
          if (child.geometry) child.geometry.dispose();
          if (child.material) child.material.dispose();
        }
        if (remote.group.parent) remote.group.parent.remove(remote.group);
      }
    });
    remotePlayers.clear();

    cleanupHUD();

    playerAddedToken = null;
    playerRemovedToken = null;
    playerDataChangedToken = null;
    teamAssignments.clear();
    team0Count = 0;
    team1Count = 0;
    game = null;
    store = null;
    mp = null;
  };

