      idleAngle += deltaTime * 0.3;
      cam.position.set(
        Math.sin(idleAngle) * dist,
        h,
        Math.cos(idleAngle) * dist
      );
      cam.lookAt(0, 1, 0);
    } else {
      if (idleAngle !== 0) {
        idleAngle = 0;
