config:
  name: "BB Player Controller"
  id: "bball.playerController"
  author: "script-wizard"
  isScript: true
  main: "script.js"
  version: "1.0.0"
  priority: 0
  description: "Local player input (keyboard + gamepad), movement, jumping,
    catch/throw signals. Broadcasts state via multiplayer setPlayerData."
  tags:
    - gameplay
  attributes: {}
  inputs:
    bb_KeyX: { action: true, bindings: [{ keyboard: KeyX }] }
  documentation: Local player input (keyboard + gamepad), movement, jumping, catch/throw
    signals. Broadcasts state via multiplayer setPlayerData. Configure
    attributes in the editor to tune gameplay behavior.

code: |
  // Source constants
  const COURT_HALF_W = 6;  // court.width / 2
  const COURT_HALF_D = 4;  // court.depth / 2
  const MOVE_SPEED = 0.1;  // units per tick
  const TICK_RATE = 1 / 20; // 50ms ticks
  const JUMP_DURATION_NO_BALL = 25;
  const JUMP_DURATION_WITH_BALL = 20;
  const JUMP_BOOST_NO_BALL = 0.5;
  const JUMP_BOOST_WITH_BALL = 0.4;
  const JUMP_GRAVITY = 0.05;
  const SYNC_INTERVAL = 0.05; // 20Hz sync to match server tick

  let game = null;
  let im;
  let store = null;
  let mp = null;
  let canvas = null;

  // Input state — bb_KeyX polled per-frame via InputManager
  let keys = {};
  let leftStickAngle = null;
  let rightStickAngle = null;
  let rightTrigger = 0;
  let jumpPressed = false;
  let wasLeftTriggerDown = false;
  let isLeftTriggerDown = false;
  let throwIntent = 0;

  // Player state
  let posX = 0;
  let posZ = 0;
  let angleX = 0;
  let angleY = 0;
  let jumpTimer = 0;
  let jumpWithBall = false;
  let catching = false;
  let accumulator = 0;
  let syncTimer = 0;

  function clamp(v, min, max) {
    return Math.min(Math.max(v, min), max);
  }

  function getAvatarY() {
    if (jumpTimer === 0) return 0;
    let duration = jumpWithBall ? JUMP_DURATION_WITH_BALL : JUMP_DURATION_NO_BALL;
    let n = duration - jumpTimer;
    let boost = jumpWithBall ? JUMP_BOOST_WITH_BALL : JUMP_BOOST_NO_BALL;
    return Math.max(0, boost * n - JUMP_GRAVITY * (n - 1) * n / 2);
  }

  function gatherKeyboard() {
    leftStickAngle = null;
    let left = (im ? im.getMotion("lateral") < 0 : false) || false;
    let up = (im ? im.getMotion("forward") > 0 : false) || false;
    let right = (im ? im.getMotion("lateral") > 0 : false) || false;
    let down = (im ? im.getMotion("forward") < 0 : false) || false;

    if (left) {
      if (up) leftStickAngle = -Math.PI * 3 / 4;
      else if (down) leftStickAngle = Math.PI * 3 / 4;
      else leftStickAngle = Math.PI;
    } else if (right) {
      if (up) leftStickAngle = -Math.PI / 4;
      else if (down) leftStickAngle = Math.PI / 4;
      else leftStickAngle = 0;
    } else if (down) {
      leftStickAngle = Math.PI / 2;
    } else if (up) {
      leftStickAngle = -Math.PI / 2;
    }

    rightStickAngle = leftStickAngle;
    rightTrigger = (im ? im.getAction("crouch") : false) || (im ? im.getAction("crouch") : false) ? 0.5 : ((im ? im.getAction("run") : false) || (im ? im.getAction("run") : false) ? 1 : 0);
    jumpPressed = (im ? im.getAction("jump") : false) || false;

    let prevLT = wasLeftTriggerDown;
    wasLeftTriggerDown = isLeftTriggerDown;
    isLeftTriggerDown = !!(im && im.getAction("bb_KeyX"));
    if (!wasLeftTriggerDown && isLeftTriggerDown) {
      throwIntent++;
    }
  }

  function gatherGamepad() {
    let gamepads = window.navigator.getGamepads ? window.navigator.getGamepads() : [];
    let found = false;
    for (let i = 0; i < gamepads.length; i++) {
      let gp = gamepads[i];
      if (!gp || gp.axes.length < 2 || gp.buttons.length < 8) continue;

      let lx = gp.axes[0];
      let ly = gp.axes[1];
      if (Math.sqrt(lx * lx + ly * ly) > 0.35) {
        leftStickAngle = Math.atan2(ly, lx);
      } else {
        leftStickAngle = null;
      }

      if (gp.axes.length >= 4) {
        let rx = gp.axes[2];
        let ry = gp.axes[3];
        if (Math.sqrt(rx * rx + ry * ry) > 0.35) {
          rightStickAngle = Math.atan2(ry, rx);
        } else {
          rightStickAngle = leftStickAngle;
        }
      }

      rightTrigger = gp.buttons[7] && gp.buttons[7].value > 0.1 ? gp.buttons[7].value : 0;
      jumpPressed = (gp.buttons[4] && gp.buttons[4].pressed) || (gp.buttons[5] && gp.buttons[5].pressed);

      let prevLT = wasLeftTriggerDown;
      wasLeftTriggerDown = isLeftTriggerDown;
      isLeftTriggerDown = gp.buttons[6] && gp.buttons[6].pressed;
      if (!wasLeftTriggerDown && isLeftTriggerDown) {
        throwIntent++;
      }

      found = true;
      break;
    }
    return found;
  }

  function gatherInput() {
    if (!gatherGamepad()) {
      gatherKeyboard();
    }
  }

  function tick() {
    let matchState = store.get("bb_match_state") || "waiting";
    let ballOwner = store.get("bb_ball_owner") || "";
    let mySession = (mp && mp.player) ? mp.player.sessionId : "local";
    let hasBall = ballOwner === mySession;
    let matchPlaying = matchState === "playing";

    // Movement (only when match is playing, not holding ball)
    if (matchPlaying && !hasBall && leftStickAngle !== null) {
      posX = clamp(posX + Math.cos(leftStickAngle) * MOVE_SPEED, -COURT_HALF_W, COURT_HALF_W);
      posZ = clamp(posZ + Math.sin(leftStickAngle) * MOVE_SPEED, -COURT_HALF_D, COURT_HALF_D);
    }

    // Aim direction
    if (rightStickAngle !== null) {
      angleY = rightStickAngle;
    }
    angleX = Math.PI / 3 * rightTrigger;

    // Jumping
    if (jumpPressed && jumpTimer === 0) {
      jumpTimer = hasBall ? JUMP_DURATION_WITH_BALL : JUMP_DURATION_NO_BALL;
      jumpWithBall = hasBall;
    }
    if (jumpTimer > 0) jumpTimer--;

    // Catching
    catching = rightTrigger > 0 && !hasBall;

    // Update gameObject transform and userData
    let gameObject = this.gameObject;
    gameObject.position.x = posX;
    gameObject.position.y = getAvatarY();
    gameObject.position.z = posZ;

    gameObject.userData.bb_angleX = angleX;
    gameObject.userData.bb_angleY = angleY;
    gameObject.userData.bb_catching = catching;
    gameObject.userData.bb_hasBall = hasBall;
    gameObject.userData.bb_isLocal = true;
  }

  this.init = function(_game) {
    game = _game;
    store = this.erth.store;
    mp = game.multiplayerState;
    im = game.inputManager;

    posX = this.gameObject.position.x;
    posZ = this.gameObject.position.z;

    // Set initial userData
    this.gameObject.userData.bb_isLocal = true;
    this.gameObject.userData.bb_team = this.gameObject.userData.bb_team || 0;
    this.gameObject.userData.bb_name = "GUEST" + Math.floor(1000 + Math.random() * 9000);
    this.gameObject.userData.bb_angleX = 0;
    this.gameObject.userData.bb_angleY = 0;
    this.gameObject.userData.bb_catching = false;
    this.gameObject.userData.bb_hasBall = false;

    canvas = game.renderer ? game.renderer.domElement : null;

    // Broadcast initial player data
    if (mp) {
      mp.setPlayerData("bb_name", this.gameObject.userData.bb_name);
      mp.setPlayerData("bb_team", "" + (this.gameObject.userData.bb_team || 0));
      mp.setPlayerData("bb_throw", "0");
    }
  };

  this.update = function(deltaTime) {
    gatherInput();

    // Tick at 20Hz
    accumulator += deltaTime;
    while (accumulator >= TICK_RATE) {
      accumulator -= TICK_RATE;
      tick.call(this);
    }

    // Broadcast to multiplayer at 20Hz
    syncTimer += deltaTime;
    if (syncTimer >= SYNC_INTERVAL && mp) {
      syncTimer = 0;
      mp.setPlayerData("bb_pos", JSON.stringify({ x: posX, z: posZ }));
      mp.setPlayerData("bb_ay", "" + angleY);
      mp.setPlayerData("bb_ax", "" + angleX);
      mp.setPlayerData("bb_catching", catching ? "1" : "0");
      mp.setPlayerData("bb_jump", JSON.stringify({ timer: jumpTimer, withBall: jumpWithBall }));
      mp.setPlayerData("bb_throw", "" + throwIntent);
    }

    // Write local state to store for ball controller
    store.set("bb_local_x", posX);
    store.set("bb_local_z", posZ);
    store.set("bb_local_y", this.gameObject.position.y);
    store.set("bb_local_ax", angleX);
    store.set("bb_local_ay", angleY);
    store.set("bb_local_catching", catching);
    store.set("bb_local_jump_timer", jumpTimer);
    store.set("bb_local_jump_with_ball", jumpWithBall);
    store.set("bb_local_throw", throwIntent);
  };

  this.dispose = function() {
    keys = {};
    game = null;
    store = null;
    mp = null;
    canvas = null;
  };

