    Reads pose from target.userData. Configure attributes in the editor to tune
    gameplay behavior.

code: |
  // Source geometry: head 0.5^3, body 0.4x0.4x0.5, arm 0.6x0.2x0.2 (shifted +0.3 x),
  // leg 0.2x0.6x0.2 (shifted -0.3 y). Materials: head #ff8888, skin #cc8888,
  // team red #ff4444, team blue #4444ff

  let meshes = [];
  let geos = [];
  let mats = [];
  let body = null;
  let shoulders = null;
  let nametagMesh = null;
  let nametagCanvas = null;
  let nametagTex = null;
  let currentName = "";
  let currentTeam = -1;

  let TEAM_COLORS = [0xff4444, 0x4444ff];

  function cleanup() {
    for (let i = 0; i < meshes.length; i++) {
      if (meshes[i].parent) meshes[i].parent.remove(meshes[i]);
    }
    for (let i = 0; i < geos.length; i++) geos[i].dispose();
    for (let i = 0; i < mats.length; i++) mats[i].dispose();
    if (nametagTex) { nametagTex.dispose(); nametagTex = null; }
    meshes = [];
    geos = [];
    mats = [];
    body = null;
    shoulders = null;
    nametagMesh = null;
    nametagCanvas = null;
    currentName = "";
    currentTeam = -1;
  }

  function buildAvatar(parent, teamIndex) {
    let headMat = new THREE.MeshStandardNodeMaterial({ color: 0xff8888, roughness: 0.8, metalness: 0.3 });
    let skinMat = new THREE.MeshStandardNodeMaterial({ color: 0xcc8888, roughness: 0.8, metalness: 0.3 });
    let teamColor = TEAM_COLORS[teamIndex] || 0xff4444;
    let bodyMat = new THREE.MeshStandardNodeMaterial({ color: teamColor, roughness: 0.8, metalness: 0.3 });
    mats.push(headMat, skinMat, bodyMat);

    // Body at y=0.7
    let bodyGeo = new THREE.BoxGeometry(0.4, 0.4, 0.5);
    body = new THREE.Mesh(bodyGeo, bodyMat);
    body.userData.isRuntimeOnly = true;
    body.castShadow = true;
    body.receiveShadow = true;
    body.position.y = 0.7;
    parent.add(body);
    meshes.push(body);
    geos.push(bodyGeo);

    // Head at y=0.5 on body (global y ~ 1.2)
    let headGeo = new THREE.BoxGeometry(0.5, 0.5, 0.5);
    let head = new THREE.Mesh(headGeo, headMat);
    head.userData.isRuntimeOnly = true;
    head.castShadow = true;
    head.receiveShadow = true;
    head.position.y = 0.5;
    body.add(head);
    meshes.push(head);
    geos.push(headGeo);

    // Shoulders group at y=0.2 on body (global y ~ 0.9 = shoulderY)
    shoulders = new THREE.Group();
    shoulders.userData.isRuntimeOnly = true;
    shoulders.position.y = 0.2;
    shoulders.rotation.order = "YXZ";
    shoulders.rotation.set(0, 0, -Math.PI * 0.4);
    body.add(shoulders);

    // Arms — geometry shifted +0.3 in x so pivot is at shoulder joint
    let armGeo = new THREE.BoxGeometry(0.6, 0.2, 0.2);
    armGeo.translate(0.3, 0, 0);

    let leftArm = new THREE.Mesh(armGeo.clone(), skinMat);
    leftArm.userData.isRuntimeOnly = true;
    leftArm.castShadow = true;
    leftArm.receiveShadow = true;
    leftArm.position.z = 0.3;
    shoulders.add(leftArm);
    meshes.push(leftArm);
    geos.push(leftArm.geometry);

    let rightArm = new THREE.Mesh(armGeo.clone(), skinMat);
    rightArm.userData.isRuntimeOnly = true;
    rightArm.castShadow = true;
    rightArm.receiveShadow = true;
    rightArm.position.z = -0.3;
    shoulders.add(rightArm);
    meshes.push(rightArm);
    geos.push(rightArm.geometry);

    armGeo.dispose();

    // Pelvis at y=-0.1 on body
    let pelvis = new THREE.Group();
    pelvis.userData.isRuntimeOnly = true;
    pelvis.position.y = -0.1;
    body.add(pelvis);

    // Legs — geometry shifted -0.3 in y so pivot is at hip joint
    let legGeo = new THREE.BoxGeometry(0.2, 0.6, 0.2);
    legGeo.translate(0, -0.3, 0);

    let leftLeg = new THREE.Mesh(legGeo.clone(), skinMat);
    leftLeg.userData.isRuntimeOnly = true;
    leftLeg.castShadow = true;
    leftLeg.receiveShadow = true;
    leftLeg.position.z = 0.1;
    pelvis.add(leftLeg);
    meshes.push(leftLeg);
    geos.push(leftLeg.geometry);

    let rightLeg = new THREE.Mesh(legGeo.clone(), skinMat);
    rightLeg.userData.isRuntimeOnly = true;
    rightLeg.castShadow = true;
    rightLeg.receiveShadow = true;
    rightLeg.position.z = -0.1;
    pelvis.add(rightLeg);
    meshes.push(rightLeg);
    geos.push(rightLeg.geometry);

    legGeo.dispose();
  }

  function buildNametag(parent, name, isLocal) {
    if (nametagMesh) {
      if (nametagMesh.parent) nametagMesh.parent.remove(nametagMesh);
      if (nametagMesh.geometry) nametagMesh.geometry.dispose();
      if (nametagMesh.material) nametagMesh.material.dispose();
    }
    if (nametagTex) { nametagTex.dispose(); nametagTex = null; }

    nametagCanvas = document.createElement("canvas"); // @check-ok
    nametagCanvas.height = 64;
    let ctx = nametagCanvas.getContext("2d");
    ctx.font = "bold 48px sans-serif";
    let text = (name || "GUEST").toUpperCase();
    let tw = ctx.measureText(text).width + 32;
    nametagCanvas.width = Math.max(tw, 64);

    ctx.fillStyle = isLocal ? "rgba(255,255,255,1)" : "rgba(0,0,0,0.5)";
    ctx.fillRect(0, 0, nametagCanvas.width, nametagCanvas.height);
    ctx.font = "bold 48px sans-serif";
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.fillStyle = isLocal ? "#000" : "#fff";
    ctx.fillText(text, nametagCanvas.width / 2, nametagCanvas.height / 2);

    nametagTex = new THREE.CanvasTexture(nametagCanvas);
    let geo = new THREE.PlaneGeometry(1, 0.25);
    let mat = new THREE.MeshBasicNodeMaterial({ map: nametagTex, transparent: true, opacity: 0.5 });
    nametagMesh = new THREE.Mesh(geo, mat);
    nametagMesh.userData.isRuntimeOnly = true;
    nametagMesh.position.y = 1.8;
    nametagMesh.scale.x = nametagCanvas.width / 256;
    parent.add(nametagMesh);
    meshes.push(nametagMesh);
    geos.push(geo);
    mats.push(mat);
  }

  function updatePose(target) {
    let ud = target.userData;
    if (!body) return;

    // Body rotation: face the look direction
    let angleY = ud.bb_angleY || 0;
    body.rotation.y = -angleY;

    // Shoulder rotation: catching/hasBall raises arms, otherwise arms hang down
    if (shoulders) {
      let catching = ud.bb_catching || false;
      let hasBall = ud.bb_hasBall || false;
      let angleX = ud.bb_angleX || 0;
      if (catching || hasBall) {
        shoulders.rotation.z = angleX;
      } else {
        shoulders.rotation.z = -Math.PI * 0.4;
      }
    }
  }

  // --- Editor mode ---
  this.onEditorAdded = function(editor) {
    let teamIdx = this.getAttribute("teamIndex") || 0;
    buildAvatar(this.gameObject._internal.three, teamIdx);
    buildNametag(this.gameObject._internal.three, "PLAYER", true);
    currentTeam = teamIdx;
  };

  this.onEditorUpdate = function() {
    // Billboard nametag toward editor camera
    if (nametagMesh) {
      nametagMesh.rotation.y = 0;
    }
  };

  this.onEditorDispose = function() {
    cleanup();
  };

  let game = null;

  // --- Play mode ---
  this.init = function(_game) {
    game = _game;
    let teamIdx = this.gameObject.userData.bb_team;
    if (teamIdx === undefined) teamIdx = this.getAttribute("teamIndex") || 0;
    buildAvatar(this.gameObject._internal.three, teamIdx);
    currentTeam = teamIdx;

    let name = this.gameObject.userData.bb_name || "GUEST";
    let isLocal = this.gameObject.userData.bb_isLocal || false;
    buildNametag(this.gameObject._internal.three, name, isLocal);
    currentName = name;
  };

  this.update = function(deltaTime) {
    let ud = this.gameObject.userData;

    // Rebuild nametag if name changed
    let name = ud.bb_name || "GUEST";
    if (name !== currentName) {
      currentName = name;
      buildNametag(this.gameObject._internal.three, name, ud.bb_isLocal || false);
    }

    // Rebuild avatar if team changed
    let teamIdx = ud.bb_team;
    if (teamIdx !== undefined && teamIdx !== currentTeam) {
      cleanup();
      buildAvatar(this.gameObject._internal.three, teamIdx);
      buildNametag(this.gameObject._internal.three, currentName, ud.bb_isLocal || false);
      currentTeam = teamIdx;
    }

    // Update pose
    updatePose(this.gameObject._internal.three);

    // Billboard nametag toward camera
    if (nametagMesh && game && game.camera) {
      nametagMesh.lookAt(game.camera.position);
    }
  };

  this.dispose = function() {
    cleanup();
    for (let i = 0; i < meshes.length; i++) {
      if (meshes[i].parent) meshes[i].parent.remove(meshes[i]);
    }
  };

