  @import "uikit-dual-mode" as uikit;

  // Dual-mode UIKit helper lives in `imports/uikit-dual-mode.yaml`.

  // Factory accepts a dual-mode `ctx` (from `uikit.createPlayContext` or
  // `uikit.createEditorContext`). The editor preview shares the same UIKit
  // tree as play; the editor doesn't call `update()` so game logic / audio
  // stays dormant there.
  function createDrop7Api(behavior, ctx) {
    const game = ctx.gameLike;
    const BOARD_SIZE = 7;
    // Drop timing: a short baseline plus per-row time so deeper chips feel
    // weightier. After the fall, the chip rests briefly at its landing slot
    // before the next preview chip appears.
    const DROP_DURATION_BASE = 0.12;
    const DROP_DURATION_PER_ROW = 0.04;
    const DROP_REST = 0.15;
    // Tap feedback: brief column highlight after dropInColumn() fires.
    const FLASH_DURATION = 0.25;

    // Layout sizes — baselines set here; applyScale() rescales them at startup
    // so the board also fits narrow phone viewports without clipping.
    let CELL_SIZE = 58;
    let CELL_GAP = 8;
    let GRID_PAD = 12;
    let PREVIEW_LANE = 72;
    let DISC_SIZE = CELL_SIZE - 10;
    let GRID_TOTAL = BOARD_SIZE * CELL_SIZE + (BOARD_SIZE - 1) * CELL_GAP + GRID_PAD * 2;
    let ROOT_PAD = 20;
    let COLUMN_BUTTON_H = 48;

    // Font size baselines — also rescaled by applyScale().
    let FS_TITLE = 34;
    let FS_SUBTITLE = 14;
    let FS_STAT_VALUE = 20;
    let FS_STAT_LABEL = 11;
    let FS_CURRENT_LABEL = 12;
    let FS_CURRENT_DISC = 18;
    let FS_STATUS = 14;
    let FS_HINT = 12;
    let FS_COLUMN_LABEL = 14;
    let FS_CELL_LABEL = 18;
    let FS_OVERLAY_TITLE = 40;
    let FS_OVERLAY_BODY = 16;
    let FS_OVERLAY_BUTTON = 16;

    const COLOR_BG = 0x101821;
    const COLOR_PANEL = 0x182634;
    const COLOR_PANEL_ALT = 0x213346;
    const COLOR_TEXT = 0xf4f3ee;
    const COLOR_MUTED = 0x93a8bb;
    const COLOR_SLOT = 0x2a3c4b;
    const COLOR_SLOT_RING = 0x30495d;
    const COLOR_BUTTON = 0x274056;
    const COLOR_BUTTON_ACTIVE = 0xffa552;
    const COLOR_BUTTON_DISABLED = 0x3a4956;
    const COLOR_OVERLAY = 0x0b1118;
    const COLOR_GLOW_ORANGE = 0xff8a5b;
    const COLOR_GLOW_TEAL = 0x33c7b6;
    const COLOR_GLOW_GOLD = 0xffd166;
    const COLOR_GLOW_SKY = 0x58a6ff;

    const DISC_COLORS = {
      1: { bg: 0xf4f1de, fg: 0x22313f },
      2: { bg: 0xe07a5f, fg: 0xffffff },
      3: { bg: 0x81b29a, fg: 0x122029 },
      4: { bg: 0xf2cc8f, fg: 0x332313 },
      5: { bg: 0x669bbc, fg: 0xffffff },
      6: { bg: 0xc8553d, fg: 0xffffff },
      7: { bg: 0x9d4edd, fg: 0xffffff }
    };

    const SOLID_COLORS = {
      hidden: { bg: 0x59636f, fg: 0xe8ecef },
      cracked: { bg: 0x98a4af, fg: 0x1b242c }
    };

    const NEIGHBORS = [
      [-1, 0],
      [1, 0],
      [0, -1],
      [0, 1]
    ];

    let board = [];
    let selectedColumn = 3;
    let currentDisc = null;
    let roundLength = 5;
    let solidDiscChance = 0.18;
    let clearBaseScore = 7;
    let clearBoardBonus = 70000;
    let score = 0;
    let bestScore = 0;
    let level = 1;
    let turnsTaken = 0;
    let statusTextValue = "Tap a column or press Space to drop.";
    let gameOver = false;
    let dirty = true;

    // "intro" before the player hits Start, "playing" during a run,
    // "over" after a game ends. Drop/input paths only fire when "playing".
    // The overlay is shown for intro and over, hidden while playing.
    let gameState = "intro";
    let overlayHandler = function () {};

    let root = null;
    let rootParented = false;
    let scoreValue = null;
    let bestValue = null;
    let levelValue = null;
    let riseValue = null;
    let columnValue = null;
    let statusText = null;
    let currentDiscView = null;
    let currentDiscLabel = null;
    let floatingDiscView = null;
    let floatingDiscLabel = null;
    let overlay = null;
    let overlayTitle = null;
    let overlayBody = null;
    let overlayButtonLabel = null;
    let activeDrop = null;

    const columnButtons = [];
    const columnLabels = [];
    const cellDiscs = [];
    const cellLabels = [];
    const columnFlashTimers = new Array(BOARD_SIZE).fill(0);
    let inputPrev = { left: false, right: false, drop: false, restart: false };

    // Audio — non-positional SFX played via a single THREE.AudioListener
    // attached to game.camera. Buffers load lazily from import-asset names;
    // playSound() silently no-ops for any name whose buffer isn't ready yet,
    // so the game remains playable even if audio files fail to load.
    let audioListener = null;
    const audioBuffers = {};
    const audioInstances = {};
    const audioNames = ["DropSfx", "LandSfx", "ClearSfx", "ChainSfx", "OverSfx"];

    function randomNumberDisc() {
      return { kind: "number", value: 1 + Math.floor(Math.random() * BOARD_SIZE) };
    }

    function solidDisc() {
      return { kind: "hidden", value: null };
    }

    function copyDisc(disc) {
      return disc ? { kind: disc.kind, value: disc.value } : null;
    }

    function cellKey(row, col) {
      return row + "," + col;
    }

    // onClick factory — captures `col` as a function parameter so each
    // handler has its own bound value. Using an inline closure inside a
    // `for (let col ...)` loop was producing handlers that all fired the
    // same column at runtime; this version is bulletproof regardless of
    // how the script is parsed or re-scoped.
    function tapHandlerFor(col) {
      return function() { dropInColumn(col); };
    }

    function loadAudioAsset(name) {
      const erth = behavior && behavior.erth;
      if (!erth || !erth.asset || !erth.asset.audio) return;
      erth.asset.audio.findByName(name).then(function(ref) {
        if (!ref) return;
        return erth.asset.audio.getUrl(ref);
      }).then(function(url) {
        if (!url) return;
        const loader = new THREE.AudioLoader();
        loader.load(url, function(buffer) {
          audioBuffers[name] = buffer;
        });
      }).catch(function() {
        // Silently ignore — playSound() guards for missing buffers.
      });
    }

    function playSound(name, volume) {
      if (!audioListener || !audioBuffers[name]) return;
      let audio = audioInstances[name];
      if (!audio) {
        audio = new THREE.Audio(audioListener);
        audioInstances[name] = audio;
      }
      if (!audio.buffer) audio.setBuffer(audioBuffers[name]);
      audio.setVolume(typeof volume === "number" ? Math.max(0, Math.min(1, volume)) : 0.6);
      audio.setLoop(false);
      if (audio.isPlaying) audio.stop();
      audio.play();
    }

    // Overlay helpers — single overlay widget reused for both the intro
    // "Start" screen and the game-over "Play again" screen.
    function showOverlay(title, body, buttonLabel, handler) {
      if (!overlay) return;
      overlayHandler = typeof handler === "function" ? handler : function () {};
      if (overlayTitle) overlayTitle.setProperties({ text: title });
      if (overlayBody) overlayBody.setProperties({ text: body });
      if (overlayButtonLabel) overlayButtonLabel.setProperties({ text: buttonLabel });
      overlay.setProperties({ visibility: "visible" });
    }

    function hideOverlay() {
      if (overlay) overlay.setProperties({ visibility: "hidden" });
    }

    // Start and Play-again both route here: reset state, unblock input,
    // dismiss the overlay.
    function beginGame() {
      newGame();
      gameState = "playing";
      hideOverlay();
    }

    // RGB lerp between two 0xRRGGBB colors, used to pulse the column
    // button toward white briefly on tap.
    function lerpHex(a, b, t) {
      const ar = (a >> 16) & 0xff;
      const ag = (a >> 8) & 0xff;
      const ab = a & 0xff;
      const br = (b >> 16) & 0xff;
      const bg = (b >> 8) & 0xff;
      const bb = b & 0xff;
      const r = Math.round(ar + (br - ar) * t);
      const g = Math.round(ag + (bg - ag) * t);
      const bl = Math.round(ab + (bb - ab) * t);
      return (r << 16) | (g << 8) | bl;
    }

    function buildStatBox(parent, label, value) {
      const box = new UIKit.Container({
        backgroundColor: COLOR_PANEL,
        borderRadius: 12,
        paddingTop: 10,
        paddingBottom: 10,
        paddingLeft: 14,
        paddingRight: 14,
        alignItems: "center",
        gap: 2,
        visibility: "visible"
      });

      box.add(new UIKit.Text({
        text: label,
        fontSize: FS_STAT_LABEL,
        color: COLOR_MUTED,
        visibility: "visible"
      }));

      const valueText = new UIKit.Text({
        text: value,
        fontSize: FS_STAT_VALUE,
        fontWeight: "bold",
        color: COLOR_TEXT,
        visibility: "visible"
      });

      box.add(valueText);
      parent.add(box);
      return valueText;
    }

    function buildOverlay(parent) {
      // Horizontal padding keeps the title/body/button off the overlay
      // edges so the button never visually clips against the rounded
      // corner of the board frame.
      const nextOverlay = new UIKit.Container({
        positionType: "absolute",
        positionTop: 0,
        positionLeft: 0,
        positionRight: 0,
        positionBottom: 0,
        borderRadius: 16,
        backgroundColor: COLOR_OVERLAY,
        backgroundOpacity: 0.86,
        flexDirection: "column",
        justifyContent: "center",
        alignItems: "center",
        gap: 12,
        paddingLeft: 24,
        paddingRight: 24,
        pointerEvents: "auto",
        // Must outrank floatingDiscView's zIndexOffset (100) so the Start
        // / Play-again button is always tappable while the overlay is up.
        zIndexOffset: 200,
        visibility: "visible"
      });
      nextOverlay.setProperties({ visibility: "hidden" });

      overlayTitle = new UIKit.Text({
        text: "Game Over",
        fontSize: FS_OVERLAY_TITLE,
        fontWeight: "bold",
        color: COLOR_TEXT,
        visibility: "visible"
      });
      nextOverlay.add(overlayTitle);

      // maxWidth keeps long body copy from stretching the overlay's
      // flex layout past the parent's edge, which was shifting the
      // centered button off-screen on narrow viewports.
      overlayBody = new UIKit.Text({
        text: "",
        fontSize: FS_OVERLAY_BODY,
        color: COLOR_MUTED,
        textAlign: "center",
        maxWidth: Math.max(200, GRID_TOTAL - 48),
        visibility: "visible"
      });
      nextOverlay.add(overlayBody);

      // minWidth gives a stable, generous tap target regardless of
      // whether the label is "Start" (5 chars) or "Play again" (10).
      const restartButton = new UIKit.Container({
        minWidth: 160,
        backgroundColor: COLOR_BUTTON_ACTIVE,
        borderRadius: 10,
        paddingTop: 12,
        paddingBottom: 12,
        paddingLeft: 24,
        paddingRight: 24,
        flexDirection: "row",
        justifyContent: "center",
        alignItems: "center",
        cursor: "pointer",
        pointerEvents: "auto",
        hover: { backgroundOpacity: 0.85 },
        // Handler is routed through overlayHandler so showOverlay() can
        // swap behavior between "Start" (intro) and "Play again" (over).
        onClick: function() { if (overlayHandler) overlayHandler(); },
        visibility: "visible"
      });
      // pointerEvents:none on the label ensures the Container's onClick
      // fires anywhere on the button — including dead center over the text
      // — instead of the label silently absorbing the hit.
      overlayButtonLabel = new UIKit.Text({
        text: "Play again",
        fontSize: FS_OVERLAY_BUTTON,
        fontWeight: "bold",
        color: 0x1d1d1d,
        pointerEvents: "none",
        visibility: "visible"
      });
      restartButton.add(overlayButtonLabel);
      nextOverlay.add(restartButton);

      parent.add(nextOverlay);
      return nextOverlay;
    }

    // Records the last viewport reading so we can see in the console which
    // signal actually fed applyScale() — invaluable when the phone layout
    // disagrees with what stemstudio thinks the viewport size is.
    let lastViewportDebug = null;

    function measureViewportWidth() {
      // Fallback chain, most-trusted first:
      //  1. canvas clientWidth (what the user actually sees in CSS px)
      //  2. renderer.getSize().x (renderer's internal size — may be DPR-scaled)
      //  3. window.innerWidth (CSS viewport — works even if canvas hasn't
      //     laid out yet at init() time, which is the suspected phone bug)
      //  4. documentElement.clientWidth (last-resort DOM fallback)
      //  5. 375 (iPhone default — better phone default than 540)
      const debug = {
        clientWidth: 0,
        clientHeight: 0,
        rendererWidth: 0,
        rendererHeight: 0,
        innerWidth: 0,
        innerHeight: 0,
        documentClientWidth: 0,
        devicePixelRatio: 0,
        source: "default",
        value: 375
      };

      if (game && game.renderer) {
        const el = game.renderer.domElement;
        if (el) {
          debug.clientWidth = el.clientWidth || 0;
          debug.clientHeight = el.clientHeight || 0;
        }
        const size = new THREE.Vector2();
        game.renderer.getSize(size);
        debug.rendererWidth = size.x || 0;
        debug.rendererHeight = size.y || 0;
      }

      // window.innerWidth is the CSS layout viewport, distinct from canvas
      // client size — we need it specifically because on phones the canvas
      // may not have laid out by the time init() runs. Canvas-based helpers
      // won't substitute here.
      if (typeof window !== "undefined") {
        debug.innerWidth = window.innerWidth || 0; // @check-ok
        debug.innerHeight = window.innerHeight || 0; // @check-ok
        debug.devicePixelRatio = window.devicePixelRatio || 0; // @check-ok
        if (window.document && window.document.documentElement) { // @check-ok
          debug.documentClientWidth = window.document.documentElement.clientWidth || 0; // @check-ok
        }
      }

      if (debug.clientWidth > 0) {
        debug.source = "canvas.clientWidth";
        debug.value = debug.clientWidth;
      } else if (debug.rendererWidth > 0) {
        debug.source = "renderer.getSize";
        debug.value = debug.rendererWidth;
      } else if (debug.innerWidth > 0) {
        debug.source = "window.innerWidth";
        debug.value = debug.innerWidth;
      } else if (debug.documentClientWidth > 0) {
        debug.source = "documentElement.clientWidth";
        debug.value = debug.documentClientWidth;
      }

      lastViewportDebug = debug;
      return debug.value;
    }

    function applyScale() {
      const availableWidth = Math.max(280, measureViewportWidth());
      const baseline = 540;
      const uiScale = Math.min(1, Math.max(0.45, (availableWidth - 24) / baseline));

      CELL_SIZE = Math.floor(58 * uiScale);
      CELL_GAP = Math.max(4, Math.floor(8 * uiScale));
      GRID_PAD = Math.max(8, Math.floor(12 * uiScale));
      PREVIEW_LANE = Math.floor(72 * uiScale);
      DISC_SIZE = CELL_SIZE - Math.max(6, Math.floor(10 * uiScale));
      GRID_TOTAL = BOARD_SIZE * CELL_SIZE + (BOARD_SIZE - 1) * CELL_GAP + GRID_PAD * 2;
      ROOT_PAD = Math.max(10, Math.floor(20 * uiScale));
      COLUMN_BUTTON_H = Math.max(44, Math.floor(48 * uiScale));

      FS_TITLE = Math.max(22, Math.floor(34 * uiScale));
      FS_SUBTITLE = Math.max(11, Math.floor(14 * uiScale));
      FS_STAT_VALUE = Math.max(14, Math.floor(20 * uiScale));
      FS_STAT_LABEL = Math.max(9, Math.floor(11 * uiScale));
      FS_CURRENT_LABEL = Math.max(10, Math.floor(12 * uiScale));
      FS_CURRENT_DISC = Math.max(14, Math.floor(18 * uiScale));
