code: |
  // ============================================================
  // Beachy Beachy Ball — Obstacle Animator
  // Drives kinematic physics bodies each frame.
  // Spinner: rotates around Y axis.
  // Limbo: oscillates Y position (sine wave).
  // Slider: oscillates X position (sine wave).
  // Source: Blocks.jsx obstacle components
  // ============================================================

  let game;
  let totalTime = 0;

  this.init = function(_game) {
      game = _game;
    totalTime = 0;

    // Set shadow properties
    let threeObj = this.gameObject._internal.three;
    threeObj.castShadow = true;
    threeObj.receiveShadow = true;
  };

  this.update = function(dt) {
    totalTime += dt;

    let type = this.getAttribute("animationType") || "spinner";
    let speed = this.getAttribute("speed") || 1.5;
    let freq = this.getAttribute("frequency") || 1.5;
    let amp = this.getAttribute("amplitude") || 1;
    let base = this.getAttribute("baseOffset") || 0;

    if (type === "spinner") {
      // Source: rotation.setFromEuler(new Euler(0, time * speed, 0))
      this.gameObject.rotation.y = totalTime * speed;
    } else if (type === "limbo") {
      // Source: y = sin(freq * difficulty * time + offset) * amplitude + baseOffset
      this.gameObject.position.y = amp * Math.sin(freq * totalTime) + base;
    } else if (type === "slider") {
      // Source: x = sin(freq * difficulty * time + offset) * amplitude + baseOffset
      this.gameObject.position.x = amp * Math.sin(freq * totalTime) + base;
    }
  };

  this.dispose = function() {
    totalTime = 0;
  };

