  const FREQ_X = 0.5;
  const FREQ_Z = 0.5;
  const OCTAVES = 3;
  const LACUNARITY = 2;
  const PERSISTENCE = 0.5;
  const TREE_DENSITY = 5;
  const SEGMENT_DENSITY = 2;

  // --- Math helpers ---
  function lerp(a, b, t) { return a + (b - a) * t; }
