    let grassR = lerp(uGrassR, 0.33, biome * 0.5);
    let grassG = lerp(uGrassG, 0.2, biome * 0.5);
    let grassB = lerp(uGrassB, 0.0, biome * 0.5);
    let landR = lerp(uLandR, 0.1, biome * 0.5);
    let landG = lerp(uLandG, 0.25, biome * 0.5);
