    let rocksG = lerp(uRocksG, 0.0, biome);
    let rocksB = lerp(uRocksB, 0.01, biome);

    let r = 0, g = 0, b = 0;

    // Layer 1: Deep ocean (source: smoothstep(-24,-40,h) → mix blue/dark blue)
    let pctDeep = smoothstep(h, -24, -40);
    r = lerp(0.0, 0.0, pctDeep);
    g = lerp(0.0, 0.0, pctDeep);
    b = lerp(0.5, 0.02, pctDeep);

    // Layer 2: Ocean (source: smoothstep(-6,-16,h) → mix with sea blue)
    let pctSea = smoothstep(h, -6, -16);
    r = lerp(0.0, r, pctSea);
    g = lerp(0.2, g, pctSea);
    b = lerp(0.6, b, pctSea);

    // Layer 3: Shoreline cutoff (source: step(h, 0) → black above water)
    if (h > 0) {
      r = 0; g = 0; b = 0;
    }

    // Layer 4: Sand (source: step(h, 0.1))
    if (h <= 0.1 && h > 0) {
      r = 0.9; g = 0.8; b = 0.5;
    }

    // Layer 5: Grass with sine/cosine perturbed boundary
    // Source: step(h + sin(wx*0.3)*0.6 + cos(wz*0.3)*0.6, 1.7)
    let pH1 = h + Math.sin(wx * 0.3) * 0.6 + Math.cos(wz * 0.3) * 0.6;
    if (pH1 > 1.7) {
      r = grassR; g = grassG; b = grassB;
    }

    // Layer 6: Land with sine/cosine perturbed boundary
    // Source: step(h + sin(wx*0.1)*1.6 + cos(wz*0.1)*1.6, 14.1)
    let pH2 = h + Math.sin(wx * 0.1) * 1.6 + Math.cos(wz * 0.1) * 1.6;
    if (pH2 > 14.1) {
      r = landR; g = landG; b = landBv;
    }

    // Layer 7: Rocks with sine/cosine perturbed boundary
    // Source: step(h + sin(wx*0.15)*2.5 + cos(wz*0.15)*2.5, 22.2)
    let pH3 = h + Math.sin(wx * 0.15) * 2.5 + Math.cos(wz * 0.15) * 2.5;
    if (pH3 > 22.2) {
      r = rocksR; g = rocksG; b = rocksB;
    }

    // Layer 8: Snow with sine/cosine perturbed boundary
    // Source: step(h + sin(wx*0.15)*5 + cos(wz*0.15)*5, 40.2)
    let pH4 = h + Math.sin(wx * 0.15) * 5.0 + Math.cos(wz * 0.15) * 5.0;
    if (pH4 > 40.2) {
      r = 0.4; g = 0.8; b = 0.9;
    }

