  }

  // --- State ---
  let store = null;
  let noises = [];
  let chunks = {};
  let pool = [];
  let lastChunkKey = null;
  let chunkMaterial = null;
  let treeMaterial = null;
  let cloudMaterial = null;
  let normalTexture = null;
  let previewMode = false;

