  function createChunkMesh(ci, cj, lod) {
    let segs = Math.max(Math.floor(CHUNK_SIZE * Math.pow(0.5, lod)), SEGMENT_DENSITY) / SEGMENT_DENSITY;
    let geo = new THREE.PlaneGeometry(CHUNK_SIZE, CHUNK_SIZE, segs, segs);
