    let posAttr = geo.getAttribute("position");
    let colors = new Float32Array(posAttr.count * 3);
    let wx = (ci + 0.5) * CHUNK_SIZE;
    let wz = (cj + 0.5) * CHUNK_SIZE;

    for (let i = 0; i < posAttr.count; i++) {
      let vx = posAttr.getX(i) + wx;
      let vz = posAttr.getZ(i) + wz;
      let h = getHeight(vx, vz, noises);
      posAttr.setY(i, Math.max(h, -1));
      let bc = getBiomeColor(h, vx, vz, noises);
      colors[i * 3] = bc[0];
      colors[i * 3 + 1] = bc[1];
      colors[i * 3 + 2] = bc[2];
