  }

  function generateTrees(ci, cj) {
    let wx = (ci + 0.5) * CHUNK_SIZE;
    let wz = (cj + 0.5) * CHUNK_SIZE;
    let positions = [];
    let half = CHUNK_SIZE;

    for (let i = 0; i < CHUNK_SIZE; i += TREE_DENSITY) {
      for (let j = 0; j < CHUNK_SIZE; j += TREE_DENSITY) {
        let x = i + wx - half;
        let z = j + wz - half;
        let h = getHeight(x, z, noises);
        // Source: noise[0](x*0.005,z*0.005) + noise[1](x*0.05,z*0.05) > -0.5 && h>4 && h<42
        let n = noises[0](x * 0.005, z * 0.005);
        if (noises.length > 1) n += noises[1](x * 0.05, z * 0.05);
        if (n > -0.5 && h > 4 && h < 42 && Math.random() < n + 0.3) {
