    let geo = new THREE.IcosahedronGeometry(1, 4);
    let inst = new THREE.InstancedMesh(geo, treeMaterial, count);
    markRuntimeOnly(inst);

    for (let i = 0; i < count; i++) {
      _pos.set(
        positions[i * 3] + (Math.random() * 2 - 1),
        positions[i * 3 + 1] + 0.5,
        positions[i * 3 + 2] + (Math.random() * 2 - 1)
      );
      let s = Math.random() * 1.8 + 0.3;
      _scale.set(s, s + Math.random() * 2, s);
      _mat4.compose(_pos, _quat, _scale);
      inst.setMatrixAt(i, _mat4);
      // Source: Color(0x557733).multiplyScalar(Math.random() * 0.8 + 0.4)
      _color.setHex(0x557733).multiplyScalar(Math.random() * 0.8 + 0.4);
