  }

  function generateClouds(ci, cj) {
    let wx = (ci + 0.5) * CHUNK_SIZE;
    let wz = (cj + 0.5) * CHUNK_SIZE;
    let positions = [];
    let half = CHUNK_SIZE;

    for (let i = 0; i < CHUNK_SIZE; i += 1) {
