        n *= n;
        if (n > 3.3 && Math.random() > 0.1) {
          // Source: y = 100 + random -5 to 5
          positions.push(x - wx, 100 + (Math.random() * 10 - 5), z - wz);
        }
      }
    }
    if (positions.length === 0) return null;

    let count = positions.length / 3;
    // Source: IcosahedronGeometry(2, 10). Using detail 5 for performance.
    let geo = new THREE.IcosahedronGeometry(2, 5);
    let inst = new THREE.InstancedMesh(geo, cloudMaterial, count);
    markRuntimeOnly(inst);

    for (let i = 0; i < count; i++) {
