    }
    if (chunkData.trees) {
      targetThree.remove(chunkData.trees);
      chunkData.trees.geometry.dispose();
    }
    if (chunkData.clouds) {
      targetThree.remove(chunkData.clouds);
      chunkData.clouds.geometry.dispose();
    }
  }

