    previewMode = !useStore;
    store = useStore ? erth.store : null;
    noises = [];
    chunks = {};
    pool = [];
    lastChunkKey = null;

    for (let i = 0; i < OCTAVES; i++) {
      noises.push(createNoise2D());
    }

    chunkMaterial = new THREE.MeshStandardNodeMaterial({ vertexColors: true, roughness: 0.85 });
    treeMaterial = new THREE.MeshStandardNodeMaterial({ vertexColors: true, roughness: 0.9 });
    cloudMaterial = new THREE.MeshStandardNodeMaterial({
      vertexColors: true,
      transparent: true,
      opacity: 0.95,
      roughness: 0.9
    });

    let normalAttr = this.getAttribute("normalTexture");
    if (normalAttr) {
      erth.asset.image.createTexture(normalAttr).then(function(tex) {
        normalTexture = tex;
        tex.wrapS = THREE.RepeatWrapping;
        tex.wrapT = THREE.RepeatWrapping;
        tex.repeat.set(6, 6);
        chunkMaterial.normalMap = tex;
        chunkMaterial.normalScale = new THREE.Vector2(1, 1);
        chunkMaterial.needsUpdate = true;
        treeMaterial.normalMap = tex;
        treeMaterial.normalScale = new THREE.Vector2(1, 1);
        treeMaterial.needsUpdate = true;
        cloudMaterial.normalMap = tex;
        cloudMaterial.normalScale = new THREE.Vector2(1, 1);
        cloudMaterial.needsUpdate = true;
      });
    }
  }

  function updateChunksForPosition(px, pz, maxOps) {
    let pi = Math.floor(px / CHUNK_SIZE);
    let pj = Math.floor(pz / CHUNK_SIZE);
    let currentKey = pi + "|" + pj;

    if (currentKey !== lastChunkKey) {
      lastChunkKey = currentKey;

      for (let ci = pi - MAX_DISTANCE + 1; ci <= pi + MAX_DISTANCE + 1; ci++) {
        for (let cj = pj - MAX_DISTANCE + 1; cj <= pj + MAX_DISTANCE + 1; cj++) {
          let key = ci + "|" + cj;
          if (isOutOfRange(ci, cj, pi, pj)) {
            if (chunks[key]) {
              disposeChunk(chunks[key], targetThree);
              chunks[key] = undefined;
            }
            continue;
          }
          if (!chunks[key]) {
            pool.push({ ci: ci, cj: cj });
          }
        }
      }

      pool.sort(function(a, b) {
        let aD = Math.sqrt(Math.pow(a.ci - pi, 2) + Math.pow(a.cj - pj, 2));
        let bD = Math.sqrt(Math.pow(b.ci - pi, 2) + Math.pow(b.cj - pj, 2));
        return bD - aD;
      });
    }

    let ops = maxOps;
    while (pool.length > 0 && ops > 0) {
      let op = pool.pop();
      let key = op.ci + "|" + op.cj;
      if (chunks[key] || isOutOfRange(op.ci, op.cj, pi, pj)) continue;

      let lod = getLOD(op.ci, op.cj, pi, pj);
      let mesh = createChunkMesh(op.ci, op.cj, lod);
      targetThree.add(mesh);

      let chunkData = { mesh: mesh, trees: null, clouds: null, lod: lod };
      if (lod <= 2) {
        let trees = generateTrees(op.ci, op.cj);
        if (trees) {
          trees.position.set((op.ci + 0.5) * CHUNK_SIZE, 0, (op.cj + 0.5) * CHUNK_SIZE);
          targetThree.add(trees);
          chunkData.trees = trees;
        }
      }

      let clouds = generateClouds(op.ci, op.cj);
      if (clouds) {
        clouds.position.set((op.ci + 0.5) * CHUNK_SIZE, 0, (op.cj + 0.5) * CHUNK_SIZE);
        targetThree.add(clouds);
        chunkData.clouds = clouds;
      }
      chunks[key] = chunkData;
      ops--;
    }
  }

  // --- Behavior lifecycle ---

  this.init = function(_game) {
      game = _game;
      erth = this.erth;
      targetThree = this.gameObject._internal.three;
    initRuntimeState(true);
  };

  this.onEditorAdded = function(editor) {
    targetThree = this.gameObject._internal.three;
    this.game = { scene: editor.scene, camera: editor.camera };
    initRuntimeState(false);
    updateChunksForPosition(0, 0, 80);
  };

  this.onEditorUpdate = function() {
    updateChunksForPosition(0, 0, 2);
  };

  this.onEditorAttributesUpdated = function() {
    this.dispose();
    initRuntimeState(!previewMode);
    if (previewMode) {
      updateChunksForPosition(0, 0, 80);
    }
  };

  this.onEditorDispose = function() {
    this.dispose();
  };

  this.onStart = function() {
    // Write spawn height so airplane knows where to start
    let spawnH = Math.max(getHeight(0, 0, noises), 0) + 60;
    store.set("ptg_spawn_height", spawnH);
  };

  this.update = function(deltaTime) {
    if (!store) return;

    let playerPos = store.get("ptg_player_pos");
    let px = playerPos ? playerPos[0] : 0;
    let pz = playerPos ? playerPos[2] : 0;
    updateChunksForPosition(px, pz, 1);
  };

  this.dispose = function() {
    let keys = Object.keys(chunks);
    for (let i = 0; i < keys.length; i++) {
      if (chunks[keys[i]]) disposeChunk(chunks[keys[i]], this.gameObject._internal.three);
    }
    if (chunkMaterial) {
      chunkMaterial.dispose();
    }
    if (treeMaterial) treeMaterial.dispose();
    if (cloudMaterial) cloudMaterial.dispose();
    if (normalTexture) {
      normalTexture.dispose();
      normalTexture = null;
    }
    chunks = {};
    pool = [];
    noises = [];
    store = null;
    lastChunkKey = null;
    chunkMaterial = null;
    treeMaterial = null;
    cloudMaterial = null;
    previewMode = false;
  };

