  // ============================================================
  // PTG Airplane Controller
  // Loads GLTF airplane model, mouse/touch cursor-driven yaw and
  // roll, constant forward movement, vapor trails, and background
  // audio playback. Source: procedural-terrain-generation (plane.js)
  // ============================================================

  let game;
  let erth;
  let targetThree;
  let store = null;
  let model = null;
  let trails = null;
  let audioElement = null;
  let audioStarted = false;

  // Cursor position normalized to [-1, 1]
  let cursorX = 0;
  let cursorY = 0;

  // Mobile detection (source: window.innerWidth < 768)
  let isMobile = window.innerWidth < 768;

  // Speed (source: baseSpeed ramps from 20 to 40 on start)
  let baseSpeed = 40;
  let speed = 0;

  // Disposal tracking
  let allGeometries = [];
  let allMaterials = [];
  let hiddenChildren = [];

  const _v3 = new THREE.Vector3();

  // Input handlers stored for cleanup
  let primaryPrev = 0;
  let previewTime = 0;

  function markRuntimeOnly(obj) {
    obj.userData.isRuntimeOnly = true;
    if (obj.traverse) {
      obj.traverse(function(child) {
        child.userData.isRuntimeOnly = true;
      });
    }
  }

  function hideOriginalModel(targetThree) {
    let children = targetThree.children;
    for (let i = 0; i < children.length; i++) {
      let child = children[i];
      if (!child.userData.isRuntimeOnly && child.visible !== false) {
        child.visible = false;
        hiddenChildren.push(child);
      }
    }
  }

  function restoreOriginalModel() {
    for (let i = 0; i < hiddenChildren.length; i++) {
      hiddenChildren[i].visible = true;
    }
    hiddenChildren = [];
  }

  const buildModel = async (gameObject) => {
    let modelAttr = this.getAttribute("airplaneModel");
    if (!modelAttr) return;
    erth.asset.model.createInstance(modelAttr).then(async function(loadedModel) {
      // Hide the target's original mesh so only the loaded model shows
      hideOriginalModel(targetThree);
      let gltfScene = loadedModel._internal.three;
      gltfScene.traverse(function(child) {
        if (child.isMesh) {
          child.geometry.center();
          child.geometry.rotateX(-Math.PI * 0.5);
          child.castShadow = true;
          child.receiveShadow = true;
        }
      });
      // Scale at root level (source: 0.005 per mesh)
      loadedModel.scale.set(0.005, 0.005, 0.005);
      model = loadedModel;
      markRuntimeOnly(gltfScene);
      await erth.scene.addObject(loadedModel, gameObject);
    });
  }

  function buildTrails() {
    let trailLen = 60;
    let trailGeo = new THREE.PlaneGeometry(7.3, trailLen, 1, trailLen * 2);
    trailGeo.rotateX(Math.PI * 0.5);
    trailGeo.translate(0, -0.15, -trailLen * 0.5 - 1.2);
    let trailMat = new THREE.MeshBasicNodeMaterial({
      color: 0xffffff,
      side: THREE.DoubleSide,
      transparent: true,
      opacity: 0.0
    });
    trails = new THREE.Mesh(trailGeo, trailMat);
    markRuntimeOnly(trails);
    allGeometries.push(trailGeo);
    allMaterials.push(trailMat);
    targetThree.add(trails);
  }

  function cleanupVisuals() {
    if (model) {
      let threeObj = model._internal ? model._internal.three : null;
      if (threeObj && threeObj.parent) {
        threeObj.parent.remove(threeObj);
      }
    }
    if (trails && trails.parent) {
      trails.parent.remove(trails);
    }
    for (let i = 0; i < allGeometries.length; i++) {
      allGeometries[ i ].dispose();
    }
    for (let i = 0; i < allMaterials.length; i++) {
      allMaterials[ i ].dispose();
    }
    restoreOriginalModel();
    allGeometries = [];
    allMaterials = [];
    model = null;
    trails = null;
  }

  function smoothstep(x, edge0, edge1) {
    let t = Math.max(0, Math.min(1, (x - edge0) / (edge1 - edge0)));
    return t * t * (3 - 2 * t);
  }

  this.init = function(_game) {
      game = _game;
      erth = this.erth;
      targetThree = this.gameObject._internal.three;
    store = this.erth.store;

    // Initialize store
    store.set("ptg_cursor_x", 0);
    store.set("ptg_cursor_y", 0);
    store.set("ptg_speed", 0);
    store.set("ptg_player_pos", [ 0, 60, 0 ]);

    buildModel(this.gameObject);
    buildTrails();
  };

  this.onStart = function() {
    // Set initial position above terrain
    let spawnH = store.get("ptg_spawn_height") || 60;
    this.gameObject.position.set(0, spawnH, 0);
    store.set("ptg_player_pos", [ 0, spawnH, 0 ]);

    // Cursor / audio start are polled per-frame via InputManager.
    // (No engine pointer-NDC API; cursor maps to InputManager motion axes.)
    primaryPrev = 0;
  };

  this.onStop = function() {
    if (audioElement) {
      audioElement.pause();
      audioElement = null;
    }
    audioStarted = false;
    primaryPrev = 0;
  };

  this.update = function(deltaTime) {
    if (!store) return;
    let dt = Math.min(deltaTime, 0.05);

    // Map InputManager axes to cursor coords (lateral=X, forward=Y)
    if (game && game.inputManager) {
      const im = game.inputManager;
      cursorX = im.getMotion('lateral') || 0;
      cursorY = im.getMotion('forward') || 0;

      // First-interaction audio unlock
      if (!audioStarted) {
        const primary = im.getMotion ? (im.getMotion('primary') || 0) : 0;
        const jump = !!im.getAction('jump');
        if ((primaryPrev <= 0.5 && primary > 0.5) || jump || Math.abs(cursorX) > 0.1 || Math.abs(cursorY) > 0.1) {
          audioStarted = true;
          let audioAttr = this.getAttribute("soundtrack");
          if (audioAttr) {
            erth.asset.audio.getUrl(audioAttr).then(function(url) {
              audioElement = new Audio(url);
              audioElement.loop = true;
              audioElement.volume = 0.1;
              audioElement.play().catch(function() {});
            }).catch(function() {});
          }
        }
        primaryPrev = primary;
      }
    }

    // Speed variation from cursor Y (source: plane.js)
    // Source: isMobile ? 0 : (cursor.y + 0.5) * baseSpeed * 0.75
    let speedVar = isMobile ? 0 : (cursorY + 0.5) * baseSpeed * 0.75;
    speed = speed + (baseSpeed + speedVar - speed) * dt * 3;

    // Forward movement (source: translateZ(V3.length()))
    _v3.set(0, 0, 1).multiplyScalar(speed * dt);
    targetThree.translateZ(_v3.length());

    // Yaw from cursor X (source: rotation.y += PI * -cursor.x * dt * 0.2)
    targetThree.rotation.y += Math.PI * -cursorX * dt * 0.2;

    // Model banking (source: model.rotation.z lerped to PI * cursor.x * 0.25)
    if (model) {
      model.rotation.z = model.rotation.z + (Math.PI * cursorX * 0.25 - model.rotation.z) * dt * 5;
    }

    // Trail opacity based on bank angle (approximation of source GLSL)
    if (trails && model) {
      let bankAmount = Math.abs(model.rotation.z);
      trails.material.opacity = smoothstep(bankAmount, 0.15, 1.2) * 0.6;
    }

    // Write position to store for terrain and camera
    store.set("ptg_cursor_x", cursorX);
    store.set("ptg_cursor_y", cursorY);
    store.set("ptg_speed", speed);
    store.set("ptg_player_pos", [
      targetThree.position.x,
      targetThree.position.y,
      targetThree.position.z
    ]);
  };

  this.dispose = function() {
    cleanupVisuals();
    store = null;
  };

  this.onEditorAdded = function(editor) {
    targetThree = this.gameObject._internal.three;
    // Build visual preview of airplane trails only (model requires asset loading)
    buildTrails();
  };

  this.onEditorDispose = function() {
    cleanupVisuals();
  };

