      lobbyScreen.startGameBtnText.setProperties({ text: 'Waiting for Host' });
    }
  }

  function buildPlayerList() {
    const isLandscape = window.innerWidth > window.innerHeight;
    const scale = isLandscape ? window.innerWidth / 1920 : window.innerWidth / 767;
    playerList.length = 0;

    for (let i = 0; i < 2; i++) {
      const playerEntry = new UIKit.Container({
        flexDirection: "row",
        gap: 8,
        width: '50%',
        justifyContent: "center",
      });

      const playerPieceColor = new UIKit.Container({
        width: 32 * scale,
        height: 32 * scale,
        backgroundColor: "#808080",
        borderWidth: 4,
        borderRadius: 999,
        borderColor: "#ffda5f",
        positionTop: 20 + (5 * i),
      });

      const playerName = new UIKit.Text({
        text: 'None',
        textAlign: "left",
        fontSize: 32 * scale,
        fontWeight: 'bold',
        color: 0xFFFFFF,
        textAlign: 'center',
        positionTop: 20 + (5 * i),
      });

      playerEntry.add(playerPieceColor, playerName);
      lobbyScreen.playerListContainer.add(playerEntry);
      playerList.push({ name: playerName, color: playerPieceColor });
    }
  }

  function updatePlayerList(updacePieceColor = true) {
    const players = multiplayerState.getPlayers();

    const playerList = [];

    playerCount = 1;
    let existingPieceColor = null;
    players.forEach(p => {
      const value = p.data.get(MP_EVENTS.LOBBY_SCREEN.PLAYER_DATA_UPDATE);
      if (value) {
        const playerData = JSON.parse(value);
        playerList.push({ username: playerData.playerDisplayName, pieceColor: playerData.pieceColor });
        existingPieceColor = playerData.pieceColor;
        playerCount++;
      }
    });

    if (updacePieceColor) {
      if (existingPieceColor) {
        pieceColor = existingPieceColor === "white" ? "black" : "white";
      } else {
        pieceColor = Math.random() < 0.5 ? "white" : "black";
      }
    }

    playerList.unshift({ username: playerDisplayName, pieceColor: pieceColor });
    updatePlayerListUi(playerList);
  }

  function updatePlayerListUi(playerData) {
    for (let i = 0; i < 2; i++) {
      let name = undefined;
      let color = undefined;
      let textColor = 0x606060;

      if (!playerData[i]) {
        name = 'None';
        textColor = 0x606060;
        color = pieceColor === "white" ? "black" : "white";
      } else {
        name = playerData[i].username;
        color = playerData[i].pieceColor;
        textColor = 0xffffff;
      }

      playerList[i].name.setProperties({ text: name, color: textColor });
      playerList[i].color.setProperties({ backgroundColor: color === "white" ? 0xd9d9d9 : 0x404040 });
      playerList[i].pieceColor = color;
    }
  }

  function addButton(text, mainContainer, scale, onClick = () => { }) {
    const _button = new UIKit.Container({
      backgroundColor: 0xffffff,
      backgroundOpacity: 1,
      padding: 8,
      cursor: 'pointer',
      pointerEvents: 'all',
      width: '100%',
      height: '45%',
      borderRadius: 16,
      borderWidth: 2,
      borderColor: 0xc1cae0,
      onClick: onClick,
    });

    const _text = new UIKit.Text({
      text: text,
      textAlign: 'center',
      fontSize: 24 * scale,
      fontWeight: 'bold',
      color: 0x101010,
      width: '100%',
    });

    _button.add(_text);

    _button.addEventListener('pointerenter', () => {
      _button.setProperties({ backgroundColor: 0x2f3342, borderColor: 0x697185 });
    });

    _button.addEventListener('pointerleave', () => {
      _button.setProperties({ backgroundColor: 0xffffff, borderColor: 0xc1cae0 });
    });

    mainContainer.add(_button);
    return { button: _button, text: _text };
  }

  function startGame() {
    erth.store.set('playerCount', playerCount);
    erth.store.set("pieceColor", pieceColor);
    removeLobbyScreen();

    if (multiplayerState && multiplayerState.isHost()) {
      const data = { state: 'startGame', time: Date.now() };
      broadcastData(MP_EVENTS.LOBBY_SCREEN.START_GAME, data);
    }

    game.behaviorManager.sendEventToObjectBehaviors(ownerObject, "startGame", {});
  }

  function swapColors() {
    pieceColor = pieceColor === "white" ? "black" : "white";

    for (let i = 0; i < 2; i++) {
      const color = playerList[i].pieceColor === "white" ? "black" : "white";
      playerList[i].color.setProperties({ backgroundColor: color === "white" ? 0xd9d9d9 : 0x404040 });
      playerList[i].pieceColor = color;
    }

    const playerData = {
      playerDisplayName,
      pieceColor,
    };

    broadcastData(MP_EVENTS.LOBBY_SCREEN.PLAYER_DATA_UPDATE, playerData);
  }

  function removeLobbyScreen() {
    if (lobbyScreen.root) {
      UIKitPointerEvents.unregisterRoot(lobbyScreen.root);
      if (lobbyScreen.root.parent) {
        lobbyScreen.root.parent.remove(lobbyScreen.root);
      }

      for (const key in lobbyScreen) {
        lobbyScreen[key] = null;
      }

    }
    UIKitPointerEvents.deinitialize();
  }

  function broadcastData(mpKey, data = {}) {
    const payload = JSON.stringify(data);
    multiplayerState.setPlayerData(mpKey, payload);
  }

