  const COLORS = { WHITE: "white", BLACK: "black" };

  // Initial board layout: [type, color] or null
  const INITIAL_SETUP = [
    [["rook", "white"], ["knight", "white"], ["bishop", "white"], ["king", "white"], ["queen", "white"], ["bishop", "white"], ["knight", "white"], ["rook", "white"]],
    [["pawn", "white"], ["pawn", "white"], ["pawn", "white"], ["pawn", "white"], ["pawn", "white"], ["pawn", "white"], ["pawn", "white"], ["pawn", "white"]],
    [null, null, null, null, null, null, null, null],
    [null, null, null, null, null, null, null, null],
    [null, null, null, null, null, null, null, null],
    [null, null, null, null, null, null, null, null],
    [["pawn", "black"], ["pawn", "black"], ["pawn", "black"], ["pawn", "black"], ["pawn", "black"], ["pawn", "black"], ["pawn", "black"], ["pawn", "black"]],
    [["rook", "black"], ["knight", "black"], ["bishop", "black"], ["king", "black"], ["queen", "black"], ["bishop", "black"], ["knight", "black"], ["rook", "black"]]
  ];

  // ===================== STATE =====================
  let pieceColor = null;
  let isGameStarted = false;
  let isGamePaused = false;
  let board = [];           // 8x8 array: { piece: {type,color,hasMoved}, file, rank }
  let selectedTile = null;  // {file, rank}
  let validMoves = [];      // [{file, rank, special}]
  let currentTurn = COLORS.WHITE;
  let gameOverState = null; // null | {winner, type}
  let moveHistory = [];     // [{from, to, piece, captured, special}]
  let animating = false;
  let animData = null;      // {mesh, startPos, endPos, elapsed, duration, arcHeight, callback}
  let captureAnim = null;   // {mesh, startPos, elapsed, duration}
  let piecesLoaded = false;
  let boardPivot = null;
  let boardRotTarget = 0;
  let boardRotCurrent = 0;
  let moveNotations = [];
  let promoteData = null;

  // ===================== VISUALS =====================
  let boardGroup = null;
  let tileMeshes = [];      // 8x8 array of tile meshes
  let pieceMeshes = [];     // 8x8 array (null or mesh group)
  let borderMesh = null;
  let mainLight = null;
  let selectionLight = null;
  let disposables = [];

  // Materials
