  let raycaster = new THREE.Raycaster();
  let pointerVec = new THREE.Vector2();

  // ===================== MATERIALS =====================
  const createMaterials = () => {
    const whiteColor = this.getAttribute("boardWhiteColor");
    const blackColor = this.getAttribute("boardBlackColor");
