    borderMat = new THREE.MeshStandardNodeMaterial({ color: borderColor, metalness: 0.6, roughness: 0.8 });

    whitePieceMat = new THREE.MeshPhysicalNodeMaterial({ color: wp, metalness: 1, roughness: 0.5, reflectivity: 0.5 });
    blackPieceMat = new THREE.MeshPhysicalNodeMaterial({ color: bp, metalness: 1, roughness: 0.5, reflectivity: 0.5 });
    whiteSelectedMat = new THREE.MeshPhysicalNodeMaterial({ color: wp, emissive: new THREE.Color(selEmissive), metalness: 1, roughness: 0.5, reflectivity: 0.5 });
    blackSelectedMat = new THREE.MeshPhysicalNodeMaterial({ color: bp, emissive: new THREE.Color(selEmissive), metalness: 1, roughness: 0.5, reflectivity: 0.5 });

    disposables.push(whiteTileMat, blackTileMat, validMoveMat, borderMat, whitePieceMat, blackPieceMat, whiteSelectedMat, blackSelectedMat);
  }

  // ===================== BOARD VISUALS =====================
  const buildBoardVisuals = () => {
