    boardPivot.userData.isRuntimeOnly = true;

    boardGroup = new THREE.Group();
    boardGroup.position.set(-3.5, -0.5, -3.5);
    boardGroup.userData.isRuntimeOnly = true;

    // Border
    let borderGeo = new THREE.BoxGeometry(9, TILE_HEIGHT, 9);
    borderMesh = new THREE.Mesh(borderGeo, borderMat);
    borderMesh.position.set(3.5, BORDER_Y, 3.5);
