  // ===================== PIECE LOADING =====================
  const loadPieceModels = async () => {
    let modelMap = {
      pawn: this.getAttribute("pawnModel"),
      rook: this.getAttribute("rookModel"),
      knight: this.getAttribute("knightModel"),
      bishop: this.getAttribute("bishopModel"),
      queen: this.getAttribute("queenModel"),
      king: this.getAttribute("kingModel")
    };

    // Try attributes first, fallback to findByName
    for (let type in modelMap) {
      let ref = modelMap[type];
      if (!ref) {
        let name = type.charAt(0).toUpperCase() + type.slice(1);
        ref = await erth.asset.model.findByName(name);
        if (!ref) {
          ref = await erth.asset.model.findByName(type);
        }
      }
      if (ref) {
        try {
          let instance = await erth.asset.model.createInstance(ref);
          let threeObj = instance._internal.three;
          // Extract geometry from the first mesh found
          threeObj.traverse(function (child) {
            if (child.isMesh && !pieceGeometries[type]) {
              pieceGeometries[type] = child.geometry.clone();
              // Normalize origin so bottom of piece is at Y=0
              pieceGeometries[type].computeBoundingBox();
              if (pieceGeometries[type].boundingBox) {
                pieceGeometries[type].translate(0, -pieceGeometries[type].boundingBox.min.y, 0);
              }

              // copy origin mesh scale
              pieceGeometries[type].userData.scale = child.scale.x;
              disposables.push(pieceGeometries[type]);
            }
          });
          // Remove the template instance
          if (threeObj.parent) threeObj.parent.remove(threeObj);
        } catch (e) {
          console.warn("Chess: failed to load model for " + type, e);
        }
      }
    }

    // Fallback: create simple geometries for any missing pieces
    if (!pieceGeometries.pawn) {
      pieceGeometries.pawn = createFallbackGeometry("pawn");
    }
    if (!pieceGeometries.rook) {
      pieceGeometries.rook = createFallbackGeometry("rook");
    }
    if (!pieceGeometries.knight) {
      pieceGeometries.knight = createFallbackGeometry("knight");
    }
    if (!pieceGeometries.bishop) {
      pieceGeometries.bishop = createFallbackGeometry("bishop");
    }
    if (!pieceGeometries.queen) {
      pieceGeometries.queen = createFallbackGeometry("queen");
    }
    if (!pieceGeometries.king) {
      pieceGeometries.king = createFallbackGeometry("king");
    }
  }

  function createFallbackGeometry(type) {
    // Simple procedural shapes as fallback if models not found
    let geo;
    switch (type) {
      case "pawn":
        geo = new THREE.CylinderGeometry(0.25, 0.35, 1.5, 16);
        break;
      case "rook":
        geo = new THREE.CylinderGeometry(0.3, 0.35, 2.0, 8);
        break;
      case "knight":
        geo = new THREE.ConeGeometry(0.35, 2.2, 8);
        break;
      case "bishop":
        geo = new THREE.ConeGeometry(0.3, 2.5, 16);
        break;
      case "queen":
        geo = new THREE.SphereGeometry(0.35, 16, 12);
        geo.scale(1, 2.2, 1);
        break;
      case "king":
        geo = new THREE.CylinderGeometry(0.2, 0.35, 2.8, 16);
        break;
      default:
        geo = new THREE.BoxGeometry(0.5, 1.5, 0.5);
    }
    // Normalize origin so bottom of piece is at Y=0
    geo.computeBoundingBox();
    if (geo.boundingBox) {
      geo.translate(0, -geo.boundingBox.min.y, 0);
    }
    disposables.push(geo);
    return geo;
  }

  // ===================== PLACE PIECES =====================
  const placePieces = () => {
    let scale = this.getAttribute("pieceScale");
    pieceMeshes = [];

    for (let rank = 0; rank < BOARD_SIZE; rank++) {
      pieceMeshes[rank] = [];
      for (let file = 0; file < BOARD_SIZE; file++) {
        let setup = INITIAL_SETUP[rank][file];
        if (setup) {
          let type = setup[0];
          let color = setup[1];
          let mesh = createPieceMesh(type, color, scale);
          mesh.position.set(file, PIECE_Y, rank);
          mesh.userData.isRuntimeOnly = true;
          mesh.userData.pieceType = type;
          mesh.userData.pieceColor = color;
          boardGroup.add(mesh);
          mesh.updateMatrixWorld(true);
          pieceMeshes[rank][file] = mesh;
        } else {
          pieceMeshes[rank][file] = null;
        }
      }
    }
  }

  function createPieceMesh(type, color, scale) {
    let geo = pieceGeometries[type];
    let mat = color === COLORS.WHITE ? whitePieceMat : blackPieceMat;
    let mesh = new THREE.Mesh(geo, mat);

    // Since we copied the original scale to pieceGeometries
    // Instead of setting the scale directly,
    // we will multiply the attribute.pieceScale to the current scale
    // ex: if the original mesh scale is 3.7:
    // -- it wiil be 3.7 * 0.5 = 1.85
    // -- 3.7 * 0.25 = 0.925
    const finalScale = geo.userData.scale * scale;
    mesh.scale.setScalar(finalScale);

    mesh.castShadow = true;
    return mesh;
  }

  // ===================== BOARD STATE =====================
  function initBoardState() {
    board = [];
    for (let rank = 0; rank < BOARD_SIZE; rank++) {
      board[rank] = [];
      for (let file = 0; file < BOARD_SIZE; file++) {
        let setup = INITIAL_SETUP[rank][file];
        if (setup) {
          board[rank][file] = { piece: { type: setup[0], color: setup[1], hasMoved: false }, file: file, rank: rank };
        } else {
          board[rank][file] = { piece: null, file: file, rank: rank };
        }
      }
    }
    currentTurn = COLORS.WHITE;
    gameOverState = null;
    moveHistory = [];
    selectedTile = null;
    validMoves = [];
  }

  function getTile(file, rank) {
    if (file < 0 || file > 7 || rank < 0 || rank > 7) return null;
    return board[rank][file];
  }

  function getPiece(file, rank) {
    let tile = getTile(file, rank);
    return tile ? tile.piece : null;
  }

