  function getMovesForPiece(file, rank) {
    let piece = getPiece(file, rank);
    if (!piece) return [];
    let moves = [];

    switch (piece.type) {
      case PIECE_TYPES.PAWN:
        moves = getPawnMoves(file, rank, piece);
        break;
      case PIECE_TYPES.ROOK:
        moves = getRookMoves(file, rank, piece);
        break;
      case PIECE_TYPES.KNIGHT:
        moves = getKnightMoves(file, rank, piece);
        break;
      case PIECE_TYPES.BISHOP:
        moves = getBishopMoves(file, rank, piece);
        break;
      case PIECE_TYPES.QUEEN:
        moves = getQueenMoves(file, rank, piece);
        break;
      case PIECE_TYPES.KING:
        moves = getKingMoves(file, rank, piece);
        break;
    }

    // Filter out moves that leave own king in check
    let legalMoves = [];
    for (let i = 0; i < moves.length; i++) {
      let m = moves[i];
      if (!wouldBeInCheck(file, rank, m.file, m.rank, piece.color)) {
        legalMoves.push(m);
      }
    }
    return legalMoves;
  }

  // Pawn moves
  function getPawnMoves(file, rank, piece) {
    let moves = [];
    let dir = piece.color === COLORS.WHITE ? 1 : -1;
    let startRank = piece.color === COLORS.WHITE ? 1 : 6;

    // Forward one
    let fwd = getTile(file, rank + dir);
    if (fwd && !fwd.piece) {
      moves.push({ file: file, rank: rank + dir });
      // Forward two from start
      if (rank === startRank) {
        let fwd2 = getTile(file, rank + dir * 2);
        if (fwd2 && !fwd2.piece) {
          moves.push({ file: file, rank: rank + dir * 2, special: "doublePush" });
        }
      }
    }

    // Diagonal captures
    for (let df = -1; df <= 1; df += 2) {
      let cap = getTile(file + df, rank + dir);
      if (cap && cap.piece && cap.piece.color !== piece.color) {
        moves.push({ file: file + df, rank: rank + dir });
      }
    }

    // En passant
    if (moveHistory.length > 0) {
      let lastMove = moveHistory[moveHistory.length - 1];
      if (lastMove.piece.type === PIECE_TYPES.PAWN && lastMove.special === "doublePush") {
        if (lastMove.to.rank === rank && Math.abs(lastMove.to.file - file) === 1) {
          moves.push({ file: lastMove.to.file, rank: rank + dir, special: "enPassant" });
        }
      }
    }

