          if (!isSquareAttacked(5, rank, piece.color) && !isSquareAttacked(6, rank, piece.color)) {
            moves.push({ file: 6, rank: rank, special: "castleKing" });
          }
        }
      }
      // Queenside (file 0 rook)
      let rookQ = getPiece(0, rank);
      if (rookQ && rookQ.type === PIECE_TYPES.ROOK && !rookQ.hasMoved) {
