          if (!isSquareAttacked(2, rank, piece.color) && !isSquareAttacked(3, rank, piece.color)) {
            moves.push({ file: 2, rank: rank, special: "castleQueen" });
          }
        }
      }
    }
    return moves;
  }

  // Check detection
  function findKing(color) {
    for (let r = 0; r < 8; r++) {
      for (let f = 0; f < 8; f++) {
        let p = getPiece(f, r);
        if (p && p.type === PIECE_TYPES.KING && p.color === color) {
          return { file: f, rank: r };
        }
      }
    }
    return null;
  }

  function isSquareAttacked(file, rank, byColor) {
    // byColor = the color of the pieces that MIGHT be attacked
