        item.position.z = item.startZ + (item.targetZ - item.startZ) * easeInQuad(t);
        item.scale.z = easeInQuart(t);
        item.matrix.compose(item.position, item.quaternion, item.scale);
        entranceStrokeMesh.setMatrixAt(item.index, item.matrix);
        needsUpdate = true;
        if (t >= 1) {
          item.position.z = 3.2;
          item.position.y = Math.random();
          item.position.x = (Math.random() - 0.5);
          item.scale.z = 0;
          item.delay = Math.random() * 4;
          item.elapsed = 0;
        }
      }
      if (needsUpdate) entranceStrokeMesh.instanceMatrix.needsUpdate = true;
    }

