    windPopTimer += deltaTime;
    if (windPopTimer >= 0.5) {
      windPopTimer -= 0.5;
      if (Math.random() < 0.3 && (windStrokeTemplate1 || windStrokeTemplate2)) {
        const template = Math.random() < 0.5 ? windStrokeTemplate1 : windStrokeTemplate2;
        if (template) {
          const mesh = spawnWindStroke(template);
          game.scene.add(mesh); // @check-ok runtime-only set in spawnWindStroke
          activeWindStrokes.push({ mesh: mesh, startX: mesh.position.x, elapsed: 0, duration: 10 });
        }
      }
    }

    // Animate active wind strokes
    for (let i = activeWindStrokes.length - 1; i >= 0; i--) {
      const ws = activeWindStrokes[i];
      ws.elapsed += deltaTime;
      let t = Math.min(ws.elapsed / ws.duration, 1);
      let eased = easeInOutQuad(t);
      ws.mesh.material._uProgress.value = eased;
      ws.mesh.position.x = ws.startX + 1.5 * eased;
      if (t >= 1) {
        ws.mesh.geometry.dispose();
        ws.mesh.material.dispose();
        if (ws.mesh.parent) ws.mesh.parent.remove(ws.mesh);
        activeWindStrokes.splice(i, 1);
      }
    }
  };

  this.onStop = function() {
    cleanupPreview();
    cleanup();
  };

  this.dispose = function() {
    cleanupPreview();
    cleanup();
  };

