  };

  // Input state
  const drag = {
    active: false,
    secondary: false,
    prevX: 0, prevY: 0,
    deltaX: 0, deltaY: 0
  };
  let wheelDelta = 0;
  let pinchPrev = 0;
  let pinchDelta = 0;

  // Bound event handlers (for cleanup)
  let onMouseDown = null;
  let onMouseMove = null;
  let onMouseUp = null;
  let onTouchStart = null;
  let onTouchMove = null;
  let onTouchEnd = null;
  let onWheel = null;
  let onContextMenu = null;

  const center = new THREE.Vector3(0, 2, 0);
  const camPos = new THREE.Vector3();

  function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

  function getViewportSize() {
    if (canvas && canvas.getBoundingClientRect) {
      const rect = canvas.getBoundingClientRect();
      if (rect.width > 0 && rect.height > 0) {
        return { width: rect.width, height: rect.height };
      }
    }
    return { width: window.innerWidth || 1, height: window.innerHeight || 1 };
  }

  function getNormalizedPointer(clientX, clientY) {
    if (canvas && canvas.getBoundingClientRect) {
      const rect = canvas.getBoundingClientRect();
      const width = rect.width || 1;
      const height = rect.height || 1;
      return {
        x: (clientX - rect.left) / width,
        y: (clientY - rect.top) / height
      };
    }
    return {
      x: clientX / (window.innerWidth || 1),
      y: clientY / (window.innerHeight || 1)
    };
  }

  function cleanupInputListeners() {
    if (!canvas) return;
    if (onMouseDown) canvas.removeEventListener("mousedown", onMouseDown) // @check-ok complex input
    if (onMouseMove) canvas.removeEventListener("mousemove", onMouseMove);
    if (onMouseUp) canvas.removeEventListener("mouseup", onMouseUp) // @check-ok complex input
    if (onMouseUp) canvas.removeEventListener("mouseleave", onMouseUp);
    if (onTouchStart) canvas.removeEventListener("touchstart", onTouchStart);
    if (onTouchMove) canvas.removeEventListener("touchmove", onTouchMove);
    if (onTouchEnd) canvas.removeEventListener("touchend", onTouchEnd);
    if (onWheel) canvas.removeEventListener("wheel", onWheel);
    if (onContextMenu) canvas.removeEventListener("contextmenu", onContextMenu);
  }

  this.init = function(_game) {
      game = _game;
    g = game;
    cam = game.camera;

    const fovAttr = this.getAttribute("fov");
    const fov = fovAttr === undefined || fovAttr === null ? 25 : fovAttr;
    const cy = this.getAttribute("centerY");
    if (cy !== undefined && cy !== null) center.y = cy;

    // Responsive initial radius
    canvas = (game.renderer && game.renderer.domElement) || null;
    if (!canvas) return;
    const viewport = getViewportSize();
    const aspect = viewport.height / viewport.width;
    spherical.target.radius = Math.max(1, aspect) * 16;
    spherical.value.radius = spherical.target.radius;

    // Configure camera
    cam.fov = fov;
    cam.near = 0.1;
    cam.far = 150;
    cam.rotation.order = "YXZ";
    cam.updateProjectionMatrix();

    // Mouse events
    onMouseDown = function(e) {
      e.preventDefault();
      drag.active = true;
      drag.secondary = e.button === 1 || e.button === 2 || e.shiftKey || e.ctrlKey;
      const pointer = getNormalizedPointer(e.clientX, e.clientY);
      drag.prevX = pointer.x;
      drag.prevY = pointer.y;
    };

    onMouseMove = function(e) {
      if (!drag.active) return;
      const pointer = getNormalizedPointer(e.clientX, e.clientY);
      drag.deltaX += pointer.x - drag.prevX;
      drag.deltaY += pointer.y - drag.prevY;
      drag.prevX = pointer.x;
      drag.prevY = pointer.y;
    };

    onMouseUp = function() {
      drag.active = false;
    };

    // Touch events
    onTouchStart = function(e) {
      e.preventDefault();
      drag.active = true;
      drag.secondary = e.touches.length > 1;
      let tx = 0, ty = 0;
      for (let i = 0; i < e.touches.length; i++) {
        tx += e.touches[i].clientX;
        ty += e.touches[i].clientY;
      }
      tx /= e.touches.length;
      ty /= e.touches.length;
      const pointer = getNormalizedPointer(tx, ty);
      drag.prevX = pointer.x;
      drag.prevY = pointer.y;
      if (e.touches.length > 1) {
        pinchPrev = Math.hypot(
          e.touches[0].clientX - e.touches[1].clientX,
          e.touches[0].clientY - e.touches[1].clientY
        );
      }
    };

    onTouchMove = function(e) {
      e.preventDefault();
      let tx = 0, ty = 0;
      for (let i = 0; i < e.touches.length; i++) {
        tx += e.touches[i].clientX;
        ty += e.touches[i].clientY;
      }
      tx /= e.touches.length;
      ty /= e.touches.length;
      const pointer = getNormalizedPointer(tx, ty);
      drag.deltaX += pointer.x - drag.prevX;
      drag.deltaY += pointer.y - drag.prevY;
      drag.prevX = pointer.x;
      drag.prevY = pointer.y;
      if (e.touches.length > 1) {
        const dist = Math.hypot(
          e.touches[0].clientX - e.touches[1].clientX,
          e.touches[0].clientY - e.touches[1].clientY
        );
        pinchDelta += dist - pinchPrev;
        pinchPrev = dist;
      }
    };

    onTouchEnd = function() {
      drag.active = false;
    };

    // Wheel
    onWheel = function(e) {
      wheelDelta += e.deltaY;
    };

    // Context menu
    onContextMenu = function(e) { e.preventDefault(); };

    canvas.addEventListener("mousedown", onMouseDown) // @check-ok
    canvas.addEventListener("mousemove", onMouseMove); // @check-ok
    canvas.addEventListener("mouseup", onMouseUp); // @check-ok
    canvas.addEventListener("mouseleave", onMouseUp); // @check-ok
    canvas.addEventListener("touchstart", onTouchStart, { passive: false }); // @check-ok
    canvas.addEventListener("touchmove", onTouchMove, { passive: false }); // @check-ok
    canvas.addEventListener("touchend", onTouchEnd); // @check-ok
    canvas.addEventListener("wheel", onWheel, { passive: true }); // @check-ok
    canvas.addEventListener("contextmenu", onContextMenu); // @check-ok
  };

  this.update = function(deltaTime) {
    const dt = Math.min(deltaTime, 0.1);
    if (!cam) return;
    const dtMs = deltaTime * 1000;

    // Radius from wheel + pinch
    spherical.target.radius += wheelDelta * spherical.speed.radius;
    spherical.target.radius += pinchDelta * spherical.value.radius * -0.2 * spherical.speed.radius;
    spherical.target.radius = clamp(spherical.target.radius, spherical.limits.radius.min, spherical.limits.radius.max);

    if (!drag.secondary) {
      // Orbit rotation
      spherical.target.phi += drag.deltaY * spherical.speed.phi;
      spherical.target.theta += drag.deltaX * spherical.speed.theta;
      spherical.target.phi = clamp(spherical.target.phi, spherical.limits.phi.min, spherical.limits.phi.max);
      spherical.target.theta = clamp(spherical.target.theta, spherical.limits.theta.min, spherical.limits.theta.max);
    } else {
      // Boom/truck
      boomTruck.target.x += drag.deltaX * boomTruck.speed;
      boomTruck.target.y += drag.deltaY * boomTruck.speed;
      boomTruck.target.x = clamp(boomTruck.target.x, boomTruck.limits.min, boomTruck.limits.max);
      boomTruck.target.y = clamp(boomTruck.target.y, boomTruck.limits.min, boomTruck.limits.max);
    }

    // Easing interpolation
    const easeFactor = spherical.easing * dtMs;
    spherical.value.radius += (spherical.target.radius - spherical.value.radius) * easeFactor;
    spherical.value.phi += (spherical.target.phi - spherical.value.phi) * easeFactor;
    spherical.value.theta += (spherical.target.theta - spherical.value.theta) * easeFactor;

    const btEase = boomTruck.easing * dtMs;
    boomTruck.value.x += (boomTruck.target.x - boomTruck.value.x) * btEase;
    boomTruck.value.y += (boomTruck.target.y - boomTruck.value.y) * btEase;

    // Reset input deltas
    drag.deltaX = 0;
    drag.deltaY = 0;
    wheelDelta = 0;
    pinchDelta = 0;

    // Convert spherical to cartesian
    const r = spherical.value.radius;
    const phi = spherical.value.phi;
    const theta = spherical.value.theta;
    camPos.x = r * Math.sin(phi) * Math.sin(theta);
    camPos.y = r * Math.cos(phi);
    camPos.z = r * Math.sin(phi) * Math.cos(theta);

    // Apply position + center offset
    cam.position.copy(camPos).add(center);
    cam.lookAt(center);

    // Apply boom/truck in camera-local space
    cam.translateX(-boomTruck.value.x * r);
    cam.translateY(boomTruck.value.y * r);
  };

  this.onStop = function() {
    cleanupInputListeners();
  };

  this.dispose = function() {
    cleanupInputListeners();
  };

const F_WALKABLE = 1 << 0;
const F_HARD = 1 << 1;
const F_SOFT = 1 << 2;
const F_LAND = 1 << 3;
const F_PLAYER = 1 << 4;
const F_ENEMY = 1 << 5;
const F_BOMB = 1 << 6;
const F_BLAST = 1 << 7;
const F_BLOCKS_SIGHT = F_HARD | F_SOFT;

const DIR_X = [1, -1, 0, 0];
const DIR_Z = [0, 0, 1, -1];
const MEGA_X = [1, -1, 0, 0, 1, 1, -1, -1];
const MEGA_Z = [0, 0, 1, -1, 1, -1, 1, -1];
const SPLASHES = [
    "MIND THE BRIDGES!",
    "DROP A BOMB!",
    "CRACK OPEN CHESTS!",
    "BEWARE THE VOID!",
    "VOXEL SKY ISLANDS!",
    "BOMBERMAN + CLOUDS!",
];

function init(owner, game) {
    dispose(owner);
    const state = createState(owner, game, false);
    owner._sb = state;
    findPlayerProxy(state);
    startLevel(owner, "start");
}

function initEditor(owner, editor) {
    dispose(owner);
    const gameLike = {
        camera: editor.camera,
        scene: editor.scene,
        renderer: editor.renderer,
        inputManager: null,
    };
    const state = createState(owner, gameLike, true);
    owner._sb = state;
    startLevel(owner, "start");
}

function update(owner, dt) {
    const state = owner._sb;
    if (!state || state.editorMode) return;
    readInputs(owner, state);
    if (state.enterPressed) advance(owner);
    if (state.phase === "playing") {
        updatePlayer(owner, state, dt);
        if (state.bombPressed) placeBomb(owner, state);
        updateBombs(owner, state, dt);
        updateExplosions(state, dt);
        updateEnemies(owner, state, dt);
        updatePickups(owner, state, dt);
        checkPlayerDeath(owner, state);
        checkWin(owner, state);
    } else {
        state.prevJump = state.jumpHeld;
    }
    updateCamera(state, dt);
    updateClouds(state, dt);
    updateUi(state);
}

function dispose(owner) {
    const state = owner._sb;
    if (!state) return;
    disposeWorld(state);
    owner._sb = null;
}

function buildUi(owner) {
    const state = owner._sb;
