    erth.store.set("skr_acceleration", this.acceleration);
    erth.store.set("skr_driftIntensity", this.driftIntensity);
    erth.store.set("skr_inputX", this.inputX);
    erth.store.set("skr_inputZ", this.inputZ);
    erth.store.set("skr_collisionCount", this._collisionCount);
    erth.store.set("skr_playerWorldSpeed", this.modelVelocity.length());
