      let baseRotY = this._wheelFR.userData && this._wheelFR.userData.skrBaseRotY !== undefined ? this._wheelFR.userData.skrBaseRotY : 0;
      this._wheelFR.rotation.y = this._lerpAngle(this._wheelFR.rotation.y, baseRotY - this.inputX / 1.5, dt * 10);
    }
  };

  this.onStop = function() {
    this._updateDriftSmoke(false);
    this._wheels = [];
    this._colliders = [];
  };

