  this._spawnNpcBatch = function(count) {
    if (!this._npcCurve || !this._npcRuntimeRoot) return;

    let laneOffsets = [-1.1, -0.4, 0.4, 1.1];
    let baseIndex = this._npcRunners.length;
    let waypointCount = Math.max(1, this._npcWaypoints.length);
    for (let i = 0; i < count; i++) {
      let idx = baseIndex + i;
      let trackPos = ((idx * 0.19) % waypointCount + waypointCount) % waypointCount;
      let colorKey = this._npcColorOrder[idx % this._npcColorOrder.length];
      let laneOffset = laneOffsets[idx % laneOffsets.length];
      let speed = 8.5 + (idx % 7) * 0.3;
      let aggression = 1.4 + (idx % 5) * 0.35;
      let runner = this._createNpcRunner(colorKey, 0, 0, speed, laneOffset, aggression);
      runner.progress = trackPos / waypointCount;
      this._syncNpcTransform(runner);
      this._createNpcVisual(runner);
      this._npcRunners.push(runner);
    }
