        child.userData = child.userData || {};
        child.userData.skrBaseRotX = child.rotation.x;
        child.userData.skrBaseRotY = child.rotation.y;
        child.userData.skrBaseRotZ = child.rotation.z;
        child.userData.skrBasePosY = child.position.y;
        npc.bodyNode = child;
      } else if (name.indexOf("wheel") !== -1) {
        child.rotation.order = "YXZ";
        child.userData = child.userData || {};
        child.userData.skrBaseRotX = child.rotation.x;
        child.userData.skrBaseRotY = child.rotation.y;
        child.userData.skrBaseRotZ = child.rotation.z;
        npc.wheels.push(child);
        if (name.indexOf("front") !== -1 && name.indexOf("left") !== -1) npc.wheelFL = child;
        if (name.indexOf("front") !== -1 && name.indexOf("right") !== -1) npc.wheelFR = child;
