    npc.visualForward.lerp(npc.forward, smooth);
    if (npc.visualForward.lengthSq() < 1e-6) {
      npc.visualForward.copy(npc.forward);
    } else {
      npc.visualForward.normalize();
    }

    npc.root.position.copy(npc.visualPosition);
    npc.root.rotation.y = this._lerpAngle(
      npc.root.rotation.y,
      Math.atan2(npc.visualForward.x, npc.visualForward.z),
      smooth
