      let baseRotX = wheel.userData && wheel.userData.skrBaseRotX !== undefined ? wheel.userData.skrBaseRotX : 0;
      let baseRotZ = wheel.userData && wheel.userData.skrBaseRotZ !== undefined ? wheel.userData.skrBaseRotZ : 0;
      wheel.rotation.x = baseRotX + npc.wheelSpin;
      wheel.rotation.z = baseRotZ;
