      let baseRotY = npc.wheelFR.userData && npc.wheelFR.userData.skrBaseRotY !== undefined ? npc.wheelFR.userData.skrBaseRotY : 0;
      npc.wheelFR.rotation.y = this._lerpAngle(npc.wheelFR.rotation.y, baseRotY + npc.steerAngle, smooth);
    }

    if (npc.bodyNode) {
      let baseRotZ = npc.bodyNode.userData && npc.bodyNode.userData.skrBaseRotZ !== undefined ? npc.bodyNode.userData.skrBaseRotZ : 0;
      let basePosY = npc.bodyNode.userData && npc.bodyNode.userData.skrBasePosY !== undefined ? npc.bodyNode.userData.skrBasePosY : npc.bodyNode.position.y;
      npc.bodyNode.rotation.z = this._lerpAngle(npc.bodyNode.rotation.z, baseRotZ - npc.steerAngle * 0.35, Math.min(1, dt * 6));
