code: |
  let game;
  const erth = this.erth;
  this.init = function(_game) {
      game = _game;
    this.engineVolMin = this.getAttribute("engineVolMin");
    this.engineVolMax = this.getAttribute("engineVolMax");
    this.enginePitchMin = this.getAttribute("enginePitchMin");
    this.enginePitchMax = this.getAttribute("enginePitchMax");
    this.skidThreshold = this.getAttribute("skidThreshold");
    this.skidVolMin = this.getAttribute("skidVolMin");
    this.skidVolMax = this.getAttribute("skidVolMax");

    this._engineSound = null;
    this._skidSound = null;
    this._impactPool = [];
    this._impactIndex = 0;
    this._listener = null;
    this._ready = false;
    this._unlocked = false;
    this._engVol = 0;
    this._engPitch = 0.5;
    this._skidVol = 0;
    this._skidPitch = 1;
    this._unlockFn = null;
  };

  this.onStart = function() {
    let self = this; // @check-ok needed for nested audio loader callbacks
    let cam = game.camera;
    if (!cam) return;

    this._listener = new THREE.AudioListener();
    cam.add(this._listener);

    let loader = new THREE.AudioLoader();

    // Resolve audio URLs from asset attributes (bound in editor)
    let engineAttr = this.getAttribute("engineSound");
    let skidAttr = this.getAttribute("skidSound");
    let impactAttr = this.getAttribute("impactSound");

    // Load engine loop
    if (engineAttr) {
      erth.asset.audio.getUrl(engineAttr).then(function(url) {
        if (!url) return;
        self._engineSound = new THREE.Audio(self._listener);
        loader.load(url, function(buffer) {
          self._engineSound.setBuffer(buffer);
          self._engineSound.setLoop(true);
          self._engineSound.setVolume(0);
          self._checkReady();
        });
      });
    }

    // Load skid loop
    if (skidAttr) {
      erth.asset.audio.getUrl(skidAttr).then(function(url) {
        if (!url) return;
        self._skidSound = new THREE.Audio(self._listener);
        loader.load(url, function(buffer) {
          self._skidSound.setBuffer(buffer);
          self._skidSound.setLoop(true);
          self._skidSound.setVolume(0);
          self._checkReady();
        });
      });
    }

    // Load impact
    if (impactAttr) {
      erth.asset.audio.getUrl(impactAttr).then(function(url) {
        if (!url) return;
        loader.load(url, function(buffer) {
          for (let i = 0; i < 3; i++) {
            let snd = new THREE.Audio(self._listener);
            snd.setBuffer(buffer);
            self._impactPool.push(snd);
          }
        });
      });
    }

    // Audio unlock polled per-frame in update() via InputManager
    this._primaryPrev = 0;
  };

  this._tryUnlock = function() {
    if (this._unlocked) return;
    this._unlocked = true;
    let ctx = this._listener && this._listener.context;
    if (ctx && ctx.state === "suspended") ctx.resume();
    this._startSounds();
  };

  this._removeUnlockListeners = function() {
    // No DOM listeners to remove — unlock is polled in update().
  };

  this._checkReady = function() {
    if (this._engineSound && this._engineSound.buffer &&
        this._skidSound && this._skidSound.buffer) {
      this._ready = true;
      if (this._unlocked) this._startSounds();
    }
  };

  this._startSounds = function() {
    if (!this._ready) return;
    if (this._engineSound && !this._engineSound.isPlaying) this._engineSound.play();
    if (this._skidSound && !this._skidSound.isPlaying) this._skidSound.play();
  };

  this._remap = function(value, inMin, inMax, outMin, outMax) {
    return outMin + (outMax - outMin) * ((value - inMin) / (inMax - inMin));
  };

  this.update = function(deltaTime) {
    if (!this._unlocked && game && game.inputManager) {
      const im = game.inputManager;
      const primary = im.getMotion ? (im.getMotion('primary') || 0) : 0;
      const fwd = im.getMotion ? (im.getMotion('forward') || 0) : 0;
      const lat = im.getMotion ? (im.getMotion('lateral') || 0) : 0;
      const jump = !!im.getAction('jump');
      if ((this._primaryPrev <= 0.5 && primary > 0.5) || jump || Math.abs(fwd) > 0.1 || Math.abs(lat) > 0.1) {
        this._tryUnlock();
      }
      this._primaryPrev = primary;
    }
    if (!this._ready) return;
    let dt = Math.min(deltaTime, 1 / 30);

    let speed = erth.store.get("skr_speed") || 0;
    let inputZ = erth.store.get("skr_inputZ") || 0;
    let drift = erth.store.get("skr_driftIntensity") || 0;

    // Engine volume and pitch
    let speedFactor = THREE.MathUtils.clamp(Math.abs(speed), 0, 1);
    let throttleFactor = THREE.MathUtils.clamp(Math.abs(inputZ), 0, 1);

    let targetVol = this._remap(speedFactor + throttleFactor * 0.5, 0, 1.5, this.engineVolMin, this.engineVolMax);
    this._engVol = THREE.MathUtils.lerp(this._engVol, targetVol, dt * 5);
    this._engineSound.setVolume(this._engVol);

    let targetPitch = this._remap(speedFactor, 0, 1, this.enginePitchMin, this.enginePitchMax);
    if (throttleFactor > 0.1) targetPitch += 0.2;
    this._engPitch = THREE.MathUtils.lerp(this._engPitch, targetPitch, dt * 2);
    this._engineSound.setPlaybackRate(this._engPitch);

    // Skid volume
    let shouldSkid = drift > this.skidThreshold;
    let targetSkidVol = 0;
    if (shouldSkid) {
      targetSkidVol = this._remap(
        THREE.MathUtils.clamp(drift, this.skidThreshold, 2),
        this.skidThreshold, 2, this.skidVolMin, this.skidVolMax
      );
    }
    this._skidVol = THREE.MathUtils.lerp(this._skidVol, targetSkidVol, dt * 10);
    this._skidSound.setVolume(this._skidVol);

    let skidPitch = THREE.MathUtils.clamp(Math.abs(speed), 1, 3);
    this._skidPitch = THREE.MathUtils.lerp(this._skidPitch, skidPitch, 0.1);
    this._skidSound.setPlaybackRate(this._skidPitch);
  };

  this.onEvent = function(msg, data) {
    if (msg === "skr_impact") {
      if (!this._unlocked || this._impactPool.length === 0) return;
      let snd = this._impactPool[this._impactIndex];
      this._impactIndex = (this._impactIndex + 1) % this._impactPool.length;
      if (snd.isPlaying) snd.stop();
      let vol = THREE.MathUtils.clamp(this._remap(data.velocity || 0, 0, 6, 0.01, 1.0), 0.01, 1.0);
      snd.setVolume(vol);
      snd.play();
    }
  };

  this.onStop = function() {
    this._removeUnlockListeners();
    if (this._engineSound) {
      if (this._engineSound.isPlaying) this._engineSound.stop();
      this._engineSound.disconnect();
    }
    if (this._skidSound) {
      if (this._skidSound.isPlaying) this._skidSound.stop();
      this._skidSound.disconnect();
    }
    for (let i = 0; i < this._impactPool.length; i++) {
      if (this._impactPool[i].isPlaying) this._impactPool[i].stop();
      this._impactPool[i].disconnect();
    }
    this._impactPool = [];
    this._engineSound = null;
    this._skidSound = null;
    if (this._listener) {
      let cam = game.camera;
      if (cam) cam.remove(this._listener);
      this._listener = null;
    }
    this._ready = false;
  };

  this.dispose = function() {
    this.onStop();
  };

