code: |
  // Oscillate Lambda
  // Applies sinusoidal oscillation to all registered objects.
  // Use for swinging maces, moving platforms, bobbing items.

  let _elapsed = 0;

  function update(deltaTime) {
      if (!deltaTime) deltaTime = 0.016;
      _elapsed += deltaTime;

      this.processObjects(deltaTime, function (object, data, dt) {
          let axis = data.axis || "y";
          let amplitude = data.amplitude || 1;
          let frequency = data.frequency || 1;
          let phase = data.phase || 0;

          // Store the base position on first frame
          if (data._baseX === undefined) {
              data._baseX = object.position.x;
              data._baseY = object.position.y;
              data._baseZ = object.position.z;
          }

          let offset =
              Math.sin(_elapsed * frequency * Math.PI * 2 + phase) * amplitude;

          if (axis === "x") {
              object.position.x = data._baseX + offset;
          } else if (axis === "y") {
              object.position.y = data._baseY + offset;
          } else if (axis === "z") {
              object.position.z = data._baseZ + offset;
          }
      });
  }

