code: |
  // Red Runner - Game Manager
  // Attach to an empty object. Manages game state, scoring, and restart flow.

  let game;
  let self = this;
  let playerScriptId = '';
  this._state = "idle";
  this._score = 0;
  this._coins = 0;
  this._highScore = 0;
  this._playerStartX = 0;
  this._restartTimer = null;

  // Events
  const EVENT = {
      START_GAME: "game_state:start_game",
  };
  const registeredEvents = [];

  this.init = function (_game) {
      game = _game;
  };

  this.onStart = function () {
      this.erth.store.set("redRunner.state", "idle");
      this.erth.store.set("redRunner.score", 0);
      this.erth.store.set("redRunner.coins", 0);
      this.erth.store.set("redRunner.highScore", 0);

      // Store this scripts' id, which will be used by other scripts to access this
      this.erth.store.set("redRunner.gameManagerId", this.id);

      // Assign player script id
      playerScriptId = this.erth.store.get("redRunner.playerId");

      // Cache player start position
      let players = this.erth.behaviors.findAll(playerScriptId);
      if (players.length > 0) {
          this._playerStartX = players[0].target.position.x;
      }

      registeredEvents.push(EventBus.instance.subscribe(EVENT.START_GAME, this._startGame.bind(this)));
  };

  this.update = function (deltaTime) {
      if (this._state !== "playing") return;

      // Score = distance traveled
      let players = this.erth.behaviors.findAll(playerScriptId);
      if (players.length > 0) {
          let px = players[0].target.position.x;
          let distance = Math.max(0, px - this._playerStartX);
          this._score = Math.floor(distance);
          this.erth.store.set("redRunner.score", this._score);
      }
  };

  this.onEvent = function (msg, data) {
      if (msg === "playerDied") {
          this._onPlayerDied();
      } else if (msg === "coinCollected") {
          this._onCoinCollected(data);
      } else if (msg === "restart") {
          this._restartGame();
      }
  };

  this._startGame = function () {
      this._state = "playing";
      this._score = 0;
      this._coins = 0;
      this.erth.store.set("redRunner.state", "playing");
      this.erth.store.set("redRunner.score", 0);
      this.erth.store.set("redRunner.coins", 0);
      console.log("[RedRunner] Game started!");
  };

  this._onPlayerDied = function () {
      if (this._state !== "playing") return;

      this._state = "gameOver";
      this._highScore = Math.max(this._highScore, this._score);
      this.erth.store.set("redRunner.state", "gameOver");
      this.erth.store.set("redRunner.highScore", this._highScore);

      console.warn(
          "[RedRunner] Game Over! Score: " +
          this._score +
          " | Coins: " +
          this._coins +
          " | High Score: " +
          this._highScore,
      );

      // Auto-restart after 2 seconds
      this._restartTimer = setTimeout(function () {
          self._restartGame();
      }, 2000);

      game.behaviorManager.sendEventToObjectBehaviors(
          self.target,
          "updateHighscoreUi",
          { highscore: this._highScore }
      );
  };

  this._onCoinCollected = function (data) {
      if (this._state !== "playing") return;
      this._coins += (data && data.value) || 1;
      this.erth.store.set("redRunner.coins", this._coins);

      game.behaviorManager.sendEventToObjectBehaviors(
          self.target,
          "updateCoinsUi",
          { coins: this._coins }
      );
  };

  this._restartGame = function () {
      const coinScriptId = this.erth.store.get("redRunner.coinsId");
      const obstacleScriptId = this.erth.store.get("redRunner.obstaclesId");

      // Reset all coins
      let coins = this.erth.behaviors.findAll(coinScriptId);
      for (let i = 0; i < coins.length; i++) {
          coins[i].onEvent("reset", {});
      }

      // Reset all obstacles
      let obstacles = this.erth.behaviors.findAll(obstacleScriptId);
      for (let i = 0; i < obstacles.length; i++) {
          obstacles[i].onEvent("reset", {});
      }

      // Reset player
      let players = this.erth.behaviors.findAll(playerScriptId);
      for (let i = 0; i < players.length; i++) {
          players[i].onEvent("restart", {});
      }

      this._startGame();
      console.log("[RedRunner] Game restarted!");

      game.behaviorManager.sendEventToObjectBehaviors(
          self.target,
          "resetScoreUi",
          {}
      );
  };

  this.onStop = function () {
      this._state = "idle";
      if (this._restartTimer) {
          clearTimeout(this._restartTimer);
          this._restartTimer = null;
      }

      for (const e of registeredEvents) {
          EventBus.instance.unsubscribe(e);
      }
  };

