          self._jumpPressed = true;
      }

      document.addEventListener("keydown", this._onKeyDown) // @check-ok
      document.addEventListener("pointerdown", this._onPointerDown);

      registeredEvents.push(EventBus.instance.subscribe(EVENT.START_GAME, this.onStartGame.bind(this)));
  };

  this.onStartGame = function () {
      self._isPaused = false;
  }

  this.update = function (deltaTime) {
      if (this._isPaused) return;
      if (this._isDead) return;

      let runSpeed = this.getAttribute("runSpeed") || 8;
      let jumpForce = this.getAttribute("jumpForce") || 12;
      let gravity = this.getAttribute("gravity") || 30;
      let groundCheckDist = this.getAttribute("groundCheckDistance") || 1.2;
      let deathY = this.getAttribute("deathY") || -10;

      // Ground detection via raycast
      let groundHit = null;
      // will use -0.5 and +0.5 of the object's positionX for raycast origin
      // this is to check if atleast the back or front is still on contact with the ground
      for (let i = -1; i < 2; i+=2) { 
          scratchVector3.copy(this.target.position);
          scratchVector3.x += i * 0.5;
          this._rayOrigin.copy(scratchVector3);
          this._rayOrigin.y += 0.1;
          this._raycaster.set(this._rayOrigin, this._downDir);
          this._raycaster.far = groundCheckDist;
          this._raycaster.near = 0;

          let sceneChildren = game.scene ? game.scene.children : [];
          let hits = this._raycaster.intersectObjects(sceneChildren, true);

          // Filter out hits on the player itself
          let playerTarget = this.target;
          for (let i = 0; i < hits.length; i++) {
              if (!this._isChildOf(hits[i].object, playerTarget)) {
                  groundHit = hits[i];
                  break;
              }
          }

          if (groundHit) break;
      }

      if (groundHit && this._velocityY <= 0) {
          this._isGrounded = true;
          this._velocityY = 0;
          this.target.position.y = groundHit.point.y + groundCheckDist * 0.5;
      } else {
          this._isGrounded = false;
      }

      // Jump
      if (this._jumpPressed && this._isGrounded) {
          this._velocityY = jumpForce;
          this._isGrounded = false;
      }
      this._jumpPressed = false;

      // Gravity
      this._velocityY -= gravity * deltaTime;

      // Move
      this.target.position.x += runSpeed * deltaTime;
      this.target.position.y += this._velocityY * deltaTime;

      // Fall death
      if (this.target.position.y < deathY) {
          this._die();
      }
  };

  this.onEvent = function (msg, data) {
      if (msg === "die") {
          this._die();
      } else if (msg === "restart") {
          this._respawn();
      }
  };

  this._die = function () {
      if (this._isDead) return;
      this._isDead = true;
      this._velocityY = 0;

      const gameManagerScriptId = this.erth.store.get("redRunner.gameManagerId");
      const gameBehaviors = this.erth.behaviors.findAll(gameManagerScriptId);
      for (let i = 0; i < gameBehaviors.length; i++) {
          gameBehaviors[i].onEvent("playerDied", {});
      }
  };

  this._respawn = function () {
      this._isDead = false;
      this._velocityY = 0;
      this._isGrounded = false;
      this.target.position.copy(this._startPos);
  };

  this._isChildOf = function (child, parent) {
      let current = child;
      while (current) {
          if (current === parent) return true;
          current = current.parent;
      }
      return false;
  };

  this.onStop = function () {
      if (this._onKeyDown) {
          document.removeEventListener("keydown", this._onKeyDown) // @check-ok complex input
      }

      if (this._onPointerDown) {
          document.removeEventListener("pointerdown", this._onPointerDown);
      }

      for (const e of registeredEvents) {
          EventBus.instance.unsubscribe(e);
      }
  };

