code: |-
  let game;
  let patterns = undefined;

  let templateCube = undefined;
  let templateCoin = undefined;
  let templateSpike = undefined;
  let templateSaw = undefined;
  let templateMace = undefined;

  const self = this;
  const platforms = [];

  let generatePlatformInterval = undefined;
  let previousStartX = 80;
  let keyArray = [];

  const COINSPAWNCHANCE = 0.7;

  // Events
  const EVENT = {
    START_GAME: "game_state:start_game",
  };
  const registeredEvents = [];

  this.init = function (_game) {
    game = _game;
  };

  this.onStart = function () {
    patterns = self.erth.store.get("patterns");
    keyArray = Object.keys(patterns);

    templateCube = game.scene.getObjectByProperty("uuid", self.attributes.templateCube);
    templateCoin = game.scene.getObjectByProperty("uuid", self.attributes.templateCoin);
    templateSpike = game.scene.getObjectByProperty("uuid", self.attributes.templateSpike);
    templateSaw = game.scene.getObjectByProperty("uuid", self.attributes.templateSaw);
    templateMace = game.scene.getObjectByProperty("uuid", self.attributes.templateMace);

    templateCoin.isSkinnedMesh = false;
    templateSpike.isSkinnedMesh = false;
    templateSaw.isSkinnedMesh = false;
    templateMace.isSkinnedMesh = false;

    registeredEvents.push(EventBus.instance.subscribe(EVENT.START_GAME, onStartGame));
  };

  this.dispose = function () {
    clearInterval(generatePlatformInterval);

    for (const e of registeredEvents) {
      EventBus.instance.unsubscribe(e);
    }
  };

  function onStartGame(event, data) {
    generatePlatformInterval = setInterval(generatePlatform, 5000);
  }

  async function generatePlatform() {
    const randomKey = keyArray[Math.floor(Math.random() * keyArray.length)];
    const pattern = patterns[randomKey];

    const { startX, startY } = getStartPosition(pattern);
    //console.warn(`[Level Manager] Spawning Pattern ${randomKey}:`, pattern);
    await spawnPattern(pattern, startX, startY);

    const lastPlatform = platforms[platforms.length - 1];
    previousStartX = lastPlatform.position.x;
  }

  function getStartPosition(pattern) {
    const lastPlatform = platforms[platforms.length - 1];
    const nextPlatform = pattern.layout[0];

    const lMin = lastPlatform ? lastPlatform.scale.x / 2 : 7.5;

    const nMin = lMin + (nextPlatform.width / 2) + 3;
    const nMax = nMin + 4;

    const gap = THREE.MathUtils.randInt(nMin, nMax);

    const startX = previousStartX + gap;
    const startY = lastPlatform ? lastPlatform.position.y : 0;
    return { startX, startY };
  }

  async function spawnPattern(pattern, startX, startY) {
    const willSpawnCoin = Math.random() < COINSPAWNCHANCE;

    for (const piece of pattern.layout) {
      if (piece.type === "platform") {
        const pl = await spawnPlatform(piece, startX, startY);
        platforms.push(pl);

        if (piece.width > 5) await spawnObstacle(piece, startX, startY);
      } else if (piece.type === "coin" && willSpawnCoin) {
        await spawnCoin(piece, startX, startY);
      }
    }
  }

  async function spawnPlatform(piece, startX, startY) {
    const platform = await game.cloneObject(templateCube);
    platform.position.set(startX + piece.x, startY + piece.y, 0);
    platform.scale.set(piece.width, 1, 4);
    await game.addObject(platform);
    return platform;
  }

  async function spawnCoin(piece, startX, startY) {
    const coin = await game.cloneObject(templateCoin);
    coin.position.set(startX + piece.x, startY + piece.y, 0);
    await game.addObject(coin);
  }

  async function spawnObstacle(piece, startX, startY) {
    if (Math.random() < 0.4) {
      const randNum = Math.random();
      if (randNum < 0.4) {
        await spawnSpike(piece, startX, startY);
      } else if (randNum < 0.75) {
        await spawnSaw(piece, startX, startY);
      } else {
        await spawnMace(piece, startX, startY);
      }
    }
  }

  async function spawnSpike(piece, startX, startY) {
    const randCount = Math.max(1, THREE.MathUtils.randInt(1, piece.width / 10)); // mininum count = 1
    spawnObstacleObject(piece, templateSpike, randCount, startX, startY, 1, -0.5);
  }

  async function spawnSaw(piece, startX, startY) {
    const randCount = Math.max(1, THREE.MathUtils.randInt(1, piece.width / 15)); // mininum count = 1
    const randPosY = THREE.MathUtils.randFloat(0.5, 1.5);
    spawnObstacleObject(piece, templateSaw, randCount, startX, startY, randPosY, 4);
  }

  async function spawnMace(piece, startX, startY) {
    const randCount = Math.max(1, THREE.MathUtils.randInt(1, piece.width / 15)); // mininum count = 1
    spawnObstacleObject(piece, templateMace, randCount, startX, startY, 3, 4);
  }

  async function spawnObstacleObject(piece, template, randCount, startX, startY, offsetY, minSpacing) {
    let currMin = (startX + piece.x) - (piece.width / 2);
    const division = (piece.width / randCount);
    let currMax = currMin + division;

    const maxLimit = (startX + piece.x) + (piece.width / 2) - 4; // - 4 to make sure player can stand on the edge
    for (let i = 0; i < randCount; i++) {
      const obstacle = await game.cloneObject(template);
      const randPosX = THREE.MathUtils.randInt(currMin, currMax);
      obstacle.position.set(randPosX, startY + piece.y + offsetY, 0);
      obstacle.updateMatrixWorld(true);
      await game.addObject(obstacle);

      currMin = randPosX + minSpacing;
      if ((currMin + division) > maxLimit) break;
      currMax = currMin + division;
    }
  }

