      "TrackStraight",
      "TrackCorner",
      "TrackBump",
      "TrackFinish",
      "DecoEmpty",
      "DecoForest",
      "DecoTents",
      "PlayerTruck",
      "NpcTruckGreen",
      "NpcTruckPurple",
      "NpcTruckRed"
    ];
  };

  this._applyTextureToObject = function(obj, texture) {
    if (!obj || !texture) return;

    let visited = new Set();
    obj.traverse(function(child) {
      if (!child.isMesh || !child.material) return;

      let materials = Array.isArray(child.material) ? child.material : [child.material];
      for (let i = 0; i < materials.length; i++) {
        let material = materials[i];
        if (!material || visited.has(material)) continue;
        visited.add(material);
        if ("map" in material) {
          material.map = texture;
          material.needsUpdate = true;
        }
      }
    });
  };

  this._applyTextureEverywhere = function(texture, scene) {
    this._ensureDefaults();
    if (!scene) scene = this._sceneRoot || (game && game.scene ? game.scene : null);
    if (!scene) return;

    for (let i = 0; i < this._targets.length; i++) {
      let obj = scene.getObjectByName(this._targets[i]);
      if (obj) {
        this._applyTextureToObject(obj, texture);
