code: |
  let game;
  this.init = function(_game) {
      game = _game;
    this._localOffset = new THREE.Vector3(
      this.getAttribute("offsetX"),
      this.getAttribute("offsetY"),
      this.getAttribute("offsetZ")
    );
    this._lookAhead = this.getAttribute("lookAhead");
    this._lerpRate = this.getAttribute("lerpRate");
    this._fov = this.getAttribute("fov");
    this._cameraPos = new THREE.Vector3();
    this._desiredPos = new THREE.Vector3();
    this._targetPos = new THREE.Vector3();
    this._lookTarget = new THREE.Vector3();
    this._forward = new THREE.Vector3(0, 0, 1);
    this._headingDir = new THREE.Vector3(0, 0, 1);
    this._offset = new THREE.Vector3();
    this._right = new THREE.Vector3();
    this._ready = false;
  };

  this.onStart = function() {
    let cam = game.camera;
    if (cam) {
      cam.fov = this._fov;
      cam.near = 0.1;
      cam.far = 600;
      cam.updateProjectionMatrix();
    }
    this._cameraPos.copy(this.gameObject.position);
    this._targetPos.copy(this.gameObject.position);
    this._ready = true;
  };

  this.update = function(deltaTime) {
    if (!this._ready) return;
    let dt = Math.min(deltaTime, 1 / 30);
    let cam = game.camera;
    if (!cam) return;

    this._forward.set(0, 0, 1).applyQuaternion(this.gameObject.quaternion);
    this._forward.y = 0;
    if (this._forward.lengthSq() > 1e-6) {
      this._forward.normalize();
      this._headingDir.lerp(this._forward, 0.22);
    }
    if (this._headingDir.lengthSq() > 1e-6) {
      this._headingDir.normalize();
    }

    this._right.set(this._headingDir.z, 0, -this._headingDir.x);
    if (this._right.lengthSq() > 1e-6) {
      this._right.normalize();
    }

    this._offset.copy(this._right).multiplyScalar(this._localOffset.x);
    this._offset.y = this._localOffset.y;
    this._offset.addScaledVector(this._headingDir, this._localOffset.z);
    this._desiredPos.copy(this.gameObject.position).add(this._offset);
    this._lookTarget.copy(this.gameObject.position);
    this._lookTarget.y += 1.0;
    this._lookTarget.addScaledVector(this._headingDir, this._lookAhead);

    let t = 1 - Math.exp(-this._lerpRate * dt);
    this._cameraPos.lerp(this._desiredPos, t);
    this._targetPos.lerp(this._lookTarget, t);
    cam.position.copy(this._cameraPos);
    cam.lookAt(this._targetPos);
  };

  this.onStop = function() {
    this._ready = false;
  };

